import threading
_VERROU_SAUVEGARDE = threading.Lock()

# Les operations d'ECRITURE (POST) passent une par une pour ne plus jamais
# qu'une operation ecrase ce qu'une autre vient d'enregistrer (perte de pions, etc.)
# Les lectures (GET, actualisation des boules...) restent paralleles et rapides.
_VERROU_ECRITURES = threading.Lock()

# ============================================================
# ⚡ CACHE ANTI-SATURATION (lecture des données)
# Au lieu de relire le fichier disque à CHAQUE requête, on garde le
# contenu en mémoire et on ne relit QUE s'il a changé (date de modif
# + taille) ou après 2 secondes. Dès que save_data écrit, la date de
# modif change → le cache se renouvelle tout seul (données toujours
# fraîches). Chaque appel re-parse le contenu → chaque requête a son
# propre objet isolé (aucun risque de mélanger l'argent de 2 personnes).
# ============================================================
import time as _time_cache
_LD_CACHE = {"contenu": None, "mtime": None, "taille": None, "ts": 0.0}
_LD_VERROU = threading.Lock()

# 🪶 Caches légers pour les lectures TRÈS fréquentes (micro + tirage).
# Avant : chaque appel relisait TOUTE la base pour 2-3 petites infos -> saturation.
# Maintenant : on garde ces infos en mémoire, on ne relit la base qu'AU PLUS 1x/2s.
# Lecture seule (ne touche jamais à l'argent). Se met à jour tout seul en 2s max.
_MICRO_CACHE = {"ts": 0.0, "actif": False, "message": ""}
_MICRO_VERROU = threading.Lock()
# 🎯 BRIQUE 3 : cache du tirage PAR TOURNOI ("" = ancien tirage global, compatibilité)
_TIRAGE_CACHE = {}
_TIRAGE_VERROU = threading.Lock()
_CACHE_LEGER_TTL = 2.0

# 🪶 Cache court pour les PETITES lectures publiques interrogées en boucle pendant un tournoi
# (maintenance, messages, tournois programmés). Avant : chacune relisait TOUTE la base.
# Maintenant : on relit la base au plus 1x / 3s par info. Lecture seule (aucune donnée d'argent).
_SET_CACHE = {}
_SET_VERROU = threading.Lock()
_SET_TTL = 3.0
def _cache_lecture(cle, producteur):
    maintenant = _time_cache.time()
    with _SET_VERROU:
        c = _SET_CACHE.get(cle)
        if c and (maintenant - c["ts"]) < _SET_TTL:
            return c["val"]
    val = producteur()
    with _SET_VERROU:
        _SET_CACHE[cle] = {"ts": maintenant, "val": val}
    return val


def _lire_donnees_brut_cache():
    """Contenu brut du fichier principal, avec cache court anti-saturation."""
    try:
        st = os.stat(DATA_FILE)
        mtime, taille = st.st_mtime, st.st_size
    except Exception:
        return None  # fichier absent -> laisser load_data gérer (.bak / défaut)
    maintenant = _time_cache.time()
    with _LD_VERROU:
        c = _LD_CACHE
        if (c["contenu"] is not None and c["mtime"] == mtime
                and c["taille"] == taille and (maintenant - c["ts"]) < 2.0):
            return c["contenu"]  # cache frais : AUCUNE lecture disque
    # Cache raté : on lit le disque UNE fois (hors verrou pour ne pas bloquer)
    try:
        with open(DATA_FILE, "r") as f:
            contenu = f.read()
    except Exception:
        return None
    with _LD_VERROU:
        _LD_CACHE["contenu"] = contenu
        _LD_CACHE["mtime"] = mtime
        _LD_CACHE["taille"] = taille
        _LD_CACHE["ts"] = maintenant
    return contenu


# ============================================================
# 🐘 POSTGRESQL — coffre-fort durable (filet anti-perte de données)
# Si la variable DATABASE_URL existe, l'appli RECOPIE en continu toutes
# ses données dans PostgreSQL (base ACID, qui ne se corrompt jamais).
# Le fichier reste la source rapide (avec le cache) ; PostgreSQL est le
# coffre-fort : si le volume Railway est perdu/abîmé, on récupère
# automatiquement depuis PostgreSQL au démarrage.
# Si DATABASE_URL n'existe pas → rien ne change (repli fichier total).
# ============================================================
_PG_URL = os.environ.get("DATABASE_URL", "").strip()
_PG_POOL = None
_PG_OK = False


def _init_postgres():
    global _PG_POOL, _PG_OK, _PG_URL
    if not _PG_URL:
        print("[PG] DATABASE_URL absent — stockage fichier classique (aucun changement).")
        return
    try:
        import psycopg2
        from psycopg2.pool import ThreadedConnectionPool
        if _PG_URL.startswith("postgres://"):
            _PG_URL = "postgresql://" + _PG_URL[len("postgres://"):]
        _PG_POOL = ThreadedConnectionPool(1, 10, _PG_URL)
        conn = _PG_POOL.getconn()
        try:
            with conn.cursor() as cur:
                cur.execute("CREATE TABLE IF NOT EXISTS app_data (id INT PRIMARY KEY, data JSONB NOT NULL)")
            conn.commit()
        finally:
            _PG_POOL.putconn(conn)
        _PG_OK = True
        print("[PG] PostgreSQL connecté — coffre-fort durable activé.")
    except Exception as e:
        print(f"[PG] Indisponible, on garde le fichier : {e}")
        _PG_OK = False


def _pg_lire():
    if not _PG_OK:
        return None
    conn = _PG_POOL.getconn()
    try:
        with conn.cursor() as cur:
            cur.execute("SELECT data FROM app_data WHERE id = 1")
            row = cur.fetchone()
        conn.commit()
        return row[0] if row else None
    finally:
        _PG_POOL.putconn(conn)


def _pg_ecrire(data):
    if not _PG_OK:
        return False
    from psycopg2.extras import Json
    conn = _PG_POOL.getconn()
    try:
        with conn.cursor() as cur:
            cur.execute(
                "INSERT INTO app_data (id, data) VALUES (1, %s) "
                "ON CONFLICT (id) DO UPDATE SET data = EXCLUDED.data",
                (Json(data),),
            )
        conn.commit()
        return True
    finally:
        _PG_POOL.putconn(conn)


def _synchroniser_postgres_demarrage():
    """Au démarrage : recopie le fichier vers PostgreSQL la 1ère fois,
    OU récupère le fichier depuis PostgreSQL si le volume a été perdu."""
    if not _PG_OK:
        return
    try:
        pg_data = _pg_lire()
        fichier_data = None
        if os.path.exists(DATA_FILE):
            try:
                with open(DATA_FILE) as f:
                    fichier_data = json.load(f)
            except Exception:
                fichier_data = None
        if pg_data is None and fichier_data is not None:
            _pg_ecrire(fichier_data)
            print("[PG] Données initiales recopiées du fichier vers PostgreSQL.")
        elif pg_data is not None and not fichier_data:
            with open(DATA_FILE + ".tmp", "w") as f:
                json.dump(pg_data, f, ensure_ascii=False, default=str)
            os.replace(DATA_FILE + ".tmp", DATA_FILE)
            print("[PG] ⚠️ Fichier perdu — données RÉCUPÉRÉES depuis PostgreSQL.")
    except Exception as e:
        print(f"[PG SYNC ERR] {e}")


_init_postgres()


# 🧠 BRIQUE 1 — LA BASE EN MÉMOIRE
# L'appli garde UNE SEULE copie analysée des données. Tant que le fichier n'a
# pas changé (empreinte mtime+taille), toutes les requêtes utilisent cette
# copie : ZÉRO relecture, ZÉRO ré-analyse. Après chaque écriture, la mémoire
# est réalignée sur ce qui vient d'être écrit. Un seul objet partagé = plus
# aucune "vieille copie" ne peut écraser une correction.
_MEM_DB = {"sig": None, "obj": None}
_MEM_VERROU = threading.Lock()

def load_data():
    # 🧠 MÉMOIRE SOUVERAINE : une fois chargée (au démarrage), la mémoire est LA
    # référence UNIQUE. On ne re-analyse plus JAMAIS le disque en cours de route
    # (l'appli est la seule à écrire son propre fichier). Avant, une re-analyse
    # pouvait créer DEUX copies concurrentes qui se volaient des écritures
    # (soldes qui « sautent », débits de tickets perdus). C'est structurellement
    # impossible désormais. Le disque n'est relu qu'au démarrage, ou après une
    # RESTAURATION explicite (qui vide la mémoire pour forcer la relecture).
    with _MEM_VERROU:
        if _MEM_DB["obj"] is not None:
            return _MEM_DB["obj"]
    try:
        _st = os.stat(DATA_FILE)
        _sig = (_st.st_mtime_ns, _st.st_size)
    except Exception:
        _sig = None
    # Essayer le fichier principal, puis la copie de secours (.bak)
    for chemin in [DATA_FILE, DATA_FILE + ".bak"]:
        try:
            data = None
            if chemin == DATA_FILE:
                _contenu = _lire_donnees_brut_cache()
                if _contenu is None:
                    continue
                data = _parse_json_rapide(_contenu)
            elif os.path.exists(chemin):
                with open(chemin, "r") as f:
                    data = json.load(f)
            else:
                continue
            if data is not None:
                if chemin.endswith(".bak"):
                    print("[LOAD] Fichier principal illisible — copie de secours utilisée")
                # AUTO-REPARATION : recreer toute case manquante (listes et dictionnaires)
                cles_listes = ["alertes_bingo", "tirage", "tournois", "ventes", "tickets",
                               "commandes_pions", "commandes_pions_joueurs", "commandes_tickets",
                               "commandes_tickets_pions", "annonces_jeux", "paiements_stripe"]
                cles_dicts = ["tickets_acheteurs", "acces_docs", "sessions", "pions_joueurs",
                              "pions_org", "coches", "parrainages"]
                for k in cles_listes:
                    if k not in data or not isinstance(data[k], list):
                        data[k] = data.get(k) if isinstance(data.get(k), list) else []
                for k in cles_dicts:
                    if k not in data or not isinstance(data[k], dict):
                        data[k] = data.get(k) if isinstance(data.get(k), dict) else {}
                if "codes" not in data or not isinstance(data["codes"], dict):
                    data["codes"] = {}
                if "ADMIN2024" not in data["codes"]:
                    data["codes"]["ADMIN2024"] = {"duree": 36500, "nom": "Administrateur", "actif": True, "admin": True}
                # CODE ADMIN SECRET (via variable Railway ADMIN_CODE_SECRET)
                _admin_secret = os.environ.get("ADMIN_CODE_SECRET", "").strip().upper()
                if _admin_secret:
                    data["codes"][_admin_secret] = {"duree": 36500, "nom": "Administrateur", "actif": True, "admin": True}
                    # SECURITE : desactiver l'ancien ADMIN2024 UNIQUEMENT si le code secret existe
                    # (garantit qu'on ne se retrouve jamais sans acces admin)
                    if "ADMIN2024" in data["codes"] and _admin_secret != "ADMIN2024":
                        data["codes"]["ADMIN2024"]["actif"] = False
                if not data.get("jeux"):
                    data["jeux"] = ["P6", "OHANA 75", "QUINES 90", "OHANA 75 4 SERIE"]
                if chemin == DATA_FILE and _sig is not None:
                    with _MEM_VERROU:
                        _MEM_DB["obj"] = data
                        _MEM_DB["sig"] = _sig
                return data
        except Exception as e:
            print(f"[LOAD ERR] {chemin}: {e}")
            # Conserver le fichier abime pour recuperation eventuelle (jamais l'ecraser)
            try:
                import shutil
                horodatage = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
                shutil.copy(chemin, chemin + ".corrompu_" + horodatage)
            except Exception:
                pass
    print("[LOAD] ATTENTION : aucune donnée lisible — démarrage sur base vide")
    return {
        "ventes": [], "tickets": [],
        "jeux": ["P6", "OHANA 75", "QUINES 90", "OHANA 75 4 SERIE"],
        "tournois": [],
        "codes": {"ADMIN2024": {"duree": 36500, "nom": "Administrateur", "actif": True, "admin": True}},
        "sessions": {}, "acces_docs": {}, "tickets_acheteurs": {},
        "alertes_bingo": [], "tirage": []
    }

# 📸 PHOTO de l'état à écrire (anti-écrasement) : quand une sauvegarde est
# demandée, on fige l'état du moment. L'écriture (même différée) écrit CETTE
# photo, et non le DB global que les téléphones ont pu recharger entre-temps.
_DB_A_ECRIRE = [None]

def _ecrire_donnees_disque():
    """Écriture atomique réelle sur le disque (anti-corruption).
    Écrit la PHOTO figée (_DB_A_ECRIRE) si elle existe, sinon le DB courant."""
    try:
        # On écrit la photo prise au moment de la demande de sauvegarde.
        # Si aucune photo (cas improbable), on retombe sur le DB courant.
        a_ecrire = _DB_A_ECRIRE[0] if _DB_A_ECRIRE[0] is not None else DB
        with _VERROU_SAUVEGARDE:
            # GRAND LIVRE : note les mouvements de pions (ne doit JAMAIS bloquer la sauvegarde)
            try:
                _journaliser_mouvements_pions()
            except Exception as _egl:
                print(f"[GRAND-LIVRE ERR] {_egl}")
            os.makedirs(os.path.dirname(DATA_FILE), exist_ok=True)
            tmp = DATA_FILE + ".tmp"
            with open(tmp, "w") as f:
                json.dump(a_ecrire, f, ensure_ascii=False, default=str)
                f.flush()
                # ⚡ CORRECTIF LENTEUR : sur volume réseau (Railway), os.fsync() peut
                # prendre plusieurs SECONDES en tenant le verrou -> tout le serveur
                # attend derrière (réponses à 20s, erreurs 503). Le os.replace()
                # ci-dessous est déjà ATOMIQUE (aucune corruption possible) et
                # PostgreSQL sert de filet durable. On ne force donc plus la synchro
                # disque physique dans le chemin bloquant, SAUF si FSYNC_BLOQUANT=1
                # (bouton de secours réactivable sur Railway sans redéployer).
                if os.environ.get("FSYNC_BLOQUANT", "0") == "1":
                    os.fsync(f.fileno())
            if os.path.exists(DATA_FILE):
                try:
                    os.replace(DATA_FILE, DATA_FILE + ".bak")
                except Exception:
                    pass
            os.replace(tmp, DATA_FILE)
            # 🧠 BRIQUE 1 : la mémoire reste alignée sur ce qu'on vient d'écrire
            try:
                _st2 = os.stat(DATA_FILE)
                with _MEM_VERROU:
                    _MEM_DB["obj"] = a_ecrire
                    _MEM_DB["sig"] = (_st2.st_mtime_ns, _st2.st_size)
            except Exception:
                pass
            # 🐘 Recopie durable dans PostgreSQL — EN ARRIÈRE-PLAN (ne bloque plus
            # la sauvegarde : le fichier ci-dessus est déjà écrit, durable).
            try:
                _pg_planifier(a_ecrire)
            except Exception as _epg:
                print(f"[PG PLANIF ERR] {_epg}")
        print(f"[SAVE OK] {DATA_FILE}")
    except Exception as e:
        print(f"[SAVE ERR] {e}")

# Système de regroupement des sauvegardes (évite de réécrire en rafale)
import threading as _threading_save
import time as _time_save
_DERNIERE_SAUVEGARDE = [0.0]
_SAUVEGARDE_EN_ATTENTE = [None]
_VERROU_THROTTLE = _threading_save.Lock()
# 🔒 Verrou unique pour sérialiser les écritures d'argent (aucun risque
# d'interblocage : un seul verrou réentrant). Ne ralentit que les écritures.
_VERROU_DB = _threading_save.RLock()
_THROTTLE_SECONDES = 2.0

# 🐘 Écriture PostgreSQL en ARRIÈRE-PLAN (hors du chemin critique).
# Le disque est déjà écrit immédiatement (durable) ; PostgreSQL est un filet de
# secours qui peut prendre quelques secondes de retard sans AUCUN risque (au
# redémarrage, c'est toujours le FICHIER qui fait foi). Évite que chaque
# mouvement d'argent bloque sur l'envoi complet vers PostgreSQL — indispensable
# sous charge (tournoi à ~20 joueuses simultanées).
_PG_SNAPSHOT = [None]
_PG_VERROU_BG = _threading_save.Lock()
_PG_DERNIER = [0.0]
_PG_TIMER = [None]
_PG_THROTTLE = 3.0  # au plus une écriture PostgreSQL toutes les 3 s

def _pg_flush_arriere_plan():
    with _PG_VERROU_BG:
        data = _PG_SNAPSHOT[0]
        _PG_SNAPSHOT[0] = None
        _PG_TIMER[0] = None
        _PG_DERNIER[0] = _time_save.time()
    if data is not None:
        try:
            _pg_ecrire(data)
        except Exception as _e:
            print(f"[PG BG ERR] {_e}")

def _pg_planifier(data):
    """Programme une écriture PostgreSQL en arrière-plan (throttlée).
    Garde toujours le DERNIER état ; ne bloque jamais l'appelant."""
    if not _PG_OK:
        return
    with _PG_VERROU_BG:
        _PG_SNAPSHOT[0] = data
        if _PG_TIMER[0] is not None:
            return  # une écriture est déjà programmée -> elle prendra ce snapshot
        delai = max(0.05, _PG_THROTTLE - (_time_save.time() - _PG_DERNIER[0]))
        t = _threading_save.Timer(delai, _pg_flush_arriere_plan)
        t.daemon = True
        _PG_TIMER[0] = t
        t.start()

def _sauvegarde_differee():
    """Exécute la sauvegarde regroupée après le délai."""
    with _VERROU_THROTTLE:
        _SAUVEGARDE_EN_ATTENTE[0] = None
        _DERNIERE_SAUVEGARDE[0] = _time_save.time()
    with _VERROU_DB:
        _ecrire_donnees_disque()
    try:
        verifier_soldes_negatifs()
    except Exception:
        pass

def save_data(immediat=False):
    """Sauvegarde NON BLOQUANTE : la modification est déjà en mémoire (DB) —
    donc rien n'est jamais perdu — et l'écriture sur le disque réseau (lent) est
    confiée à un thread dédié qui n'immobilise JAMAIS les requêtes des joueurs.

    Durabilité garantie par 3 filets :
      1) la mémoire (DB) — vérité immédiate pour toutes les requêtes
      2) PostgreSQL en arrière-plan (_pg_planifier) — copie durable
      3) le fichier disque, écrit par le thread dédié + sauvegardes horodatées

    immediat=True ne force plus une écriture disque SYNCHRONE (c'était la cause
    des blocages à 20s sur volume réseau) : il demande juste une écriture disque
    au plus vite (réveille le writer sans délai). L'ordre des écritures reste
    sérialisé -> aucun écrasement possible.
    """
    # 📸 On fige l'état courant en mémoire : la modif de l'appelant est déjà "sauvée"
    # du point de vue de toutes les requêtes (qui lisent DB en mémoire).
    _DB_A_ECRIRE[0] = DB
    # 🚀 On réveille le thread d'écriture disque (non bloquant).
    _demander_ecriture_disque(urgent=immediat)


# ── Thread d'écriture disque dédié (un seul writer, jamais bloquant) ──
_ECRITURE_DEMANDEE = _threading_save.Event()
_ECRITURE_URGENTE = [False]
_WRITER_DEMARRE = [False]
_WRITER_VERROU = _threading_save.Lock()

def _demander_ecriture_disque(urgent=False):
    """Signale au writer qu'il y a des données à écrire. Retour immédiat."""
    if urgent:
        _ECRITURE_URGENTE[0] = True
    _ECRITURE_DEMANDEE.set()
    _demarrer_writer_disque()

def _boucle_writer_disque():
    """Écrit le dernier état sur le disque, en regroupant les rafales.
    Ne bloque jamais une requête : c'est CE thread, et lui seul, qui touche le disque."""
    while True:
        try:
            _ECRITURE_DEMANDEE.wait()          # attend qu'une écriture soit demandée
            urgent = _ECRITURE_URGENTE[0]
            # Regroupement : on laisse les rafales s'accumuler un court instant,
            # puis on écrit UNE fois le dernier état (throttle réseau).
            _time_save.sleep(0.15 if urgent else max(0.3, _THROTTLE_SECONDES))
            _ECRITURE_DEMANDEE.clear()
            _ECRITURE_URGENTE[0] = False
            with _VERROU_DB:
                _ecrire_donnees_disque()
            try:
                verifier_soldes_negatifs()
            except Exception:
                pass
        except Exception as _e:
            print(f"[WRITER DISQUE ERR] {_e}")
            _time_save.sleep(1.0)

def _demarrer_writer_disque():
    if _WRITER_DEMARRE[0]:
        return
    with _WRITER_VERROU:
        if _WRITER_DEMARRE[0]:
            return
        _WRITER_DEMARRE[0] = True
        t = _threading_save.Thread(target=_boucle_writer_disque, daemon=True)
        t.start()
        print("[WRITER DISQUE] Thread d'écriture disque démarré (non bloquant).")

# 🛟 FILET DE SÉCURITÉ À L'ARRÊT : si Railway redémarre le serveur, on force
# UNE écriture disque finale synchrone pour ne rien perdre (soldes, gains...).
# Se déclenche à l'arrêt normal (atexit) ET sur signal d'arrêt Railway (SIGTERM).
def _sauvegarde_finale_arret(*_a):
    try:
        _DB_A_ECRIRE[0] = DB
        with _VERROU_DB:
            _ecrire_donnees_disque()
        print("[ARRET] Sauvegarde finale effectuée (données préservées).")
    except Exception as _e:
        print(f"[ARRET] Erreur sauvegarde finale : {_e}")

try:
    import atexit as _atexit
    _atexit.register(_sauvegarde_finale_arret)
    import signal as _signal
    def _handler_sigterm(signum, frame):
        _sauvegarde_finale_arret()
        # Laisse le comportement par défaut se poursuivre (arrêt).
        try:
            _signal.signal(signum, _signal.SIG_DFL)
            os.kill(os.getpid(), signum)
        except Exception:
            pass
    _signal.signal(_signal.SIGTERM, _handler_sigterm)
    print("[ARRET] Filet de sauvegarde à l'arrêt armé (atexit + SIGTERM).")
except Exception as _e:
    print(f"[ARRET] Impossible d'armer le filet d'arrêt : {_e}")

_synchroniser_postgres_demarrage()
DB = load_data()

