def _get_client_ip():
    """Recupere l'adresse IP reelle du client (gere les proxys Railway)."""
    try:
        # Railway / proxys mettent l'IP reelle dans X-Forwarded-For
        fwd = request.headers.get("X-Forwarded-For", "")
        if fwd:
            return fwd.split(",")[0].strip()
        return request.remote_addr or ""
    except Exception:
        return ""

# === GARDE DE SÉCURITÉ DES TRANSACTIONS JOUEUSES (additif, défensif) ===
# Refuse tout montant négatif, non numérique ou délirant sur les transactions.
# 100% additif : en cas de doute, on laisse passer (ne bloque jamais une
# opération légitime). Couvre /api/pions/*, /api/ticket, /api/gain/*, /api/retrait/*.
_SECU_PATHS_TX = ("/api/pions/", "/api/ticket", "/api/gain/", "/api/retrait/")
_SECU_CHAMPS_MONTANT = ("montant", "pions", "nb_pions", "montant_gain", "montant_paye", "prix")
_SECU_MONTANT_MAX = 5000000
import time as _t_secu
_SECU_RL = {}        # identité -> [timestamps]  (limite anti-spam par joueuse)
_SECU_DEDUP = {}     # empreinte -> timestamp     (anti double-clic)
_SECU_RL_MAX = 15
_SECU_RL_WIN = 10
_SECU_DEDUP_WIN = 1.5

@app.before_request
def _garde_securite_transactions():
    try:
        if request.method != "POST":
            return None
        path = request.path or ""
        if not any(path == p.rstrip("/") or path.startswith(p) for p in _SECU_PATHS_TX):
            return None
        d = request.get_json(silent=True)
        if not isinstance(d, dict):
            return None
        # 1) Bornes des montants : refuse négatif, non numérique, délirant
        for champ in _SECU_CHAMPS_MONTANT:
            v = d.get(champ)
            if champ in d and v is not None and v != "":
                try:
                    val = int(float(v))
                except (ValueError, TypeError):
                    return jsonify({"ok": False, "msg": "Montant invalide."}), 400
                if val < 0 or val > _SECU_MONTANT_MAX:
                    return jsonify({"ok": False, "msg": "Montant hors limites."}), 400
        now = _t_secu.time()
        ident = str(d.get("code_joueur") or d.get("code") or d.get("code_gagnant")
                    or d.get("code_source") or _get_client_ip() or "?").upper()
        # 2) Limite anti-spam PAR JOUEUSE (pas par IP → pas de blocage en salle/wifi partagé)
        log = _SECU_RL.setdefault(ident, [])
        log[:] = [t for t in log if now - t < _SECU_RL_WIN]
        if len(log) >= _SECU_RL_MAX:
            return jsonify({"ok": False, "msg": "Trop d'opérations d'affilée, patiente quelques secondes."}), 429
        log.append(now)
        # 3) Anti double-clic : même joueuse + même action + même contenu en moins de 1,5 s
        try:
            raw = request.get_data(cache=True) or b""
        except Exception:
            raw = b""
        emp = hashlib.sha256((ident + "|" + path + "|").encode("utf-8", "ignore") + raw).hexdigest()
        last = _SECU_DEDUP.get(emp)
        if last and now - last < _SECU_DEDUP_WIN:
            return jsonify({"ok": False, "msg": "Action déjà envoyée, patiente une seconde."}), 409
        _SECU_DEDUP[emp] = now
        # Nettoyage mémoire
        if len(_SECU_DEDUP) > 4000:
            for k in [k for k, t in list(_SECU_DEDUP.items()) if now - t > 60]:
                _SECU_DEDUP.pop(k, None)
        if len(_SECU_RL) > 4000:
            for k in [k for k, ts in list(_SECU_RL.items()) if not ts or now - ts[-1] > 60]:
                _SECU_RL.pop(k, None)
    except Exception:
        return None
    return None

def journaliser_connexion(code, resultat, type_compte="organisateur", nom=""):
    """Enregistre chaque tentative de connexion (reussie ou echouee) avec IP pour controle."""
    global DB
    try:
        if "journal_connexions" not in DB:
            DB["journal_connexions"] = []
        ip = _get_client_ip()
        ua = ""
        try:
            ua = request.headers.get("User-Agent", "")[:120]
        except Exception:
            pass
        DB["journal_connexions"].insert(0, {
            "code": code,
            "nom": nom,
            "resultat": resultat,
            "type_compte": type_compte,
            "ip": ip,
            "user_agent": ua,
            "date": datetime.datetime.now().isoformat()
        })
        DB["journal_connexions"] = DB["journal_connexions"][:300]
    except Exception as e:
        print(f"[JOURNAL] Erreur : {e}")


def verifier_soldes_negatifs():
    """Detecte tout solde de pions negatif (disparition/anomalie grave). Anti-doublon: 1 alerte/code/heure."""
    global DB
    try:
        maintenant = datetime.datetime.now()
        il_y_a_1h = (maintenant - datetime.timedelta(hours=1)).isoformat()
        # Codes deja alertes recemment (anti-doublon historique)
        deja_alertes = set()
        for a in DB.get("alertes_systeme", []):
            if a.get("type") == "Solde de pions négatif" and a.get("date", "") > il_y_a_1h:
                deja_alertes.add(a.get("cible", ""))
        
        # Verifier les soldes des joueuses
        for code, pions in DB.get("pions_joueurs", {}).items():
            if isinstance(pions, dict):
                for valeur, nb in pions.items():
                    if isinstance(nb, (int, float)) and nb < 0 and code not in deja_alertes:
                        creer_alerte_systeme("Solde de pions négatif", "grave",
                                             f"ANOMALIE : la joueuse « {code} » a un solde négatif ({nb} pions à {valeur} XPF). Disparition ou bug possible.", code)
                        deja_alertes.add(code)
        
        # Verifier les stocks des organisateurs
        for code, pions in DB.get("pions_org", {}).items():
            if isinstance(pions, dict):
                for valeur, nb in pions.items():
                    if isinstance(nb, (int, float)) and nb < 0 and code not in deja_alertes:
                        creer_alerte_systeme("Solde de pions négatif", "grave",
                                             f"ANOMALIE : l'organisateur « {code} » a un stock négatif ({nb} pions à {valeur} XPF).", code)
                        deja_alertes.add(code)
    except Exception as e:
        print(f"[ALERTE] Erreur verification soldes : {e}")

# ============================================
# REGLE UNIQUE DES FRAIS DE SERVICE
# 5% sur tout paiement electronique (carte, virement, deblock, ccp, bt)
# 0% sur especes (cash)
# ============================================
def calculer_frais_service(montant, mode_paiement):
    """Retourne le montant des frais de service selon le mode de paiement."""
    try:
        montant = float(montant)
    except (ValueError, TypeError):
        montant = 0
    mode = str(mode_paiement or "").lower()
    # Especes / cash = 0% de frais
    if any(x in mode for x in ["espece", "espèce", "cash", "liquide", "comptant"]):
        return 0
    # Tout le reste (carte, virement, deblock, ccp, bt) = 5%
    return round(montant * 0.05)

def gen_code(n=8):
    # Alphabet SANS caracteres ambigus (0/O, 1/I/L bannis) pour eviter les
    # confusions de saisie qui font atterrir sur le mauvais compte.
    # N'affecte QUE les nouveaux codes ; tous les codes existants restent valides.
    _ALPHABET_SANS_AMBIGU = "ABCDEFGHJKMNPQRSTUVWXYZ23456789"
    return ''.join(secrets.choice(_ALPHABET_SANS_AMBIGU) for _ in range(n))

def verif_session(token):
    # Recharger depuis fichier pour avoir sessions a jour
    fresh = load_data()
    s = fresh["sessions"].get(token)
    if not s:
        return None
    # Si pas de date d'expiration (admin) ou session non expirée
    if s.get("expire"):
        try:
            if datetime.datetime.now() > datetime.datetime.fromisoformat(s["expire"]):
                return None
        except:
            pass
    return s

def upload_cloudinary_image(image_b64):
    try:
        data = urllib.parse.urlencode({
            "file": f"data:image/jpeg;base64,{image_b64}",
            "upload_preset": CLOUDINARY_PRESET
        }).encode('utf-8')
        url = f"https://api.cloudinary.com/v1_1/{CLOUDINARY_CLOUD}/image/upload"
        req = urllib.request.Request(url, data=data, method='POST')
        req.add_header('Content-Type', 'application/x-www-form-urlencoded')
        resp = urllib.request.urlopen(req, timeout=30)
        result = json.loads(resp.read().decode())
        return result.get("secure_url")
    except Exception as e:
        print(f"[CLOUDINARY ERR] {e}")
        return None

