@app.route("/api/bingo", methods=["POST"])
def declarer_bingo():
    global DB
    DB = load_data()
    d = request.json
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    # Trouver l'organisateur du ticket
    ticket_id = d.get("ticketId", "")
    ticket = next((t for t in DB["tickets"] if t["id"] == ticket_id), None)
    # L'alerte va a l'organisatrice DU JEU joue : code_org du ticket si connu,
    # sinon celui envoye par la joueuse (le jeu qu'elle joue actuellement).
    code_org_alerte = (ticket.get("code_org", "") if ticket else "") or (d.get("code_org", "") or "").strip()
    
    alerte = {
        "id": gen_code(8),
        "acheteur": d.get("acheteur", "Inconnu"),
        "code_org": code_org_alerte,
        "jeu": d.get("jeu", ""),
        "serie": d.get("serie", ""),
        "ticket_id": d.get("ticketId", ""),
        "pdf_url": d.get("pdf_url", None),
        "page_debut": d.get("page_debut", None),
        "page_fin": d.get("page_fin", None),
        "coches": d.get("coches", []),
        "date": datetime.datetime.now().isoformat(),
        "statut": "en_attente"
    }
    # === Vérification automatique (recalcul serveur) au moment du BINGO ===
    try:
        import re as _re
        tirage_set = set()
        _t_org = DB.get("tirages", {}).get(code_org_alerte) if code_org_alerte else None
        _src_t = _t_org.get("boules", []) if _t_org is not None else DB.get("tirage", [])
        for _x in _src_t:
            try:
                tirage_set.add(int(_x))
            except Exception:
                pass
        seriaux = [int(x) for x in _re.findall(r"\d+", str(d.get("serie", "")))]
        jeu_a = d.get("jeu", "")
        res_ok = [r for sx in seriaux for r in [_verifier_serial(jeu_a, sx, tirage_set)] if r.get("trouve")]
        if res_ok:
            meilleur = next((r for r in res_ok if r.get("complet")), None) \
                or max(res_ok, key=lambda r: r.get("sortis", 0))
            alerte["verif"] = {"gagnant": bool(meilleur.get("complet")), "boules": len(tirage_set), **meilleur}
        else:
            alerte["verif"] = {"trouve": False}
    except Exception:
        alerte["verif"] = {"trouve": False}
    if "alertes_bingo" not in DB:
        DB["alertes_bingo"] = []
    DB["alertes_bingo"].insert(0, alerte)
    save_data()
    return jsonify({"ok": True, "alerte_id": alerte["id"], "verif": alerte.get("verif")})

@app.route("/api/bingo/alertes")
def get_alertes_bingo():
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    alertes = DB.get("alertes_bingo", [])
    # Masquer les tickets validés dont la visibilité de 5 jours est écoulée
    _now_iso = datetime.datetime.now().isoformat()
    alertes = [a for a in alertes if not a.get("expire_le") or str(a.get("expire_le")) > _now_iso]
    # Admin voit toutes les alertes
    if s and s.get("admin"):
        return jsonify(alertes)
    # Organisateur voit seulement ses alertes
    if s:
        code_org = s["code"]
        alertes = [a for a in alertes if a.get("code_org") == code_org or not a.get("code_org")]
        return jsonify(alertes)
    return jsonify([])

@app.route("/api/bingo/effacer-non-valides", methods=["POST"])
def effacer_alertes_non_valides():
    """ORGANISATEUR — Efface tous les tickets bingo NON validés. Seuls les tickets
    validés restent, et deviennent invisibles automatiquement après 5 jours."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    code_org = s["code"]
    is_admin = bool(s.get("admin"))
    exp = (datetime.datetime.now() + datetime.timedelta(days=5)).isoformat()
    gardees = []
    effacees = 0
    for a in DB.get("alertes_bingo", []):
        appartient = is_admin or a.get("code_org") == code_org or not a.get("code_org")
        if not appartient:
            gardees.append(a)
            continue
        if a.get("statut") == "valide":
            a["expire_le"] = exp   # visible encore 5 jours
            gardees.append(a)
        else:
            effacees += 1          # non validé -> effacé
    DB["alertes_bingo"] = gardees
    save_data(immediat=True)
    return jsonify({"ok": True, "effacees": effacees})

import threading

def effacer_pdfs_apres_tournoi(code_org, delai_secondes=180):
    """Nettoie, X secondes apres la fin d'un tournoi, UNIQUEMENT les PDF de cet
    organisateur qui sont ENTIEREMENT VENDUS (epuises). Un PDF qui a encore des
    feuilles invendues est CONSERVE : l'organisateur doit pouvoir vendre le reste
    sur les tournois suivants. Le registre des feuilles vendues reste intact (les
    feuilles deja vendues ne pourront jamais etre revendues, meme fichier efface).
    La liste des fichiers est figee a l'instant de la validation (avant l'attente)."""
    import time
    # 1) FIGER la liste des PDF EPUISES a effacer MAINTENANT (avant d'attendre)
    a_effacer = []
    try:
        d0 = load_data()
        reg = d0.get("feuilles_vendues", {}).get(code_org, {})
        # total de feuilles vendues par l'admin a cet org, par pdf_url
        totaux = {}
        for v in d0.get("ventes", []):
            if (v.get("code_org") or "") == code_org and v.get("pdf_url"):
                totaux[v["pdf_url"]] = totaux.get(v["pdf_url"], 0) + int(v.get("total_feuilles", 0) or 0)
        # pdf_url utilises par cet org
        pdfs_org = set()
        for ticket in d0.get("tickets", []):
            if ticket.get("code_org") == code_org and (ticket.get("pdf_url") or ""):
                pdfs_org.add(ticket["pdf_url"])
        for pdf_url in pdfs_org:
            vendues = len(reg.get(pdf_url, {}))
            total = totaux.get(pdf_url, 0)
            # EPUISE : toutes les feuilles vendues -> on peut nettoyer le fichier
            if total > 0 and vendues >= total:
                pdf_id = pdf_url.split("/")[-1].replace(".pdf", "")
                p = f"/data/pdfs/{pdf_id}.pdf"
                if p not in a_effacer:
                    a_effacer.append(p)
    except Exception as e:
        print(f"[AUTO-EFFACEMENT] preparation impossible: {e}")
        return

    # 2) Attendre le delai (3 minutes par defaut)
    time.sleep(delai_secondes)

    # 3) Effacer SEULEMENT les fichiers figes a l'etape 1
    pdfs_supprimes = []
    for p in a_effacer:
        try:
            if os.path.exists(p):
                os.remove(p)
                pdfs_supprimes.append(p)
        except Exception:
            pass

    # 4) Journaliser
    try:
        global DB
        DB = load_data()
        if "historique_effacement" not in DB:
            DB["historique_effacement"] = []
        DB["historique_effacement"].append({
            "code_org": code_org,
            "date": datetime.datetime.now().isoformat(),
            "nb_pdfs_supprimes": len(pdfs_supprimes),
            "pdfs": pdfs_supprimes
        })
        save_data()
        print(f"[AUTO-EFFACEMENT] {len(pdfs_supprimes)} PDF epuises effaces pour {code_org} (feuilles invendues conservees ailleurs)")
    except Exception as e:
        print(f"[AUTO-EFFACEMENT ERR] {e}")

