@app.route("/api/tournoi/reset", methods=["POST"])
def reset_tournoi():
    """Remet tout à zéro après un tournoi"""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    
    code_org = s["code"]
    
    # 1. Remettre le tirage à zéro (le SIEN uniquement + le global de compatibilité)
    DB["tirage"] = []
    DB["tirage_vitesse"] = 3
    if code_org:
        DB.setdefault("tirages", {})[code_org] = {"boules": [], "vitesse": 3}
    with _TIRAGE_VERROU:
        _TIRAGE_CACHE.clear()
    
    # 2. Effacer TOUTES les alertes bingo
    DB["alertes_bingo"] = []
    
    # 3. NE PLUS JAMAIS EFFACER LES TICKETS (corrige 12/06/2026)
    # Les codes joueurs sont PERMANENTS : le ticket porte le code de connexion de la
    # joueuse et ses pions y sont attaches. Pour le tournoi suivant, l'organisateur
    # REASSIGNE simplement jeu/pages/PDF via "Mes joueurs" — il n'efface rien.
    
    # 4. Effacer les coches/pointages joueurs
    DB["coches"] = {}
    
    # 5. Les ventes (PDFs achetés par l'organisateur) RESTENT INTACTES
    # On efface uniquement les tickets joueurs, pas les achats de l'organisateur
    
    # 6. Commandes tickets pions de ce tournoi :
    #    - VALIDEES : conservees A VIE (traçabilite des achats — correction 10/07/2026)
    #    - EN ATTENTE : la joueuse a DEJA ete debitee mais la vente n'a jamais ete
    #      validee -> REMBOURSEMENT AUTOMATIQUE (10/07/2026). Ses pions reviennent
    #      dans sa poche (reel/bonus selon ce qu'elle avait paye), une trace
    #      "Remboursement" est ecrite pour son releve, et la commande est conservee
    #      au statut "annulee_remboursee" (l'achat et le remboursement se voient tous
    #      les deux : comptabilite equilibree).
    _remb_detail = []
    for c in DB.get("commandes_tickets_pions", []):
        if c.get("code_org") == code_org and c.get("statut") == "en_attente":
            cj = (c.get("code_joueur") or "").upper().strip()
            montant = int(c.get("total_pions", 0) or 0)
            if cj and montant > 0:
                pr = c.get("paye_reel")
                pb = c.get("paye_bonus")
                if pr is None and pb is None:
                    # Ancienne commande (repartition inconnue) : remboursement en
                    # BONUS par prudence (jouable, non retirable en argent).
                    pr, pb = 0, montant
                pr = int(pr or 0)
                pb = int(pb or 0)
                if pr > 0:
                    poche_r = DB.setdefault("pions_joueurs", {}).get(cj, {})
                    _crediter_pions_montant(poche_r, pr)
                    DB["pions_joueurs"][cj] = poche_r
                if pb > 0:
                    poche_b = DB.setdefault("pions_bonus_joueurs", {}).get(cj, {})
                    _crediter_pions_montant(poche_b, pb)
                    DB["pions_bonus_joueurs"][cj] = poche_b
                _remb_detail.append({"code_joueur": cj, "montant": montant})
            c["statut"] = "annulee_remboursee"
            c["remboursee_le"] = datetime.datetime.now().isoformat()
    if _remb_detail:
        DB.setdefault("remboursements_tournoi", []).insert(0, {
            "date": datetime.datetime.now().isoformat(),
            "jeu": "Commande en attente (remise à zéro du tournoi)",
            "code_org": code_org,
            "detail": _remb_detail
        })
    DB["commandes_tickets_pions"] = [c for c in DB.get("commandes_tickets_pions", []) if c.get("code_org") != code_org or c.get("statut") in ("validee", "annulee_remboursee")]
    
    # 7. Supprimer l'annonce du jeu en cours
    DB["annonces_jeux"] = [a for a in DB.get("annonces_jeux", []) if a.get("code_org") != code_org]
    
    # 8. Remettre le micro à zéro
    DB["micro_status"] = {"actif": False, "message": ""}
    
    # NE PAS EFFACER : codes joueurs, codes organisateurs, soldes pions, ventes/PDFs organisateur
    
    save_data()
    print(f"[RESET] Tournoi remis à zéro pour {code_org}")
    return jsonify({"ok": True, "message": "Tournoi remis à zéro !"})

@app.route("/api/bingo/valider", methods=["POST"])
def valider_bingo():
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    d = request.json
    alerte_id = d.get("alerte_id", "")
    statut = d.get("statut", "valide")
    code_org = s["code"]
    
    for a in DB.get("alertes_bingo", []):
        if a["id"] == alerte_id:
            a["statut"] = statut
            break
    
    # Enregistrer la fin du tournoi
    if "tournois_termines" not in DB:
        DB["tournois_termines"] = []
    DB["tournois_termines"].append({
        "code_org": code_org,
        "alerte_id": alerte_id,
        "date_fin": datetime.datetime.now().isoformat(),
        "effacement_prevu": (datetime.datetime.now() + datetime.timedelta(minutes=3)).isoformat()
    })
    save_data()
    
    # Nettoyage automatique SÛR : ~3 minutes apres la fin du tournoi, on efface
    # UNIQUEMENT les PDF entierement vendus (epuises). Les PDF avec des feuilles
    # invendues sont conserves pour les tournois suivants. La liste est figee
    # maintenant, donc un nouveau tournoi lance entre-temps n'est jamais touche.
    if statut == "valide":
        threading.Thread(
            target=effacer_pdfs_apres_tournoi,
            args=(code_org, 180),
            daemon=True
        ).start()
        print(f"[INFO] Gagnant validé pour {code_org} — nettoyage des PDF épuisés dans 3 min")
    
    return jsonify({"ok": True, "message": "Gagnant validé ! Les PDF entièrement vendus seront nettoyés ; ceux qui ont encore des feuilles invendues sont conservés."})

@app.route("/api/tirage", methods=["POST"])
def sauvegarder_tirage():
    global DB
    DB = load_data()
    d = request.json
    org = (d.get("org") or "").upper().strip()
    boules = d.get("boules", [])
    vitesse = d.get("vitesse", 3)
    # 🎯 BRIQUE 3 : chaque tournoi garde SA liste de boules
    if org:
        DB.setdefault("tirages", {})[org] = {"boules": boules, "vitesse": vitesse}
    # Compatibilité : les anciens écrans (pas encore rechargés) lisent le global
    DB["tirage"] = boules
    DB["tirage_vitesse"] = vitesse
    save_data()
    _val = {"boules": boules, "vitesse": vitesse, "ts": _time_cache.time()}
    with _TIRAGE_VERROU:
        _TIRAGE_CACHE[org or ""] = dict(_val)
        if org:
            _TIRAGE_CACHE[""] = dict(_val)
    return jsonify({"ok": True})

@app.route("/api/tirage")
def get_tirage():
    org = (request.args.get("org") or "").upper().strip()
    cle = org or ""
    maintenant = _time_cache.time()
    with _TIRAGE_VERROU:
        c = _TIRAGE_CACHE.get(cle)
        if c and (maintenant - c["ts"]) < _CACHE_LEGER_TTL:
            return jsonify({"boules": c["boules"], "vitesse": c["vitesse"]})
    _d = load_data()
    if org:
        t = _d.get("tirages", {}).get(org)
        if t is None:
            # Tournoi sans tirage propre (transition) -> retomber sur le global
            t = {"boules": _d.get("tirage", []), "vitesse": _d.get("tirage_vitesse", 3)}
    else:
        t = {"boules": _d.get("tirage", []), "vitesse": _d.get("tirage_vitesse", 3)}
    val = {"boules": t.get("boules", []), "vitesse": t.get("vitesse", 3), "ts": maintenant}
    with _TIRAGE_VERROU:
        _TIRAGE_CACHE[cle] = val
        return jsonify({"boules": val["boules"], "vitesse": val["vitesse"]})

@app.route("/api/verifier-bingo", methods=["POST"])
def verifier_bingo_auto():
    """Vérifie automatiquement si un ticket est gagnant"""
    global DB
    DB = load_data()
    d = request.json
    ticket_id = d.get("ticket_id", "")
    
    # Récupérer le ticket
    ticket = next((t for t in DB["tickets"] if t["id"] == ticket_id), None)
    if not ticket:
        return jsonify({"ok": False, "msg": "Ticket introuvable"}), 404
    
    # Récupérer les boules tirées
    boules_tirees = DB.get("tirage", [])
    
    # Récupérer les numéros cochés par le joueur
    coches = d.get("coches", [])
    
    if not coches:
        return jsonify({"ok": True, "valide": False, "msg": "Aucun numéro coché", "details": []})
    
    # Vérifier chaque numéro coché
    details = []
    tous_valides = True
    for num in coches:
        est_sorti = int(num) in boules_tirees
        details.append({"numero": num, "sorti": est_sorti})
        if not est_sorti:
            tous_valides = False
    
    return jsonify({
        "ok": True,
        "valide": tous_valides,
        "coches": len(coches),
        "valides": sum(1 for d in details if d["sorti"]),
        "details": details,
        "boules_tirees": len(boules_tirees)
    })

@app.route("/api/proxy-pdf")
def proxy_pdf():
    """Proxy pour servir les PDFs depuis Cloudinary"""
    try:
        url = request.args.get("url", "")
        if not url or "cloudinary.com" not in url:
            return jsonify({"ok": False}), 400
        req = urllib.request.Request(url)
        resp = urllib.request.urlopen(req, timeout=30)
        data = resp.read()
        return Response(data, content_type="application/pdf", headers={
            "Access-Control-Allow-Origin": "*",
            "Content-Disposition": "inline",
            "Cache-Control": "public, max-age=3600"
        })
    except Exception as e:
        print(f"[PROXY ERR] {e}")
        return jsonify({"ok": False}), 500

