@app.route("/api/annonce/jeu", methods=["POST", "DELETE"])
def gerer_annonce_jeu():
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False}), 403
    
    if "annonces_jeux" not in DB:
        DB["annonces_jeux"] = []
    
    if request.method == "DELETE":
        code_org = request.json.get("code_org", "")
        DB["annonces_jeux"] = [a for a in DB["annonces_jeux"] if a.get("code_org") != code_org]
        save_data()
        return jsonify({"ok": True})
    
    d = request.json
    # Supprimer l'ancienne annonce de cet organisateur
    DB["annonces_jeux"] = [a for a in DB["annonces_jeux"] if a.get("code_org") != s["code"]]
    
    annonce = {
        "id": secrets.token_hex(4).upper(),
        "code_org": s["code"],
        "nom_org": s.get("nom", s["code"]),
        "jeu": d.get("jeu", ""),
        "prix": int(d.get("prix", 0)),
        "desc": d.get("desc", ""),
        "ventes_ouvertes": True,
        "date": datetime.datetime.now().isoformat()
    }
    DB["annonces_jeux"].insert(0, annonce)
    # Photo "tout est propre" AUTOMATIQUE juste avant le jeu (aucune action manuelle).
    try:
        creer_sauvegarde_horodatee("avant-jeu")
    except Exception:
        pass
    save_data()
    return jsonify({"ok": True})

@app.route("/api/annonce/jeux")
def get_annonces_jeux():
    global DB
    DB = load_data()
    annonces = DB.get("annonces_jeux", [])
    codes = DB.get("codes", {})

    # 1) SECURITE : ne garder que les annonces d'organisateurs ACTIFS.
    #    Quand un ancien organisateur est desactive, son annonce disparait
    #    automatiquement de tous les espaces (plus de jeu fantome a rembourser).
    def _org_actif(a):
        info = codes.get(a.get("code_org"))
        return bool(info and info.get("actif"))
    annonces = [a for a in annonces if _org_actif(a)]

    # 2) Toutes les joueuses voient TOUS les jeux des organisatrices ACTIVES.
    #    Cloisonnement par organisatrice DÉSACTIVÉ (à la demande de l'admin) :
    #    une joueuse peut participer aux tournois de n'importe quelle organisatrice
    #    active, y compris une nouvelle arrivée. Le paramètre "code" reste accepté
    #    mais ne restreint plus l'affichage.
    return jsonify(annonces)

@app.route("/api/annonce/ventes", methods=["POST"])
def annonce_ventes():
    """ORGANISATEUR — Ouvre ou ferme les ventes de son jeu annonce.
    Quand c'est ferme, plus aucune joueuse ne peut commander (bloque cote serveur)."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    d = request.get_json(silent=True) or {}
    ouvertes = bool(d.get("ouvertes", False))
    trouve = False
    for a in DB.get("annonces_jeux", []):
        if a.get("code_org") == s["code"]:
            a["ventes_ouvertes"] = ouvertes
            trouve = True
            break  # une seule annonce active par organisateur
    if not trouve:
        return jsonify({"ok": False, "msg": "Aucun jeu annoncé à clôturer."}), 404
    save_data()
    return jsonify({"ok": True, "ventes_ouvertes": ouvertes})

@app.route("/api/commande/ticket-pions", methods=["POST"])
def commander_ticket_pions():
    global DB
    DB = load_data()
    d = request.json
    code_joueur = d.get("code_joueur", "").upper()
    # NEUTRALISATION (13/07/2026) : un compte du reseau de fraude reactive mais
    # neutralise peut consulter son releve, mais ne peut plus jouer.
    if code_joueur in set((x or "").upper() for x in DB.get("comptes_neutralises", [])):
        return jsonify({"ok": False, "msg": "Ce compte est en lecture seule et ne peut plus participer aux jeux."}), 403
    jeu = d.get("jeu", "")
    prix = int(d.get("prix", 0))
    nb_tickets = int(d.get("nb_tickets", 1))
    total = int(d.get("total", 0))
    code_org = d.get("code_org", "")

    # === BLOCAGE VENTES FERMEES (avant tout debit de pions) ===
    # Si l'organisateur a cloture la vente de ce jeu, on refuse la commande
    # AVANT de toucher aux pions : la joueuse ne paie donc jamais pour rien.
    for a in DB.get("annonces_jeux", []):
        if a.get("code_org") == code_org and (a.get("jeu", "") or "") == jeu:
            if a.get("ventes_ouvertes") is False:
                return jsonify({"ok": False, "msg": "🛑 Les ventes de ce jeu sont fermées par l'organisateur. Aucun pion n'a été débité."}), 400
            break

    # === SOLDE = pions réels (retirables) + bonus (jouables, NON retirables) ===
    pions_joueur = DB.get("pions_joueurs", {}).get(code_joueur, {})
    pions_bonus = DB.get("pions_bonus_joueurs", {}).get(code_joueur, {})
    solde_reel = _xpf_total_pions(pions_joueur)
    solde_bonus = _xpf_total_pions(pions_bonus)
    solde_total = solde_reel + solde_bonus

    if solde_total < total:
        return jsonify({"ok": False, "msg": f"Solde insuffisant — vous avez {solde_total} XPF de pions, il faut {total} XPF"}), 400

    # On dépense le BONUS d'abord (le crédit gratuit se consomme en jouant),
    # puis les pions réels pour le reste. Copies + validation uniquement si les
    # deux débits réussissent (anti-incohérence).
    reel_copie = dict(pions_joueur)
    bonus_copie = dict(pions_bonus)
    montant_bonus = min(solde_bonus, total)
    if montant_bonus > 0 and not _debiter_pions_montant(bonus_copie, montant_bonus):
        return jsonify({"ok": False, "msg": "Solde insuffisant en pions"}), 400
    montant_reel = total - montant_bonus
    if montant_reel > 0 and not _debiter_pions_montant(reel_copie, montant_reel):
        return jsonify({"ok": False, "msg": "Solde insuffisant en pions"}), 400

    DB.setdefault("pions_joueurs", {})[code_joueur] = reel_copie
    DB.setdefault("pions_bonus_joueurs", {})[code_joueur] = bonus_copie
    
    # Créditer les pions à l'organisateur
    if "pions_org" not in DB:
        DB["pions_org"] = {}
    if code_org not in DB["pions_org"]:
        DB["pions_org"][code_org] = {}
    
    # Enregistrer la commande ticket
    if "commandes_tickets_pions" not in DB:
        DB["commandes_tickets_pions"] = []
    
    commande = {
        "id": secrets.token_hex(4).upper(),
        "code_joueur": code_joueur,
        "code_org": code_org,
        "jeu": jeu,
        "prix": prix,
        "nb_tickets": nb_tickets,
        "total_pions": total,
        "paye_bonus": montant_bonus,
        "paye_reel": montant_reel,
        "statut": "en_attente",
        "date": datetime.datetime.now().isoformat()
    }
    DB["commandes_tickets_pions"].insert(0, commande)

    # === BONUS PAR JEU : 5 tickets d'un jeu => bonus de ce jeu (jouable, NON
    # retirable). 1 fois par jeu et par joueur. P6 -> 500 F, OHANA -> 5000 F. ===
    try:
        jeu_up = (jeu or "").upper()
        bonus_jeu = 0
        if "P6" in jeu_up:
            bonus_jeu = 500
        elif "OHANA" in jeu_up:
            bonus_jeu = 5000
        if bonus_jeu > 0:
            compteur = DB.setdefault("tickets_par_jeu_joueur", {})
            cle = code_joueur + "|" + (jeu or "")
            compteur[cle] = int(compteur.get(cle, 0)) + int(nb_tickets)
            deja = DB.setdefault("bonus_jeu_donne", [])
            if compteur[cle] >= 5 and cle not in deja:
                poche_bonus = DB.setdefault("pions_bonus_joueurs", {}).get(code_joueur, {})
                _crediter_pions_montant(poche_bonus, bonus_jeu)
                DB["pions_bonus_joueurs"][code_joueur] = poche_bonus
                deja.append(cle)
                commande["bonus_jeu"] = bonus_jeu
    except Exception:
        pass

    save_data(immediat=True)
    return jsonify({"ok": True, "commande_id": commande["id"], "bonus_jeu": commande.get("bonus_jeu", 0)})

