@app.route("/liste-comptes-bloques")
def liste_comptes_bloques():
    """LISTE (13/07/2026) : affiche tous les comptes bloques avec leur nom, solde
    (poche + bonus), IP, et un indicateur s'ils font partie du reseau de fraude
    VAHINE connu. Sert a preparer la reactivation : distinguer les fraudeurs
    (a vider + neutraliser) des comptes a reactiver normalement. ?cle=ADMIN"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")

    bloques = [b for b in DB.get("codes_bloques", []) if b]
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    # reseau de fraude VAHINE connu
    reseau = {"RT50CJ", "UURZ4Y", "397LAI", "JKNTZY", "H1I5G9"}
    ip_de = {}
    for j in DB.get("journal_connexions", []):
        cj = (j.get("code") or "").upper().strip()
        ipj = (j.get("ip") or "").strip()
        if cj and ipj:
            ip_de.setdefault(cj, set()).add(ipj)

    def fmt(n): return format(n, ",")

    lignes = []
    total_solde_bloques = 0
    for b in bloques:
        cb = (b or "").upper()
        poche = _xpf_total_pions(DB.get("pions_joueurs", {}).get(cb, {}))
        bonus = _xpf_total_pions(DB.get("pions_bonus_joueurs", {}).get(cb, {}))
        total = poche + bonus
        total_solde_bloques += total
        est_reseau = cb in reseau
        ips = sorted(ip_de.get(cb, set()))
        lignes.append((cb, nomde(cb), poche, bonus, total, est_reseau, ips))
    lignes.sort(key=lambda r: (not r[5], -r[4]))

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Comptes bloques</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:920px;margin:0 auto}"
    html += "h1{color:#C00000;border-bottom:3px solid #C00000;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:7px;text-align:left}td{border:1px solid #bbb;padding:6px}"
    html += ".dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".fraude{background:#FDECEA;color:#C00000;font-weight:bold}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128683; Comptes bloques — vue d'ensemble</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(len(bloques)) + " comptes bloques</div>"
    html += "<p style='font-size:14px'>Liste de tous les comptes actuellement bloques. Les lignes en rouge appartiennent au reseau de fraude VAHINE connu. Utilise cette liste pour decider lesquels vider/neutraliser (fraudeurs) et lesquels reactiver normalement.</p>"

    html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Poche</th><th class='dr'>Bonus</th><th class='dr'>Total</th><th>Reseau ?</th><th>IP</th></tr>"
    for (cb, nom, poche, bonus, total, est_reseau, ips) in lignes:
        cls = "fraude" if est_reseau else ""
        html += "<tr class='" + cls + "'><td><b>" + cb + "</b></td><td>" + (nom or "—") + "</td><td class='dr'>" + fmt(poche) + "</td><td class='dr'>" + fmt(bonus) + "</td><td class='dr'>" + fmt(total) + " F</td><td>" + ("&#9888;&#65039; OUI" if est_reseau else "non") + "</td><td style='font-size:10px'>" + (", ".join(ips[:2]) if ips else "—") + "</td></tr>"
    html += "<tr style='background:#EEE;font-weight:bold'><td colspan='4' style='text-align:right'>TOTAL des soldes bloques</td><td class='dr'>" + fmt(total_solde_bloques) + " F</td><td colspan='2'></td></tr>"
    html += "</table>"

    html += "<div class='meta' style='margin-top:14px;font-size:14px'>&#128161; Prochaine etape : dis-moi quels codes sont des <b>fraudeurs</b> (a vider + neutraliser) et lesquels sont a <b>reactiver normalement</b>. Les lignes rouges (reseau VAHINE) sont les candidates evidentes pour la neutralisation.</div>"
    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/impact-complice-caisse")
def impact_complice_caisse():
    """ANALYSE IMPACT (13/07/2026) : calcule l'impact d'un ou plusieurs comptes
    complices sur la caisse d'une organisatrice. Pour chaque complice : ce que
    l'org a 'encaisse' de lui (mises sur tickets) vs ce que l'org lui a 'donne'
    (gains payes + pions recharges). Si l'org lui a donne plus qu'il n'a paye,
    la difference est sortie de la caisse -> explique une partie de l'ecart.
    ?cle=ADMIN&org=CODE&complices=A,B,C"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    complices_param = (request.args.get("complices", "") or "").strip().upper()
    if not org or not complices_param:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE&complices=A,B,C</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes_org = set([org] + ([aussi] if aussi else []))
    complices = [c.strip() for c in complices_param.split(",") if c.strip()]
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    def fmt(n): return format(n, ",")

    resultats = []
    total_encaisse_complices = 0
    total_donne_complices = 0
    for cx in complices:
        # Ce que l'org a "encaisse" de ce complice (mises sur tickets)
        encaisse = 0
        for e in DB.get("encaissements_org", []):
            if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes_org and (e.get("code_joueur", "") or "").upper() == cx:
                encaisse += _iv(e.get("montant", 0))
        # Ce que l'org a paye en GAINS a ce complice
        gains = 0
        for g in DB.get("gains_finaux", []):
            if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes_org and (g.get("code_gagnant", "") or "").upper() == cx and not g.get("annule"):
                gains += _iv(g.get("montant_credite", 0))
        # Ce que l'org lui a distribue en PIONS (recharges)
        recharges = 0
        for t in DB.get("transactions_joueur_org", []):
            if isinstance(t, dict) and (t.get("code_org", "") or "").upper() in codes_org and (t.get("code_joueur", "") or "").upper() == cx:
                recharges += _iv(t.get("montant_total", 0))
        donne = gains + recharges
        impact = donne - encaisse  # ce qui est sorti net de la caisse pour ce complice
        total_encaisse_complices += encaisse
        total_donne_complices += donne
        resultats.append((cx, encaisse, gains, recharges, donne, impact))

    impact_total = total_donne_complices - total_encaisse_complices

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Impact complices</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:880px;margin:0 auto}"
    html += "h1{color:#C00000;border-bottom:3px solid #C00000;padding-bottom:8px}h2{color:#1F4E79;margin-top:20px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:13px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:8px;text-align:left}td{border:1px solid #bbb;padding:7px}"
    html += ".dr{text-align:right;font-weight:bold;white-space:nowrap}.neg{color:#C00000}"
    html += ".sect{background:#FDECEA;font-weight:bold;color:#C00000}.big{font-size:16px}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128200; Impact des comptes complices sur la caisse — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + "</div>"
    html += "<p style='font-size:14px'>Pour chaque complice : ce que l'org a <b>encaisse</b> de lui (ses mises) vs ce qu'elle lui a <b>donne</b> (gains + recharges de pions). Si l'org a donne plus qu'encaisse, la difference est sortie de sa caisse.</p>"

    html += "<table><tr><th>Complice</th><th class='dr'>Encaisse (ses mises)</th><th class='dr'>Gains recus</th><th class='dr'>Pions recharges</th><th class='dr'>Total donne</th><th class='dr'>Impact caisse</th></tr>"
    for (cx, encaisse, gains, recharges, donne, impact) in resultats:
        html += "<tr><td>" + cx + (" — " + nomde(cx) if nomde(cx) else "") + "</td>"
        html += "<td class='dr'>" + fmt(encaisse) + " F</td><td class='dr'>" + fmt(gains) + " F</td><td class='dr'>" + fmt(recharges) + " F</td>"
        html += "<td class='dr'>" + fmt(donne) + " F</td><td class='dr neg'>-" + fmt(impact) + " F</td></tr>"
    html += "<tr class='sect'><td>TOTAL</td><td class='dr'>" + fmt(total_encaisse_complices) + " F</td><td class='dr'>-</td><td class='dr'>-</td><td class='dr'>" + fmt(total_donne_complices) + " F</td><td class='dr big'>-" + fmt(impact_total) + " F</td></tr>"
    html += "</table>"

    html += "<div class='warn'>&#9888;&#65039; <b>Lecture :</b> l'impact caisse = ce que l'org a donne a ses complices MOINS ce qu'ils ont vraiment paye. "
    html += "Ces comptes ont recu <b>" + fmt(total_donne_complices) + " F</b> (gains + recharges) de la caisse de l'org, mais n'ont mise que <b>" + fmt(total_encaisse_complices) + " F</b>. "
    html += "La difference de <b>" + fmt(impact_total) + " F</b> est sortie de la caisse au profit des complices &mdash; ce qui explique une partie de l'ecart constate.</div>"

    html += "<h2>Rappel de l'ecart</h2>"
    html += "<div class='meta' style='font-size:14px'>Ecart constate dans la caisse de VAHINE : <b>78 360 F</b>.<br>"
    html += "Impact des complices calcule ci-dessus : <b>" + fmt(impact_total) + " F</b>.<br>"
    if abs(impact_total - 78360) < 15000:
        html += "&#9989; Ces montants sont proches : l'ecart s'explique en grande partie par les gains et recharges verses aux comptes complices."
    else:
        html += "Difference restante a expliquer : <b>" + fmt(78360 - impact_total) + " F</b> (autres pistes : deblock, CCP...)."
    html += "</div>"

    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/reconstitution-caisse-org")
def reconstitution_caisse_org():
    """RECONSTITUTION (13/07/2026) : reconstitue la caisse d'une organisatrice pour
    retrouver l'origine d'un ecart. Additionne TOUTES les entrees (ventes pions +
    mises tickets) et TOUTES les sorties (gains, remboursements, recharges de
    joueuses, retraits CCP/especes, corrections, transferts) pour voir ou est parti
    chaque franc. ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    # === ENTREES ===
    ventes_pions = 0
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_org", "") or "").upper() in codes:
            ventes_pions += _iv(t.get("montant_total", 0))
    mises_tickets = 0
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes:
            mises_tickets += _iv(e.get("montant", 0))
    total_entrees = ventes_pions + mises_tickets

    # === SORTIES ===
    gains = 0
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes and not g.get("annule"):
            gains += _iv(g.get("montant_credite", 0))
    remb = 0
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict) and (rb.get("code_org", "") or "").upper() in codes:
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    remb += _iv(det.get("montant", 0))

    # Recharges de joueuses = ventes de pions (deja comptees en entree mais elles
    # SORTENT de la poche org... non : quand l'org vend des pions, elle recoit l'argent
    # et donne des pions. Le montant_total est l'argent recu. Neutre pour la caisse.)
    # Mais les DEBLOCK sans paiement especes sont a part :
    deblock = 0
    especes_ventes = 0
    ccp_ventes = 0
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_org", "") or "").upper() in codes:
            mode = str(t.get("mode_paiement", "") or "").lower()
            m = _iv(t.get("montant_total", 0))
            if "deblock" in mode or "débloc" in mode:
                deblock += m
            elif "espèce" in mode or "especes" in mode or "cash" in mode:
                especes_ventes += m
            elif "ccp" in mode or "virement" in mode:
                ccp_ventes += m

    # Transferts sortants de la poche org (nos outils)
    transf_poche_sortants = 0
    for t in DB.get("transferts_poche_org", []):
        if isinstance(t, dict) and (t.get("de", "") or "").upper() in codes:
            transf_poche_sortants += _iv(t.get("montant", 0))

    # Corrections/retraits sur le compte org (si servi de joueuse)
    corrections_org = 0
    retraits_ccp = 0
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() in codes:
            m = _iv(c.get("montant_retire", 0))
            if "ccp" in str(c.get("motif", "") or "").lower():
                retraits_ccp += m
            else:
                corrections_org += m

    poche_reelle = 0
    for c in codes:
        poche_reelle += _xpf_total_pions(DB.get("pions_org", {}).get(c, {}))

    total_sorties = gains + remb
    solde_theorique = total_entrees - total_sorties
    ecart = solde_theorique - poche_reelle

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Reconstitution caisse</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:820px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:20px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:14px;margin:10px 0}"
    html += "td{border:1px solid #ccc;padding:8px}.dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".sect{background:#E8EEF6;font-weight:bold;color:#1F4E79}.big{font-size:16px}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;border-radius:10px;padding:14px;margin:12px 0}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#129518; Reconstitution de la caisse — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + "</div>"

    html += "<h2>Entrees</h2><table>"
    html += "<tr><td>Ventes de pions aux joueuses</td><td class='dr'>+" + fmt(ventes_pions) + " F</td></tr>"
    html += "<tr><td>Mises de tickets encaissees (100% credite a la poche)</td><td class='dr'>+" + fmt(mises_tickets) + " F</td></tr>"
    html += "<tr class='sect'><td>TOTAL ENTREES</td><td class='dr big'>+" + fmt(total_entrees) + " F</td></tr></table>"

    html += "<h2>Sorties (gains et remboursements)</h2><table>"
    html += "<tr><td>Gains payes aux gagnantes</td><td class='dr'>-" + fmt(gains) + " F</td></tr>"
    html += "<tr><td>Remboursements</td><td class='dr'>-" + fmt(remb) + " F</td></tr>"
    html += "<tr class='sect'><td>TOTAL SORTIES</td><td class='dr big'>-" + fmt(total_sorties) + " F</td></tr></table>"

    html += "<h2>Solde theorique vs reel</h2><table>"
    html += "<tr><td>Solde theorique (entrees - sorties)</td><td class='dr'>" + fmt(solde_theorique) + " F</td></tr>"
    html += "<tr><td>Caisse reelle (poche)</td><td class='dr'>" + fmt(poche_reelle) + " F</td></tr>"
    html += "<tr class='sect'><td>ECART A EXPLIQUER</td><td class='dr big'>" + fmt(ecart) + " F</td></tr></table>"

    html += "<h2>Pistes pour expliquer l'ecart</h2>"
    html += "<table>"
    html += "<tr><td>Pions distribues en DEBLOCK (virement/avance, pas especes directes)</td><td class='dr'>" + fmt(deblock) + " F</td></tr>"
    html += "<tr><td>Pions distribues par VIREMENT CCP</td><td class='dr'>" + fmt(ccp_ventes) + " F</td></tr>"
    html += "<tr><td>Pions distribues en ESPECES</td><td class='dr'>" + fmt(especes_ventes) + " F</td></tr>"
    html += "<tr><td>Retraits CCP traces sur le compte</td><td class='dr'>" + fmt(retraits_ccp) + " F</td></tr>"
    html += "<tr><td>Transferts sortants de poche org</td><td class='dr'>" + fmt(transf_poche_sortants) + " F</td></tr>"
    html += "<tr><td>Autres corrections sur le compte</td><td class='dr'>" + fmt(corrections_org) + " F</td></tr>"
    html += "</table>"

    somme_pistes = deblock + retraits_ccp
    html += "<div class='warn'>&#9888;&#65039; <b>Analyse de l'ecart de " + fmt(ecart) + " F :</b><br><br>"
    html += "Le mode de distribution des pions eclaire l'ecart. Quand VAHINE distribuait des pions en <b>deblock</b> (" + fmt(deblock) + " F) ou <b>virement CCP</b> (" + fmt(ccp_ventes) + " F), l'argent correspondant allait potentiellement sur son compte bancaire personnel (CCP), et non dans sa caisse-plateforme. "
    html += "Ces pions ont ete <b>joues</b> par les joueuses (donc comptes comme mises encaissees a 100%), mais la contrepartie en argent n'est jamais entree dans la poche-systeme &mdash; elle est sur son CCP. "
    html += "Cela explique pourquoi le theorique (qui compte tout) depasse la caisse-systeme reelle.</div>"

    html += "<div class='ok'>&#128161; <b>Conclusion :</b> l'ecart ne signifie pas forcement de l'argent vole. Une partie correspond aux paiements recus par VAHINE hors especes (deblock, CCP), qui alimentaient son compte bancaire au lieu de la caisse-systeme. Pour confirmer le montant exact, il faut comparer avec son releve CCP reel.</div>"

    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/distributions-pions-org")
def distributions_pions_org():
    """ANALYSE DISTRIBUTIONS (13/07/2026) : liste tous les pions que l'organisatrice
    a distribues a ses joueuses, repartis par MODE DE PAIEMENT. Distingue ce qui a
    ete PAYE par la joueuse (especes, virement...) de ce qui a pu etre offert/deblock.
    Permet de voir si l'org a distribue des pions gratuits (cadeaux/fraude) ou si
    tout correspond a des paiements. ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    # Toutes les distributions org -> joueur
    par_mode = {}
    par_joueuse = {}
    total = 0
    nb = 0
    lignes = []
    for t in DB.get("transactions_joueur_org", []):
        if not isinstance(t, dict) or (t.get("code_org", "") or "").upper() not in codes:
            continue
        mode = str(t.get("mode_paiement", "") or "?").strip() or "?"
        m = _iv(t.get("montant_total", 0))
        cj = (t.get("code_joueur", "") or "").upper()
        par_mode[mode] = par_mode.get(mode, 0) + m
        par_joueuse[cj] = par_joueuse.get(cj, 0) + m
        total += m
        nb += 1
        lignes.append((str(t.get("date", "")), cj, mode, m))

    # Encaissements tickets (pour comparaison)
    total_encaisse_tickets = 0
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes:
            total_encaisse_tickets += _iv(e.get("montant", 0))

    def fmt(n): return format(n, ",")

    # Modes consideres "payes" vs "gratuits/deblock"
    modes_payes = ["espèces", "especes", "virement", "carte", "cash", "ccp", "bt"]
    total_paye = sum(v for k, v in par_mode.items() if any(mp in k.lower() for mp in modes_payes))
    total_deblock = sum(v for k, v in par_mode.items() if "deblock" in k.lower() or "débloc" in k.lower())
    total_autre = total - total_paye - total_deblock

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Distributions pions org</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:860px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:22px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:13px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:8px;text-align:left}td{border:1px solid #bbb;padding:7px}"
    html += ".dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".sect{background:#E8EEF6;font-weight:bold;color:#1F4E79}.big{font-size:16px}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;border-radius:10px;padding:14px;margin:12px 0}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#127920; Distributions de pions — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(nb) + " distributions</div>"
    html += "<p style='font-size:14px'>Tous les pions que l'organisatrice a distribues a ses joueuses, par mode de paiement. Objectif : verifier si les distributions correspondent a des paiements (normal) ou a des pions offerts.</p>"

    html += "<h2>Repartition par mode de paiement</h2>"
    html += "<table><tr><th>Mode de paiement</th><th class='dr'>Montant distribue</th></tr>"
    for mode, m in sorted(par_mode.items(), key=lambda x: -x[1]):
        html += "<tr><td>" + mode + "</td><td class='dr'>" + fmt(m) + " F</td></tr>"
    html += "<tr class='sect'><td>TOTAL DISTRIBUE</td><td class='dr big'>" + fmt(total) + " F</td></tr>"
    html += "</table>"

    html += "<h2>Analyse</h2>"
    html += "<table>"
    html += "<tr><td>Distribue contre PAIEMENT (especes, virement...)</td><td class='dr'>" + fmt(total_paye) + " F</td></tr>"
    if total_deblock:
        html += "<tr><td>Distribue en DEBLOCK (pions debloques)</td><td class='dr'>" + fmt(total_deblock) + " F</td></tr>"
    if total_autre:
        html += "<tr><td>Autre / non classe</td><td class='dr'>" + fmt(total_autre) + " F</td></tr>"
    html += "</table>"

    # Interpretation
    if total_deblock > 0:
        html += "<div class='warn'>&#9888;&#65039; <b>" + fmt(total_deblock) + " F</b> ont ete distribues en mode &laquo; deblock &raquo; (pions debloques). Selon ton fonctionnement, le deblock peut etre : soit des pions payes autrement, soit des pions avances. A verifier si ces pions ont bien ete payes par les joueuses.</div>"
    else:
        html += "<div class='ok'>&#9989; Toutes les distributions correspondent a des modes de paiement classiques. Aucune distribution &laquo; deblock &raquo; suspecte.</div>"

    html += "<div class='meta' style='margin-top:12px;font-size:14px'>Pour rappel : total encaisse en tickets par l'org = <b>" + fmt(total_encaisse_tickets) + " F</b>. Total distribue en pions = <b>" + fmt(total) + " F</b>. Les joueuses achetent des pions (distribution) puis les jouent en tickets (encaissement) : les deux montants sont lies mais pas identiques (une partie des pions vient aussi des gains).</div>"

    html += "<h2>Detail des distributions les plus importantes</h2>"
    gros = sorted(par_joueuse.items(), key=lambda x: -x[1])[:15]
    html += "<table><tr><th>Joueuse</th><th>Code</th><th class='dr'>Total pions recus de l'org</th></tr>"
    for cj, m in gros:
        html += "<tr><td>" + (nomde(cj) or "—") + "</td><td>" + cj + "</td><td class='dr'>" + fmt(m) + " F</td></tr>"
    html += "</table>"

    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/audit-joueuses-tournoi")
def audit_joueuses_tournoi():
    """AUDIT PAR JOUEUSE (13/07/2026) : pour chaque joueuse ayant participe au
    tournoi d'une organisatrice, compare ce qu'elle a REELLEMENT paye en tickets
    (encaissements a l'org) avec ses ENTREES de pions (achats + credits + gains
    recus). Objectif : reperer les joueuses qui ont joue BEAUCOUP plus que ce
    qu'elles ont mis / recu &mdash; signe possible de jeux non debites (temoignages
    'j'ai paye mais mes pions n'ont pas baisse'). ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes_org = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    # Par joueuse : total tickets payes chez cette org (= ce qu'elle a joue)
    joue = {}
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes_org:
            cj = (e.get("code_joueur", "") or "").upper()
            joue[cj] = joue.get(cj, 0) + _iv(e.get("montant", 0))

    # Par joueuse : entrees de pions (achats valides + credits admin + pions recus org + gains)
    entrees = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            cj = (c.get("code_joueur", "") or "").upper()
            m = _iv(c.get("montant_net", 0)) or _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))
            entrees[cj] = entrees.get(cj, 0) + m
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict):
            cj = (t.get("code_joueur", "") or "").upper()
            entrees[cj] = entrees.get(cj, 0) + _iv(t.get("montant_total", 0))
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            cj = (c.get("code_joueur", "") or "").upper()
            m = _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))
            if m > 0:
                entrees[cj] = entrees.get(cj, 0) + m
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and not g.get("annule"):
            cj = (g.get("code_gagnant", "") or "").upper()
            entrees[cj] = entrees.get(cj, 0) + _iv(g.get("montant_credite", 0))

    # Analyse : joueuses qui ont JOUE plus que leurs entrees (signe de jeux non debites)
    lignes = []
    for cj, total_joue in joue.items():
        ent = entrees.get(cj, 0)
        # ratio : joue vs entrees. Si joue >> entrees, suspect.
        ecart = total_joue - ent
        lignes.append((cj, total_joue, ent, ecart))
    # trier par ecart decroissant (les plus suspectes en haut)
    lignes.sort(key=lambda r: -r[3])

    def fmt(n): return format(n, ",")

    total_joue_all = sum(r[1] for r in lignes)
    total_ent_all = sum(r[2] for r in lignes)
    nb_suspectes = sum(1 for r in lignes if r[3] > 500)
    total_ecart_positif = sum(r[3] for r in lignes if r[3] > 0)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Audit joueuses tournoi</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:22px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:7px;text-align:left}td{border:1px solid #bbb;padding:6px}"
    html += ".dr{text-align:right;white-space:nowrap;font-weight:bold}"
    html += ".sus{background:#FFF4E5}.tres{background:#FDECEA;color:#C00000;font-weight:bold}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128270; Audit des joueuses — tournoi " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(len(lignes)) + " joueuses</div>"
    html += "<p style='font-size:14px'>Pour chaque joueuse : ce qu'elle a <b>joue</b> (tickets payes chez l'org) compare a ses <b>entrees de pions</b> (achats + credits + gains). Si une joueuse a joue BEAUCOUP plus que ses entrees, cela peut indiquer des jeux valides sans debit reel de ses pions.</p>"

    html += "<table><tr><th>Joueuse</th><th>Code</th><th class='dr'>A joue (tickets)</th><th class='dr'>Entrees pions</th><th class='dr'>Ecart</th></tr>"
    for (cj, total_joue, ent, ecart) in lignes:
        cls = "tres" if ecart > 20000 else ("sus" if ecart > 500 else "")
        html += "<tr class='" + cls + "'><td>" + (nomde(cj) or "—") + "</td><td>" + cj + "</td><td class='dr'>" + fmt(total_joue) + " F</td><td class='dr'>" + fmt(ent) + " F</td><td class='dr'>" + ("+" if ecart > 0 else "") + fmt(ecart) + " F</td></tr>"
    html += "</table>"

    html += "<h2>Synthese</h2>"
    html += "<div class='meta' style='font-size:14px'>Total joue (tous) : <b>" + fmt(total_joue_all) + " F</b> &middot; Total entrees pions : <b>" + fmt(total_ent_all) + " F</b><br>"
    html += "Joueuses ayant joue plus que leurs entrees : <b>" + str(nb_suspectes) + "</b> &middot; Ecart positif cumule : <b>" + fmt(total_ecart_positif) + " F</b></div>"
    html += "<div style='background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin-top:10px;font-size:14px'>"
    html += "&#9888;&#65039; <b>Lecture :</b> un ecart positif important signifie qu'une joueuse a joue plus de tickets que ce que ses entrees de pions justifient. "
    html += "Cela peut correspondre aux temoignages (jeux payes sans debit de pions). Attention : un petit ecart peut aussi venir de pions bonus, de reports, ou de l'ordre des operations. Les lignes en rouge (ecart > 20 000 F) meritent une verification du releve detaille.</div>"
    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/audit-ecart-pions")
def audit_ecart_pions():
    """AUDIT ECART (13/07/2026) : cherche l'origine de l'ecart de caisse d'une
    organisatrice. Compare, pour son tournoi : le total des mises encaissees
    (encaissements_org) vs le total reellement debite des pions des joueuses
    (commandes_tickets_pions validees). Si des mises ont ete encaissees SANS
    debit de pions correspondant (ou l'inverse), ca revele l'ecart : des jeux
    encaisses en direct/especes sans passer par le systeme, ou des bugs de debit.
    ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    # 1. Total ENCAISSE (mises creditees a l'org) via encaissements_org
    total_encaisse = 0
    nb_encaiss = 0
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes:
            total_encaisse += _iv(e.get("montant", 0))
            nb_encaiss += 1

    # 2. Total des commandes de tickets VALIDEES (ce qui aurait du etre debite des joueuses)
    total_commandes_validees = 0
    nb_cmd_validees = 0
    total_commandes_non_validees = 0
    nb_cmd_non_val = 0
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and (c.get("code_org", "") or "").upper() in codes:
            m = _iv(c.get("total_pions", 0))
            if c.get("statut") == "validee":
                total_commandes_validees += m
                nb_cmd_validees += 1
            else:
                total_commandes_non_validees += m
                nb_cmd_non_val += 1

    # 3. Mises encaissees marquees "mise_creditee_org" sans commande ? (approche par difference)
    ecart = total_encaisse - total_commandes_validees

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Audit ecart pions</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:820px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:22px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:14px;margin:12px 0}"
    html += "td{border:1px solid #ccc;padding:9px}.dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".sect{background:#E8EEF6;font-weight:bold;color:#1F4E79}"
    html += ".big{font-size:16px}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;border-radius:10px;padding:14px;margin:12px 0}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128270; Audit de l'ecart de caisse — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Codes : " + ", ".join(sorted(codes)) + "</div>"
    html += "<p style='font-size:14px'>Cet audit compare ce qui a ete <b>encaisse</b> (mises reversees a l'organisatrice) avec ce qui a ete reellement <b>debite</b> des pions des joueuses (commandes de tickets validees). Un ecart peut reveler des jeux encaisses sans debit de pions.</p>"

    html += "<table>"
    html += "<tr class='sect'><td colspan='2'>Comparaison encaissements / debits</td></tr>"
    html += "<tr><td>Total ENCAISSE (mises creditees a l'org) &mdash; " + str(nb_encaiss) + " encaissements</td><td class='dr'>" + fmt(total_encaisse) + " F</td></tr>"
    html += "<tr><td>Total des commandes de tickets VALIDEES (pions debites) &mdash; " + str(nb_cmd_validees) + " commandes</td><td class='dr'>" + fmt(total_commandes_validees) + " F</td></tr>"
    html += "<tr class='sect'><td>ECART (encaisse - debite)</td><td class='dr big " + ("" if ecart == 0 else "") + "'>" + ("+" if ecart > 0 else "") + fmt(ecart) + " F</td></tr>"
    html += "</table>"

    if nb_cmd_non_val:
        html += "<div class='meta'>Note : " + str(nb_cmd_non_val) + " commande(s) non validee(s) pour un total de " + fmt(total_commandes_non_validees) + " F (en attente ou abandonnees).</div>"

    html += "<h2>Interpretation</h2>"
    if ecart == 0:
        html += "<div class='ok'>&#9989; Encaissements et debits correspondent exactement. Chaque mise encaissee a bien un debit de pions en face. Aucun jeu encaisse &laquo; hors systeme &raquo;.</div>"
    elif ecart > 0:
        html += "<div class='warn'>&#9888;&#65039; <b>Il a ete ENCAISSE " + fmt(ecart) + " F de plus que ce qui a ete debite des pions des joueuses.</b><br><br>"
        html += "Cela signifie que des mises ont ete creditees a l'organisatrice SANS qu'un debit de pions correspondant n'apparaisse. Deux explications possibles :<br>"
        html += "&bull; Des joueuses ont paye leur jeu (en especes ou autrement) et l'organisatrice a valide le ticket sans que leurs pions baissent &mdash; ce qui correspond aux temoignages recueillis.<br>"
        html += "&bull; Ou un dysfonctionnement technique a credite la mise sans debiter la joueuse.<br><br>"
        html += "Dans les deux cas, cet ecart de <b>" + fmt(ecart) + " F</b> pourrait expliquer une partie de la difference constatee dans la caisse.</div>"
    else:
        html += "<div class='warn'>&#9888;&#65039; <b>Il a ete DEBITE " + fmt(abs(ecart)) + " F de plus que ce qui a ete encaisse a l'organisatrice.</b><br><br>"
        html += "Des pions de joueuses ont ete debites sans que la mise ne soit reversee a l'organisatrice. A examiner : commandes validees dont la mise n'a pas ete creditee, ou remboursements.</div>"

    html += "<div class='meta' style='margin-top:14px'>Rappel : la caisse reelle de l'organisatrice est de 92 300 F. Cet audit aide a comprendre d'ou vient la difference entre le theorique et le reel.</div>"
    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/test-transferts-reseau")
def test_transferts_reseau():
    """TEST DECISIF (13/07/2026) : pour une liste de comptes, verifie si chacun a
    RECU un transfert venant d'un compte du reseau de fraude. C'est le critere qui
    distingue un vrai fraudeur (a recu de l'argent du reseau) d'une joueuse
    honnete qui partage seulement une IP d'operateur mobile.
    ?cle=ADMIN&codes=A,B,C&reseau=RT50CJ,UURZ4Y,... (comptes du reseau connu)"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    codes_param = (request.args.get("codes", "") or "").strip().upper()
    if not codes_param:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &codes=A,B,C (comptes a tester)</h1>", status=400, mimetype="text/html; charset=utf-8")
    a_tester = [c.strip() for c in codes_param.split(",") if c.strip()]

    # Reseau connu (par defaut : tous les comptes bloques + les identifies)
    reseau_param = (request.args.get("reseau", "") or "").strip().upper()
    if reseau_param:
        reseau = set(c.strip() for c in reseau_param.split(",") if c.strip())
    else:
        reseau = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)
        reseau |= {"RT50CJ", "UURZ4Y", "H1I5G9", "QGVXNI"}

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    # Pour chaque compte a tester : lister les transferts recus depuis le reseau
    resultats = {}
    for code in a_tester:
        recus = []
        for t in DB.get("transferts_pions", []):
            if not isinstance(t, dict):
                continue
            if (t.get("vers", "") or "").upper() == code:
                de = (t.get("de", "") or "").upper()
                if de in reseau:
                    recus.append((str(t.get("date", "")), de, _iv(t.get("montant", 0)), t.get("annule_fraude")))
        resultats[code] = recus

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Test transferts reseau</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:880px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += ".card{border-radius:10px;padding:14px;margin:10px 0;font-size:14px}"
    html += ".fraude{background:#FDECEA;border:2px solid #C00000}"
    html += ".propre{background:#E8F5E9;border:2px solid #1E7B34}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:8px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;font-weight:bold}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#9878;&#65039; Test decisif — transferts recus du reseau</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + "</div>"
    html += "<p style='font-size:14px'>Critere : un compte qui a <b>recu un transfert d'un compte du reseau</b> est implique dans la fraude. Un compte sans aucun transfert du reseau, meme s'il partage une IP d'operateur, est <b>presume honnete</b>.</p>"

    nb_fraude = 0; nb_propre = 0
    for code in a_tester:
        recus = resultats[code]
        titre = code + (" — " + nomde(code) if nomde(code) else "")
        if recus:
            nb_fraude += 1
            html += "<div class='card fraude'>&#128683; <b>" + titre + "</b> a RECU des transferts du reseau :<table><tr><th>Date</th><th>De</th><th class='dr'>Montant</th><th>Etat</th></tr>"
            for (d, de, m, an) in sorted(recus):
                html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + de + (" — " + nomde(de) if nomde(de) else "") + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + ("annule" if an else "actif") + "</td></tr>"
            html += "</table><b>&rarr; IMPLIQUE DANS LE RESEAU.</b></div>"
        else:
            nb_propre += 1
            html += "<div class='card propre'>&#9989; <b>" + titre + "</b> : AUCUN transfert recu du reseau. Presume <b>joueuse honnete</b> (partage d'IP = meme operateur mobile, pas complicite).</div>"

    html += "<h2 style='color:#1F4E79'>Conclusion</h2>"
    html += "<div class='meta' style='font-size:15px'><b>" + str(nb_fraude) + "</b> compte(s) implique(s) dans le reseau &middot; <b>" + str(nb_propre) + "</b> compte(s) presume(s) honnete(s).</div>"
    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/controle-gagnantes")
def controle_gagnantes():
    """CONTROLE GLOBAL (13/07/2026) : prend toutes les gagnantes d'un tournoi et
    croise leurs adresses IP pour reperer les comptes lies (partage d'IP entre
    gagnantes, ou avec un reseau connu). Classe chaque gagnante : ISOLEE (propre)
    ou LIEE (partage une IP -> a examiner). ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes_org = set([org] + ([aussi] if aussi else []))

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    bloques = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)

    # Gagnantes du tournoi (gains non annules)
    gagnantes = {}
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes_org and not g.get("annule"):
            cg = (g.get("code_gagnant", "") or "").upper()
            gagnantes[cg] = gagnantes.get(cg, 0) + _iv(g.get("montant_credite", 0))

    # IP de chaque compte (toutes sources)
    ip_de = {}
    for j in DB.get("journal_connexions", []):
        cj = (j.get("code") or "").upper().strip()
        ipj = (j.get("ip") or "").strip()
        if cj and ipj:
            ip_de.setdefault(cj, set()).add(ipj)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("ip") or "").strip():
            for k in ("de", "vers"):
                ck = (t.get(k, "") or "").upper()
                if ck:
                    ip_de.setdefault(ck, set()).add((t.get("ip") or "").strip())

    # IP du reseau connu (VAHINE + comptes deja identifies)
    reseau_connu = codes_org | {"RT50CJ", "UURZ4Y", "H1I5G9", "QGVXNI", "397LAI", "JKNTZY"}
    ips_reseau = set()
    for c in reseau_connu:
        ips_reseau |= ip_de.get(c, set())

    # Construire un index IP -> comptes gagnants (pour detecter les partages entre gagnantes)
    ip_vers_gagnantes = {}
    for cg in gagnantes:
        for ip in ip_de.get(cg, set()):
            ip_vers_gagnantes.setdefault(ip, set()).add(cg)

    # Classer chaque gagnante
    lignes = []
    for cg, montant in gagnantes.items():
        ips = ip_de.get(cg, set())
        partage_reseau = bool(ips & ips_reseau)
        # partage avec une autre gagnante ?
        autres = set()
        for ip in ips:
            autres |= (ip_vers_gagnantes.get(ip, set()) - {cg})
        est_bloque = cg in bloques
        if est_bloque:
            statut = "BLOQUE"
        elif partage_reseau:
            statut = "LIEE AU RESEAU"
        elif autres:
            statut = "PARTAGE IP"
        else:
            statut = "ISOLEE"
        lignes.append((montant, cg, statut, sorted(ips), sorted(autres)))
    lignes.sort(key=lambda r: (r[2] == "ISOLEE", -r[0]))

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Controle gagnantes</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:920px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:7px;text-align:left}td{border:1px solid #bbb;padding:6px}"
    html += ".dr{text-align:right;white-space:nowrap;font-weight:bold}"
    html += ".bloq{background:#FDECEA;color:#C00000;font-weight:bold}"
    html += ".lie{background:#FCE4D6;color:#C55A11;font-weight:bold}"
    html += ".part{background:#FFF9C4;color:#9C6500}"
    html += ".ok{background:#E8F5E9;color:#1E7B34}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#9989; Controle des gagnantes — tournoi " + str(nomde(org) or org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(len(gagnantes)) + " gagnantes analysees</div>"

    tot_isolee = sum(m for (m, cg, st, i, a) in lignes if st == "ISOLEE")
    tot_lie = sum(m for (m, cg, st, i, a) in lignes if st in ("LIEE AU RESEAU", "BLOQUE"))
    tot_part = sum(m for (m, cg, st, i, a) in lignes if st == "PARTAGE IP")

    html += "<div class='meta' style='font-size:14px'>"
    html += "&#128994; <b>Propres (isolees) : " + fmt(tot_isolee) + " F</b> &nbsp;&middot;&nbsp; "
    html += "&#128992; <b>Liees au reseau / bloquees : " + fmt(tot_lie) + " F</b> &nbsp;&middot;&nbsp; "
    html += "&#128993; <b>Partage IP (a verifier) : " + fmt(tot_part) + " F</b></div>"

    html += "<table><tr><th>Gagnante</th><th>Code</th><th class='dr'>Gains</th><th>Statut</th><th>IP / liens</th></tr>"
    for (montant, cg, statut, ips, autres) in lignes:
        cls = {"BLOQUE": "bloq", "LIEE AU RESEAU": "lie", "PARTAGE IP": "part", "ISOLEE": "ok"}.get(statut, "")
        detail = ", ".join(ips[:3])
        if autres:
            detail += " &mdash; partage avec : " + ", ".join((a + (" (" + nomde(a) + ")" if nomde(a) else "")) for a in autres[:4])
        html += "<tr class='" + cls + "'><td>" + (nomde(cg) or "—") + "</td><td>" + cg + "</td><td class='dr'>" + fmt(montant) + " F</td><td>" + statut + "</td><td style='font-size:11px'>" + detail + "</td></tr>"
    html += "</table>"

    html += "<h2 style='color:#1F4E79;margin-top:20px'>Conclusion</h2>"
    if tot_lie == 0 and tot_part == 0:
        html += "<div class='ok' style='border:2px solid #1E7B34;border-radius:10px;padding:14px'>&#9989; Toutes les gagnantes restantes sont ISOLEES (aucun partage d'IP). Les " + fmt(tot_isolee) + " F de gains sont propres.</div>"
    else:
        html += "<div style='background:#FFF4E5;border:2px solid #C55A11;border-radius:10px;padding:14px;font-size:14px'>&#9888;&#65039; Il reste des gagnantes liees au reseau (" + fmt(tot_lie) + " F) ou partageant une IP (" + fmt(tot_part) + " F). Seuls les <b>" + fmt(tot_isolee) + " F</b> des gagnantes ISOLEES sont surement propres. Les autres sont a examiner (voir lignes orange/jaune).</div>"
    html += "<p style='margin-top:20px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/enquete-ip")
def enquete_ip():
    """ENQUETE PAR IP (13/07/2026) : liste TOUS les comptes qui se sont connectes
    depuis une ou plusieurs adresses IP donnees. Revele les comptes multiples
    d'une meme personne / d'un meme reseau. Pour chaque compte : nom, statut
    (bloque ou actif), nombre de connexions, et ses gains totaux.
    ?cle=ADMIN&ip=IP1[,IP2,...]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    ip_param = (request.args.get("ip", "") or "").strip()
    if not ip_param:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &ip=ADRESSE_IP (ou plusieurs : IP1,IP2)</h1>", status=400, mimetype="text/html; charset=utf-8")
    ips = set(i.strip() for i in ip_param.split(",") if i.strip())

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomde(c):
        c = (c or "").upper()
        return noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")

    bloques = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)

    # Comptes par IP (depuis le journal des connexions)
    comptes = {}  # code -> {ips:set, connexions:int}
    for j in DB.get("journal_connexions", []):
        ipj = (j.get("ip") or "").strip()
        cj = (j.get("code") or "").upper().strip()
        if ipj in ips and cj:
            comptes.setdefault(cj, {"ips": set(), "cx": 0})
            comptes[cj]["ips"].add(ipj)
            comptes[cj]["cx"] += 1
    # Aussi via les transferts (IP)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("ip") or "").strip() in ips:
            for k in ("de", "vers"):
                ck = (t.get(k, "") or "").upper()
                if ck:
                    comptes.setdefault(ck, {"ips": set(), "cx": 0})
                    comptes[ck]["ips"].add((t.get("ip") or "").strip())

    # Gains totaux par compte
    gains_par = {}
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and not g.get("annule"):
            cg = (g.get("code_gagnant", "") or "").upper()
            gains_par[cg] = gains_par.get(cg, 0) + _iv(g.get("montant_credite", 0))

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Enquete IP</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:13px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:8px;text-align:left}td{border:1px solid #bbb;padding:7px}"
    html += ".dr{text-align:right;white-space:nowrap;font-weight:bold}"
    html += ".bloq{background:#FDECEA;color:#C00000;font-weight:bold}.actif{background:#FFF9C4}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128225; Enquete par IP</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; IP analysees : " + ", ".join(sorted(ips)) + "</div>"

    if comptes:
        # trier : actifs non bloques d'abord (les plus interessants), puis par gains
        items = sorted(comptes.items(), key=lambda x: (x[0] in bloques, -gains_par.get(x[0], 0)))
        nb_actifs = sum(1 for c in comptes if c not in bloques)
        nb_bloques = sum(1 for c in comptes if c in bloques)
        html += "<div class='meta'><b>" + str(len(comptes)) + " comptes</b> connectes depuis ces IP : <b style='color:#C00000'>" + str(nb_bloques) + " deja bloques</b>, <b style='color:#9C4A00'>" + str(nb_actifs) + " encore actifs</b>.</div>"
        html += "<table><tr><th>Code</th><th>Nom</th><th>Statut</th><th class='dr'>Connexions</th><th class='dr'>Gains totaux</th></tr>"
        for code, info in items:
            est_bloque = code in bloques
            cls = "bloq" if est_bloque else ("actif" if gains_par.get(code, 0) > 0 else "")
            html += "<tr class='" + cls + "'><td><b>" + code + "</b></td><td>" + (nomde(code) or "—") + "</td><td>" + ("&#128683; BLOQUE" if est_bloque else "actif") + "</td><td class='dr'>" + str(info["cx"]) + "</td><td class='dr'>" + fmt(gains_par.get(code, 0)) + " F</td></tr>"
        html += "</table>"
        # total gains des comptes encore actifs
        tot_actifs_gains = sum(gains_par.get(c, 0) for c in comptes if c not in bloques)
        html += "<div class='meta' style='margin-top:12px;font-size:14px'>&#9888;&#65039; Total des gains des comptes <b>encore actifs</b> connectes depuis ces IP : <b>" + fmt(tot_actifs_gains) + " F</b>. Ces comptes partagent le reseau mais ne sont pas encore bloques &mdash; a examiner.</div>"
    else:
        html += "<p>Aucun compte trouve pour ces IP dans le journal des connexions.</p>"

    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/tracer-compte")
def tracer_compte():
    """TRAÇAGE COMPLET (13/07/2026) : sort le profil complet d'un compte suspect :
    ses adresses IP, tous ses mouvements (achats, gains, transferts emis/recus avec
    contreparties), et ses IP PARTAGEES avec d'autres comptes (indice de comptes
    multiples d'une meme personne). ?cle=ADMIN&code=CODE"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    if not code:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &code=CODE</h1>", status=400, mimetype="text/html; charset=utf-8")

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomcode(c):
        c = (c or "").upper()
        n = noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")
        return c + (" — " + n if n else "")

    nom = noms.get(code, "") or (DB.get("codes", {}).get(code, {}) or {}).get("nom", "")
    bloque = code in set((b or "").upper() for b in DB.get("codes_bloques", []) if b)

    # IP de ce compte
    ips = set()
    for j in DB.get("journal_connexions", []):
        if (j.get("code") or "").upper().strip() == code and (j.get("ip") or "").strip():
            ips.add((j.get("ip") or "").strip())
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("ip") or "").strip():
            if (t.get("de", "") or "").upper() == code or (t.get("vers", "") or "").upper() == code:
                ips.add((t.get("ip") or "").strip())

    # Comptes partageant une IP
    comptes_meme_ip = {}
    for j in DB.get("journal_connexions", []):
        ipj = (j.get("ip") or "").strip()
        cj = (j.get("code") or "").upper().strip()
        if ipj in ips and cj and cj != code:
            comptes_meme_ip.setdefault(ipj, set()).add(cj)

    # Mouvements
    mv = []
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() == code and c.get("statut") == "validee":
            mv.append((str(c.get("date", "")), "Achat pions", "", _iv(c.get("montant_net", 0)) or _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))))
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_joueur", "") or "").upper() == code:
            mv.append((str(t.get("date", "")), "Pions recus (org)", "de " + nomcode(t.get("code_org", "?")), _iv(t.get("montant_total", 0))))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_gagnant", "") or "").upper() == code:
            mv.append((str(g.get("date", "")), "Gain" + (" ANNULE" if g.get("annule") else ""), str(g.get("jeu", "?")) + " (org " + nomcode(g.get("code_org", "?")) + ")", 0 if g.get("annule") else _iv(g.get("montant_credite", 0))))
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_joueur", "") or "").upper() == code:
            mv.append((str(e.get("date", "")), "Achat tickets", str(e.get("jeu", "?")), -_iv(e.get("montant", 0))))
    for t in DB.get("transferts_pions", []):
        if not isinstance(t, dict):
            continue
        de = (t.get("de", "") or "").upper(); vers = (t.get("vers", "") or "").upper()
        m = _iv(t.get("montant", 0))
        an = " [ANNULE fraude]" if t.get("annule_fraude") else ""
        if de == code:
            mv.append((str(t.get("date", "")), "Transfert EMIS" + an, "vers " + nomcode(vers) + (" · IP " + str(t.get("ip")) if t.get("ip") else ""), 0 if t.get("annule_fraude") else -m))
        if vers == code:
            mv.append((str(t.get("date", "")), "Transfert RECU" + an, "de " + nomcode(de), 0 if t.get("annule_fraude") else m))
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() == code:
            m = _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))
            mv.append((str(c.get("date", "")), "Credit admin" if m >= 0 else "Debit admin", str(c.get("motif", "") or ""), m))
    mv.sort(key=lambda r: r[0])

    pj = _xpf_total_pions(DB.get("pions_joueurs", {}).get(code, {}))
    pb = _xpf_total_pions(DB.get("pions_bonus_joueurs", {}).get(code, {}))

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Tracage compte</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:22px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += ".ips{background:#FFF7E6;border:1px solid #E8C77B;border-radius:8px;padding:12px;margin:10px 0;font-size:13px}"
    html += ".warn{background:#FDECEA;border:2px solid #C00000;border-radius:8px;padding:12px;margin:10px 0;font-size:13px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:8px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;white-space:nowrap;font-weight:bold}.neg{color:#C00000}.pos{color:#1E7B34}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128270; Traçage complet — " + code + (" (" + nom + ")" if nom else "") + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Statut : " + ("&#128683; BLOQUE" if bloque else "actif") + "</div>"

    html += "<div class='ips'><b>Adresses IP de ce compte :</b> " + (", ".join(sorted(ips)) if ips else "aucune enregistree") + "</div>"

    if comptes_meme_ip:
        html += "<div class='warn'><b>&#9888;&#65039; Comptes partageant une IP avec " + code + " (comptes possiblement lies / meme personne) :</b><br>"
        for ip, cpts in comptes_meme_ip.items():
            html += "&bull; IP " + ip + " : " + ", ".join(nomcode(c) for c in sorted(cpts)) + "<br>"
        html += "</div>"
    else:
        html += "<div class='meta'>Aucun autre compte ne partage d'IP avec celui-ci (dans le journal des connexions).</div>"

    html += "<h2>Tous les mouvements</h2>"
    if mv:
        html += "<table><tr><th>Date</th><th>Type</th><th>Detail</th><th class='dr'>Montant</th></tr>"
        for (d, ty, det, m) in mv:
            cls = "pos" if m > 0 else ("neg" if m < 0 else "")
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + ty + "</td><td>" + det + "</td><td class='dr " + cls + "'>" + (("+" if m > 0 else "") + fmt(m) if m else "0") + "</td></tr>"
        html += "</table>"
    else:
        html += "<p>Aucun mouvement trace.</p>"

    html += "<div class='meta' style='margin-top:12px'>Soldes actuels : poche <b>" + fmt(pj) + " F</b> &middot; bonus <b>" + fmt(pb) + " F</b></div>"
    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/transferts-sortants-org")
def transferts_sortants_org():
    """TRAÇAGE (13/07/2026) : recherche TOUS les mouvements ou le(s) code(s) d'une
    organisatrice apparai(ssen)t comme SOURCE d'un depart d'argent vers un autre
    compte, EN DEHORS des gains normaux payes aux gagnantes. Objectif : detecter
    si son compte a servi a envoyer des pions ailleurs (complices, comptes lies),
    deguises ou non. Balaie : transferts de pions, transferts de poche org,
    credits qu'elle aurait emis vers d'autres, deductions inexpliquees.
    ?cle=ADMIN&org=CODE1[,CODE2,...] (un ou plusieurs codes de la personne)"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org_param = (request.args.get("org", "") or "").strip().upper()
    if not org_param:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE (ou plusieurs : CODE1,CODE2)</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set(c.strip() for c in org_param.split(",") if c.strip())
    nom_org = ""
    for c in codes:
        n = (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")
        if n:
            nom_org = n; break
    if not nom_org:
        nom_org = list(codes)[0]

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))
    def nomcode(c):
        c = (c or "").upper()
        n = noms.get(c) or (DB.get("codes", {}).get(c, {}) or {}).get("nom", "")
        return c + (" — " + n if n else "")

    sorties = []  # (date, type, destinataire, montant, etat, source_table)

    # 1. Transferts de pions (poche joueuse) OU son code est source
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("de", "") or "").upper() in codes:
            vers = (t.get("vers", "") or "").upper()
            sorties.append((str(t.get("date", "")), "Transfert de pions", vers, _iv(t.get("montant", 0)),
                            "ANNULE fraude" if t.get("annule_fraude") else "actif", "transferts_pions"))

    # 2. Transferts de poche org OU son code est source
    for t in DB.get("transferts_poche_org", []):
        if isinstance(t, dict) and (t.get("de", "") or "").upper() in codes:
            vers = (t.get("vers", "") or "").upper()
            par = str(t.get("par", "?"))
            # legitime si fait par un admin
            legit = par.upper() in DB.get("codes", {}) and DB.get("codes", {}).get(par.upper(), {}).get("admin")
            sorties.append((str(t.get("date", "")), "Transfert poche org" + (" (par admin)" if legit else ""), vers, _iv(t.get("montant", 0)),
                            "legitime (admin)" if legit else "A EXAMINER", "transferts_poche_org"))

    # 3. Gains : normalement sortie legitime. On les liste SEPAREMENT pour comparaison,
    #    en signalant ceux verses a un compte AUJOURD'HUI bloque.
    bloques = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)
    gains_vers_bloques = []
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes and not g.get("annule"):
            cg = (g.get("code_gagnant", "") or "").upper()
            if cg in bloques:
                gains_vers_bloques.append((str(g.get("date", "")), cg, _iv(g.get("montant_credite", 0)), str(g.get("jeu", "?"))))

    sorties.sort(key=lambda r: r[0])

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Transferts sortants org</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#C00000;border-bottom:3px solid #C00000;padding-bottom:8px}h2{color:#1F4E79;margin-top:24px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;border-radius:10px;padding:14px;margin:12px 0}"
    html += ".warn{background:#FDECEA;border:2px solid #C00000;border-radius:10px;padding:14px;margin:12px 0;font-size:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;white-space:nowrap;font-weight:bold}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128269; Traçage des sorties d'argent — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Codes analyses : " + ", ".join(sorted(codes)) + "</div>"
    html += "<p style='font-size:14px'>Recherche de tous les departs d'argent depuis ses comptes vers d'autres comptes, <b>en dehors des gains normaux</b>. Permet de verifier si son compte a servi a transferer des pions ailleurs.</p>"

    html += "<h2>1. Transferts sortants (hors gains)</h2>"
    if sorties:
        html += "<table><tr><th>Date</th><th>Type</th><th>Vers (destinataire)</th><th class='dr'>Montant</th><th>Etat</th></tr>"
        for (d, ty, dest, m, etat, src) in sorties:
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + ty + "</td><td>" + nomcode(dest) + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + etat + "</td></tr>"
        html += "</table>"
        # total des sorties a examiner (hors legitimes admin)
        tot_exam = sum(m for (d, ty, dest, m, etat, src) in sorties if "legitime" not in etat and "ANNULE" not in etat)
        if tot_exam:
            html += "<div class='warn'>&#9888;&#65039; Total des sorties <b>A EXAMINER</b> (hors transferts admin legitimes et hors deja annules) : <b>" + fmt(tot_exam) + " F</b>. Ces mouvements sortent du role normal d'une organisatrice.</div>"
        else:
            html += "<div class='ok'>&#9989; Toutes les sorties listees sont soit des operations admin legitimes (nos outils du 11/07), soit deja annulees pour fraude. Aucune sortie suspecte active.</div>"
    else:
        html += "<div class='ok'>&#9989; AUCUN transfert sortant depuis ses comptes (hors gains). Son compte organisateur n'a jamais servi a envoyer des pions vers d'autres comptes. C'est le comportement normal d'une organisatrice.</div>"

    html += "<h2>2. Gains verses a des comptes aujourd'hui bloques</h2>"
    if gains_vers_bloques:
        html += "<table><tr><th>Date</th><th>Gagnant (bloque)</th><th>Jeu</th><th class='dr'>Montant</th></tr>"
        tot_gb = 0
        for (d, cg, m, jeu) in sorted(gains_vers_bloques):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + nomcode(cg) + "</td><td>" + jeu + "</td><td class='dr'>" + fmt(m) + " F</td></tr>"
            tot_gb += m
        html += "<tr style='background:#FDECEA;font-weight:bold'><td colspan='3' style='text-align:right'>TOTAL vers comptes bloques</td><td class='dr'>" + fmt(tot_gb) + " F</td></tr></table>"
        html += "<div class='warn'>&#9888;&#65039; Ces gains ont ete verses par son tournoi a des comptes aujourd'hui bloques (reseau de fraude). Meme s'ils passent pour des &laquo; gains &raquo;, ils alimentaient le reseau.</div>"
    else:
        html += "<div class='ok'>&#9989; Aucun gain verse a un compte bloque depuis ce tournoi.</div>"

    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/stripe-par-org")
def stripe_par_org():
    """PAIEMENTS STRIPE (13/07/2026) : calcule tous les paiements par carte (Stripe)
    lies a une organisatrice. Ces paiements sont encaisses par l'ADMINISTRATION
    (compte Stripe), PAS par la poche de l'organisatrice. Distingue la part qui
    revient a l'organisatrice de la part administration/cagnotte.
    ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    paiements = DB.get("paiements_stripe", [])
    if isinstance(paiements, dict):
        paiements = list(paiements.values())

    lignes = []
    total = 0
    tot_part_org = 0
    tot_part_cagnotte = 0
    tot_part_tb = 0
    par_type = {}
    for p in paiements:
        if not isinstance(p, dict):
            continue
        if (p.get("code_org", "") or "").upper() not in codes:
            continue
        if p.get("statut") and p.get("statut") != "paye":
            continue
        m = _iv(p.get("montant", 0)) or _iv(p.get("total", 0))
        typ = str(p.get("type", "?"))
        par_type[typ] = par_type.get(typ, 0) + m
        total += m
        po = _iv(p.get("part_org", 0)); pc = _iv(p.get("part_cagnotte", 0)); ptb = _iv(p.get("part_ticket_bingo", 0))
        tot_part_org += po; tot_part_cagnotte += pc; tot_part_tb += ptb
        lignes.append((str(p.get("date", "")), typ, str(p.get("jeu", "") or p.get("description", "") or ""), str(p.get("acheteur", "") or ""), m, po, pc, ptb))

    lignes.sort(key=lambda r: r[0])

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Stripe par org</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#635BFF;border-bottom:3px solid #635BFF;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += ".cards{display:flex;flex-wrap:wrap;gap:10px;margin:14px 0}"
    html += ".card{flex:1;min-width:150px;background:#F5F3FF;border:1px solid #635BFF;border-radius:8px;padding:12px;text-align:center}"
    html += ".card .v{font-size:19px;font-weight:bold;color:#635BFF}.card .l{font-size:11px;color:#555}"
    html += ".tot{background:#635BFF;color:#fff;border-radius:10px;padding:16px;margin:14px 0;font-size:18px;font-weight:bold;text-align:center}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#EEE;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;white-space:nowrap}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#F5F3FF;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128179; Paiements par carte (Stripe) — tournoi de " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(len(lignes)) + " paiements Stripe</div>"
    html += "<div style='background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0;font-size:14px'>&#9888;&#65039; <b>Important :</b> ces paiements par carte ont ete encaisses sur le compte Stripe de l'ADMINISTRATION (toi), et non dans la poche de l'organisatrice. L'argent reel de ces transactions est deja chez toi.</div>"

    html += "<div class='tot'>TOTAL ENCAISSE PAR CARTE (STRIPE) : " + fmt(total) + " XPF</div>"

    if tot_part_org or tot_part_cagnotte or tot_part_tb:
        html += "<div class='cards'>"
        html += "<div class='card'><div class='v'>" + fmt(tot_part_org) + " F</div><div class='l'>Part ORGANISATRICE (a lui reverser)</div></div>"
        html += "<div class='card'><div class='v'>" + fmt(tot_part_cagnotte) + " F</div><div class='l'>Part CAGNOTTE (gains joueuses)</div></div>"
        html += "<div class='card'><div class='v'>" + fmt(tot_part_tb) + " F</div><div class='l'>Part TICKET BINGO (commission)</div></div>"
        html += "</div>"

    if par_type:
        html += "<div class='meta'>Repartition par type : " + " &middot; ".join([t + " : " + fmt(v) + " F" for t, v in par_type.items()]) + "</div>"

    if lignes:
        html += "<table><tr><th>Date</th><th>Type</th><th>Jeu / description</th><th>Acheteur</th><th class='dr'>Montant</th><th class='dr'>Part org</th><th class='dr'>Cagnotte</th></tr>"
        for (d, typ, desc, ach, m, po, pc, ptb) in lignes:
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + typ + "</td><td>" + desc[:30] + "</td><td>" + ach[:18] + "</td><td class='dr'>" + fmt(m) + "</td><td class='dr'>" + (fmt(po) if po else "") + "</td><td class='dr'>" + (fmt(pc) if pc else "") + "</td></tr>"
        html += "<tr style='background:#EEE;font-weight:bold'><td colspan='4' style='text-align:right'>TOTAL</td><td class='dr'>" + fmt(total) + "</td><td class='dr'>" + fmt(tot_part_org) + "</td><td class='dr'>" + fmt(tot_part_cagnotte) + "</td></tr>"
        html += "</table>"
    else:
        html += "<p>Aucun paiement Stripe rattache au code de cette organisatrice.</p>"

    # === PERIODE DES TOURNOIS DE VAHINE (dans la base) ===
    dates_tournois = []
    for src in ("tournois_termines", "tournois_programmes", "encaissements_org", "gains_finaux"):
        for x in DB.get(src, []):
            if isinstance(x, dict) and (x.get("code_org", "") or "").upper() in codes and x.get("date"):
                dates_tournois.append(str(x.get("date"))[:19])
    html += "<h2 style='color:#635BFF'>Periode d'activite de " + str(nom_org) + "</h2>"
    if dates_tournois:
        dmin = min(dates_tournois); dmax = max(dates_tournois)
        html += "<div class='meta' style='font-size:14px'>Premiere activite : <b>" + dmin.replace("T", " ") + "</b> &middot; Derniere activite : <b>" + dmax.replace("T", " ") + "</b></div>"
    else:
        html += "<div class='meta'>Aucune date d'activite trouvee.</div>"
        dmin = None; dmax = None

    # === TOUS les paiements Stripe sur cette periode (toutes org confondues) ===
    html += "<h2 style='color:#635BFF'>Tous les paiements Stripe sur cette periode (toutes organisatrices)</h2>"
    html += "<div class='meta'>Pour ne rien rater : les paiements par carte qui pourraient concerner ce tournoi meme s'ils sont rattaches a un autre code (ou a aucun).</div>"
    periode_lignes = []
    total_periode = 0
    if dates_tournois:
        d0 = dmin[:10]; d1 = dmax[:10]
        for p in paiements:
            if not isinstance(p, dict):
                continue
            dp = str(p.get("date", ""))[:10]
            if d0 <= dp <= d1:
                m = _iv(p.get("montant", 0)) or _iv(p.get("total", 0))
                periode_lignes.append((str(p.get("date", "")), str(p.get("type", "?")), (p.get("code_org", "") or "—"), str(p.get("acheteur", "") or p.get("description", "") or ""), m))
                total_periode += m
    if periode_lignes:
        periode_lignes.sort(key=lambda r: r[0])
        html += "<table><tr><th>Date</th><th>Type</th><th>Code org</th><th>Acheteur/desc</th><th class='dr'>Montant</th></tr>"
        for (d, typ, co, ach, m) in periode_lignes:
            surligne = " style='background:#FFF9C4'" if co.upper() in codes else ""
            html += "<tr" + surligne + "><td>" + d[:16].replace("T", " ") + "</td><td>" + typ + "</td><td>" + co + "</td><td>" + ach[:24] + "</td><td class='dr'>" + fmt(m) + "</td></tr>"
        html += "<tr style='background:#EEE;font-weight:bold'><td colspan='4' style='text-align:right'>TOTAL periode</td><td class='dr'>" + fmt(total_periode) + "</td></tr></table>"
        html += "<div class='meta'>Les lignes surlignees en jaune sont rattachees au code de " + str(nom_org) + ". Les autres concernent d'autres tournois mais se sont produites pendant la meme periode.</div>"
    else:
        html += "<p>Aucun paiement Stripe sur toute la periode d'activite &mdash; ni pour ce tournoi, ni pour aucun autre. Cela confirme que les paiements se faisaient en especes/direct.</p>"

    html += "<h2 style='color:#635BFF'>Ce que ca implique</h2>"
    html += "<div class='meta' style='font-size:14px'>Les " + fmt(total) + " F encaisses par carte sont deja sur ton compte Stripe. Si des joueuses de ce tournoi ont paye par carte et doivent etre remboursees, l'argent existe deja chez toi &mdash; tu n'as pas besoin de le reclamer a l'organisatrice. En revanche, la part organisatrice (" + fmt(tot_part_org) + " F) est ce que tu devrais normalement lui reverser pour son travail : a mettre en balance avec ce qu'elle te doit.</div>"
    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/gains-a-payer")
def gains_a_payer():
    """RELEVE DES GAINS A PAYER (13/07/2026) : pour une organisatrice, liste tous
    les gains remportes par les joueuses dans SON tournoi, avec le nom, le code,
    le montant et le total. Sert a savoir qui doit etre paye et par qui.
    ?cle=ADMIN&org=CODE[&aussi=ANCIEN][&lieu=texte libre du lieu de paiement]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    lieu = (request.args.get("lieu", "") or "").strip()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    bloques = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)
    deja_soldees = {"EY6K47", "OXUZRO", "NR5FUW"}

    par_joueuse = {}
    total = 0
    nb = 0
    for g in DB.get("gains_finaux", []):
        if not isinstance(g, dict) or (g.get("code_org", "") or "").upper() not in codes:
            continue
        if g.get("annule"):
            continue
        cg = (g.get("code_gagnant", "") or "").upper()
        m = _iv(g.get("montant_credite", 0))
        if cg not in par_joueuse:
            par_joueuse[cg] = {"total": 0, "nb": 0}
        par_joueuse[cg]["total"] += m
        par_joueuse[cg]["nb"] += 1
        total += m
        nb += 1

    classement = sorted(par_joueuse.items(), key=lambda x: -x[1]["total"])

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Gains a payer</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:880px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:14px}"
    html += ".lieu{background:#DEEAF6;border:2px solid #1F4E79;border-radius:10px;padding:14px;margin:14px 0;font-size:15px;font-weight:bold;color:#1F4E79}"
    html += ".tot{background:#1F4E79;color:#fff;border-radius:10px;padding:16px;margin:14px 0;font-size:18px;font-weight:bold;text-align:center}"
    html += "table{width:100%;border-collapse:collapse;font-size:13px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:8px;text-align:left}td{border:1px solid #bbb;padding:7px}"
    html += ".dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".bloq{background:#FDECEA;color:#C00000;font-weight:bold}.solde{background:#FFF4E5;color:#9C4A00}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#127942; Gains a payer — tournoi de " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(nb) + " gains &middot; " + str(len(classement)) + " gagnantes</div>"
    if lieu:
        html += "<div class='lieu'>&#128205; Lieu de paiement : " + lieu + "</div>"
    html += "<div class='tot'>TOTAL DES GAINS A PAYER : " + format(total, ",") + " XPF</div>"

    if classement:
        html += "<table><tr><th>Gagnante</th><th>Code</th><th class='dr'>Nb gains</th><th class='dr'>Total a recevoir</th><th>Note</th></tr>"
        for cg, v in classement:
            note = ""
            cls = ""
            if cg in bloques:
                note = "COMPTE BLOQUE (fraude) — NE PAS PAYER"; cls = "bloq"
            elif cg in deja_soldees:
                note = "Deja soldee en especes"; cls = "solde"
            html += "<tr class='" + cls + "'><td>" + (noms.get(cg, "") or "—") + "</td><td>" + cg + "</td><td class='dr'>" + str(v["nb"]) + "</td><td class='dr'>" + format(v["total"], ",") + " F</td><td style='font-size:11px'>" + note + "</td></tr>"
        html += "</table>"

        total_net = sum(v["total"] for cg, v in classement if cg not in bloques and cg not in deja_soldees)
        total_bloq = sum(v["total"] for cg, v in classement if cg in bloques)
        total_solde = sum(v["total"] for cg, v in classement if cg in deja_soldees)
        html += "<table style='margin-top:16px'>"
        html += "<tr><td><b>Total a payer aux gagnantes legitimes</b></td><td class='dr'>" + format(total_net, ",") + " F</td></tr>"
        if total_bloq:
            html += "<tr class='bloq'><td>Dont comptes bloques (a NE PAS payer)</td><td class='dr'>" + format(total_bloq, ",") + " F</td></tr>"
        if total_solde:
            html += "<tr class='solde'><td>Dont deja soldees en especes</td><td class='dr'>" + format(total_solde, ",") + " F</td></tr>"
        html += "</table>"
    else:
        html += "<p>Aucun gain enregistre pour ce tournoi.</p>"

    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/audit-poche-org")
def audit_poche_org():
    """AUDIT POCHE ORG (13/07/2026) : passe au crible TOUS les mouvements de la
    poche organisateur d'un code, et separe l'activite NORMALE (ravitaillement
    des joueuses en pions = ventes, encaissement de tickets, paiement de gains)
    des mouvements ATYPIQUES (transferts, credits admin recus, sorties non
    justifiees par l'activite de tournoi). Objectif : detecter si l'organisatrice
    a fait autre chose que son role legitime. ?cle=ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG (option &aussi=ANCIEN)</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = set([org] + ([aussi] if aussi else []))
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    # === ACTIVITE NORMALE (attendue pour une organisatrice) ===
    nb_ravito = 0; tot_ravito = 0     # ventes de pions aux joueuses
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_org", "") or "").upper() in codes:
            nb_ravito += 1; tot_ravito += _iv(t.get("montant_total", 0))
    nb_tickets = 0; tot_tickets = 0   # encaissements tickets
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes:
            nb_tickets += 1; tot_tickets += _iv(e.get("montant", 0))
    nb_gains = 0; tot_gains = 0        # gains payes
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes and not g.get("annule"):
            nb_gains += 1; tot_gains += _iv(g.get("montant_credite", 0))

    # === MOUVEMENTS ATYPIQUES (a examiner) ===
    # a) Credits de poche org recus (ravitaillement stock) : normal si par admin, suspect sinon
    credits_poche = []
    for c in DB.get("credits_poche_org", []):
        if isinstance(c, dict) and (c.get("code_org", "") or "").upper() in codes:
            credits_poche.append((str(c.get("date", "")), _iv(c.get("montant", 0)), str(c.get("motif", "") or ""), str(c.get("par", "?")), str(c.get("ip", "") or "")))
    # b) Transferts de poche org -> org (nos outils du 11/07)
    transf_poche = []
    for t in DB.get("transferts_poche_org", []):
        if isinstance(t, dict) and ((t.get("de", "") or "").upper() in codes or (t.get("vers", "") or "").upper() in codes):
            transf_poche.append((str(t.get("date", "")), (t.get("de", "") or "").upper(), (t.get("vers", "") or "").upper(), _iv(t.get("montant", 0)), str(t.get("par", "?"))))
    # c) Credits admin recus sur un compte joueuse portant ce code (si le code org sert aussi de joueuse)
    credits_admin = []
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() in codes:
            m = _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))
            credits_admin.append((str(c.get("date", "")), m, str(c.get("motif", "") or ""), str(c.get("par", "?"))))
    # d) Transferts de pions (poche joueuse) impliquant ce code
    transf_joueur = []
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and ((t.get("de", "") or "").upper() in codes or (t.get("vers", "") or "").upper() in codes):
            transf_joueur.append((str(t.get("date", "")), (t.get("de", "") or "").upper(), (t.get("vers", "") or "").upper(), _iv(t.get("montant", 0)), t.get("annule_fraude")))

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Audit poche org</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#1F4E79;margin-top:24px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:16px}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;border-radius:10px;padding:14px;margin:12px 0}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;border-radius:10px;padding:14px;margin:12px 0}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;white-space:nowrap}.gris{color:#888}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128269; Audit de la poche organisateur — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Codes : " + ", ".join(sorted(codes)) + "</div>"

    html += "<h2>1. Activite NORMALE d'organisatrice (attendue)</h2>"
    html += "<table><tr><th>Type d'operation</th><th class='dr'>Nombre</th><th class='dr'>Montant</th></tr>"
    html += "<tr><td>Ravitaillement des joueuses en pions (ventes)</td><td class='dr'>" + str(nb_ravito) + "</td><td class='dr'>" + fmt(tot_ravito) + " F</td></tr>"
    html += "<tr><td>Encaissement de tickets (mises)</td><td class='dr'>" + str(nb_tickets) + "</td><td class='dr'>" + fmt(tot_tickets) + " F</td></tr>"
    html += "<tr><td>Gains payes aux gagnantes</td><td class='dr'>" + str(nb_gains) + "</td><td class='dr'>" + fmt(tot_gains) + " F</td></tr>"
    html += "</table>"
    html += "<div class='ok'>&#9989; Ces trois types d'operations sont l'activite LEGITIME d'une organisatrice : vendre des pions, encaisser des tickets, payer les gagnantes.</div>"

    html += "<h2>2. Mouvements ATYPIQUES (a examiner)</h2>"

    # a) credits poche org
    html += "<h3 style='color:#9C4A00'>a) Ravitaillements de son stock (credits de poche org)</h3>"
    if credits_poche:
        html += "<table><tr><th>Date</th><th class='dr'>Montant</th><th>Motif</th><th>Par</th><th>IP</th></tr>"
        for (d, m, mo, par, ip) in sorted(credits_poche):
            suspect = par.upper() not in DB.get("codes", {}) or not DB.get("codes", {}).get(par.upper(), {}).get("admin")
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + mo + "</td><td" + (" style='color:#C00000;font-weight:bold'" if suspect else "") + ">" + par + "</td><td class='gris'>" + ip + "</td></tr>"
        html += "</table><div class='meta'>Normal si &laquo; Par &raquo; = un code admin (tu l'as ravitaillee). Suspect si credite par un autre code.</div>"
    else:
        html += "<p class='gris'>Aucun credit de poche enregistre.</p>"

    # b) transferts poche org
    html += "<h3 style='color:#9C4A00'>b) Transferts de poche organisateur</h3>"
    if transf_poche:
        html += "<table><tr><th>Date</th><th>De</th><th>Vers</th><th class='dr'>Montant</th><th>Par</th></tr>"
        for (d, de, vers, m, par) in sorted(transf_poche):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + de + "</td><td>" + vers + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + par + "</td></tr>"
        html += "</table><div class='meta'>Les transferts par un code admin (nos outils du 11/07 pour recuperer sa poche) sont legitimes.</div>"
    else:
        html += "<p class='gris'>Aucun transfert de poche org.</p>"

    # c) credits admin
    html += "<h3 style='color:#9C4A00'>c) Credits admin recus (si ce code a aussi servi de compte joueuse)</h3>"
    if credits_admin:
        html += "<table><tr><th>Date</th><th class='dr'>Montant</th><th>Motif</th><th>Par</th></tr>"
        for (d, m, mo, par) in sorted(credits_admin):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + mo + "</td><td>" + par + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='gris'>Aucun credit admin sur ce code (normal pour un pur compte organisateur).</p>"

    # d) transferts pions joueur
    html += "<h3 style='color:#9C4A00'>d) Transferts de pions (poche joueuse) impliquant ce code</h3>"
    if transf_joueur:
        html += "<table><tr><th>Date</th><th>De</th><th>Vers</th><th class='dr'>Montant</th><th>Etat</th></tr>"
        for (d, de, vers, m, a) in sorted(transf_joueur):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + de + "</td><td>" + vers + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + ("annule fraude" if a else "actif") + "</td></tr>"
        html += "</table><div class='warn'>&#9888;&#65039; Un code purement organisateur ne devrait PAS faire de transferts de pions entre joueuses. Toute ligne ici est a examiner.</div>"
    else:
        html += "<p class='gris'>Aucun transfert de pions joueuse sur ce code &mdash; c'est le comportement NORMAL d'un compte purement organisateur.</p>"

    html += "<h2>Conclusion</h2>"
    if not transf_joueur and not credits_admin:
        html += "<div class='ok'>&#9989; Le compte ORGANISATEUR de " + str(nom_org) + " n'a fait QUE son activite legitime : ravitailler les joueuses en pions, encaisser des tickets, payer les gains. Aucun transfert de pions atypique ni credit admin suspect sur ce code organisateur.<br><br>Autrement dit : la fraude n'a PAS transite par sa poche d'organisatrice, mais par ses comptes JOUEUSES separes (RT50CJ et le reseau). Sa comptabilite d'organisatrice reste donc telle qu'auditee.</div>"
    else:
        html += "<div class='warn'>&#9888;&#65039; Des mouvements atypiques ont ete detectes sur ce code (transferts de pions ou credits admin). Voir les sections ci-dessus : ces operations sortent du role normal d'une organisatrice et doivent etre examinees une par une.</div>"
    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/audit-fraude-org")
def audit_fraude_org():
    """AUDIT FRAUDE (11/07/2026) : audite l'ensemble des comptes lies a une meme
    personne (ex: une organisatrice qui possede aussi des comptes joueuses du
    reseau). Croise : transferts entre ses comptes, gains qu'elle s'est verses a
    elle-meme (org -> ses propres comptes joueuses), encaissements suspects.
    ?cle=ADMIN&comptes=CODE1,CODE2,CODE3 (tous les codes de la personne)
    Page imprimable."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    comptes_param = (request.args.get("comptes", "") or "").strip().upper()
    if not comptes_param:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &comptes=CODE1,CODE2,CODE3 (tous les codes de la personne)</h1>", status=400, mimetype="text/html; charset=utf-8")
    comptes = [c.strip() for c in comptes_param.split(",") if c.strip()]
    comptes_set = set(comptes)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    # 1. TRANSFERTS impliquant ses comptes (emis/recus), en distinguant internes
    transf_internes = []   # entre ses propres comptes (auto-alimentation)
    transf_entrants = []   # depuis un compte tiers vers un de ses comptes
    transf_sortants = []   # depuis un de ses comptes vers un tiers
    for t in DB.get("transferts_pions", []):
        if not isinstance(t, dict):
            continue
        de = (t.get("de", "") or "").upper()
        vers = (t.get("vers", "") or "").upper()
        m = _iv(t.get("montant", 0))
        annul = t.get("annule_fraude")
        if de in comptes_set and vers in comptes_set:
            transf_internes.append((str(t.get("date", "")), de, vers, m, annul))
        elif vers in comptes_set:
            transf_entrants.append((str(t.get("date", "")), de, vers, m, annul))
        elif de in comptes_set:
            transf_sortants.append((str(t.get("date", "")), de, vers, m, annul))

    # 2. GAINS qu'elle s'est verses : org (un de ses codes) -> gagnant (un de ses codes)
    auto_gains = []
    for g in DB.get("gains_finaux", []):
        if not isinstance(g, dict):
            continue
        org = (g.get("code_org", "") or "").upper()
        gag = (g.get("code_gagnant", "") or "").upper()
        if org in comptes_set and gag in comptes_set:
            auto_gains.append((str(g.get("date", "")), org, gag, _iv(g.get("montant_credite", 0)), g.get("annule"), str(g.get("jeu", "?"))))

    # 3. Ses comptes qui ont acheté des tickets chez son PROPRE tournoi (mises qui reviennent)
    auto_encaiss = []
    for e in DB.get("encaissements_org", []):
        if not isinstance(e, dict):
            continue
        org = (e.get("code_org", "") or "").upper()
        jou = (e.get("code_joueur", "") or "").upper()
        if org in comptes_set and jou in comptes_set:
            auto_encaiss.append((str(e.get("date", "")), org, jou, _iv(e.get("montant", 0)), str(e.get("jeu", "?"))))

    # Totaux
    tot_internes = sum(m for (_, _, _, m, a) in transf_internes)
    tot_entrants = sum(m for (_, _, _, m, a) in transf_entrants)
    tot_auto_gains = sum(m for (_, _, _, m, a, j) in auto_gains if not a)
    tot_auto_encaiss = sum(m for (_, _, _, m, j) in auto_encaiss)

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Audit fraude</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:900px;margin:0 auto}"
    html += "h1{color:#C00000;border-bottom:3px solid #C00000;padding-bottom:8px}h2{color:#1F4E79;margin-top:26px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:16px}"
    html += ".alert{background:#FDECEA;border:2px solid #C00000;border-radius:10px;padding:14px;margin:14px 0;font-size:14px}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin:10px 0}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}td{border:1px solid #bbb;padding:5px}"
    html += ".dr{text-align:right;font-weight:bold;white-space:nowrap}.neg{color:#C00000}.gris{color:#888}"
    html += ".card{display:inline-block;background:#F5F7FA;border:1px solid #ccc;border-radius:8px;padding:12px 16px;margin:6px}"
    html += ".card .v{font-size:19px;font-weight:bold;color:#C00000}.card .l{font-size:11px;color:#555}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128680; AUDIT FRAUDE — comptes lies</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Comptes audites : <b>" + ", ".join(comptes) + "</b></div>"
    html += "<div class='alert'>&#9888;&#65039; Cet audit part de l'hypothese que TOUS les comptes listes ci-dessus appartiennent a la MEME personne. Il revele les operations ou ces comptes se sont alimentes entre eux ou se sont verse des gains &mdash; ce qui, entre comptes d'une meme personne dont un organisateur, constitue une auto-attribution de fonds.</div>"

    html += "<div style='text-align:center'>"
    html += "<div class='card'><div class='v'>" + fmt(tot_internes) + " F</div><div class='l'>Transferts INTERNES (entre ses comptes)</div></div>"
    html += "<div class='card'><div class='v'>" + fmt(tot_entrants) + " F</div><div class='l'>Transferts RECUS de tiers</div></div>"
    html += "<div class='card'><div class='v'>" + fmt(tot_auto_gains) + " F</div><div class='l'>Gains qu'elle s'est verses a elle-meme</div></div>"
    html += "<div class='card'><div class='v'>" + fmt(tot_auto_encaiss) + " F</div><div class='l'>Mises de ses comptes chez son tournoi</div></div>"
    html += "</div>"

    # 1. Transferts internes
    html += "<h2>1. Transferts entre ses propres comptes (auto-alimentation)</h2>"
    if transf_internes:
        html += "<table><tr><th>Date</th><th>De</th><th>Vers</th><th class='dr'>Montant</th><th>Etat</th></tr>"
        for (d, de, vers, m, a) in sorted(transf_internes):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + de + "</td><td>" + vers + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + ("annule fraude" if a else "actif") + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='gris'>Aucun transfert direct entre les comptes listes.</p>"

    # 2. Gains auto-verses
    html += "<h2>2. Gains qu'elle s'est verses (son tournoi &rarr; ses comptes)</h2>"
    if auto_gains:
        html += "<table><tr><th>Date</th><th>Tournoi (org)</th><th>Gagnant</th><th>Jeu</th><th class='dr'>Montant</th></tr>"
        for (d, org, gag, m, a, jeu) in sorted(auto_gains):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + org + "</td><td>" + gag + "</td><td>" + jeu + "</td><td class='dr " + ("gris" if a else "neg") + "'>" + fmt(m) + " F" + (" (annule)" if a else "") + "</td></tr>"
        html += "</table>"
        html += "<div class='meta'>&#9888;&#65039; Ces gains sont verses par son propre tournoi a ses propres comptes joueuses : elle gagne ses propres cagnottes.</div>"
    else:
        html += "<p class='gris'>Aucun gain verse de son tournoi vers ses comptes listes.</p>"

    # 3. Auto-encaissements
    html += "<h2>3. Mises de ses comptes joueuses dans son propre tournoi</h2>"
    if auto_encaiss:
        html += "<table><tr><th>Date</th><th>Tournoi (org)</th><th>Compte joueuse</th><th>Jeu</th><th class='dr'>Mise</th></tr>"
        s = 0
        for (d, org, jou, m, jeu) in sorted(auto_encaiss):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + org + "</td><td>" + jou + "</td><td>" + jeu + "</td><td class='dr'>" + fmt(m) + " F</td></tr>"
            s += m
        html += "<tr style='background:#DEEAF6;font-weight:bold'><td colspan='4' style='text-align:right'>TOTAL</td><td class='dr'>" + fmt(s) + " F</td></tr></table>"
    else:
        html += "<p class='gris'>Aucune mise de ses comptes dans son propre tournoi.</p>"

    # 4. Transferts entrants de tiers (le reseau qui l'alimente)
    html += "<h2>4. Transferts recus de comptes tiers (le reseau qui alimente ses comptes)</h2>"
    if transf_entrants:
        html += "<table><tr><th>Date</th><th>De (tiers)</th><th>Vers (son compte)</th><th class='dr'>Montant</th><th>Etat</th></tr>"
        for (d, de, vers, m, a) in sorted(transf_entrants):
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + de + "</td><td>" + vers + "</td><td class='dr'>" + fmt(m) + " F</td><td>" + ("annule fraude" if a else "actif") + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='gris'>Aucun transfert entrant de tiers.</p>"

    html += "<h2>Synthese</h2>"
    html += "<div class='alert'>Cet audit documente les flux internes et auto-attributions des comptes de cette personne. "
    html += "Total des gains qu'elle s'est verses (actifs) : <b>" + fmt(tot_auto_gains) + " F</b>. "
    html += "Total des transferts recus du reseau : <b>" + fmt(tot_entrants) + " F</b>. "
    html += "Ces montants representent des fonds obtenus par manipulation de son propre tournoi et par le reseau de comptes complices.</div>"
    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/liens-releves")
def liens_releves():
    """ADMIN — Genere les liens de releve a envoyer aux joueuses/organisatrices.
    Chaque lien utilise le PROPRE code de la personne comme cle (pas la cle admin) :
    la personne voit uniquement son releve, ne peut rien modifier. 
    ?cle=ADMIN[&codes=A,B,C pour des liens precis]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    base = request.host_url.rstrip("/")
    codes_param = (request.args.get("codes", "") or "").strip()

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Liens releves</title><style>"
    html += "body{font-family:system-ui,sans-serif;background:#0d1117;color:#e6edf3;padding:20px;max-width:760px;margin:0 auto}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:16px;font-size:14px}"
    html += ".box{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:14px;margin:12px 0}"
    html += "input{width:100%;padding:12px;border-radius:8px;border:1px solid #30363d;background:#0d1117;color:#e6edf3;font-size:15px;box-sizing:border-box}"
    html += ".lien{background:#0d1117;border:1px solid #30363d;border-radius:6px;padding:10px;font-family:monospace;font-size:12px;word-break:break-all;margin:6px 0;color:#3fb950}"
    html += "button{background:#238636;color:#fff;border:none;border-radius:8px;padding:10px 16px;font-size:14px;font-weight:bold;cursor:pointer;margin-top:8px}"
    html += ".row{display:flex;justify-content:space-between;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid #21262d}"
    html += "a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128279; Liens de releve a envoyer</h1>"
    html += "<div class='sub'>Chaque lien utilise le CODE de la personne comme cle : elle voit seulement SON releve, ne peut rien modifier, et ta cle admin n'apparait jamais. Copie le lien et envoie-le par message.</div>"

    # Generateur : tape un code
    html += "<div class='box'><b>Generer un lien pour un code :</b><br>"
    html += "<input id='c' placeholder='Tape le code de la joueuse (ex: EY6K47)' oninput='gen()' style='margin-top:8px'>"
    html += "<div id='out'></div></div>"
    html += "<script>var base='" + base + "';"
    html += "function gen(){var c=document.getElementById('c').value.trim().toUpperCase();var o=document.getElementById('out');"
    html += "if(c.length<4){o.innerHTML='';return;}"
    html += "var url=base+'/releve-financier-joueur/'+c+'?cle='+c;"
    html += "o.innerHTML=\"<div class='lien'>\"+url+\"</div><button onclick=\\\"navigator.clipboard.writeText('\"+url+\"');this.textContent='Copie !'\\\">Copier le lien</button>\";}"
    html += "</script>"

    # Liste optionnelle
    if codes_param:
        html += "<div class='box'><b>Liens demandes :</b>"
        for c in codes_param.split(","):
            c = c.strip().upper()
            if not c:
                continue
            url = base + "/releve-financier-joueur/" + c + "?cle=" + c
            nom = noms.get(c, "")
            html += "<div class='row'><span>" + c + (" — " + nom if nom else "") + "</span></div>"
            html += "<div class='lien'>" + url + "</div>"
        html += "</div>"

    html += "<div class='sub' style='margin-top:16px'>Astuce : ajoute <b>&codes=CODE1,CODE2,CODE3</b> a l'adresse pour generer plusieurs liens d'un coup.</div>"
    html += "</body></html>"
    return html


@app.route("/ajouter-dette-joueuse")
def ajouter_dette_joueuse():
    """ADMIN — Enregistre une dette de joueuse (avance especes a rembourser).
    ?cle=ADMIN&code=CODE&montant=N[&motif=...][&executer=1]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("Acces reserve.", status=403, mimetype="text/plain; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    try:
        montant = int(request.args.get("montant", "0") or 0)
    except ValueError:
        montant = 0
    motif = (request.args.get("motif", "") or "").strip() or "Avance en espèces (retrait supérieur au solde) — à rembourser"
    executer = (request.args.get("executer", "") or "") == "1"

    def page(t, c, col="#1F4E79"):
        return Response("<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'></head><body style='margin:0;background:#0d1117;font-family:system-ui,sans-serif;color:#e6edf3;padding:18px'><div style='max-width:560px;margin:0 auto'><h1 style='font-size:20px;color:" + col + "'>" + t + "</h1>" + c + "</div></body></html>", mimetype="text/html; charset=utf-8")
    if not code or montant <= 0:
        return page("Parametres", "<p>Ajoute <b>&code=CODE&montant=N</b>.</p>", "#f85149")
    nom = ""
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and (t.get("code_acheteur") or "").upper() == code and t.get("acheteur"):
            nom = str(t.get("acheteur")); break
    if not executer:
        corps = "<div style='background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px'>Enregistrer une dette de <b>" + format(montant, ",") + " F</b> pour <b>" + code + (" — " + nom if nom else "") + "</b><br><span style='color:#8b949e;font-size:13px'>" + motif + "</span></div>"
        corps += "<a href='?cle=" + _cle + "&code=" + code + "&montant=" + str(montant) + "&motif=" + motif.replace(" ", "%20").replace("—", "-") + "&executer=1' style='display:block;text-align:center;background:#16a34a;color:#fff;padding:13px;border-radius:10px;text-decoration:none;font-weight:700;margin-top:14px'>&#9989; Enregistrer la dette</a>"
        return page("Ajouter une dette — apercu", corps)
    DB.setdefault("dettes_joueuses", []).insert(0, {
        "id": "D" + datetime.datetime.now().strftime("%Y%m%d%H%M%S"),
        "code_joueur": code, "nom": nom, "montant": montant,
        "motif": motif, "statut": "du", "date": datetime.datetime.now().isoformat()})
    save_data(immediat=True)
    return page("Dette enregistree", "<div style='background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:10px;padding:16px;color:#6ee7b7'>&#9989; " + code + " te doit " + format(montant, ",") + " F. Voir <a href='/dettes-joueuses?cle=" + _cle + "' style='color:#58a6ff'>/dettes-joueuses</a>.</div>", "#10b981")


@app.route("/requalifier-retrait")
def requalifier_retrait():
    """REQUALIFICATION — change le LIBELLE d'un debit admin deja effectue en
    'Retrait especes (boutique)', SANS re-debiter. ?cle=ADMIN&code=CODE&montant=N[&jour=AAAA-MM-JJ][&executer=1]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("Acces reserve.", status=403, mimetype="text/plain; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    executer = (request.args.get("executer", "") or "") == "1"
    jour = (request.args.get("jour", "") or "").strip()
    heure = (request.args.get("heure", "") or "").strip()
    try:
        montant = int(request.args.get("montant", "0") or 0)
    except ValueError:
        montant = 0

    def page(t, c, col="#1F4E79"):
        return Response("<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'></head><body style='margin:0;background:#0d1117;font-family:system-ui,sans-serif;color:#e6edf3;padding:18px'><div style='max-width:620px;margin:0 auto'><h1 style='font-size:20px;color:" + col + "'>" + t + "</h1>" + c + "</div></body></html>", mimetype="text/html; charset=utf-8")
    if not code or montant <= 0:
        return page("Parametres", "<p>Ajoute <b>&code=CODE&montant=N</b> (montant du retrait), option <b>&jour=AAAA-MM-JJ&heure=HH:MM</b>.</p>", "#f85149")

    cibles = []
    for i, c in enumerate(DB.get("credits_admin", [])):
        if not isinstance(c, dict) or (c.get("code_joueur", "") or "").upper() != code:
            continue
        m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        if m >= 0 or abs(m) != montant:
            continue
        if jour and str(c.get("date", ""))[:10] != jour:
            continue
        if heure and str(c.get("date", ""))[11:16] != heure:
            continue
        if "espèce" in str(c.get("motif", "") or "").lower() or "especes" in str(c.get("motif", "") or "").lower():
            continue
        cibles.append(("credits_admin", i, c, -abs(m)))
    # Chercher AUSSI dans corrections_pions (type "Correction" sur le releve)
    for i, c in enumerate(DB.get("corrections_pions", [])):
        if not isinstance(c, dict) or (c.get("code_joueur", "") or "").upper() != code:
            continue
        retire = int(c.get("montant_retire", 0) or 0)
        if retire <= 0:
            retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
        if retire != montant:
            continue
        if jour and str(c.get("date", ""))[:10] != jour:
            continue
        if heure and str(c.get("date", ""))[11:16] != heure:
            continue
        if "espèce" in str(c.get("motif", "") or "").lower() or "especes" in str(c.get("motif", "") or "").lower():
            continue
        cibles.append(("corrections_pions", i, c, -retire))
    if not cibles:
        return page("Aucune trace", "<p>Aucun debit de <b>" + format(montant, ",") + " F</b> trouve pour <b>" + code + "</b>" + ((" le " + jour) if jour else "") + ((" a " + heure) if heure else "") + " (ou deja requalifie).</p>", "#f85149")
    if not executer:
        corps = "<div style='background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;font-size:14px'><b>" + str(len(cibles)) + " trace(s)</b> pour <b>" + code + "</b> :<br><br>"
        for (src, i, c, m) in cibles:
            corps += "&bull; " + str(c.get("date", ""))[:16].replace("T", " ") + " : " + format(m, ",") + " F &mdash; &laquo; " + str(c.get("motif", "") or "Correction") + " &raquo;<br>"
        corps += "<br>&rarr; deviendra <b style='color:#3fb950'>Retrait en especes (boutique)</b>. <span style='color:#8b949e'>Aucun pion touche.</span></div>"
        corps += "<a href='?cle=" + _cle + "&code=" + code + "&montant=" + str(montant) + (("&jour=" + jour) if jour else "") + (("&heure=" + heure) if heure else "") + "&executer=1' style='display:block;text-align:center;background:#16a34a;color:#fff;padding:13px;border-radius:10px;text-decoration:none;font-weight:700;margin-top:14px'>&#9989; Requalifier</a>"
        return page("Requalifier — apercu", corps)
    n = 0
    for (src, i, c, m) in cibles:
        DB[src][i]["motif"] = "Retrait en espèces (boutique)"
        n += 1
    save_data(immediat=True)
    return page("Requalifie", "<div style='background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:10px;padding:16px;color:#6ee7b7'>&#9989; " + str(n) + " trace(s) de " + code + " requalifiee(s) en <b>Retrait especes (boutique)</b>.</div>", "#10b981")


@app.route("/dettes-joueuses")
def dettes_joueuses():
    """ADMIN — Liste des dettes de joueuses (avances especes a rembourser).
    ?cle=ADMIN[&payer=ID]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("Acces reserve.", status=403, mimetype="text/plain; charset=utf-8")
    payer = (request.args.get("payer", "") or "").strip()
    msg = ""
    if payer:
        for d in DB.get("dettes_joueuses", []):
            if d.get("id") == payer and d.get("statut") == "du":
                d["statut"] = "paye"
                d["date_paiement"] = datetime.datetime.now().isoformat()
                save_data(immediat=True)
                msg = "&#9989; " + d.get("code_joueur", "") + " a rembourse " + format(d.get("montant", 0), ",") + " F."
                break
    dettes = DB.get("dettes_joueuses", [])
    dues = [d for d in dettes if d.get("statut") == "du"]
    total_du = sum(int(d.get("montant", 0) or 0) for d in dues)
    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>Dettes joueuses</title><style>body{font-family:system-ui,sans-serif;background:#0d1117;color:#e6edf3;padding:20px;max-width:720px;margin:0 auto}h1{color:#f0883e}table{width:100%;border-collapse:collapse;margin-top:14px;font-size:13px}th{background:#161b22;border:1px solid #30363d;padding:9px;text-align:left;color:#8b949e}td{border:1px solid #30363d;padding:8px}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128181; Dettes des joueuses (avances a rembourser)</h1>"
    if msg:
        html += "<div style='background:#14532d;color:#bbf7d0;padding:12px;border-radius:8px;margin-bottom:12px'>" + msg + "</div>"
    html += "<div style='background:#161b22;border:1px solid #30363d;border-radius:8px;padding:14px;margin-bottom:12px'>TOTAL DU : <b style='font-size:18px;color:#f0883e'>" + format(total_du, ",") + " XPF</b></div>"
    if dues:
        html += "<table><tr><th>Date</th><th>Joueuse</th><th>Motif</th><th style='text-align:right'>Montant</th><th>Action</th></tr>"
        for d in dues:
            html += "<tr><td>" + str(d.get("date", ""))[:10] + "</td><td><b>" + d.get("code_joueur", "") + "</b>" + ((" — " + d.get("nom", "")) if d.get("nom") else "") + "</td><td style='font-size:12px'>" + str(d.get("motif", "")) + "</td>"
            html += "<td style='text-align:right;font-weight:bold'>" + format(d.get("montant", 0), ",") + " F</td>"
            html += "<td><a href='?cle=" + _cle + "&payer=" + d.get("id", "") + "' onclick=\"return confirm('Marquer comme rembourse ?')\">&#9989; Rembourse</a></td></tr>"
        html += "</table>"
    else:
        html += "<p style='color:#3fb950'>&#9989; Aucune dette en cours.</p>"
    html += "</body></html>"
    return html


@app.route("/verif-comptable-org")
def verif_comptable_org():
    """VERIFICATION COMPTABLE (11/07/2026) : rapprochement complet pour une
    organisatrice. Compare ce qui est ENTRE dans sa caisse (ventes de pions +
    encaissements de tickets) avec ce qui est SORTI (gains payes + remboursements),
    tient compte de la commande a credit (ardoise), et verifie si le resultat
    correspond a sa poche reelle actuelle. Affiche chaque ecart pour comprendre.
    Peut agreger l'ancien code ET le nouveau (parametre &aussi=ANCIEN_CODE).
    Page imprimable. Acces ADMIN : ?cle=CODE_ADMIN&org=CODE[&aussi=ANCIEN]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    aussi = (request.args.get("aussi", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG (et optionnellement &aussi=ANCIEN_CODE)</h1>", status=400, mimetype="text/html; charset=utf-8")
    codes = [org] + ([aussi] if aussi else [])
    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    # ENTREES : ventes de pions aux joueuses
    ventes_pions = 0
    nb_ventes_pions = 0
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_org", "") or "").upper() in codes:
            ventes_pions += _iv(t.get("montant_total", 0))
            nb_ventes_pions += 1
    # ENTREES : encaissements de tickets (mises)
    encaiss_tickets = 0
    nb_tickets = 0
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() in codes:
            encaiss_tickets += _iv(e.get("montant", 0))
            nb_tickets += 1
    total_entrees = ventes_pions + encaiss_tickets

    # SORTIES : gains payes (non annules)
    gains_payes = 0
    nb_gains = 0
    gains_annules = 0
    gains_vers_bloques = 0
    nb_gains_bloques = 0
    detail_gains_bloques = []
    _bloques = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() in codes:
            if g.get("annule"):
                gains_annules += _iv(g.get("montant_credite", 0))
            else:
                m = _iv(g.get("montant_credite", 0))
                gains_payes += m
                nb_gains += 1
                cg = (g.get("code_gagnant", "") or "").upper()
                if cg in _bloques:
                    gains_vers_bloques += m
                    nb_gains_bloques += 1
                    detail_gains_bloques.append((str(g.get("date", ""))[:16].replace("T", " "), cg, str(g.get("jeu", "?")), m))
    # SORTIES : remboursements
    remboursements = 0
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict) and (rb.get("code_org", "") or "").upper() in codes:
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    remboursements += _iv(det.get("montant", 0))
    total_sorties = gains_payes + remboursements

    # ARDOISE (commande a credit) : pions/jeux fournis par l'admin, a rembourser
    ardoise_due = 0
    for c in DB.get("credits_organisateurs", []):
        if isinstance(c, dict) and (c.get("code_org", "") or "").upper() in codes and c.get("statut") == "du":
            ardoise_due += _iv(c.get("montant", 0))

    # POCHE REELLE actuelle (sur tous les codes agreges)
    poche_reelle = 0
    for c in codes:
        poche_reelle += _xpf_total_pions(DB.get("pions_org", {}).get(c, {}))

    # RAISONNEMENT :
    # Ce qui devrait etre en poche = entrees - sorties (l'argent des joueuses moins les gains)
    # + les pions avances a credit (ils sont physiquement dans la poche jusqu'au remboursement)
    poche_theorique = total_entrees - total_sorties
    ecart = poche_reelle - poche_theorique

    def fmt(n): return format(n, ",")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Verification comptable</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:820px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:16px}"
    html += "table{width:100%;border-collapse:collapse;font-size:14px;margin:14px 0}"
    html += "td{border:1px solid #ccc;padding:9px}.dr{text-align:right;font-weight:bold;white-space:nowrap}"
    html += ".sect{background:#E8EEF6;font-weight:bold;color:#1F4E79}"
    html += ".pos{color:#1E7B34}.neg{color:#C00000}"
    html += ".big{font-size:16px}"
    html += ".verdict{border-radius:10px;padding:16px;margin:16px 0;font-size:15px}"
    html += ".ok{background:#E8F5E9;border:2px solid #1E7B34;color:#1E7B34}"
    html += ".warn{background:#FFF4E5;border:2px solid #E8830C;color:#9C4A00}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; Pour enregistrer : <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#129518; Verification comptable — " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Codes analyses : " + ", ".join(codes) + "</div>"

    html += "<table>"
    html += "<tr class='sect'><td colspan='2'>1. CE QUI EST ENTRE dans sa caisse (argent des joueuses)</td></tr>"
    html += "<tr><td>Ventes de pions aux joueuses (" + str(nb_ventes_pions) + " ventes)</td><td class='dr pos'>+" + fmt(ventes_pions) + " XPF</td></tr>"
    html += "<tr><td>Encaissements de tickets / mises (" + str(nb_tickets) + " tickets)</td><td class='dr pos'>+" + fmt(encaiss_tickets) + " XPF</td></tr>"
    html += "<tr><td><b>Total ENTRE</b></td><td class='dr pos big'>+" + fmt(total_entrees) + " XPF</td></tr>"
    html += "<tr class='sect'><td colspan='2'>2. CE QUI EST SORTI de sa caisse (paye aux joueuses)</td></tr>"
    html += "<tr><td>Gains payes aux gagnantes (" + str(nb_gains) + " gains)</td><td class='dr neg'>-" + fmt(gains_payes) + " XPF</td></tr>"
    html += "<tr><td>Remboursements</td><td class='dr neg'>-" + fmt(remboursements) + " XPF</td></tr>"
    if gains_annules:
        html += "<tr><td style='color:#888'>(Gains annules — non comptes)</td><td class='dr' style='color:#888'>" + fmt(gains_annules) + " XPF</td></tr>"
    html += "<tr><td><b>Total SORTI</b></td><td class='dr neg big'>-" + fmt(total_sorties) + " XPF</td></tr>"
    html += "<tr class='sect'><td colspan='2'>3. VERIFICATION</td></tr>"
    html += "<tr><td>Poche qu'elle DEVRAIT avoir (entre - sorti)</td><td class='dr'>" + fmt(poche_theorique) + " XPF</td></tr>"
    html += "<tr><td>Poche qu'elle a REELLEMENT (pions en caisse)</td><td class='dr'>" + fmt(poche_reelle) + " XPF</td></tr>"
    html += "<tr><td><b>Ecart</b></td><td class='dr " + ("pos" if ecart == 0 else "neg") + " big'>" + ("+" if ecart > 0 else "") + fmt(ecart) + " XPF</td></tr>"
    html += "</table>"

    # VERDICT
    if ecart == 0:
        html += "<div class='verdict ok'>&#9989; <b>COMPTES EQUILIBRES.</b> Ce qui est entre moins ce qui est sorti correspond exactement a ce qu'elle a en caisse. Tout est coherent.</div>"
    else:
        html += "<div class='verdict warn'>&#9888;&#65039; <b>Ecart de " + fmt(abs(ecart)) + " XPF</b> entre le theorique et la poche reelle. "
        if ecart < 0:
            html += "Sa poche est PLUS BASSE que le calcul. Causes possibles : des pions ont ete retires de sa caisse (corrections, transferts annules lors du nettoyage fraude du 11/07), ou des gains payes hors systeme. "
        else:
            html += "Sa poche est PLUS HAUTE que le calcul. Causes possibles : des pions credites directement (bonus, avance a credit non tracee en vente), ou un encaissement non enregistre comme vente. "
        html += "Cet ecart n'est pas forcement une erreur — il faut l'expliquer par les operations de correction. Voir le detail des mouvements dans /rapport-tournoi-org.</div>"

    # SEPARATION CAISSE vs ARDOISE
    html += "<h2 style='color:#1F4E79;margin-top:24px'>4. Controle anti-fraude : gains payes a des comptes bloques</h2>"
    if nb_gains_bloques > 0:
        html += "<div class='verdict warn'>&#9888;&#65039; <b>" + str(nb_gains_bloques) + " gain(s) pour un total de " + fmt(gains_vers_bloques) + " XPF</b> ont ete payes par cette organisatrice a des comptes qui sont AUJOURD'HUI bloques (reseau de fraude). Ces gains faisaient peut-etre partie du circuit frauduleux : ils gonflent artificiellement le total 'gains payes'. A examiner.</div>"
        html += "<table><tr><td class='sect'>Date</td><td class='sect'>Gagnante (bloquee)</td><td class='sect'>Jeu</td><td class='sect dr'>Montant</td></tr>"
        for (d, cg, jeu, m) in sorted(detail_gains_bloques, key=lambda x: -x[3]):
            html += "<tr><td>" + d + "</td><td>" + cg + "</td><td>" + jeu + "</td><td class='dr neg'>" + fmt(m) + " XPF</td></tr>"
        html += "</table>"
        html += "<div class='meta'>Note : ces gains ont deja ete verses. S'ils sont frauduleux, l'argent est chez des comptes bloques (donc recuperable via le bilan fraude). Cela n'enleve rien a la caisse de l'organisatrice, mais explique une partie de l'ecart : une part des 'ventes' encaissees venait de pions frauduleux qui ont ensuite ete nettoyes.</div>"
    else:
        html += "<div class='verdict ok'>&#9989; <b>Aucun gain paye a un compte bloque.</b> Tous les gains de cette organisatrice ont ete verses a des joueuses legitimes. Son activite de paiement est saine.</div>"

    html += "<h2 style='color:#1F4E79;margin-top:24px'>5. Ce qui revient a l'organisatrice</h2>"
    html += "<table>"
    html += "<tr><td>Caisse reelle actuelle (poche)</td><td class='dr'>" + fmt(poche_reelle) + " XPF</td></tr>"
    html += "<tr><td>Commande a credit a te rembourser (ardoise)</td><td class='dr neg'>-" + fmt(ardoise_due) + " XPF</td></tr>"
    html += "<tr class='sect'><td><b>Solde net revenant a l'organisatrice</b></td><td class='dr big'>" + fmt(poche_reelle - ardoise_due) + " XPF</td></tr>"
    html += "</table>"
    html += "<div class='meta'>La caisse contient l'argent encaisse des joueuses. Sur ce montant, " + fmt(ardoise_due) + " XPF correspondent aux jeux et pions avances par l'administration (a rembourser). Le reste (" + fmt(poche_reelle - ardoise_due) + " XPF) est le benefice net de l'organisatrice.</div>"
    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/transfert-poche-org")
def transfert_poche_org():
    """ADMIN (11/07/2026) : deplace les pions de la POCHE ORGANISATEUR d'un code
    vers un autre. Sert notamment apres un changement de code : l'historique suit
    automatiquement mais la poche de pions org doit etre deplacee a la main.
    Ne DETRUIT rien : les pions passent d'une poche a l'autre, traces des deux cotes.
    ?cle=ADMIN&de=ANCIEN&vers=NOUVEAU[&montant=N][&confirme=1]
    Sans montant : deplace TOUTE la poche source."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    de = (request.args.get("de", "") or "").strip().upper()
    vers = (request.args.get("vers", "") or "").strip().upper()
    confirme = request.args.get("confirme", "") == "1"

    def page(titre, corps, couleur="#1F4E79"):
        return Response("<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>" + titre + "</title></head><body style='margin:0;background:#0d1117;font-family:system-ui,sans-serif;color:#e6edf3;padding:18px'><div style='max-width:560px;margin:0 auto'><h1 style='font-size:20px;color:" + couleur + "'>" + titre + "</h1>" + corps + "</div></body></html>", mimetype="text/html; charset=utf-8")

    if not de or not vers:
        return page("Parametres manquants", "<p>Ajoute <b>&de=ANCIEN_CODE&vers=NOUVEAU_CODE</b>.</p>", "#f85149")

    poche_src = dict(DB.get("pions_org", {}).get(de, {}))
    solde_src = _xpf_total_pions(poche_src)
    poche_dst_avant = _xpf_total_pions(DB.get("pions_org", {}).get(vers, {}))

    try:
        montant = int(request.args.get("montant", "0") or 0)
    except ValueError:
        montant = 0
    if montant <= 0:
        montant = solde_src  # tout par defaut

    if solde_src <= 0:
        return page("Poche source vide", "<p>La poche organisateur de <b>" + de + "</b> est a 0. Rien a transferer.</p>", "#f85149")
    if montant > solde_src:
        return page("Montant trop eleve", "<p>La poche de <b>" + de + "</b> contient <b>" + format(solde_src, ",") + " F</b>, tu demandes <b>" + format(montant, ",") + " F</b>. Reduis le montant.</p>", "#f85149")

    if not confirme:
        corps = "<div style='background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;font-size:14px'>"
        corps += "<div>De (poche ORG) : <b style='font-family:monospace;color:#fca5a5'>" + de + "</b> &mdash; contient <b>" + format(solde_src, ",") + " F</b></div>"
        corps += "<div style='margin-top:6px'>Vers (poche ORG) : <b style='font-family:monospace;color:#6ee7b7'>" + vers + "</b> &mdash; contient <b>" + format(poche_dst_avant, ",") + " F</b></div>"
        corps += "<div style='margin-top:6px'>Montant a deplacer : <b style='font-size:18px;color:#58a6ff'>" + format(montant, ",") + " F</b></div>"
        corps += "<div style='margin-top:6px;color:#8b949e'>Apres : " + de + " aura " + format(solde_src - montant, ",") + " F, " + vers + " aura " + format(poche_dst_avant + montant, ",") + " F</div></div>"
        corps += "<a href='?cle=" + _cle + "&de=" + de + "&vers=" + vers + "&montant=" + str(montant) + "&confirme=1' style='display:block;text-align:center;background:#16a34a;color:#fff;padding:13px;border-radius:10px;text-decoration:none;font-weight:700;margin-top:14px'>&#128257; Confirmer le transfert de " + format(montant, ",") + " F</a>"
        return page("Transfert poche organisateur", corps)

    # CONFIRME : deplacer (par denomination, en preservant les coupures)
    if _debiter_pions_montant(poche_src, montant):
        DB.setdefault("pions_org", {})[de] = poche_src
        poche_dst = dict(DB.get("pions_org", {}).get(vers, {}))
        _crediter_pions_montant(poche_dst, montant)
        DB.setdefault("pions_org", {})[vers] = poche_dst
        DB.setdefault("transferts_poche_org", []).insert(0, {
            "de": de, "vers": vers, "montant": montant, "par": _cle,
            "date": datetime.datetime.now().isoformat()
        })
        save_data(immediat=True)
        corps = "<div style='background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:10px;padding:16px;color:#6ee7b7;font-size:15px'>"
        corps += "&#9989; <b>Transfert effectue !</b><br><br>"
        corps += format(montant, ",") + " F deplaces de la poche org <b>" + de + "</b> vers <b>" + vers + "</b>.<br><br>"
        corps += "Nouvelle poche de <b>" + vers + "</b> : <b>" + format(_xpf_total_pions(DB['pions_org'][vers]), ",") + " F</b><br>"
        corps += "Poche de <b>" + de + "</b> : <b>" + format(_xpf_total_pions(DB['pions_org'][de]), ",") + " F</b></div>"
        return page("Transfert reussi", corps, "#10b981")
    return page("Echec", "<p>Le transfert n'a pas pu se faire (denominations non divisibles). Reessaie avec un montant multiple de 10.</p>", "#f85149")


@app.route("/rapport-tournoi-org")
def rapport_tournoi_org():
    """RAPPORT COMPLET (11/07/2026) : toutes les transactions liees a une
    organisatrice, transaction par transaction, avec totaux. Regroupe :
    ventes de pions aux joueuses, encaissements de tickets, gains payes aux
    gagnantes, cagnottes, remboursements. Page imprimable (Ctrl+P -> PDF).
    Les codes joueuses restent visibles ; le code org et la cle admin ne sont
    pas exposes. Acces ADMIN : ?cle=CODE_ADMIN&org=CODE_ORG."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    if not org:
        return Response("<h1 style='font-family:sans-serif'>Ajoute &org=CODE_ORG a l'adresse</h1>", status=400, mimetype="text/html; charset=utf-8")

    nom_org = (DB.get("codes", {}).get(org, {}) or {}).get("nom", org)

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    lignes = []  # (date, type, joueuse, detail, entree_pour_org, sortie_pour_org)

    # 1. Ventes de pions aux joueuses (l'org encaisse) — transactions_joueur_org
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and (t.get("code_org", "") or "").upper() == org:
            m = _iv(t.get("montant_total", 0))
            lignes.append((str(t.get("date", "")), "Vente pions", (t.get("code_joueur", "") or "").upper(),
                           str(t.get("nb_pions", "?")) + " x " + str(t.get("valeur_pion", "?")) + " XPF", m, 0))

    # 2. Encaissements de tickets (l'org encaisse la mise) — encaissements_org
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_org", "") or "").upper() == org:
            m = _iv(e.get("montant", 0))
            lignes.append((str(e.get("date", "")), "Vente ticket", (e.get("code_joueur", "") or "").upper(),
                           str(e.get("jeu", "?")), m, 0))

    # 3. Gains payes aux gagnantes (l'org paie) — gains_finaux
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and (g.get("code_org", "") or "").upper() == org:
            m = _iv(g.get("montant_credite", 0))
            annul = g.get("annule")
            lignes.append((str(g.get("date", "")), "Gain paye" + (" ANNULE" if annul else ""),
                           (g.get("code_gagnant", "") or "").upper(),
                           str(g.get("jeu", "?")) + (" (annule)" if annul else ""), 0, 0 if annul else m))

    # 4. Remboursements effectues sur ses tournois
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict) and (rb.get("code_org", "") or "").upper() == org:
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    lignes.append((str(rb.get("date", "")), "Remboursement", (det.get("code_joueur", "") or "").upper(),
                                   str(rb.get("jeu", "?")), 0, _iv(det.get("montant", 0))))

    lignes.sort(key=lambda r: r[0])
    tot_entrees = sum(r[4] for r in lignes)
    tot_sorties = sum(r[5] for r in lignes)
    solde_theorique = tot_entrees - tot_sorties

    # Poche actuelle de l'org
    poche = _xpf_total_pions(DB.get("pions_org", {}).get(org, {}))

    # Comptage par type
    nb_ventes_pions = sum(1 for r in lignes if r[1] == "Vente pions")
    nb_tickets = sum(1 for r in lignes if r[1] == "Vente ticket")
    nb_gains = sum(1 for r in lignes if r[1].startswith("Gain paye") and "ANNULE" not in r[1])

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Rapport tournoi</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:24px;max-width:960px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:16px}"
    html += ".cards{display:flex;flex-wrap:wrap;gap:10px;margin:16px 0}"
    html += ".card{flex:1;min-width:150px;background:#F5F7FA;border:1px solid #ccc;border-radius:8px;padding:12px;text-align:center}"
    html += ".card .v{font-size:20px;font-weight:bold;color:#1F4E79}.card .l{font-size:12px;color:#555}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin-top:12px}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:7px;text-align:left}"
    html += "td{border:1px solid #bbb;padding:6px}.dr{text-align:right;white-space:nowrap}"
    html += ".pos{color:#1E7B34}.neg{color:#C00000}"
    html += "tr:nth-child(even){background:#FAFBFC}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; Pour enregistrer : <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128202; Rapport d'activite — organisatrice " + str(nom_org) + "</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT (N&deg; TAHITI B90121, Papeete) &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; Document confidentiel</div>"

    html += "<div class='cards'>"
    html += "<div class='card'><div class='v pos'>+" + format(tot_entrees, ",") + "</div><div class='l'>ENCAISSE (ventes pions + tickets)</div></div>"
    html += "<div class='card'><div class='v neg'>-" + format(tot_sorties, ",") + "</div><div class='l'>PAYE (gains + remboursements)</div></div>"
    html += "<div class='card'><div class='v'>" + format(solde_theorique, ",") + "</div><div class='l'>SOLDE THEORIQUE (encaisse - paye)</div></div>"
    html += "<div class='card'><div class='v'>" + format(poche, ",") + "</div><div class='l'>POCHE ACTUELLE (pions org)</div></div>"
    html += "</div>"
    html += "<div class='meta'>" + str(nb_ventes_pions) + " ventes de pions &middot; " + str(nb_tickets) + " ventes de tickets &middot; " + str(nb_gains) + " gains payes &middot; " + str(len(lignes)) + " transactions au total</div>"

    if lignes:
        html += "<table><tr><th style='width:120px'>Date</th><th style='width:110px'>Type</th><th style='width:95px'>Joueuse</th><th>Detail</th><th class='dr' style='width:85px'>Encaisse</th><th class='dr' style='width:85px'>Paye</th></tr>"
        for (d, ty, jou, det, e, s) in lignes:
            lien_jou = ("<a href='/releve-financier-joueur/" + jou + "?cle=" + _cle + "' target='_blank'>" + jou + "</a>") if jou else ""
            html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + ty + "</td><td>" + lien_jou + "</td><td>" + det + "</td>"
            html += "<td class='dr pos'>" + ("+" + format(e, ",") if e else "") + "</td>"
            html += "<td class='dr neg'>" + ("-" + format(s, ",") if s else "") + "</td></tr>"
        html += "<tr style='background:#DEEAF6;font-weight:bold'><td colspan='4' style='text-align:right'>TOTAUX</td>"
        html += "<td class='dr pos'>+" + format(tot_entrees, ",") + "</td><td class='dr neg'>-" + format(tot_sorties, ",") + "</td></tr>"
        html += "</table>"
        html += "<div style='margin-top:12px;font-size:12px;color:#555'>&#128279; Chaque code de joueuse est cliquable : il ouvre le releve financier detaille de cette joueuse, pour verifier chaque transaction des deux cotes (organisatrice et joueuse).</div>"
    else:
        html += "<p>Aucune transaction trouvee pour cette organisatrice.</p>"

    html += "<div style='margin-top:18px;font-size:13px'><strong>Lecture :</strong> le SOLDE THEORIQUE (" + format(solde_theorique, ",") + " XPF) represente ce que l'organisatrice devrait avoir en caisse (encaissements moins gains payes). La POCHE ACTUELLE (" + format(poche, ",") + " XPF) est ce qu'elle a reellement en pions sur la plateforme. Un ecart peut venir de retraits en especes deja effectues ou de decouverts completes de sa poche.</div>"

    # === RECAPITULATIF PAR JOUEUSE (relie aux releves) ===
    par_j = {}
    for (d, ty, jou, det, e, s) in lignes:
        if not jou:
            continue
        par_j.setdefault(jou, {"encaisse": 0, "paye": 0, "nb": 0})
        par_j[jou]["encaisse"] += e
        par_j[jou]["paye"] += s
        par_j[jou]["nb"] += 1
    recap = sorted(par_j.items(), key=lambda x: -(x[1]["encaisse"] + x[1]["paye"]))
    html += "<h2 style='color:#1F4E79;margin-top:26px'>Recapitulatif par joueuse &mdash; relie aux releves</h2>"
    html += "<div style='font-size:12px;color:#555;margin-bottom:8px'>Pour chaque joueuse ayant eu une activite chez cette organisatrice : total depense (achats de pions/tickets) et total recu (gains). Le code est cliquable vers son releve detaille.</div>"
    html += "<table><tr><th style='width:110px'>Joueuse</th><th class='dr'>Transactions</th><th class='dr'>A depense (encaisse par l'org)</th><th class='dr'>A recu (gains)</th><th>Releve</th></tr>"
    for jou, v in recap:
        html += "<tr><td><a href='/releve-financier-joueur/" + jou + "?cle=" + _cle + "' target='_blank'>" + jou + "</a></td>"
        html += "<td class='dr'>" + str(v["nb"]) + "</td>"
        html += "<td class='dr pos'>" + format(v["encaisse"], ",") + "</td>"
        html += "<td class='dr neg'>" + format(v["paye"], ",") + "</td>"
        html += "<td style='font-size:11px'><a href='/releve-financier-joueur/" + jou + "?cle=" + _cle + "' target='_blank'>ouvrir le releve &rarr;</a></td></tr>"
    html += "</table>"
    html += "<div style='font-size:12px;color:#555;margin-top:6px'>" + str(len(recap)) + " joueuse(s) distincte(s) ont eu une activite chez cette organisatrice.</div>"

    html += "<p style='margin-top:22px;text-align:right;font-size:13px'><strong>L'Administration — TATIE TUKEA</strong><br>TUKEA IMPORT — Ticket Bingo, Papeete</p>"
    html += "</body></html>"
    return html


@app.route("/dossier-reseau")
def dossier_reseau():
    """DOSSIER DE PREUVE (11/07/2026) : genere le releve COMPLET de chaque code
    du reseau de fraude (tous les codes bloques), RT50CJ en tete. Pour chaque
    code : ses adresses IP relevees, tous ses mouvements dates (entrees,
    sorties, transferts avec contreparties, corrections) et ses soldes finaux.
    Page imprimable (Ctrl+P -> PDF) pour archives et contestations.
    Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    ips_par_code = {}
    for j in DB.get("journal_connexions", []):
        cj = (j.get("code") or "").upper().strip()
        ip_j = (j.get("ip") or "").strip()
        if cj and ip_j:
            ips_par_code.setdefault(cj, set()).add(ip_j)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("ip") or "").strip():
            for k in ("de", "vers"):
                ck = (t.get(k) or "").upper().strip()
                if ck:
                    ips_par_code.setdefault(ck, set()).add((t.get("ip") or "").strip())

    def _iv(x):
        try:
            return int(x or 0)
        except (ValueError, TypeError):
            return 0

    def mouvements(code):
        mv = []
        for c in DB.get("commandes_pions_joueurs", []):
            if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() == code and c.get("statut") == "validee":
                m = _iv(c.get("nb_pions", c.get("pions_credites", 0))) * _iv(c.get("valeur_pion", 0))
                if m <= 0:
                    m = _iv(c.get("montant_net", 0))
                mv.append((str(c.get("date", "")), "Achat pions", "commande validee", m))
        for t in DB.get("transactions_joueur_org", []):
            if isinstance(t, dict) and (t.get("code_joueur", "") or "").upper() == code:
                mv.append((str(t.get("date", "")), "Pions recus (org)", "vendu par org " + str(t.get("code_org", "?")), _iv(t.get("montant_total", 0))))
        for g in DB.get("gains_finaux", []):
            if isinstance(g, dict) and (g.get("code_gagnant", "") or "").upper() == code:
                if g.get("annule"):
                    mv.append((str(g.get("date", "")), "Gain ANNULE", str(g.get("jeu", "?")), 0))
                else:
                    mv.append((str(g.get("date", "")), "Gain", str(g.get("jeu", "?")) + " (org " + str(g.get("code_org", "?")) + ")", _iv(g.get("montant_credite", 0))))
        for c in DB.get("credits_admin", []):
            if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() == code:
                m = _iv(c.get("nb_pions", 0)) * _iv(c.get("valeur_pion", 0))
                mv.append((str(c.get("date", "")), "Credit admin" if m >= 0 else "Reprise admin", str(c.get("motif", "") or "") + " (par " + str(c.get("par", "?")) + ")", m))
        for cm in DB.get("credits_masse", []):
            if isinstance(cm, dict) and cm.get("profil", "joueur") == "joueur" and code in [(x or "").upper() for x in (cm.get("codes") or [])]:
                m = _iv(cm.get("nb_pions", 0)) * _iv(cm.get("valeur_pion", 0))
                mv.append((str(cm.get("date", "")), "Credit masse", str(cm.get("motif", "") or "dedommagement"), m))
        for rb in DB.get("remboursements_tournoi", []):
            if isinstance(rb, dict):
                for det in (rb.get("detail") or []):
                    if isinstance(det, dict) and (det.get("code_joueur", "") or "").upper() == code:
                        mv.append((str(rb.get("date", "")), "Remboursement", str(rb.get("jeu", "?")), _iv(det.get("montant", 0))))
        for x in DB.get("rejoindre_log", []):
            if (x.get("code", "") or "").upper() == code and (x.get("campagne", "") or "") == "semaine":
                mv.append((str(x.get("date", "")), "Cadeau inscription", "bonus QR semaine", 500))
                break
        for e in DB.get("encaissements_org", []):
            if isinstance(e, dict) and (e.get("code_joueur", "") or "").upper() == code:
                mv.append((str(e.get("date", "")), "Achat tickets", str(e.get("jeu", "?")) + " (org " + str(e.get("code_org", "?")) + ")", -_iv(e.get("montant", 0))))
        for r in DB.get("demandes_retrait", []):
            if isinstance(r, dict) and (r.get("code_joueur", "") or "").upper() == code and r.get("statut") == "validee":
                mv.append((str(r.get("date", "")), "RETRAIT ARGENT", "retrait valide", -_iv(r.get("montant_demande", 0))))
        for c in DB.get("corrections_pions", []):
            if isinstance(c, dict) and (c.get("code_joueur", "") or "").upper() == code:
                retire = _iv(c.get("montant_retire", 0))
                if retire <= 0:
                    retire = _iv(c.get("solde_avant", 0)) - _iv(c.get("solde_apres", 0))
                mv.append((str(c.get("date", "")), "Correction", str(c.get("motif", "") or "correction admin"), -max(0, retire)))
        for t in DB.get("transferts_pions", []):
            if not isinstance(t, dict):
                continue
            de = (t.get("de", "") or "").upper()
            vers = (t.get("vers", "") or "").upper()
            m = _iv(t.get("montant", 0))
            annul = " [ANNULE FRAUDE le " + str(t.get("annule_fraude_date", ""))[:10] + "]" if t.get("annule_fraude") else ""
            if de == code:
                mv.append((str(t.get("date", "")), "Transfert EMIS" + (" ANNULE" if annul else ""), "vers " + vers + (" (" + str(t.get("ip", "")) + ")" if t.get("ip") else "") + annul, 0 if annul else -m))
            if vers == code:
                mv.append((str(t.get("date", "")), "Transfert RECU" + (" ANNULE" if annul else ""), "de " + de + annul, 0 if annul else m))
        mv.sort(key=lambda r: r[0])
        return mv

    bloques = sorted(set((b or "").upper() for b in DB.get("codes_bloques", []) if b))
    if "RT50CJ" in bloques:
        bloques.remove("RT50CJ")
        bloques.insert(0, "RT50CJ")

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Dossier reseau fraude</title><style>"
    html += "body{font-family:Arial,sans-serif;background:#fff;color:#111;padding:26px;max-width:960px;margin:0 auto}"
    html += "h1{color:#1F4E79;border-bottom:3px solid #1F4E79;padding-bottom:8px}h2{color:#C00000;margin-top:34px;page-break-before:auto}"
    html += ".meta{color:#555;font-size:13px;margin-bottom:18px}"
    html += ".fiche{border:1px solid #bbb;border-radius:8px;padding:14px 16px;margin:18px 0;page-break-inside:avoid}"
    html += ".ips{background:#FFF7E6;border:1px solid #E8C77B;border-radius:6px;padding:8px 10px;font-size:12px;margin:8px 0}"
    html += "table{width:100%;border-collapse:collapse;font-size:12px;margin-top:8px}"
    html += "th{background:#E8EEF6;border:1px solid #999;padding:6px;text-align:left}"
    html += "td{border:1px solid #bbb;padding:5px}.dr{text-align:right;white-space:nowrap}"
    html += ".neg{color:#C00000}.pos{color:#1E7B34}.zero{color:#777}"
    html += ".soldes{font-weight:bold;margin-top:8px;font-size:13px}"
    html += "@media print{.noprint{display:none}}"
    html += "</style></head><body>"
    html += "<div class='noprint' style='background:#E8EEF6;padding:10px 14px;border-radius:8px;margin-bottom:14px'>&#128424;&#65039; Pour archiver ce dossier : <strong>Ctrl+P &rarr; Enregistrer en PDF</strong></div>"
    html += "<h1>&#128737;&#65039; DOSSIER DE PREUVE — Reseau de fraude RT50CJ</h1>"
    html += "<div class='meta'>TICKET BINGO — TUKEA IMPORT (N&deg; TAHITI B90121, Papeete) &middot; Genere le " + datetime.datetime.now().strftime("%d/%m/%Y a %H:%M") + " &middot; " + str(len(bloques)) + " codes bloques &middot; Document confidentiel — administration</div>"
    html += "<p style='font-size:13px'>Ce dossier presente, pour chaque compte du reseau bloque, l'integralite de ses mouvements traces (entrees, sorties, transferts avec contreparties et adresses IP, corrections) ainsi que ses soldes finaux. Toutes les donnees proviennent directement de la base de la plateforme et font foi.</p>"

    for code in bloques:
        pj = _xpf_total_pions(DB.get("pions_joueurs", {}).get(code, {}))
        pb = _xpf_total_pions(DB.get("pions_bonus_joueurs", {}).get(code, {}))
        po = _xpf_total_pions(DB.get("pions_org", {}).get(code, {})) if code in DB.get("codes", {}) else 0
        mv = mouvements(code)
        tot_e = sum(m for (_, _, _, m) in mv if m > 0)
        tot_s = sum(-m for (_, _, _, m) in mv if m < 0)
        titre_c = code + (" — " + noms[code] if code in noms and noms[code] else "")
        if code == "RT50CJ":
            titre_c += "  [PIVOT DU RESEAU]"
        html += "<div class='fiche'><h2 style='margin-top:0'>" + titre_c + " <span style='font-size:13px;color:#C00000'>&#128683; BLOQUE</span></h2>"
        ips = sorted(ips_par_code.get(code, set()))
        html += "<div class='ips'><strong>Adresses IP relevees :</strong> " + (", ".join(ips) if ips else "aucune enregistree (compte anterieur au journal des connexions)") + "</div>"
        if mv:
            html += "<table><tr><th style='width:120px'>Date</th><th style='width:150px'>Type</th><th>Detail</th><th class='dr' style='width:90px'>Montant</th></tr>"
            for (d, ty, det, m) in mv:
                cls = "pos" if m > 0 else ("neg" if m < 0 else "zero")
                html += "<tr><td>" + d[:16].replace("T", " ") + "</td><td>" + ty + "</td><td>" + det + "</td><td class='dr " + cls + "'>" + ("+" if m > 0 else "") + format(m, ",") + "</td></tr>"
            html += "</table>"
        else:
            html += "<p style='font-size:12px;color:#777'>Aucun mouvement trace (compte anterieur aux journaux, traite par vidage direct).</p>"
        html += "<div class='soldes'>Total entrees tracees : <span class='pos'>+" + format(tot_e, ",") + " XPF</span> &middot; Total sorties tracees : <span class='neg'>-" + format(tot_s, ",") + " XPF</span><br>"
        html += "SOLDES FINAUX : poche reelle <strong>" + format(pj, ",") + "</strong> &middot; bonus <strong>" + format(pb, ",") + "</strong>"
        if code in DB.get("codes", {}):
            html += " &middot; organisateur <strong>" + format(po, ",") + "</strong>"
        html += " XPF &mdash; <span style='color:#1E7B34'>compte neutralise</span></div></div>"

    html += "<p style='margin-top:26px;font-size:13px;font-style:italic'>Fin du dossier — " + str(len(bloques)) + " comptes documentes. L'Administration, TATIE TUKEA — Ticket Bingo, Papeete.</p>"
    html += "</body></html>"
    return html


@app.route("/bilan-fraude")
def bilan_fraude():
    """BILAN FRAUDE (11/07/2026) : la page de CLOTURE du dossier fraude.
    En un coup d'oeil : 1) chaque code bloque avec son etat (poche videe ?
    transferts annules ?) et l'action restante s'il y en a une ;
    2) les emetteurs de transferts NON bloques (fraudeurs potentiels non
    encore traites) ; 3) le total purge. LECTURE SEULE, avec liens vers les
    outils d'action. Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    # === ACTIONS EN MASSE (uniquement sur les codes DEJA BLOQUES = deja juges) ===
    _bloques_set = set((b or "").upper() for b in DB.get("codes_bloques", []) if b)
    msg_action = ""
    if (request.args.get("annuler_tous", "") or "") == "1":
        nb_a = 0
        tot_a = 0
        now = datetime.datetime.now().isoformat()
        for t in DB.get("transferts_pions", []):
            if isinstance(t, dict) and not t.get("annule_fraude") and (t.get("de") or "").upper() in _bloques_set:
                t["annule_fraude"] = True
                t["annule_fraude_date"] = now
                t["annule_fraude_par"] = _cle
                nb_a += 1
                tot_a += int(t.get("montant", 0) or 0)
        if nb_a:
            DB.setdefault("annulations_fraude", []).insert(0, {
                "code_fraudeur": "TOUS-LES-BLOQUES", "nb_transferts": nb_a,
                "total": tot_a, "par": _cle, "date": now})
            save_data(immediat=True)
        msg_action = "&#9989; " + str(nb_a) + " transfert(s) de codes bloques annules (" + format(tot_a, ",") + " XPF)."
    if (request.args.get("vider_bloques", "") or "") == "1":
        nb_v = 0
        tot_v = 0
        now = datetime.datetime.now().isoformat()
        for b in _bloques_set:
            repris_b = 0
            for nom_p in ("pions_joueurs", "pions_bonus_joueurs", "pions_org"):
                if nom_p == "pions_org" and b not in DB.get("codes", {}):
                    continue
                poche = dict(DB.get(nom_p, {}).get(b, {}))
                part = _xpf_total_pions(poche)
                if part > 0 and _debiter_pions_montant(poche, part):
                    DB.setdefault(nom_p, {})[b] = poche
                    repris_b += part
            if repris_b > 0:
                DB.setdefault("corrections_pions", []).insert(0, {
                    "code_joueur": b, "montant_retire": repris_b,
                    "motif": "Pions de fraude retirés (compte banni — solde résiduel, bilan fraude)",
                    "par": _cle, "date": now})
                nb_v += 1
                tot_v += repris_b
        if nb_v:
            save_data(immediat=True)
        msg_action += " &#9989; " + str(nb_v) + " poche(s) residuelle(s) videe(s) (" + format(tot_v, ",") + " XPF)."
    _clot = (request.args.get("cloturer", "") or "").strip().upper()
    if _clot:
        DB.setdefault("emetteurs_clotures", [])
        if _clot not in DB["emetteurs_clotures"]:
            DB["emetteurs_clotures"].append(_clot)
            save_data(immediat=True)
        msg_action += " &#9989; " + _clot + " cloture comme legitime (transferts juges normaux)."
    _rouv = (request.args.get("rouvrir", "") or "").strip().upper()
    if _rouv and _rouv in DB.get("emetteurs_clotures", []):
        DB["emetteurs_clotures"] = [x for x in DB["emetteurs_clotures"] if x != _rouv]
        save_data(immediat=True)
        msg_action += " &#128260; " + _rouv + " reouvert pour examen."
    # Transferts par emetteur (actifs / annules)
    emis_actifs = {}
    emis_annules = {}
    for t in DB.get("transferts_pions", []):
        if not isinstance(t, dict):
            continue
        de = (t.get("de") or "").upper().strip()
        m = int(t.get("montant", 0) or 0)
        if not de or m <= 0:
            continue
        if t.get("annule_fraude"):
            emis_annules[de] = emis_annules.get(de, 0) + m
        else:
            emis_actifs[de] = emis_actifs.get(de, 0) + m

    # Pions fraude repris par code (vidages + corrections liees a la fraude)
    repris_fraude = {}
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict):
            motif_u = str(c.get("motif", "") or "").lower()
            if "fraude" in motif_u or "banni" in motif_u or "fabriqu" in motif_u:
                cj = (c.get("code_joueur") or "").upper().strip()
                retire = int(c.get("montant_retire", 0) or 0)
                if retire <= 0:
                    retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
                if cj and retire > 0:
                    repris_fraude[cj] = repris_fraude.get(cj, 0) + retire

    bloques = [(b or "").upper() for b in DB.get("codes_bloques", []) if b]

    # SECTION 1 : etat de chaque code bloque
    lignes_b = []
    actions_restantes = 0
    for b in sorted(set(bloques)):
        pj = _xpf_total_pions(DB.get("pions_joueurs", {}).get(b, {}))
        pb = _xpf_total_pions(DB.get("pions_bonus_joueurs", {}).get(b, {}))
        po = _xpf_total_pions(DB.get("pions_org", {}).get(b, {})) if b in DB.get("codes", {}) else 0
        poche = pj + pb + po
        actifs = emis_actifs.get(b, 0)
        etat_ok = (poche == 0 and actifs == 0)
        if not etat_ok:
            actions_restantes += 1
        lignes_b.append({"code": b, "nom": noms.get(b, ""), "poche": poche,
                         "actifs": actifs, "annules": emis_annules.get(b, 0),
                         "repris": repris_fraude.get(b, 0), "ok": etat_ok})
    lignes_b.sort(key=lambda r: (r["ok"], -(r["poche"] + r["actifs"])))

    # SECTION 2 : emetteurs de transferts NON bloques (a examiner)
    # Croisement IP automatique : les IP de chaque emetteur (connexions +
    # transferts) sont comparees a TOUTES les IP du reseau bloque.
    ips_par_code = {}
    for j in DB.get("journal_connexions", []):
        cj = (j.get("code") or "").upper().strip()
        ip_j = (j.get("ip") or "").strip()
        if cj and ip_j:
            ips_par_code.setdefault(cj, set()).add(ip_j)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            ip_t = (t.get("ip") or "").strip()
            if ip_t:
                for k in ("de", "vers"):
                    ck = (t.get(k) or "").upper().strip()
                    if ck:
                        ips_par_code.setdefault(ck, set()).add(ip_t)
    ips_reseau = set()
    for b in set(bloques):
        ips_reseau |= ips_par_code.get(b, set())

    clotures = set((x or "").upper() for x in DB.get("emetteurs_clotures", []))
    lignes_e = []
    for de, m in emis_actifs.items():
        if de in bloques or de in clotures:
            continue
        communes = sorted(ips_par_code.get(de, set()) & ips_reseau)
        lignes_e.append({"code": de, "nom": noms.get(de, ""), "montant": m,
                         "est_org": de in DB.get("codes", {}),
                         "communes": communes})
    lignes_e.sort(key=lambda r: (0 if r["communes"] else 1, -r["montant"]))

    total_repris = sum(repris_fraude.values())
    total_annules = sum(emis_annules.values())

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Bilan fraude</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#f85149}h2{color:#58a6ff;margin-top:30px}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".totaux{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:16px 0;display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:14px;text-align:center}"
    html += ".m{font-size:18px;font-weight:bold}"
    html += "table{width:100%;border-collapse:collapse;margin-top:14px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128737;&#65039; Bilan fraude — page de cloture</h1>"
    if msg_action:
        html += "<div style='background:#14532d;color:#bbf7d0;padding:14px 18px;border-radius:10px;margin-bottom:16px;font-weight:600'>" + msg_action + "</div>"
    html += "<div class='totaux'>"
    html += "<div><strong>Codes bloques</strong><br><span class='m'>" + str(len(set(bloques))) + "</span></div>"
    html += "<div><strong>Pions fraude repris</strong><br><span class='m ok'>" + format(total_repris, ",") + " XPF</span></div>"
    html += "<div><strong>Transferts annules</strong><br><span class='m ok'>" + format(total_annules, ",") + " XPF</span></div>"
    html += "<div><strong>Actions restantes</strong><br><span class='m " + ("ko" if (actions_restantes + len(lignes_e)) else "ok") + "'>" + str(actions_restantes + len(lignes_e)) + "</span></div>"
    html += "</div>"

    html += "<h2>1&#65039;&#8283; Etat des codes bloques</h2>"
    html += "<div class='sub'>Un code bloque est NEUTRALISE quand sa poche est a 0 ET tous ses transferts emis sont annules. Sinon, l'action restante est indiquee.</div>"
    _tot_actifs_bloques = sum(r["actifs"] for r in lignes_b)
    _tot_poches_bloques = sum(r["poche"] for r in lignes_b)
    if _tot_actifs_bloques > 0:
        html += "<a style='display:inline-block;margin:6px 8px 6px 0;padding:12px 20px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold' href='?cle=" + _cle + "&annuler_tous=1' onclick=\"return confirm('Annuler TOUS les transferts actifs emis par les codes bloques (" + format(_tot_actifs_bloques, ",") + " XPF) ?')\">&#128683; ANNULER TOUS LEURS TRANSFERTS (" + format(_tot_actifs_bloques, ",") + " XPF)</a>"
    if _tot_poches_bloques > 0:
        html += "<a style='display:inline-block;margin:6px 0;padding:12px 20px;background:#f0883e;color:#0d1117;border-radius:10px;text-decoration:none;font-weight:bold' href='?cle=" + _cle + "&vider_bloques=1' onclick=\"return confirm('Vider les poches residuelles des codes bloques (" + format(_tot_poches_bloques, ",") + " XPF) ?')\">&#129688; VIDER LEURS POCHES RESIDUELLES (" + format(_tot_poches_bloques, ",") + " XPF)</a>"
    if lignes_b:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Poche restante</th><th class='dr'>Transferts emis ACTIFS</th><th class='dr'>Transferts annules</th><th class='dr'>Pions repris</th><th>Etat / Action</th></tr>"
        for r in lignes_b:
            if r["ok"]:
                etat = "<span class='ok'>&#9989; NEUTRALISE</span>"
            else:
                a = []
                if r["poche"] > 0:
                    a.append("vider la poche (<a href='/quarantaine-code?cle=" + _cle + "&code=" + r["code"] + "'>quarantaine</a>)")
                if r["actifs"] > 0:
                    a.append("<a href='/annuler-transferts-fraude?cle=" + _cle + "&code=" + r["code"] + "'>annuler ses transferts</a>")
                etat = "<span class='ko'>&#9888;&#65039; " + " + ".join(a) + "</span>"
            html += "<tr><td><a href='/trace-pions?cle=" + _cle + "&code=" + r["code"] + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + "</td>"
            html += "<td class='dr'>" + format(r["poche"], ",") + "</td>"
            html += "<td class='dr'>" + (("<strong class='ko'>" + format(r["actifs"], ",") + "</strong>") if r["actifs"] else "0") + "</td>"
            html += "<td class='dr'>" + format(r["annules"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["repris"], ",") + "</td>"
            html += "<td>" + etat + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok'>Aucun code bloque.</p>"

    html += "<h2>2&#65039;&#8283; Emetteurs de transferts NON bloques</h2>"
    html += "<div class='sub'>Le transfert de pions entre comptes etait LE vecteur de la fraude. Le verdict IP compare automatiquement leurs adresses a celles du reseau bloque. Attention : une IP mobile (Vini/Vodafone) peut etre partagee par de nombreuses personnes — le verdict est un INDICE, pas une preuve. Si un emetteur est legitime a tes yeux, clique 'Cloturer'.</div>"
    if lignes_e:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Total transfere (actif)</th><th>Verdict IP</th><th>Outils</th></tr>"
        for r in lignes_e:
            if r["communes"]:
                verdict_ip = "<span class='ko'>&#128680; IP partagee avec le reseau : " + ", ".join(r["communes"][:3]) + ("..." if len(r["communes"]) > 3 else "") + "</span>"
            else:
                verdict_ip = "<span class='ok'>&#9989; aucun lien IP detecte avec le reseau</span>"
            html += "<tr><td><a href='/trace-pions?cle=" + _cle + "&code=" + r["code"] + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + (" (organisatrice)" if r["est_org"] else "") + "</td>"
            html += "<td class='dr'><strong>" + format(r["montant"], ",") + "</strong></td>"
            html += "<td style='font-size:11px'>" + verdict_ip + "</td>"
            html += "<td style='font-size:12px'><a href='/empreinte?cle=" + _cle + "&code=" + r["code"] + "'>empreinte</a> &middot; <a href='/annuler-transferts-fraude?cle=" + _cle + "&code=" + r["code"] + "'>annuler</a> &middot; <a href='/anti-fraude?cle=" + _cle + "&codes=" + r["code"] + "'>bloquer</a> &middot; <a style='color:#3fb950;font-weight:bold' href='?cle=" + _cle + "&cloturer=" + r["code"] + "' onclick=\"return confirm('Cloturer " + r["code"] + " comme LEGITIME ? Ses transferts sont juges normaux.')\">&#9989; Cloturer (legitime)</a></td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok'>&#9989; Aucun emetteur a examiner : tous ont ete traites ou cloturés comme legitimes.</p>"
    if clotures:
        html += "<div class='sub' style='margin-top:14px'>Emetteurs cloturés comme legitimes : "
        html += " &middot; ".join("<span style='color:#3fb950'>" + c + "</span> (<a href='?cle=" + _cle + "&rouvrir=" + c + "' style='font-size:11px'>rouvrir</a>)" for c in sorted(clotures))
        html += "</div>"

    html += "<p class='sub' style='margin-top:24px'>Quand toutes les lignes sont vertes, le dossier fraude est CLOS. &#128274;</p>"
    html += "<p class='sub'><a href='/audit-soldes?cle=" + _cle + "'>&larr; Audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/reparer-restitutions")
def reparer_restitutions():
    """REPARATION (11/07/2026) : les restitutions ont ete executees avec
    l'ancienne version de l'outil (avant les verrous de securite). Cette page
    recalcule pour chaque code ce que la version SECURISEE aurait verse, et
    reprend UNIQUEMENT la difference versee en trop (ex: 'restitutions' faites
    a des codes qui n'avaient que des vidages fraude ou des corrections sans
    rapport avec un double-clic).
    SANS parametre : SIMULATION. Avec &executer=1 : applique.
    Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    executer = (request.args.get("executer", "") or "").strip() == "1"
    _PAR_OUTILS = ("CONVERSION-QR", "CORRECTION-DOUBLE", "CORRECTION-ECRITURE", "QUARANTAINE", "RESTITUTION", "CORRECTION-RESTITUTION")

    # Ce qui a ete VERSE par l'ancienne version
    verse = {}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("par") or "") == "RESTITUTION":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0:
                cj = (c.get("code_joueur") or "").upper().strip()
                verse[cj] = verse.get(cj, 0) + m

    # Ce que la version SECURISEE aurait verse (du_sur)
    groupes = {}
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict) or (c.get("par") or "") in _PAR_OUTILS:
            continue
        m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        if m <= 0:
            continue
        cj = (c.get("code_joueur") or "").upper().strip()
        jour = str(c.get("date") or "")[:10]
        motif = (c.get("motif") or "sans motif").strip()
        if cj and jour:
            groupes[(cj, jour, m, motif)] = groupes.get((cj, jour, m, motif), 0) + 1
    trop = {}
    for (cj, jour, m, motif), nb in groupes.items():
        if nb >= 2:
            trop[cj] = trop.get(cj, 0) + m * (nb - 1)
    auto = {}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("par") or "") == "CORRECTION-DOUBLE":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m < 0:
                cj = (c.get("code_joueur") or "").upper().strip()
                auto[cj] = auto.get(cj, 0) + (-m)
    manuel_d = {}
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict) and "DOUBLE" in str(c.get("motif", "") or "").upper():
            cj = (c.get("code_joueur") or "").upper().strip()
            retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
            if retire <= 0:
                retire = int(c.get("montant_retire", 0) or 0)
            if cj and retire > 0:
                manuel_d[cj] = manuel_d.get(cj, 0) + retire
    _bloques = set((b or "").upper() for b in DB.get("codes_bloques", []))

    deja_rep = set(DB.get("reparations_restitutions_faites", []))
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    lignes_res = []
    for cj, v in verse.items():
        if cj in deja_rep:
            continue
        if cj in _bloques or auto.get(cj, 0) <= 0:
            du_sur = 0
        else:
            du_sur = min(max(0, auto.get(cj, 0) + manuel_d.get(cj, 0) - trop.get(cj, 0)), auto.get(cj, 0))
        errone = v - du_sur
        if errone <= 0:
            continue
        est_org = cj in DB.get("codes", {})
        pj = DB.get("pions_joueurs", {}).get(cj, {})
        pb = DB.get("pions_bonus_joueurs", {}).get(cj, {})
        po = DB.get("pions_org", {}).get(cj, {}) if est_org else {}
        dispo = _xpf_total_pions(pj) + _xpf_total_pions(pb) + _xpf_total_pions(po)
        recup = min(errone, dispo)
        nom_aff = noms.get(cj, "")
        if est_org:
            nom_aff = (DB["codes"].get(cj, {}).get("nom", "") or nom_aff) + " (organisatrice)"
        lignes_res.append({"code": cj, "nom": nom_aff, "est_org": est_org, "verse": v,
                           "du_sur": du_sur, "errone": errone, "dispo": dispo,
                           "recup": recup, "perte": errone - recup,
                           "bloque": cj in _bloques})
    lignes_res.sort(key=lambda r: r["errone"], reverse=True)
    total_errone = sum(r["errone"] for r in lignes_res)
    total_recup = sum(r["recup"] for r in lignes_res)

    faits = []
    if executer and lignes_res:
        for r in lignes_res:
            cj = r["code"]
            reste = r["recup"]
            repris = 0
            if reste > 0:
                for nom_p, dic in (("pions_joueurs", DB.get("pions_joueurs", {})),
                                   ("pions_bonus_joueurs", DB.get("pions_bonus_joueurs", {})),
                                   ("pions_org", DB.get("pions_org", {}) if r["est_org"] else {})):
                    if reste <= 0:
                        break
                    poche = dict(dic.get(cj, {}))
                    part = min(reste, _xpf_total_pions(poche))
                    if part > 0 and _debiter_pions_montant(poche, part):
                        DB.setdefault(nom_p, {})[cj] = poche
                        repris += part
                        reste -= part
            if repris > 0 and repris % 100 == 0:
                DB.setdefault("credits_admin", []).insert(0, {
                    "code_joueur": cj,
                    "nb_pions": -(repris // 100),
                    "valeur_pion": 100,
                    "par": "CORRECTION-RESTITUTION",
                    "motif": "Annulation d'une restitution versée par erreur (outil du 11/07 avant sécurisation)",
                    "date": datetime.datetime.now().isoformat()
                })
            DB.setdefault("reparations_restitutions_faites", []).append(cj)
            r["repris"] = repris
            faits.append(r)
        save_data(immediat=True)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Reparation restitutions</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#f0883e}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}</style></head><body>"
    html += "<h1>&#128295; Reparation des restitutions erronees</h1>"
    html += "<div class='sub'>Compare chaque restitution VERSEE (ancien outil) avec ce que la version SECURISEE aurait verse. Reprend uniquement la difference.</div>"
    if executer:
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; REPARATION EFFECTUEE</span><br>"
        html += str(len(faits)) + " code(s) &middot; " + format(sum(r.get('repris', 0) for r in faits), ",") + " XPF repris.</div>"
        liste = faits
    else:
        html += "<div class='enc'><strong>MODE SIMULATION</strong> &mdash; rien n'a ete modifie.<br>"
        html += "Restitutions erronees : <strong>" + str(len(lignes_res)) + "</strong> code(s) &middot; verse en trop : <strong class='ko'>" + format(total_errone, ",") + " XPF</strong> &middot; recuperable : <strong class='ok'>" + format(total_recup, ",") + " XPF</strong></div>"
        if lignes_res:
            html += "<a class='btn' href='?cle=" + _cle + "&executer=1' onclick=\"return confirm('Reprendre " + format(total_recup, ",") + " XPF verses par erreur ?')\">&#128295; EXECUTER LA REPARATION (" + format(total_recup, ",") + " XPF)</a>"
        liste = lignes_res
    if liste:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Verse (ancien outil)</th><th class='dr'>Du (version sure)</th><th class='dr'>Verse EN TROP</th><th class='dr'>Dispo</th><th class='dr'>" + ("Repris" if executer else "Recuperable") + "</th><th>Note</th></tr>"
        for r in liste:
            note = ""
            if r.get("bloque"):
                note = "<span class='ko'>CODE BLOQUE (fraude)</span>"
            elif r["du_sur"] == 0:
                note = "corrections sans rapport avec un double"
            html += "<tr><td><a href='/trace-pions?cle=" + _cle + "&code=" + r["code"] + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + "</td>"
            html += "<td class='dr'>" + format(r["verse"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["du_sur"], ",") + "</td>"
            html += "<td class='dr'><strong class='ko'>" + format(r["errone"], ",") + "</strong></td>"
            html += "<td class='dr'>" + format(r["dispo"], ",") + "</td>"
            html += "<td class='dr'><strong class='ok'>" + format(r.get("repris", r["recup"]), ",") + "</strong></td>"
            html += "<td style='font-size:11px'>" + note + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok' style='font-size:16px'>&#127881; Aucune restitution erronee : l'ancien outil n'a rien verse en trop (ou tout est deja repare).</p>"
    html += "<p class='sub'><a href='/audit-soldes?cle=" + _cle + "'>&larr; Audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/annuler-transferts-fraude")
def annuler_transferts_fraude():
    """FRAUDE (11/07/2026) : annule TOUS les transferts EMIS par un code fraudeur
    (ex: RT50CJ). Chaque transfert est marque 'annule_fraude' : il ne compte plus
    dans les soldes traces (audit, releves, outils) et apparait sur le releve des
    comptes receveurs comme 'Transfert ANNULE (fraude)' — la joueuse voit
    clairement que cette entree a ete invalidee par l'administration.
    NOTE : ceci corrige les TRACES. Les poches des receveurs ont normalement deja
    ete traitees par /vider-soldes-bannis ou /restituer-legitime ; s'il reste des
    pions de fraude en poche, l'audit les fera ressortir en 'A EXAMINER'.
    SANS &executer=1 : apercu. ?cle=ADMIN&code=RT50CJ[&executer=1]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    code_f = (request.args.get("code", "") or "").strip().upper()
    executer = (request.args.get("executer", "") or "").strip() == "1"

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Annulation transferts fraude</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#f85149}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}</style></head><body>"
    html += "<h1>&#128683; Annulation des transferts d'un fraudeur</h1>"
    if not code_f:
        html += "<div class='enc'>Ajoute <strong>&amp;code=LECODE</strong> (ex: RT50CJ) a l'adresse.</div></body></html>"
        return html

    vises = []
    deja = 0
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and (t.get("de") or "").upper() == code_f:
            if t.get("annule_fraude"):
                deja += 1
            else:
                vises.append(t)
    total_v = sum(int(t.get("montant", 0) or 0) for t in vises)

    if executer and vises:
        now = datetime.datetime.now().isoformat()
        for t in vises:
            t["annule_fraude"] = True
            t["annule_fraude_date"] = now
            t["annule_fraude_par"] = _cle
        DB.setdefault("annulations_fraude", []).insert(0, {
            "code_fraudeur": code_f, "nb_transferts": len(vises),
            "total": total_v, "par": _cle, "date": now
        })
        save_data(immediat=True)
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; TRANSFERTS ANNULES</span><br>"
        html += str(len(vises)) + " transfert(s) de <strong>" + code_f + "</strong> annules (" + format(total_v, ",") + " XPF).<br>"
        html += "Ils n'entrent plus dans aucun solde trace et apparaissent 'ANNULE (fraude)' sur les releves des receveurs.</div>"
        html += "<p class='sub'><a href='/audit-soldes?cle=" + _cle + "'>Relancer l'audit pour voir l'effet</a></p>"
    else:
        html += "<div class='enc'><strong>APERCU</strong> pour le fraudeur <strong>" + code_f + "</strong> &mdash; rien n'a ete modifie.<br>"
        html += "Transferts a annuler : <strong class='ko'>" + str(len(vises)) + "</strong> pour <strong class='ko'>" + format(total_v, ",") + " XPF</strong>"
        if deja:
            html += " &middot; deja annules : " + str(deja)
        html += "</div>"
        if vises:
            html += "<table><tr><th>Date</th><th>Vers (receveur)</th><th class='dr'>Montant</th><th>IP</th></tr>"
            for t in vises:
                html += "<tr><td>" + str(t.get("date", ""))[:19].replace("T", " ") + "</td>"
                html += "<td><a href='/trace-pions?cle=" + _cle + "&code=" + (t.get("vers") or "?") + "'>" + (t.get("vers") or "?") + "</a></td>"
                html += "<td class='dr'>" + format(int(t.get("montant", 0) or 0), ",") + "</td>"
                html += "<td style='font-size:11px;color:#8b949e'>" + str(t.get("ip", "") or "") + "</td></tr>"
            html += "</table>"
            html += "<a class='btn' href='?cle=" + _cle + "&code=" + code_f + "&executer=1' onclick=\"return confirm('Annuler " + str(len(vises)) + " transferts de " + code_f + " (" + format(total_v, ",") + " XPF) ?')\">&#128683; ANNULER CES TRANSFERTS</a>"
        else:
            html += "<p class='ok'>Aucun transfert actif a annuler pour ce code.</p>"
    html += "</body></html>"
    return html


@app.route("/verifier-restitutions")
def verifier_restitutions():
    """RESTITUTION (11/07/2026) : croise les reprises AUTOMATIQUES d'aujourd'hui
    (outil doubles-clics) avec les corrections MANUELLES deja faites en juin
    (corrections_pions 'ERREUR DOUBLE'). Si un meme double-clic a ete corrige
    DEUX fois (une fois a la main + une fois par l'outil), la joueuse a ete
    trop debitee : on lui RESTITUE la difference, avec trace.
    SANS parametre : SIMULATION. Avec &executer=1 : applique.
    Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    executer = (request.args.get("executer", "") or "").strip() == "1"
    _PAR_OUTILS = ("CONVERSION-QR", "CORRECTION-DOUBLE", "CORRECTION-ECRITURE", "QUARANTAINE", "RESTITUTION")

    # 1. Trop-percu LEGITIME par code (les vrais doubles d'origine)
    groupes = {}
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict) or (c.get("par") or "") in _PAR_OUTILS:
            continue
        m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        if m <= 0:
            continue
        code_j = (c.get("code_joueur") or "").upper().strip()
        jour = str(c.get("date") or "")[:10]
        motif = (c.get("motif") or "sans motif").strip()
        if code_j and jour:
            groupes[(code_j, jour, m, motif)] = groupes.get((code_j, jour, m, motif), 0) + 1
    trop = {}
    for (code_j, jour, m, motif), nb in groupes.items():
        if nb >= 2:
            trop[code_j] = trop.get(code_j, 0) + m * (nb - 1)

    # 2. Total CORRIGE par code = reprises auto (aujourd'hui) + corrections manuelles (juin)
    auto = {}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("par") or "") == "CORRECTION-DOUBLE":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m < 0:
                cj = (c.get("code_joueur") or "").upper().strip()
                auto[cj] = auto.get(cj, 0) + (-m)
    manuel = {}
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict):
            # 🔒 VERROU : seules les corrections dont le motif mentionne un DOUBLE
            # comptent ici. Les vidages fraude ('Pions de fraude retirés'), retraits
            # CCP et autres corrections n'ont RIEN a voir avec les doubles-clics.
            if "DOUBLE" not in str(c.get("motif", "") or "").upper():
                continue
            cj = (c.get("code_joueur") or "").upper().strip()
            retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
            if retire <= 0:
                retire = int(c.get("montant_retire", 0) or 0)
            if cj and retire > 0:
                manuel[cj] = manuel.get(cj, 0) + retire

    deja_faites = set(DB.get("restitutions_faites", []))
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    lignes_res = []
    # 🔒 VERROUS : on ne restitue QU'AUX codes que l'outil du 11/07 a repris
    # (jamais a un code seulement corrige a la main), JAMAIS a un code bloque
    # (fraude), et JAMAIS plus que ce que l'outil a repris.
    _bloques = set((b or "").upper() for b in DB.get("codes_bloques", []))
    for cj in auto.keys():
        if cj in deja_faites or cj in _bloques:
            continue
        total_corrige = auto.get(cj, 0) + manuel.get(cj, 0)
        du = max(0, total_corrige - trop.get(cj, 0))
        du = min(du, auto.get(cj, 0))
        if du <= 0:
            continue
        est_org = cj in DB.get("codes", {})
        reel_vide = (_xpf_total_pions(DB.get("pions_joueurs", {}).get(cj, {})) +
                     _xpf_total_pions(DB.get("pions_bonus_joueurs", {}).get(cj, {}))) == 0
        vers_org = est_org and reel_vide and auto.get(cj, 0) > 0
        nom_aff = noms.get(cj, "")
        if est_org:
            nom_aff = (DB["codes"].get(cj, {}).get("nom", "") or nom_aff) + " (organisatrice)"
        lignes_res.append({"code": cj, "nom": nom_aff, "trop": trop.get(cj, 0),
                           "manuel": manuel.get(cj, 0), "auto": auto.get(cj, 0),
                           "du": du, "vers_org": vers_org})
    lignes_res.sort(key=lambda r: r["du"], reverse=True)
    total_du = sum(r["du"] for r in lignes_res)

    faits = []
    if executer and lignes_res:
        for r in lignes_res:
            cj = r["code"]
            du = r["du"]
            if du % 100 == 0 and du > 0:
                if r["vers_org"]:
                    poche = DB.setdefault("pions_org", {}).setdefault(cj, {})
                    _crediter_pions_montant(poche, du)
                    DB["pions_org"][cj] = poche
                else:
                    poche = DB.setdefault("pions_joueurs", {}).setdefault(cj, {})
                    _crediter_pions_montant(poche, du)
                    DB["pions_joueurs"][cj] = poche
                DB.setdefault("credits_admin", []).insert(0, {
                    "code_joueur": cj,
                    "nb_pions": du // 100,
                    "valeur_pion": 100,
                    "par": "RESTITUTION",
                    "motif": "Restitution — double-clic corrigé deux fois (correction manuelle de juin + outil du 11/07)",
                    "date": datetime.datetime.now().isoformat()
                })
                DB.setdefault("restitutions_faites", []).append(cj)
                faits.append(r)
        save_data(immediat=True)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Restitutions</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#3fb950}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#3fb950;color:#0d1117;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}</style></head><body>"
    html += "<h1>&#128257; Restitutions (corrections comptees en double)</h1>"
    html += "<div class='sub'>Un double-clic corrige a la main en juin PUIS repris par l'outil du 11/07 = joueuse trop debitee. On lui rend la difference.</div>"
    if executer:
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; RESTITUTIONS EFFECTUEES</span><br>"
        html += str(len(faits)) + " restitution(s) &middot; " + format(sum(r['du'] for r in faits), ",") + " XPF rendus.</div>"
        liste = faits
    else:
        html += "<div class='enc'><strong>MODE SIMULATION</strong> &mdash; rien n'a ete modifie.<br>"
        html += "A restituer : <strong>" + str(len(lignes_res)) + "</strong> code(s) &middot; <strong class='ok'>" + format(total_du, ",") + " XPF</strong></div>"
        if lignes_res:
            html += "<a class='btn' href='?cle=" + _cle + "&executer=1' onclick=\"return confirm('Restituer " + format(total_du, ",") + " XPF a " + str(len(lignes_res)) + " code(s) ?')\">&#128257; EXECUTER LES RESTITUTIONS (" + format(total_du, ",") + " XPF)</a>"
        liste = lignes_res
    if liste:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Trop-percu d'origine</th><th class='dr'>Corrige a la main (juin)</th><th class='dr'>Repris par l'outil (11/07)</th><th class='dr'>A RESTITUER</th><th>Destination</th></tr>"
        for r in liste:
            html += "<tr><td><a href='/trace-pions?cle=" + _cle + "&code=" + r["code"] + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + "</td>"
            html += "<td class='dr'>" + format(r["trop"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["manuel"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["auto"], ",") + "</td>"
            html += "<td class='dr'><strong class='ok'>+" + format(r["du"], ",") + "</strong></td>"
            html += "<td>" + ("poche ORGANISATEUR" if r["vers_org"] else "poche reelle joueuse") + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok' style='font-size:16px'>&#127881; Aucune restitution necessaire : aucune correction comptee en double.</p>"
    html += "<p class='sub'><a href='/audit-soldes?cle=" + _cle + "'>&larr; Audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/correction-ecriture")
def correction_ecriture():
    """CORRECTION D'ECRITURE (10/07/2026) : annule SUR LE PAPIER des credits en
    trop (ex: traces d'un double-clic dont les pions ne sont jamais entres dans
    la poche) SANS toucher a aucune poche. Ecrit une contre-trace negative sur
    le releve du code, et marque le groupe pour que l'outil de reprise des
    doubles-clics ne le traite pas une deuxieme fois.
    ?cle=ADMIN&code=LECODE&montant=15000&jour=2026-06-29&umontant=5000&motif=...[&executer=1]
    - montant : total a annuler sur le papier
    - jour + umontant + motif : identifient le groupe de doubles a marquer comme traite"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    code_v = (request.args.get("code", "") or "").strip().upper()
    try:
        montant = int(request.args.get("montant", "0") or 0)
    except ValueError:
        montant = 0
    jour = (request.args.get("jour", "") or "").strip()
    umontant = (request.args.get("umontant", "") or "").strip()
    motif_g = (request.args.get("motif", "") or "").strip()
    executer = (request.args.get("executer", "") or "").strip() == "1"

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Correction d'ecriture</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128221; Correction d'ecriture (papier seulement)</h1>"
    if not code_v or montant <= 0 or montant % 100 != 0:
        html += "<div class='enc'>Parametres requis : <strong>&amp;code=LECODE&amp;montant=15000</strong> (multiple de 100).</div></body></html>"
        return html

    cle_groupe = ""
    if jour and umontant and motif_g:
        cle_groupe = code_v + "|" + jour + "|" + umontant + "|" + motif_g
    deja = cle_groupe and cle_groupe in DB.get("corrections_doubles_faites", [])

    if executer and not deja:
        DB.setdefault("credits_admin", []).insert(0, {
            "code_joueur": code_v,
            "nb_pions": -(montant // 100),
            "valeur_pion": 100,
            "par": "CORRECTION-ECRITURE",
            "motif": "Annulation d'écriture — crédits en double (double-clic) annulés sur le relevé, aucune poche modifiée",
            "date": datetime.datetime.now().isoformat()
        })
        if cle_groupe:
            DB.setdefault("corrections_doubles_faites", []).append(cle_groupe)
        save_data(immediat=True)
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; ECRITURE CORRIGEE</span><br>"
        html += "Code <strong>" + code_v + "</strong> : <strong>-" + format(montant, ",") + " XPF</strong> annules sur le releve (papier). AUCUNE poche touchee.<br>"
        html += "Le groupe de doubles est marque comme traite : l'outil de reprise ne le proposera plus.</div>"
        html += "<p class='sub'><a href='/releve-financier-joueur/" + code_v + "?cle=" + _cle + "'>Voir son releve corrige</a> &middot; <a href='/corriger-doubles-clics?cle=" + _cle + "'>Outil doubles-clics</a></p>"
    elif deja:
        html += "<div class='enc'><span class='ok'>&#9989; Deja corrige</span> : ce groupe a deja ete traite, rien a faire.</div>"
    else:
        html += "<div class='enc'><strong>APERCU</strong> &mdash; rien n'a ete modifie.<br><br>"
        html += "Code : <strong>" + code_v + "</strong><br>"
        html += "Annulation sur le releve : <strong class='ko'>-" + format(montant, ",") + " XPF</strong> (contre-trace, AUCUNE poche touchee)<br>"
        if cle_groupe:
            html += "Groupe de doubles marque comme traite : <span style='font-size:11px;color:#8b949e'>" + cle_groupe + "</span><br>"
        html += "</div>"
        url_exec = "?cle=" + _cle + "&code=" + code_v + "&montant=" + str(montant)
        if jour:
            url_exec += "&jour=" + jour + "&umontant=" + umontant + "&motif=" + motif_g.replace(" ", "%20")
        url_exec += "&executer=1"
        html += "<a class='btn' href='" + url_exec + "' onclick=\"return confirm('Annuler " + format(montant, ",") + " XPF sur le releve de " + code_v + " (papier seulement) ?')\">&#128221; CORRIGER L'ECRITURE</a>"
    html += "</body></html>"
    return html


@app.route("/quarantaine-code")
def quarantaine_code():
    """QUARANTAINE (10/07/2026) : pour un code suspect (ex: code fantome ayant
    recu des credits par erreur), fait 3 gestes d'un coup :
    1. VIDE toutes ses poches (reelle, bonus, organisateur le cas echeant)
    2. BLOQUE le code (plus de jeu ni de retrait possible)
    3. TRACE la reprise sur son releve (transparence si reclamation)
    Si la vraie personne se manifeste, on la recredite sur son bon code.
    SANS &executer=1 : apercu seulement. ?cle=ADMIN&code=LECODE[&executer=1]"""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    code_v = (request.args.get("code", "") or "").strip().upper()
    executer = (request.args.get("executer", "") or "").strip() == "1"

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Quarantaine</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#f0883e}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128683; Mise en quarantaine d'un code</h1>"
    if not code_v:
        html += "<div class='enc'>Ajoute <strong>&amp;code=LECODE</strong> a l'adresse pour choisir le code a mettre en quarantaine.</div></body></html>"
        return html

    pj = DB.get("pions_joueurs", {}).get(code_v, {})
    pb = DB.get("pions_bonus_joueurs", {}).get(code_v, {})
    po = DB.get("pions_org", {}).get(code_v, {}) if code_v in DB.get("codes", {}) else {}
    t_r = _xpf_total_pions(pj)
    t_b = _xpf_total_pions(pb)
    t_o = _xpf_total_pions(po)
    total = t_r + t_b + t_o
    deja_bloque = code_v in DB.get("codes_bloques", [])

    if executer:
        repris = 0
        if t_r > 0:
            p = dict(pj)
            if _debiter_pions_montant(p, t_r):
                DB.setdefault("pions_joueurs", {})[code_v] = p
                repris += t_r
        if t_b > 0:
            p = dict(pb)
            if _debiter_pions_montant(p, t_b):
                DB.setdefault("pions_bonus_joueurs", {})[code_v] = p
                repris += t_b
        if t_o > 0:
            p = dict(po)
            if _debiter_pions_montant(p, t_o):
                DB.setdefault("pions_org", {})[code_v] = p
                repris += t_o
        if not deja_bloque:
            DB.setdefault("codes_bloques", []).append(code_v)
        if repris > 0 and repris % 100 == 0:
            DB.setdefault("credits_admin", []).insert(0, {
                "code_joueur": code_v,
                "nb_pions": -(repris // 100),
                "valeur_pion": 100,
                "par": "QUARANTAINE",
                "motif": "Code mis en quarantaine — pions repris en attente de réclamation du titulaire légitime",
                "date": datetime.datetime.now().isoformat()
            })
        DB.setdefault("quarantaines", []).insert(0, {
            "code": code_v, "repris": repris, "par": _cle,
            "date": datetime.datetime.now().isoformat()
        })
        save_data(immediat=True)
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; QUARANTAINE APPLIQUEE</span><br>"
        html += "Code <strong>" + code_v + "</strong> : <strong>" + format(repris, ",") + " XPF</strong> repris &middot; code <strong>BLOQUE</strong> (jeu et retrait impossibles).<br>"
        html += "Si la vraie personne se manifeste : recredite-la sur son bon code, la trace est la pour justifier.</div>"
        html += "<p class='sub'><a href='/trace-pions?cle=" + _cle + "&code=" + code_v + "'>Voir sa trace</a> &middot; <a href='/audit-soldes?cle=" + _cle + "'>Audit des soldes</a></p>"
    else:
        html += "<div class='enc'><strong>APERCU</strong> pour le code <strong>" + code_v + "</strong> &mdash; rien n'a ete modifie.<br><br>"
        html += "Poche REELLE : <strong>" + format(t_r, ",") + " XPF</strong><br>"
        html += "Poche BONUS : <strong>" + format(t_b, ",") + " XPF</strong><br>"
        if code_v in DB.get("codes", {}):
            html += "Poche ORGANISATEUR : <strong>" + format(t_o, ",") + " XPF</strong><br>"
        html += "TOTAL a reprendre : <strong class='ko'>" + format(total, ",") + " XPF</strong><br>"
        html += "Statut actuel : " + ("<span class='ko'>deja bloque</span>" if deja_bloque else "<span class='ok'>actif</span> &rarr; sera BLOQUE") + "</div>"
        html += "<a class='btn' href='?cle=" + _cle + "&code=" + code_v + "&executer=1' onclick=\"return confirm('Vider et bloquer le code " + code_v + " (" + format(total, ",") + " XPF) ?')\">&#128683; VIDER ET BLOQUER CE CODE</a>"
    html += "</body></html>"
    return html


@app.route("/corriger-doubles-clics")
def corriger_doubles_clics():
    """CORRECTION (10/07/2026) : reprend le trop-percu des remboursements en
    DOUBLE-CLIC — la meme joueuse creditee plusieurs fois du meme montant, le
    meme jour, avec le MEME motif (signature du double-clic). Le premier credit
    est conserve (legitime), les suivants sont repris dans sa poche (reel puis
    bonus). Si elle a deja tout depense, on reprend ce qui reste et le solde
    irrecuperable est signale. Une trace 'Correction double-clic' est ecrite
    sur chaque releve. Les operations 'ardoise' sont EXCLUES (volontaires).
    SANS parametre : SIMULATION. Avec &executer=1 : applique.
    Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    executer = (request.args.get("executer", "") or "").strip() == "1"

    # Groupes (code, jour, montant, motif) -> nb d'occurrences dans credits_admin
    groupes = {}
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict):
            continue
        par = (c.get("par") or "")
        if par in ("CONVERSION-QR", "CORRECTION-DOUBLE"):
            continue
        motif = (c.get("motif") or "sans motif").strip()
        m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        if m <= 0:
            continue
        code_j = (c.get("code_joueur") or "").upper().strip()
        jour = str(c.get("date") or "")[:10]
        if not code_j or not jour:
            continue
        cle_g = code_j + "|" + jour + "|" + str(m) + "|" + motif
        groupes[cle_g] = groupes.get(cle_g, 0) + 1

    deja_faites = set(DB.get("corrections_doubles_faites", []))
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    # Trop-percu par joueuse (somme de tous ses groupes en double non traites)
    par_joueuse = {}
    groupes_a_marquer = {}
    for cle_g, nb in groupes.items():
        if nb < 2 or cle_g in deja_faites:
            continue
        code_j, jour, m, motif = cle_g.split("|", 3)
        trop = int(m) * (nb - 1)
        par_joueuse.setdefault(code_j, {"trop": 0, "detail": []})
        par_joueuse[code_j]["trop"] += trop
        par_joueuse[code_j]["detail"].append(jour + " · " + format(int(m), ",") + " x" + str(nb) + " (" + motif + ")")
        groupes_a_marquer.setdefault(code_j, []).append(cle_g)

    lignes_res = []
    for code_j, info in par_joueuse.items():
        est_org = code_j in DB.get("codes", {})
        pj = DB.get("pions_joueurs", {}).get(code_j, {})
        pb = DB.get("pions_bonus_joueurs", {}).get(code_j, {})
        po = DB.get("pions_org", {}).get(code_j, {}) if est_org else {}
        # Le disponible = TOUTES les poches du code (certains codes sont hybrides
        # joueur + organisateur : on reprend la ou l'argent se trouve vraiment)
        dispo = _xpf_total_pions(pj) + _xpf_total_pions(pb) + _xpf_total_pions(po)
        recuperable = min(info["trop"], dispo)
        nom_aff = noms.get(code_j, "")
        if est_org:
            nom_aff = (DB["codes"].get(code_j, {}).get("nom", "") or nom_aff) + " (organisatrice)"
        lignes_res.append({"code": code_j, "nom": nom_aff, "est_org": est_org, "trop": info["trop"],
                           "dispo": dispo, "recup": recuperable,
                           "perte": info["trop"] - recuperable, "detail": info["detail"]})
    lignes_res.sort(key=lambda r: r["trop"], reverse=True)
    total_trop = sum(r["trop"] for r in lignes_res)
    total_recup = sum(r["recup"] for r in lignes_res)
    total_perte = sum(r["perte"] for r in lignes_res)

    faits = []
    if executer and lignes_res:
        for r in lignes_res:
            code_j = r["code"]
            a_reprendre = r["recup"]
            if a_reprendre > 0:
                # Reprise en cascade : poche REELLE -> poche BONUS -> poche ORG
                repris = 0
                reste = a_reprendre
                poche_r = dict(DB.get("pions_joueurs", {}).get(code_j, {}))
                part = min(reste, _xpf_total_pions(poche_r))
                if part > 0 and _debiter_pions_montant(poche_r, part):
                    DB.setdefault("pions_joueurs", {})[code_j] = poche_r
                    repris += part
                    reste -= part
                if reste > 0:
                    poche_b = dict(DB.get("pions_bonus_joueurs", {}).get(code_j, {}))
                    part = min(reste, _xpf_total_pions(poche_b))
                    if part > 0 and _debiter_pions_montant(poche_b, part):
                        DB.setdefault("pions_bonus_joueurs", {})[code_j] = poche_b
                        repris += part
                        reste -= part
                if reste > 0 and r.get("est_org"):
                    poche_o = dict(DB.get("pions_org", {}).get(code_j, {}))
                    part = min(reste, _xpf_total_pions(poche_o))
                    if part > 0 and _debiter_pions_montant(poche_o, part):
                        DB.setdefault("pions_org", {})[code_j] = poche_o
                        repris += part
                        reste -= part
                if repris > 0 and repris % 100 == 0:
                    DB.setdefault("credits_admin", []).insert(0, {
                        "code_joueur": code_j,
                        "nb_pions": -(repris // 100),
                        "valeur_pion": 100,
                        "par": "CORRECTION-DOUBLE",
                        "motif": "Correction double-clic — reprise du trop-perçu (remboursement crédité en double)",
                        "date": datetime.datetime.now().isoformat()
                    })
                r["repris"] = repris
            else:
                r["repris"] = 0
            for cle_g in groupes_a_marquer.get(code_j, []):
                DB.setdefault("corrections_doubles_faites", []).append(cle_g)
            faits.append(r)
        save_data(immediat=True)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Correction doubles-clics</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}.b{color:#a78bfa}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}</style></head><body>"
    html += "<h1>&#9986;&#65039; Correction des doubles-clics</h1>"
    html += "<div class='sub'>Reprise du trop-percu : meme joueuse + meme jour + meme montant + MEME motif, credite 2 fois ou plus. Le 1er credit est conserve, les suivants sont repris (poche organisatrice geree aussi).</div>"
    if executer:
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; CORRECTION EFFECTUEE</span><br>"
        html += str(len(faits)) + " joueuse(s) &middot; " + format(sum(r.get('repris', 0) for r in faits), ",") + " XPF repris"
        if total_perte:
            html += " &middot; <span class='ko'>" + format(total_perte, ",") + " XPF irrecuperables (deja depenses)</span>"
        html += "</div>"
        liste = faits
    else:
        html += "<div class='enc'><strong>MODE SIMULATION</strong> &mdash; rien n'a ete modifie.<br>"
        html += "Joueuses : <strong>" + str(len(lignes_res)) + "</strong> &middot; Trop-percu : <strong>" + format(total_trop, ",") + " XPF</strong>"
        html += " &middot; Recuperable : <strong class='ok'>" + format(total_recup, ",") + " XPF</strong>"
        if total_perte:
            html += " &middot; Irrecuperable (deja depense) : <strong class='ko'>" + format(total_perte, ",") + " XPF</strong>"
        html += "</div>"
        if lignes_res:
            html += "<a class='btn' href='?cle=" + _cle + "&executer=1' onclick=\"return confirm('Reprendre le trop-percu chez " + str(len(lignes_res)) + " joueuses ? Cette action ecrit dans la base.')\">&#9889; EXECUTER LA REPRISE (" + format(total_recup, ",") + " XPF)</a>"
        liste = lignes_res
    if liste:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Trop-percu</th><th class='dr'>Dispo en poche</th><th class='dr'>" + ("Repris" if executer else "Recuperable") + "</th><th class='dr'>Irrecuperable</th><th>Detail des doubles</th></tr>"
        for r in liste:
            html += "<tr><td><a href='/trace-pions?cle=" + _cle + "&code=" + r["code"] + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + "</td>"
            html += "<td class='dr'>" + format(r["trop"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["dispo"], ",") + "</td>"
            html += "<td class='dr'><strong class='ok'>" + format(r.get("repris", r["recup"]), ",") + "</strong></td>"
            html += "<td class='dr'>" + ("<strong class='ko'>" + format(r["perte"], ",") + "</strong>" if r["perte"] else "0") + "</td>"
            html += "<td style='font-size:11px;color:#8b949e'>" + "<br>".join(r["detail"]) + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok' style='font-size:16px'>&#127881; Aucun double-clic a corriger : tout est deja regularise.</p>"
    html += "<p class='sub' style='margin-top:16px'><a href='/detecter-doubles-remboursements?cle=" + _cle + "'>&larr; Retour au detecteur</a> &middot; <a href='/audit-soldes?cle=" + _cle + "'>Audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/detecter-doubles-remboursements")
def detecter_doubles_remboursements():
    """DETECTEUR (10/07/2026) : repere les DOUBLES remboursements — la meme
    joueuse creditee 2 fois ou plus du MEME montant le MEME jour, par des
    circuits de remboursement differents (remboursement de jeu, credit admin,
    remboursement au reset). Chaque double = de l'argent que l'organisateur
    a perdu et qu'il faut lui rendre. Page en LECTURE SEULE : elle detecte,
    c'est toi qui decides du dedommagement.
    Acces ADMIN : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")

    # Tous les credits "type remboursement" : (joueuse, jour, montant) -> [sources]
    groupes = {}

    def _noter(code_j, date_str, montant, source):
        code_j = (code_j or "").upper().strip()
        jour = str(date_str or "")[:10]
        try:
            montant = int(montant or 0)
        except (ValueError, TypeError):
            montant = 0
        if not code_j or not jour or montant <= 0:
            return
        groupes.setdefault((code_j, jour, montant), []).append(source)

    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            src = "Remboursement jeu/reset : " + str(rb.get("jeu", "?")) + " (org " + str(rb.get("code_org", "?")) + ")"
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    _noter(det.get("code_joueur"), rb.get("date"), det.get("montant"), src)
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("par") or "") != "CONVERSION-QR":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0:
                _noter(c.get("code_joueur"), c.get("date"), m,
                       "Crédit admin : " + str(c.get("motif") or "sans motif") + " (par " + str(c.get("par", "?")) + ")")
    for cm in DB.get("credits_masse", []):
        if isinstance(cm, dict) and cm.get("profil", "joueur") == "joueur":
            m = int(cm.get("nb_pions", 0) or 0) * int(cm.get("valeur_pion", 0) or 0)
            if m > 0:
                for cj in (cm.get("codes") or []):
                    _noter(cj, cm.get("date"), m, "Crédit en masse : " + str(cm.get("motif") or "dédommagement"))

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    doubles = []
    for (code_j, jour, montant), sources in groupes.items():
        if len(sources) >= 2:
            doubles.append({"code": code_j, "nom": noms.get(code_j, ""), "jour": jour,
                            "montant": montant, "nb": len(sources), "sources": sources,
                            "trop_percu": montant * (len(sources) - 1)})
    doubles.sort(key=lambda d: d["trop_percu"], reverse=True)
    total_trop = sum(d["trop_percu"] for d in doubles)

    # === DOUBLES GAINS : meme gagnante + meme jeu + meme montant + meme jour,
    # paye 2 fois ou plus. L'heure exacte permet de trancher : meme seconde =
    # double-clic certain ; heures differentes = peut-etre 2 vrais gains.
    groupes_gains = {}
    for g in DB.get("gains_finaux", []):
        if not isinstance(g, dict) or g.get("annule"):
            continue
        cg = (g.get("code_gagnant") or "").upper().strip()
        jour_g = str(g.get("date") or "")[:10]
        try:
            mg = int(g.get("montant_gain", 0) or 0)
        except (ValueError, TypeError):
            mg = 0
        if not cg or not jour_g or mg <= 0:
            continue
        cle_gg = (cg, jour_g, mg, str(g.get("jeu", "")), (g.get("code_org") or "").upper())
        groupes_gains.setdefault(cle_gg, []).append(str(g.get("date") or "")[11:19])
    doubles_gains = []
    for (cg, jour_g, mg, jeu_g, org_g), heures in groupes_gains.items():
        if len(heures) >= 2:
            doubles_gains.append({"code": cg, "nom": noms.get(cg, ""), "jour": jour_g,
                                  "montant": mg, "jeu": jeu_g, "org": org_g,
                                  "nb": len(heures), "heures": sorted(heures),
                                  "trop": mg * (len(heures) - 1)})
    doubles_gains.sort(key=lambda d: d["trop"], reverse=True)
    total_trop_gains = sum(d["trop"] for d in doubles_gains)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Doubles remboursements</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128269; Doubles remboursements</h1>"
    html += "<div class='sub'>Meme joueuse + meme montant + meme jour, credites par 2 circuits ou plus. Chaque double = argent a rendre a l'organisateur.</div>"
    if doubles:
        html += "<div class='enc'><span class='ko' style='font-size:18px;font-weight:bold'>&#9888;&#65039; " + str(len(doubles)) + " double(s) detecte(s)</span><br>"
        html += "Trop-percu total : <strong>" + format(total_trop, ",") + " XPF</strong> &mdash; a compenser aupres de l'organisateur concerne.</div>"
        html += "<table><tr><th>Jour</th><th>Code</th><th>Nom</th><th class='dr'>Montant</th><th class='dr'>Fois</th><th class='dr'>Trop-percu</th><th>Circuits</th></tr>"
        for d in doubles:
            html += "<tr><td>" + d["jour"] + "</td>"
            html += "<td><a href='/trace-pions?cle=" + _cle + "&code=" + d["code"] + "'>" + d["code"] + "</a></td>"
            html += "<td>" + d["nom"] + "</td>"
            html += "<td class='dr'>" + format(d["montant"], ",") + "</td>"
            html += "<td class='dr'>" + str(d["nb"]) + "</td>"
            html += "<td class='dr'><strong class='ko'>" + format(d["trop_percu"], ",") + "</strong></td>"
            html += "<td style='font-size:11px;color:#8b949e'>" + "<br>".join(d["sources"]) + "</td></tr>"
        html += "</table>"
        html += "<p class='sub' style='margin-top:14px'>Chaque code ouvre sa trace complete pour verifier avant de corriger (retrait du trop-percu chez la joueuse ou dedommagement de l'organisateur, a ta main).</p>"
    else:
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; Aucun double remboursement detecte</span><br>Aucune joueuse n'a recu deux fois le meme montant le meme jour par des circuits de remboursement.</div>"
    html += "<h1 style='margin-top:34px'>&#127942; Gains payes en double</h1>"
    html += "<div class='sub'>Meme gagnante + meme jeu + meme montant + meme jour, paye 2 fois ou plus. Regle de lecture : MEME SECONDE = double-clic certain ; heures differentes = peut-etre 2 vrais gains (a toi de juger).</div>"
    if doubles_gains:
        html += "<div class='enc'><span class='ko' style='font-size:18px;font-weight:bold'>&#9888;&#65039; " + str(len(doubles_gains)) + " gain(s) en double detecte(s)</span><br>"
        html += "Trop-paye potentiel : <strong>" + format(total_trop_gains, ",") + " XPF</strong>. Pour corriger un vrai double : bouton Annuler sur la page du gain (lien dans la colonne Code).</div>"
        html += "<table><tr><th>Jour</th><th>Heures exactes</th><th>Code</th><th>Nom</th><th>Jeu</th><th>Org</th><th class='dr'>Montant</th><th class='dr'>Fois</th><th class='dr'>Trop-paye</th></tr>"
        for d in doubles_gains:
            meme_sec = len(set(d["heures"])) < d["nb"]
            heures_aff = " / ".join(d["heures"]) + (" <strong class='ko'>&#8592; MEME SECONDE</strong>" if meme_sec else "")
            html += "<tr><td>" + d["jour"] + "</td>"
            html += "<td style='font-size:11px'>" + heures_aff + "</td>"
            html += "<td><a href='/annuler-gain?cle=" + _cle + "&code=" + d["code"] + "'>" + d["code"] + "</a></td>"
            html += "<td>" + d["nom"] + "</td>"
            html += "<td>" + d["jeu"] + "</td>"
            html += "<td>" + d["org"] + "</td>"
            html += "<td class='dr'>" + format(d["montant"], ",") + "</td>"
            html += "<td class='dr'>" + str(d["nb"]) + "</td>"
            html += "<td class='dr'><strong class='ko'>" + format(d["trop"], ",") + "</strong></td></tr>"
        html += "</table>"
        html += "<p class='sub' style='margin-top:14px'>&#9888;&#65039; Attention : annuler un gain corrige le RELEVE mais ne touche pas les poches. Si les pions du double ont vraiment ete credites a la joueuse, dis-le a Claude pour preparer la reprise physique.</p>"
    else:
        html += "<div class='enc'><span class='ok' style='font-size:16px;font-weight:bold'>&#9989; Aucun gain paye en double</span></div>"
    html += "<p class='sub'><a href='/audit-soldes?cle=" + _cle + "'>&larr; Retour a l'audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/convertir-cadeaux-qr")
def convertir_cadeaux_qr():
    """CONVERSION (10/07/2026) : regularise le double cadeau d'inscription QR.
    Des inscrites QR (campagne semaine) detiennent 500 F en pions REELS
    (retirables en argent) en plus des 500 F de bonus, sans AUCUNE origine
    tracee. Cette page convertit ces 500 F reels en pions BONUS (jouables,
    non retirables) — l'esprit du cadeau — et ecrit une trace propre sur le
    releve de chaque joueuse (son audit devient equilibre).
    SANS parametre : SIMULATION (liste seulement, ne touche a rien).
    Avec &executer=1 : applique la conversion.
    Acces ADMIN uniquement : ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _info = DB.get("codes", {}).get(_cle)
    if not (_info and _info.get("admin")):
        return Response("<h1 style='font-family:sans-serif'>Acces reserve a l'administration</h1>", status=403, mimetype="text/html; charset=utf-8")
    executer = (request.args.get("executer", "") or "").strip() == "1"

    # 1. Somme des ENTREES de pions REELS tracees par joueuse (argent reel).
    #    V2 (10/07/2026) : on somme les MONTANTS au lieu de marquer les codes.
    #    Un gain paye entierement en especes (montant_credite = 0) ne compte
    #    plus comme origine : aucun pion reel n'est entre en poche.
    ent_reel = {}

    def _addr(code_x, m):
        code_x = (code_x or "").upper().strip()
        try:
            m = int(m or 0)
        except (ValueError, TypeError):
            m = 0
        if code_x and m > 0:
            ent_reel[code_x] = ent_reel.get(code_x, 0) + m

    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            nb = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0)
            val = int(c.get("valeur_pion", 0) or 0)
            v = nb * val
            if v <= 0:
                v = int(c.get("montant_net", 0) or 0)
            _addr(c.get("code_joueur"), v)
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict):
            _addr(t.get("code_joueur"), t.get("montant_total", 0))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and not g.get("annule"):
            _addr(g.get("code_gagnant"), g.get("montant_credite", 0))
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and (c.get("par") or "") != "CONVERSION-QR":
            _addr(c.get("code_joueur"), int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0))
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict) and c.get("profil", "joueur") == "joueur":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            for cj in (c.get("codes") or []):
                _addr(cj, m)
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    _addr(det.get("code_joueur"), det.get("montant", 0))
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and not t.get("annule_fraude"):
            _addr(t.get("vers"), t.get("montant", 0))

    # 2. Candidates : inscrites QR "semaine", EXACTEMENT 500 F reels, ZERO
    #    entree d'argent reel tracee, et pas deja converties.
    deja_converties = set(DB.get("conversions_cadeau_qr", []))
    vues = set()
    candidates = []
    for x in DB.get("rejoindre_log", []):
        code_j = (x.get("code", "") or "").upper().strip()
        if not code_j or code_j in vues:
            continue
        vues.add(code_j)
        if (x.get("campagne", "") or "") != "semaine":
            continue
        if code_j in deja_converties:
            continue
        if ent_reel.get(code_j, 0) > 0:
            continue
        pj = DB.get("pions_joueurs", {}).get(code_j, {})
        poche_reel = _xpf_total_pions(pj)
        if poche_reel != 500:
            continue
        pb = DB.get("pions_bonus_joueurs", {}).get(code_j, {})
        candidates.append({"code": code_j, "nom": x.get("nom", "") or "",
                           "reel": poche_reel, "bonus": _xpf_total_pions(pb)})

    convertis = []
    echecs = []
    if executer and candidates:
        for cand in candidates:
            code_j = cand["code"]
            poche = dict(DB.get("pions_joueurs", {}).get(code_j, {}))
            if not _debiter_pions_montant(poche, 500):
                echecs.append(code_j)
                continue
            bonus = dict(DB.get("pions_bonus_joueurs", {}).get(code_j, {}))
            _crediter_pions_montant(bonus, 500)
            DB.setdefault("pions_joueurs", {})[code_j] = poche
            DB.setdefault("pions_bonus_joueurs", {})[code_j] = bonus
            DB.setdefault("conversions_cadeau_qr", []).append(code_j)
            DB.setdefault("credits_admin", []).insert(0, {
                "code_joueur": code_j,
                "nb_pions": 5,
                "valeur_pion": 100,
                "par": "CONVERSION-QR",
                "motif": "Cadeau inscription QR régularisé — 500 F convertis en pions bonus (jouables, non retirables)",
                "date": datetime.datetime.now().isoformat()
            })
            convertis.append(cand)
        save_data(immediat=True)

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Conversion cadeaux QR</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:16px}.ok{color:#3fb950}.ko{color:#f85149}.b{color:#a78bfa}"
    html += "table{width:100%;border-collapse:collapse;margin-top:16px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}.dr{text-align:right}"
    html += ".btn{display:inline-block;margin:14px 0;padding:14px 26px;background:#f85149;color:#fff;border-radius:10px;text-decoration:none;font-weight:bold;font-size:15px}"
    html += ".enc{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:14px 0}</style></head><body>"
    html += "<h1>&#127873; Conversion du double cadeau QR</h1>"
    html += "<div class='sub'>500 F reels sans origine &rarr; 500 F bonus (jouables, non retirables). Trace ecrite sur chaque releve.</div>"
    if executer:
        html += "<div class='enc'><span class='ok' style='font-size:18px;font-weight:bold'>&#9989; CONVERSION EFFECTUEE</span><br>"
        html += str(len(convertis)) + " joueuse(s) convertie(s) &middot; " + format(len(convertis) * 500, ",") + " XPF proteges."
        if echecs:
            html += "<br><span class='ko'>&#9888;&#65039; Echecs (denominations non divisibles) : " + ", ".join(echecs) + "</span>"
        html += "</div>"
        liste = convertis
    else:
        html += "<div class='enc'><strong>MODE SIMULATION</strong> &mdash; rien n'a ete modifie.<br>"
        html += "Joueuses concernees : <strong>" + str(len(candidates)) + "</strong> &middot; Montant total a proteger : <strong>" + format(len(candidates) * 500, ",") + " XPF</strong><br>"
        html += "Criteres v2 : inscrite QR semaine + EXACTEMENT 500 F reels + ZERO entree d'argent reel tracee (un gain paye en especes ne compte pas).</div>"
        if candidates:
            html += "<a class='btn' href='?cle=" + _cle + "&executer=1' onclick=\"return confirm('Convertir " + str(len(candidates)) + " joueuses ? Cette action ecrit dans la base.')\">&#9889; EXECUTER LA CONVERSION (" + str(len(candidates)) + " joueuses)</a>"
        liste = candidates
    if liste:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Reels avant</th><th class='dr'>Reels apres</th><th class='dr'>Bonus avant</th><th class='dr'>Bonus apres</th></tr>"
        for c in liste:
            html += "<tr><td>" + c["code"] + "</td><td>" + c["nom"] + "</td>"
            html += "<td class='dr'>" + format(c["reel"], ",") + "</td><td class='dr'>" + format(c["reel"] - 500, ",") + "</td>"
            html += "<td class='dr b'>" + format(c["bonus"], ",") + "</td><td class='dr b'>" + format(c["bonus"] + 500, ",") + "</td></tr>"
        html += "</table>"
    else:
        html += "<p class='ok'>Aucune joueuse a convertir : tout est deja regularise. &#127881;</p>"
    html += "<p class='sub' style='margin-top:16px'><a href='/audit-soldes?cle=" + _cle + "' style='color:#58a6ff'>&larr; Retour a l'audit des soldes</a></p>"
    html += "</body></html>"
    return html


@app.route("/audit-soldes")
def audit_soldes():
    """AUDIT GLOBAL (10/07/2026) : compare pour CHAQUE joueuse sa poche reelle
    (pions jouables) avec la somme de ses mouvements traces (entrees - sorties),
    exactement comme le releve financier. Fait en UNE page ce que la verification
    joueuse par joueuse ferait a la main.
    Acces : ?cle=CODE (admin ou organisatrice). Ajouter &tous=1 pour voir aussi
    les comptes equilibres."""
    global DB
    DB = load_data()
    _cle = (request.args.get("cle", "") or "").strip().upper()
    if _cle not in DB.get("codes", {}):
        return Response("<h1 style='font-family:sans-serif'>Acces refuse</h1>", status=403, mimetype="text/html; charset=utf-8")

    ent = {}
    sor = {}

    def _add(d, code_x, m):
        code_x = (code_x or "").upper().strip()
        try:
            m = int(m or 0)
        except (ValueError, TypeError):
            m = 0
        if code_x and m:
            d[code_x] = d.get(code_x, 0) + m

    # === ENTREES (memes sources que le releve financier joueur) ===
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            nb = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0)
            val = int(c.get("valeur_pion", 0) or 0)
            v = nb * val
            if v <= 0:
                v = int(c.get("montant_net", 0) or 0)
            _add(ent, c.get("code_joueur"), v)
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict):
            _add(ent, t.get("code_joueur"), t.get("montant_total", 0))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and not g.get("annule"):
            _add(ent, g.get("code_gagnant"), g.get("montant_credite", 0))
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0:
                _add(ent, c.get("code_joueur"), m)
            elif m < 0:
                _add(sor, c.get("code_joueur"), -m)
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict) and c.get("profil", "joueur") == "joueur":
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0:
                for cj in (c.get("codes") or []):
                    _add(ent, cj, m)
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            for det in (rb.get("detail") or []):
                if isinstance(det, dict):
                    _add(ent, det.get("code_joueur"), det.get("montant", 0))
    _cadeau_vu = set()
    for x in DB.get("rejoindre_log", []):
        cj = (x.get("code", "") or "").upper()
        if cj and cj not in _cadeau_vu and (x.get("campagne", "") or "") == "semaine":
            _add(ent, cj, 500)
            _cadeau_vu.add(cj)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and not t.get("annule_fraude"):
            _add(sor, t.get("de"), t.get("montant", 0))
            _add(ent, t.get("vers"), t.get("montant", 0))

    # === ENTREE : bonus par jeu (5 tickets P6 -> +500, 5 tickets OHANA -> +5000) ===
    for cle_bj in DB.get("bonus_jeu_donne", []):
        try:
            cj_b, jeu_b = str(cle_bj).split("|", 1)
        except ValueError:
            continue
        jbu = (jeu_b or "").upper()
        if "P6" in jbu:
            _add(ent, cj_b, 500)
        elif "OHANA" in jbu:
            _add(ent, cj_b, 5000)

    # === SORTIES ===
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict):
            _add(sor, e.get("code_joueur"), e.get("montant", 0))
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and c.get("statut") != "validee":
            _add(sor, c.get("code_joueur"), c.get("total_pions", 0))
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict) and r.get("statut") == "validee":
            _add(sor, r.get("code_joueur"), r.get("montant_demande", 0))
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict):
            retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
            if retire > 0:
                _add(sor, c.get("code_joueur"), retire)

    # === Tous les codes connus (traces + poches) ===
    codes_j = set(ent.keys()) | set(sor.keys())
    for k in DB.get("pions_joueurs", {}).keys():
        codes_j.add((k or "").upper())
    for k in DB.get("pions_bonus_joueurs", {}).keys():
        codes_j.add((k or "").upper())
    codes_j.discard("")
    # Ne pas auditer les codes organisateurs/staff comme des joueuses
    codes_j -= set((k or "").upper() for k in DB.get("codes", {}).keys())

    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = str(t.get("acheteur"))

    resultats = []
    for code_j in codes_j:
        pj = DB.get("pions_joueurs", {}).get(code_j, {})
        pb = DB.get("pions_bonus_joueurs", {}).get(code_j, {})
        poche_reel = _xpf_total_pions(pj)
        poche_bonus = _xpf_total_pions(pb)
        poche = poche_reel + poche_bonus
        e_t = ent.get(code_j, 0)
        s_t = sor.get(code_j, 0)
        solde_trace = e_t - s_t
        ecart = poche - solde_trace
        resultats.append({"code": code_j, "code_lien": code_j, "nom": noms.get(code_j, ""),
                          "poche": poche, "poche_reel": poche_reel, "poche_bonus": poche_bonus,
                          "entrees": e_t, "sorties": s_t, "trace": solde_trace, "ecart": ecart})

    # === FUSION DES CODES JUMEAUX ===
    # Ex : 90QFHR et 9OQFHR (zero et lettre O confondus a la saisie), ou un
    # emoji colle au code. C'est la MEME joueuse dont la trace est partie sur
    # un code mal tape : on fusionne pour voir son VRAI solde.
    groupes = {}
    for r in resultats:
        brut = "".join(ch for ch in r["code"] if ch.isalnum())
        canon = brut.replace("O", "0")
        groupes.setdefault(canon, []).append(r)
    fusionnes = []
    for canon, grp in groupes.items():
        if len(grp) == 1:
            fusionnes.append(grp[0])
            continue
        grp.sort(key=lambda r: (bool(r["nom"]), r["poche"]), reverse=True)
        base = dict(grp[0])
        base["fusion"] = True
        base["code"] = " + ".join(g["code"] for g in grp)
        for g in grp[1:]:
            base["entrees"] += g["entrees"]
            base["sorties"] += g["sorties"]
            base["poche"] += g["poche"]
            base["poche_reel"] += g["poche_reel"]
            base["poche_bonus"] += g["poche_bonus"]
        base["trace"] = base["entrees"] - base["sorties"]
        base["ecart"] = base["poche"] - base["trace"]
        fusionnes.append(base)
    resultats = fusionnes

    # === MONTANT A RISQUE (v4) : la seule chose qui compte pour un retrait.
    # = la part de l'ecart NON couverte par le bonus, plafonnee a la poche reelle.
    # Poche reelle vide => rien a retirer => risque 0, quel que soit l'ecart.
    def _risque(r):
        if r["ecart"] <= 0:
            return 0
        return max(0, min(r["ecart"] - r["poche_bonus"], r["poche_reel"]))

    voir_tous = (request.args.get("tous", "") or "").strip() == "1"
    nb_total = len(resultats)
    nb_ok = sum(1 for r in resultats if r["ecart"] == 0)
    nb_examiner = sum(1 for r in resultats if _risque(r) > 0)
    nb_sans_risque = nb_total - nb_ok - nb_examiner
    montant_risque_total = sum(_risque(r) for r in resultats)
    if not voir_tous:
        resultats = [r for r in resultats if r["ecart"] != 0]
    # Tri : les cas A EXAMINER d'abord (par montant a risque), le reste ensuite
    resultats.sort(key=lambda r: (0 if _risque(r) > 0 else 1, -_risque(r), -abs(r["ecart"])))

    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Audit des soldes</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:20px}"
    html += ".totaux{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:20px 0;display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;text-align:center}"
    html += ".m{font-size:18px;font-weight:bold}.ok{color:#3fb950}.ko{color:#f85149}.neu{color:#fbbf24}"
    html += "table{width:100%;border-collapse:collapse;margin-top:20px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}tr:hover{background:#21262d}"
    html += ".dr{text-align:right}a{color:#58a6ff}</style></head><body>"
    html += "<h1>&#128269; Audit des soldes joueuses</h1>"
    html += "<div class='sub'>Poche reelle (pions jouables) comparee aux mouvements traces (entrees &minus; sorties)</div>"
    html += "<div class='totaux' style='grid-template-columns:1fr 1fr 1fr 1fr'>"
    html += "<div><strong>Joueuses auditees</strong><br><span class='m'>" + str(nb_total) + "</span></div>"
    html += "<div><strong>Equilibrees</strong><br><span class='m ok'>" + str(nb_ok) + "</span></div>"
    html += "<div><strong>Sans risque</strong><br><span class='m' style='color:#a78bfa'>" + str(nb_sans_risque) + "</span><br><span style='font-size:11px;color:#8b949e'>ecart couvert par le bonus ou rien a retirer</span></div>"
    html += "<div><strong>A EXAMINER</strong><br><span class='m " + ("ko" if nb_examiner else "ok") + "'>" + str(nb_examiner) + "</span><br><span style='font-size:11px;color:#8b949e'>risque total : " + format(montant_risque_total, ",") + " XPF</span></div>"
    html += "</div>"
    if voir_tous:
        html += "<p><a href='?cle=" + _cle + "'>Voir seulement les ecarts</a></p>"
    else:
        html += "<p><a href='?cle=" + _cle + "&tous=1'>Voir toutes les joueuses (y compris equilibrees)</a></p>"
    if resultats:
        html += "<table><tr><th>Code</th><th>Nom</th><th class='dr'>Entrees tracees</th><th class='dr'>Sorties tracees</th><th class='dr'>Solde trace</th><th class='dr'>Poche REELLE</th><th class='dr'>Poche BONUS</th><th class='dr'>Ecart</th><th class='dr'>Montant A RISQUE</th><th>Lecture</th></tr>"
        for r in resultats:
            rq = _risque(r)
            if r["ecart"] == 0:
                verdict = "<span class='ok'>&#9989; equilibre</span>"
            elif rq > 0:
                verdict = "<span class='ko'>&#128680; A EXAMINER : pions retirables sans origine tracee</span>"
            elif r["ecart"] > 0 and r["poche_reel"] == 0:
                verdict = "<span style='color:#58a6ff'>&#8505;&#65039; historique incomplet — rien a retirer (sans risque)</span>"
            elif r["ecart"] > 0:
                verdict = "<span style='color:#a78bfa'>&#9989; sans risque : ecart couvert par le bonus (non retirable)</span>"
            else:
                verdict = "<span class='neu'>&#9888;&#65039; traces &gt; poche (sorties anciennes non tracees) — rien a payer au-dela de la poche</span>"
            if r.get("fusion"):
                verdict += " <span style='color:#a78bfa'>&#128279; codes jumeaux fusionnes</span>"
            html += "<tr><td><a href='/releve-financier-joueur/" + r["code_lien"] + "?cle=" + _cle + "'>" + r["code"] + "</a></td>"
            html += "<td>" + r["nom"] + "</td>"
            html += "<td class='dr'>+" + format(r["entrees"], ",") + "</td>"
            html += "<td class='dr'>-" + format(r["sorties"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["trace"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["poche_reel"], ",") + "</td>"
            html += "<td class='dr' style='color:#a78bfa'>" + format(r["poche_bonus"], ",") + "</td>"
            html += "<td class='dr'>" + format(r["ecart"], ",") + "</td>"
            html += "<td class='dr'><strong class='" + ("ko" if rq > 0 else "ok") + "'>" + format(rq, ",") + "</strong></td>"
            html += "<td>" + verdict + "</td></tr>"
        html += "</table>"
        html += "<p class='sub' style='margin-top:16px'>Chaque code est cliquable : il ouvre le releve detaille de la joueuse pour analyser l'ecart ligne par ligne.</p>"
    else:
        html += "<p class='ok' style='font-size:16px'>&#127881; Aucune joueuse en ecart : toutes les poches correspondent aux traces !</p>"
    html += "</body></html>"
    return html


@app.route("/releve-financier-joueur/<code>")
def releve_financier_joueur(code):
    """Releve financier d'une joueuse : pions achetes/recus (entrees) et tickets achetes (sorties)."""
    global DB
    DB = load_data()
    code = code.upper().strip()

    # === RELEVE PRIVE : seuls l'admin, une organisatrice/staff, ou le joueur lui-meme ===
    _cle = (request.args.get("cle", "") or "").strip().upper()
    _staff = _cle in DB.get("codes", {})          # admin, organisatrice ou revendeuse
    _is_admin = bool(DB.get("codes", {}).get(_cle, {}).get("admin"))
    _proprietaire = (_cle == code)                 # le joueur consulte SON propre releve
    if not (_staff or _proprietaire):
        return Response('''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:40px;color:#fff;text-align:center">
        <div style="max-width:420px;margin:0 auto;background:#161b22;border:1px solid #30363d;border-radius:12px;padding:30px">
        <div style="font-size:42px;margin-bottom:10px">&#128274;</div>
        <h1 style="font-size:20px;color:#f0883e">Relev&eacute; priv&eacute;</h1>
        <p style="color:#8b949e;font-size:14px;line-height:1.6">Ce relev&eacute; est confidentiel. Seuls le joueur concern&eacute;, une organisatrice ou l'administration peuvent y acc&eacute;der.</p>
        <p style="color:#6e7681;font-size:12px">Connectez-vous avec votre code pour consulter votre propre relev&eacute;.</p>
        </div></body></html>''', status=403, mimetype="text/html; charset=utf-8")
    
    # Nom de la joueuse (depuis les tickets)
    nom = "Joueuse"
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") == code and t.get("acheteur"):
            nom = t.get("acheteur")
            break
    
    lignes = []  # {date, type, desc, entree, sortie}

    # === ENTREE : achats de pions — VALEUR EN PIONS (pas l'argent payé, frais exclus) ===
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("code_joueur") == code and c.get("statut") == "validee":
            # Achat carte (Stripe) : champ "pions_credites" ; achat manuel : champ "nb_pions"
            nb = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0)
            val = int(c.get("valeur_pion", 0) or 0)
            valeur_pions = nb * val
            if valeur_pions <= 0:
                valeur_pions = int(c.get("montant_net", 0) or 0)  # filet de sécurité (Stripe)
            lignes.append({
                "date": c.get("date", "?"),
                "type": "Achat pions",
                "desc": str(nb) + " pions x " + str(val) + " XPF (" + str(c.get("mode_paiement", "?")) + ")"
                        + ((" · payé " + format(int(c.get("montant_paye", 0) or 0), ",") + " XPF") if c.get("montant_paye") else "")
                        + ((" · frais " + format(int(c.get("frais_service", 0) or 0), ",") + " XPF") if c.get("frais_service") else "")
                        + ((" · réf. " + str(c.get("ref_paiement"))) if c.get("ref_paiement") else ""),
                "entree": valeur_pions,
                "sortie": 0
            })

    # === ENTREE : pions reçus de l'organisateur ===
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and t.get("code_joueur") == code:
            lignes.append({
                "date": t.get("date", "?"),
                "type": "Pions reçus (org)",
                "desc": str(t.get("nb_pions", "?")) + " x " + str(t.get("valeur_pion", "?")) + " XPF (" + str(t.get("mode_paiement", "?")) + ")",
                "entree": int(t.get("montant_total", 0) or 0),
                "sortie": 0
            })

    # === ENTREE : gains à la cagnotte (pions gagnés au tournoi) ===
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code_gagnant") == code and not g.get("annule"):
            gain = int(g.get("montant_credite", 0) or 0)
            if gain > 0:
                lignes.append({
                    "date": g.get("date", "?"),
                    "type": "Gain cagnotte",
                    "desc": "Pions gagnés au tournoi",
                    "entree": gain,
                    "sortie": 0
                })

    # === SORTIE : tickets achetés en pions — trace permanente encaissements_org
    # (retrouve aussi les achats des ANCIENS tournois) ===
    for e in DB.get("encaissements_org", []):
        if isinstance(e, dict) and (e.get("code_joueur") or "").upper() == code:
            lignes.append({
                "date": e.get("date", "?"),
                "type": "Achat tickets",
                "desc": str(e.get("jeu", "?")) + " (vente validée — " + _nom_org_public(e.get("code_org", "")) + ")",
                "entree": 0,
                "sortie": int(e.get("montant", 0) or 0)
            })
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and c.get("code_joueur") == code and c.get("statut") != "validee":
            lignes.append({
                "date": c.get("date", "?"),
                "type": "Achat tickets (en attente)",
                "desc": str(c.get("jeu", "?")) + " (" + str(c.get("nb_tickets", "?")) + " tickets)",
                "entree": 0,
                "sortie": int(c.get("total_pions", 0) or 0)
            })

    # === SORTIE : retraits validés (pions convertis en argent) ===
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict) and r.get("code_joueur") == code and r.get("statut") == "validee":
            lignes.append({
                "date": r.get("date", "?"),
                "type": "Retrait argent",
                "desc": "Pions convertis en argent (" + str(r.get("mode", "?")) + ")",
                "entree": 0,
                "sortie": int(r.get("montant_demande", 0) or 0)
            })

    # === SORTIE : corrections admin (pions retirés) ===
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict) and c.get("code_joueur") == code:
            retire = int(c.get("solde_avant", 0) or 0) - int(c.get("solde_apres", 0) or 0)
            if retire > 0:
                lignes.append({
                    "date": c.get("date", "?"),
                    "type": "Correction admin",
                    "desc": "Pions retirés (correction)",
                    "entree": 0,
                    "sortie": retire
                })

    # === ENTREE/SORTIE : crédits directs de l'admin (recrédit après incident) ===
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and c.get("code_joueur") == code:
            montant = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            _motif = (c.get("motif") or c.get("jeu") or "").strip()
            if montant > 0:
                lignes.append({"date": c.get("date", "?"), "type": ("Remboursement" if _motif else "Crédit admin"),
                               "desc": (_motif if _motif else "Pions crédités par l'admin"), "entree": montant, "sortie": 0})
            elif montant < 0:
                lignes.append({"date": c.get("date", "?"), "type": "Débit admin",
                               "desc": "Pions retirés par l'admin", "entree": 0, "sortie": -montant})

    # === ENTREE : crédits en masse de l'admin (dédommagements / transferts) ===
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict) and c.get("profil", "joueur") == "joueur" and code in (c.get("codes") or []):
            montant = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if montant > 0:
                lignes.append({"date": c.get("date", "?"), "type": "Crédit admin (groupe)",
                               "desc": "Dédommagement / transfert admin", "entree": montant, "sortie": 0})

    # === ENTREE : remboursements (jeu annulé par l'organisateur) ===
    for rb in DB.get("remboursements_tournoi", []):
        if isinstance(rb, dict):
            for det in (rb.get("detail") or []):
                if isinstance(det, dict) and det.get("code_joueur") == code:
                    montant = int(det.get("montant", 0) or 0)
                    if montant > 0:
                        lignes.append({"date": rb.get("date", "?"), "type": "Remboursement",
                                       "desc": "Jeu annulé : " + str(rb.get("jeu", "?")),
                                       "entree": montant, "sortie": 0})

    # === ENTREE : cadeau d'inscription (campagne "semaine" : 500 F de bonus offerts à l'inscription) ===
    for x in DB.get("rejoindre_log", []):
        if (x.get("code", "") or "").upper() == code and (x.get("campagne", "") or "") == "semaine":
            lignes.append({"date": x.get("date", "?"), "type": "Cadeau inscription",
                           "desc": "Bonus 500 F offert à l'inscription", "entree": 500, "sortie": 0})
            break

    # === TRANSFERTS DE PIONS (envoyés / reçus) — notés comme sur un relevé bancaire ===
    # CONFIDENTIALITE (11/07/2026) : sur le releve d'une joueuse, on ne montre ni
    # le code complet de l'autre partie, ni les adresses IP. On masque le code
    # (2 premiers caracteres + ***) pour que la joueuse s'y retrouve sans exposer
    # un code qui sert a se connecter.
    def _masque_code(c):
        c = (c or "").upper()
        return (c[:2] + "***") if len(c) > 2 else "***"
    for t in DB.get("transferts_pions", []):
        if not isinstance(t, dict):
            continue
        de = (t.get("de", "") or "").upper()
        vers = (t.get("vers", "") or "").upper()
        montant = int(t.get("montant", 0) or 0)
        if t.get("annule_fraude"):
            if de == code or vers == code:
                lignes.append({"date": t.get("date", "?"), "type": "Transfert ANNULÉ",
                               "desc": "Transfert de " + format(montant, ",") + " F ANNULÉ par l'administration (fraude)",
                               "entree": 0, "sortie": 0})
            continue
        if de == code:
            lignes.append({"date": t.get("date", "?"), "type": "Transfert émis",
                           "desc": "Pions transférés vers le compte " + _masque_code(vers),
                           "entree": 0, "sortie": montant})
        elif vers == code:
            lignes.append({"date": t.get("date", "?"), "type": "Transfert reçu",
                           "desc": "Pions reçus du compte " + _masque_code(de),
                           "entree": montant, "sortie": 0})

    # Solde de pions actuel = pions RÉELS + pions BONUS (tous deux jouables)
    pj = DB.get("pions_joueurs", {}).get(code, {})
    pb = DB.get("pions_bonus_joueurs", {}).get(code, {})
    solde_pions = 0
    for v, nb in pj.items():
        try:
            solde_pions += int(v) * int(nb)
        except (ValueError, TypeError):
            pass
    solde_bonus = 0
    for v, nb in pb.items():
        try:
            solde_bonus += int(v) * int(nb)
        except (ValueError, TypeError):
            pass
    solde_pions = solde_pions + solde_bonus

    # === FILTRE PAR DATES (optionnel) : ?du=AAAA-MM-JJ&au=AAAA-MM-JJ ===
    du = (request.args.get("du") or "").strip()
    au = (request.args.get("au") or "").strip()
    periode_active = bool(du or au)

    def _dans_periode(dt):
        j = str(dt)[:10]
        if not j or j == "?":
            return False  # une ligne sans date n'entre pas dans une période filtrée
        if du and j < du:
            return False
        if au and j > au:
            return False
        return True

    if periode_active:
        # Vue PÉRIODE : seulement les mouvements de la période choisie
        # (pas de régularisation : elle ne vaut que pour le solde global).
        lignes = [l for l in lignes if _dans_periode(l["date"])]
    else:
        # Vue TOTALE : régularisation pour que entrées − sorties = solde réel.
        _ent = sum(l["entree"] for l in lignes)
        _sor = sum(l["sortie"] for l in lignes)
        ajustement = solde_pions - (_ent - _sor)
        # Fraude = lié à 2+ AUTRES comptes par transfert (réseau de 3 codes ou +).
        # 2 codes (HEINI + MAEVA) pour un même joueur = normal, pas de la fraude.
        _lies_reg = set()
        for _t in DB.get("transferts_pions", []):
            if not isinstance(_t, dict):
                continue
            _d = (_t.get("de") or "").upper(); _v = (_t.get("vers") or "").upper()
            if _d == code and _v:
                _lies_reg.add(_v)
            elif _v == code and _d:
                _lies_reg.add(_d)
        _bloque = code in DB.get("codes_bloques", [])
        # AUCUNE ligne d'équilibrage pour personne : le solde = entrées − sorties brut.

    lignes.sort(key=lambda x: str(x["date"]), reverse=True)

    # Totaux RÉELS (hors mise à zéro / solde antérieur) + l'ajustement à part
    total_entrees = sum(l["entree"] for l in lignes if not l.get("ajustement"))
    total_sorties = sum(l["sortie"] for l in lignes if not l.get("ajustement"))
    _ajust_entree = sum(l["entree"] for l in lignes if l.get("ajustement"))
    _ajust_sortie = sum(l["sortie"] for l in lignes if l.get("ajustement"))
    _ajust_net = _ajust_entree - _ajust_sortie  # négatif = pions retirés
    _ajust_label = next((l["type"] for l in lignes if l.get("ajustement")), "")
    # RÈGLE SACRÉE : le solde affiché = ENTRÉES − SORTIES (+ ligne Total pour le réseau)
    _solde_affiche = total_entrees - total_sorties + _ajust_net
    
    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Mon releve</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:20px}"
    html += ".totaux{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:20px 0;display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;text-align:center}"
    html += ".m{font-size:18px;font-weight:bold}.ent{color:#3fb950}.sor{color:#f85149}.sol{color:#fbbf24}"
    html += "table{width:100%;border-collapse:collapse;margin-top:20px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}tr:hover{background:#21262d}"
    html += ".td-ent{color:#3fb950;text-align:right}.td-sor{color:#f85149;text-align:right}</style></head><body>"
    html += "<h1>Mon releve de pions</h1>"
    html += "<div class='sub'>" + str(nom) + " (" + code + ")</div>"
    # === ORIGINE DU CODE : QR (inscription pub) ou créé par une organisatrice ? ===
    _rj = next((x for x in DB.get("rejoindre_log", []) if (x.get("code", "") or "").upper() == code), None)
    _tks_all = [t for t in DB.get("tickets", []) if (t.get("code_acheteur", "") or "").upper() == code]
    _pub = any((t.get("code_org") == "PUB" or t.get("source") == "publicite") for t in _tks_all)
    if _rj or _pub:
        _camp = (_rj.get("campagne") if _rj else "") or "—"
        _dt = ((_rj.get("date") if _rj else "") or "")[:16].replace("T", " ")
        html += ('<div style="background:#0c4a6e;color:#bae6fd;padding:12px 14px;border-radius:10px;margin:12px 0;font-size:13px">'
                 '📲 <b>Origine du compte : auto-inscription par QR code</b> (publicité).'
                 + (f'<br><span style="color:#7dd3fc;font-size:12px">Campagne : <b>{_camp}</b>{(" · le " + _dt) if _dt else ""}</span>' if (_camp != "—" or _dt) else "")
                 + '</div>')
    elif _tks_all:
        _org_codes = sorted({t.get("code_org") for t in _tks_all if t.get("code_org")})
        _org_noms = ", ".join(DB.get("codes", {}).get(o, {}).get("nom", o) for o in _org_codes) or "—"
        html += ('<div style="background:#3b1d5e;color:#e9d5ff;padding:12px 14px;border-radius:10px;margin:12px 0;font-size:13px">'
                 '✍️ <b>Origine du compte : créé par une organisatrice</b>.'
                 f'<br><span style="color:#c4b5fd;font-size:12px">Organisatrice : <b>{_org_noms}</b></span></div>')
    # === SECURITE : adresses IP enregistrees pour ce compte ===
    _ips_vues = {}
    for _x in DB.get("journal_connexions", []):
        if isinstance(_x, dict) and (_x.get("code") or "").upper() == code and _x.get("ip"):
            _d = str(_x.get("date", ""))
            if _x["ip"] not in _ips_vues or _d > _ips_vues[_x["ip"]]:
                _ips_vues[_x["ip"]] = _d
    for _t in DB.get("transferts_pions", []):
        if isinstance(_t, dict) and _t.get("ip") and ((_t.get("de") or "").upper() == code or (_t.get("vers") or "").upper() == code):
            _d = str(_t.get("date", ""))
            if _t["ip"] not in _ips_vues or _d > _ips_vues[_t["ip"]]:
                _ips_vues[_t["ip"]] = _d
    if _ips_vues:
        _lignes_ip = ""
        for _ip, _d in sorted(_ips_vues.items(), key=lambda kv: kv[1], reverse=True)[:15]:
            _dd = _d[:16].replace("T", " ") if _d else ""
            _lignes_ip += "<div style='font-family:monospace;font-size:12px;color:#e6edf3'>" + str(_ip) + ("  <span style='color:#8b949e'>(" + _dd + ")</span>" if _dd else "") + "</div>"
        html += ("<div style='background:#161b22;border:1px solid #30363d;border-radius:8px;padding:12px;margin:12px 0'>"
                 "<div style='font-size:13px;color:#58a6ff;font-weight:bold;margin-bottom:6px'>&#128274; Connexions enregistrees sur ce compte</div>"
                 + _lignes_ip +
                 "<div style='font-size:11px;color:#8b949e;margin-top:6px'>Chaque acces a ce compte est enregistre (adresse IP, date et appareil) a des fins de securite.</div></div>")
    # === SYNTHESE D'AUDIT (uniquement comptes avec transferts ; releve prive) ===
    _recu_de = {}; _envoye_a = {}
    for _t in DB.get("transferts_pions", []):
        if not isinstance(_t, dict):
            continue
        _de = (_t.get("de", "") or "").upper()
        _vers = (_t.get("vers", "") or "").upper()
        _m = int(_t.get("montant", 0) or 0)
        if _vers == code and _de:
            _recu_de[_de] = _recu_de.get(_de, 0) + _m
        elif _de == code and _vers:
            _envoye_a[_vers] = _envoye_a.get(_vers, 0) + _m
    _lies = set(_recu_de) | set(_envoye_a)
    if len(_lies) >= 2:  # lié à 2+ autres comptes = réseau de 3 codes ou + = fraude
        _tot_recu = sum(_recu_de.values())
        _tot_env = sum(_envoye_a.values())
        _nb_ip = len(_ips_vues)
        _tot_cred = 0
        for _c in DB.get("credits_admin", []):
            if isinstance(_c, dict) and (_c.get("code_joueur") or "").upper() == code:
                _tot_cred += int(_c.get("nb_pions", 0) or 0) * int(_c.get("valeur_pion", 0) or 0)
        for _c in DB.get("credits_masse", []):
            if isinstance(_c, dict) and code in [(x or "").upper() for x in (_c.get("codes") or [])]:
                _tot_cred += int(_c.get("nb_pions", 0) or 0) * int(_c.get("valeur_pion", 0) or 0)
        _tot_achat_reel = 0
        for _c in DB.get("commandes_pions_joueurs", []):
            if isinstance(_c, dict) and (_c.get("code_joueur") or "").upper() == code and _c.get("statut") == "validee":
                _nbp = int(_c.get("nb_pions", _c.get("pions_credites", 0)) or 0)
                _vp = int(_c.get("valeur_pion", 0) or 0)
                _tot_achat_reel += (_nbp * _vp) or int(_c.get("montant_net", 0) or 0)
        # Gains de tournoi (pour le total "réellement eu")
        _tot_gain = 0
        for _g in DB.get("gains_finaux", []):
            if isinstance(_g, dict) and (_g.get("code") or "").upper() == code:
                _tot_gain += int(_g.get("montant_gain", _g.get("montant_credite", 0)) or 0)
        # Contrôle du débit source : a-t-il envoyé plus qu'il n'a jamais eu ?
        _total_eu = _tot_achat_reel + _tot_gain + _tot_cred + _tot_recu
        _ecart_source = _tot_env - _total_eu  # > 0 => pions envoyés sans les avoir eus
        if len(_recu_de) >= 2 and _tot_recu > _tot_env:
            _role = "Collecteur (reçoit des pions de plusieurs comptes)"
        elif len(_envoye_a) >= 2 and _tot_env > _tot_recu:
            _role = "Redistributeur (envoie des pions vers plusieurs comptes)"
        elif _lies:
            _role = "Compte relié à un réseau de transferts"
        else:
            _role = ""
        def _orig_court(_cc):
            _r = next((x for x in DB.get("rejoindre_log", []) if (x.get("code", "") or "").upper() == _cc), None)
            _tk = [t for t in DB.get("tickets", []) if (t.get("code_acheteur", "") or "").upper() == _cc]
            _pb = any((t.get("code_org") == "PUB" or t.get("source") == "publicite") for t in _tk)
            if _r or _pb:
                return "QR"
            if _tk:
                _os = sorted({t.get("code_org") for t in _tk if t.get("code_org")})
                _nm = ", ".join(DB.get("codes", {}).get(o, {}).get("nom", o) for o in _os)
                return _nm or "?"
            return "?"
        _liste_html = "".join(
            "<div style='margin-left:12px;font-family:monospace;font-size:12px'>&ndash; " + _c +
            " <span style='color:#d4a857;font-family:system-ui'>(émis par : " + _orig_court(_c) + ")</span></div>"
            for _c in sorted(_lies))
        html += ("<div style='background:#2b1a00;border:1px solid #f59e0b;border-radius:10px;padding:14px;margin:12px 0;color:#fde68a;font-size:13px;line-height:1.7'>"
                 "<div style='font-size:14px;font-weight:bold;color:#f0b03e;margin-bottom:6px'>&#128202; Total des transferts de pions (de code &agrave; code)</div>"
                 "<div>&bull; Comptes li&eacute;s par transfert : <b>" + str(len(_lies)) + "</b></div>" + _liste_html +
                 "<div>&bull; Pions re&ccedil;us par transfert : <b>" + format(_tot_recu, ",") + " XPF</b>" +
                 (" depuis " + str(len(_recu_de)) + " compte(s)" if _recu_de else "") + "</div>"
                 "<div>&bull; Pions envoy&eacute;s par transfert : <b>" + format(_tot_env, ",") + " XPF</b>" +
                 (" vers " + str(len(_envoye_a)) + " compte(s)" if _envoye_a else "") + "</div>"
                 "<div>&bull; Adresses IP de connexion enregistr&eacute;es : <b>" + str(_nb_ip) + "</b></div>"
                 + ("<div>&bull; Pions r&eacute;ellement achet&eacute;s (vrai paiement) : <b>" + format(_tot_achat_reel, ",") + " XPF</b></div>" if _tot_achat_reel else "<div>&bull; Pions r&eacute;ellement achet&eacute;s : <b>0 XPF</b> (aucun achat r&eacute;el)</div>")
                 + ("<div>&bull; Recr&eacute;dits administratifs re&ccedil;us : <b>" + format(_tot_cred, ",") + " XPF</b></div>" if _tot_cred else "")
                 + ((("<div style='margin-top:6px;padding:8px;background:rgba(248,81,73,.15);border-radius:6px'>&#128308; <b>Contr&ocirc;le d&eacute;bit : ce compte a envoy&eacute; " + format(_ecart_source, ",") + " XPF de PLUS qu'il n'en a jamais eu</b> (envoy&eacute; " + format(_tot_env, ",") + " / r&eacute;ellement eu " + format(_total_eu, ",") + "). Ces pions n'avaient pas de contrepartie r&eacute;elle.</div>") if _ecart_source > 0 else ("<div style='margin-top:6px;padding:8px;background:rgba(63,185,80,.1);border-radius:6px;color:#3fb950'>&#9989; D&eacute;bit coh&eacute;rent : ce compte a envoy&eacute; " + format(_tot_env, ",") + " XPF, couverts par ce qu'il a r&eacute;ellement eu (" + format(_total_eu, ",") + " XPF).</div>")) if _tot_env > 0 else "")
                 + ((("<div style='margin-top:6px;padding:8px;background:rgba(248,81,73,.12);border-radius:6px'>&#128308; <b>Ce compte d&eacute;tient encore " + format(_solde_affiche, ",") + " XPF</b> de pions sur les transferts re&ccedil;us.</div>") if _solde_affiche > 0 else ("<div style='margin-top:6px;padding:8px;background:rgba(63,185,80,.12);border-radius:6px;color:#3fb950'>&#9989; <b>Ce compte ne d&eacute;tient plus de pions</b> (solde &agrave; 0). Les pions re&ccedil;us par transfert ne sont plus disponibles.</div>")) if _tot_recu > 0 else "")
                 + "<div style='margin-top:8px;font-size:12px;color:#d4a857'>Toutes ces op&eacute;rations sont enregistr&eacute;es et document&eacute;es (dates, montants et adresses IP).</div></div>")
    html += "<form method='get' style='margin:10px 0;display:flex;gap:8px;flex-wrap:wrap;align-items:center'>"
    html += "<span style='font-size:12px;color:#8b949e'>Periode :</span>"
    html += "<input type='date' name='du' value='" + du + "' style='background:#0d1117;color:#e6edf3;border:1px solid #30363d;border-radius:6px;padding:6px'>"
    html += "<input type='date' name='au' value='" + au + "' style='background:#0d1117;color:#e6edf3;border:1px solid #30363d;border-radius:6px;padding:6px'>"
    html += "<button type='submit' style='background:#58a6ff;color:#0d1117;border:none;border-radius:6px;padding:7px 14px;font-weight:bold;cursor:pointer'>Filtrer</button>"
    html += "<a href='?' style='color:#8b949e;font-size:12px;text-decoration:underline'>Tout voir</a>"
    html += "</form>"
    if periode_active:
        html += "<div class='sub' style='color:#58a6ff'>Periode du " + (du or "debut") + " au " + (au or "aujourd'hui") + "</div>"
    html += "<div class='totaux'>"
    html += "<div><strong>Pions achetes/recus</strong><br><span class='m ent'>+" + format(total_entrees, ",") + " XPF</span></div>"
    html += "<div><strong>Pions depenses</strong><br><span class='m sor'>-" + format(total_sorties, ",") + " XPF</span><br><span style='font-size:11px;color:#8b949e'>tickets, retraits, corrections</span></div>"
    if periode_active:
        net = total_entrees - total_sorties
        html += "<div><strong>Net periode</strong><br><span class='m sol'>" + ("+" if net >= 0 else "") + format(net, ",") + " XPF</span><br><span style='font-size:11px;color:#8b949e'>solde actuel : " + format(solde_pions, ",") + " XPF</span></div>"
    else:
        _note_bonus = ("dont " + format(solde_bonus, ",") + " F bonus jouable") if solde_bonus > 0 else "voir récapitulatif en bas"
        html += "<div><strong>Solde actuel</strong><br><span class='m sol'>" + format(_solde_affiche, ",") + " XPF</span><br><span style='font-size:11px;color:#8b949e'>= entrees - sorties</span></div>"
    html += "</div>"
    
    if lignes:
        html += "<table><tr><th>Date</th><th>Type</th><th>Detail</th><th>Entree</th><th>Sortie</th></tr>"
        for l in lignes:
            ent = "+" + format(l["entree"], ",") if l["entree"] > 0 else ""
            sor = "-" + format(l["sortie"], ",") if l["sortie"] > 0 else ""
            html += "<tr><td>" + str(l["date"])[:16] + "</td>"
            html += "<td>" + str(l["type"]) + "</td>"
            html += "<td>" + str(l["desc"]) + "</td>"
            html += "<td class='td-ent'>" + ent + "</td>"
            html += "<td class='td-sor'>" + sor + "</td></tr>"
        html += "</table>"
        # === RÉCAPITULATIF VRAI : entrées, sorties RÉELLES, mise à zéro séparée ===
        _solde_theorique = total_entrees - total_sorties
        html += ("<div style='background:#0d1117;border:2px solid #30363d;border-radius:10px;padding:16px;margin:18px 0;font-size:14px'>"
                 "<div style='font-weight:bold;color:#e6edf3;margin-bottom:10px;font-size:15px'>📋 Récapitulatif du relevé</div>"
                 "<div style='display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.06)'>"
                 "<span style='color:#8b949e'>① Total des ENTRÉES (pions reçus, achetés, gagnés)</span>"
                 "<b style='color:#3fb950'>+" + format(total_entrees, ",") + " XPF</b></div>"
                 "<div style='display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.06)'>"
                 "<span style='color:#8b949e'>② Total des SORTIES réelles (tickets, transferts envoyés, retraits)</span>"
                 "<b style='color:#f85149'>-" + format(total_sorties, ",") + " XPF</b></div>"
                 + (("<div style='display:flex;justify-content:space-between;padding:6px 0;border-bottom:1px solid rgba(255,255,255,.06)'>"
                     "<span style='color:#8b949e'>" + _ajust_label + "</span>"
                     "<b style='color:" + ("#f85149" if _ajust_net < 0 else "#3fb950") + "'>" + ("+" if _ajust_net >= 0 else "") + format(_ajust_net, ",") + " XPF</b></div>") if _ajust_net != 0 else "")
                 + "<div style='display:flex;justify-content:space-between;padding:10px 0 2px;font-size:16px'>"
                 "<span style='color:#e6edf3;font-weight:bold'>SOLDE ACTUEL du compte</span>"
                 "<b style='color:#58a6ff'>" + format(_solde_affiche, ",") + " XPF</b></div>"
                 + (("<div style='margin-top:8px;padding:8px;background:rgba(63,185,80,.1);border-radius:6px;font-size:12px;color:#3fb950'>✓ Vérification : " + format(total_entrees, ",") + " − " + format(total_sorties, ",") + (((" − " + format(-_ajust_net, ",")) if _ajust_net < 0 else (" + " + format(_ajust_net, ","))) if _ajust_net != 0 else "") + " = " + format(_solde_affiche, ",") + " XPF. Calcul équilibré.</div>")
                    if (_solde_theorique + _ajust_net) == _solde_affiche else "")
                 + "</div>")
    else:
        html += "<p style='color:#8b949e;margin-top:20px'>Aucune operation pour le moment.</p>"
    
    html += "</body></html>"
    return html



# ============================================
# SYSTEME DE RETRAIT DE PIONS EN ARGENT (fin de tournoi)
# La joueuse demande -> l'organisateur valide -> les pions sont retires
# Cash = 0% de frais, Virement = 5% de frais
# ============================================

@app.route("/api/retrait/demander", methods=["POST"])
def demander_retrait():
    """La joueuse demande de convertir ses pions en argent."""
    global DB
    DB = load_data()
    d = request.json
    code_joueur = (d.get("code_joueur") or "").upper().strip()
    code_org = (d.get("code_org") or "").upper().strip()
    montant = int(d.get("montant", 0))
    mode = str(d.get("mode", "Cash"))  # Cash ou Virement
    coordonnees = str(d.get("coordonnees", ""))  # pour virement
    
    if code_joueur in DB.get("codes_bloques", []):
        return jsonify({"ok": False, "msg": "Ce code a été désactivé"}), 403
    if not code_joueur or montant < 20:
        return jsonify({"ok": False, "msg": "Montant invalide (minimum 20 XPF)"}), 400
    
    # Verifier le solde de pions de la joueuse
    pions = DB.get("pions_joueurs", {}).get(code_joueur, {})
    solde_total = 0
    for v, nb in pions.items():
        try:
            solde_total += int(v) * nb
        except (ValueError, TypeError):
            pass
    if montant > solde_total:
        return jsonify({"ok": False, "msg": f"Solde insuffisant — vous avez {solde_total} XPF de pions"}), 400
    
    # Calcul des frais : Cash = 0%, Virement = 5%
    mode_bas = mode.lower()
    if "virement" in mode_bas or "ccp" in mode_bas or "bt" in mode_bas or "deblock" in mode_bas:
        frais = round(montant * 0.05)
    else:
        frais = 0  # Cash
    montant_net = montant - frais
    
    if "demandes_retrait" not in DB:
        DB["demandes_retrait"] = []
    
    demande = {
        "id": secrets.token_hex(4).upper(),
        "code_joueur": code_joueur,
        "code_org": code_org,
        "montant_demande": montant,
        "mode": mode,
        "coordonnees": coordonnees,
        "frais": frais,
        "montant_net": montant_net,
        "statut": "en_attente",
        "date": datetime.datetime.now().isoformat()
    }
    DB["demandes_retrait"].insert(0, demande)
    save_data()
    return jsonify({"ok": True, "demande_id": demande["id"], "montant_net": montant_net, "frais": frais})


@app.route("/api/retrait/liste")
def liste_retraits():
    """L'organisateur voit les demandes de retrait de ses joueuses (ou admin voit tout)."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False}), 403
    
    code = s["code"]
    est_admin = s.get("admin")
    resultats = []
    for r in DB.get("demandes_retrait", []):
        if est_admin or r.get("code_org") == code:
            resultats.append(r)
    return jsonify(resultats)


@app.route("/api/retrait/valider", methods=["POST"])
def valider_retrait():
    """L'organisateur valide : les pions sont retires du compte de la joueuse."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False}), 403
    
    demande_id = request.json.get("demande_id", "")
    for r in DB.get("demandes_retrait", []):
        if r["id"] == demande_id:
            # ANTI DOUBLE-VALIDATION
            if r.get("statut") == "validee":
                return jsonify({"ok": False, "msg": "Ce retrait a déjà été validé"}), 400
            
            code_joueur = r["code_joueur"]
            montant = int(r["montant_demande"])
            
            # Re-verifier le solde au moment de la validation (anti-triche)
            pions = DB.get("pions_joueurs", {}).get(code_joueur, {})
            solde_total = 0
            for v, nb in pions.items():
                try:
                    solde_total += int(v) * nb
                except (ValueError, TypeError):
                    pass
            if montant > solde_total:
                return jsonify({"ok": False, "msg": "Solde de pions insuffisant maintenant"}), 400
            
            # Debiter les pions (gere 10/20/50/100 + monnaie)
            reste = montant
            for valeur in ["10", "20", "50", "100"]:
                nb_dispo = pions.get(valeur, 0)
                if nb_dispo > 0 and reste > 0:
                    val_int = int(valeur)
                    nb_utilise = min(nb_dispo, reste // val_int)
                    if nb_utilise > 0:
                        pions[valeur] = nb_dispo - nb_utilise
                        reste -= nb_utilise * val_int
            if reste > 0:
                for valeur in ["20", "50", "100"]:
                    val_int = int(valeur)
                    if pions.get(valeur, 0) > 0 and val_int >= reste:
                        pions[valeur] -= 1
                        rendu = val_int - reste
                        if rendu > 0:
                            pions["10"] = pions.get("10", 0) + (rendu // 10)
                        reste = 0
                        break
            if reste > 0:
                return jsonify({"ok": False, "msg": "Impossible de couvrir le montant avec les pions disponibles"}), 400
            
            DB["pions_joueurs"][code_joueur] = pions
            r["statut"] = "validee"
            r["date_validation"] = datetime.datetime.now().isoformat()
            save_data(immediat=True)
            return jsonify({"ok": True, "montant_net": r.get("montant_net")})
    
    return jsonify({"ok": False, "msg": "Demande introuvable"}), 404


@app.route("/api/retrait/refuser", methods=["POST"])
def refuser_retrait():
    """L'organisateur refuse une demande (les pions ne sont pas touches)."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False}), 403
    demande_id = request.json.get("demande_id", "")
    for r in DB.get("demandes_retrait", []):
        if r["id"] == demande_id and r.get("statut") == "en_attente":
            r["statut"] = "refusee"
            save_data(immediat=True)
            return jsonify({"ok": True})
    return jsonify({"ok": False, "msg": "Demande introuvable"}), 404



@app.route("/api/admin/fusionner-codes", methods=["POST"])
def fusionner_codes():
    """ADMIN — Fusionne deux codes organisateur : transfere TOUT du code source vers le code cible."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s or not s.get("admin"):
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    
    d = request.json
    source = (d.get("source") or "").upper().strip()
    cible = (d.get("cible") or "").upper().strip()
    
    if not source or not cible:
        return jsonify({"ok": False, "msg": "Codes manquants"}), 400
    if source == cible:
        return jsonify({"ok": False, "msg": "Les deux codes sont identiques"}), 400
    
    rapport = {"pions_org": 0, "transactions": 0}
    
    # 1. Transferer le STOCK DE PIONS de l'organisateur (pions_org)
    if source in DB.get("pions_org", {}):
        DB.setdefault("pions_org", {})
        DB["pions_org"].setdefault(cible, {})
        for valeur, nb in DB["pions_org"][source].items():
            DB["pions_org"][cible][valeur] = DB["pions_org"][cible].get(valeur, 0) + nb
            rapport["pions_org"] += nb
        del DB["pions_org"][source]
    
    # 2. Transferer les pions legacy (DB["pions"]) si present
    if source in DB.get("pions", {}):
        DB.setdefault("pions", {})
        try:
            DB["pions"][cible] = DB["pions"].get(cible, 0) + DB["pions"][source]
        except TypeError:
            pass
        del DB["pions"][source]
    
    # 3. Remplacer code_org == source par cible dans TOUTES les collections (listes de dicts)
    for cle, valeur in DB.items():
        if isinstance(valeur, list):
            for item in valeur:
                if isinstance(item, dict) and item.get("code_org") == source:
                    item["code_org"] = cible
                    rapport["transactions"] += 1
    
    # 4. Desactiver l'ancien code (on le garde pour l'historique mais inaccessible)
    if source in DB.get("codes", {}):
        DB["codes"][source]["actif"] = False
        DB["codes"][source]["fusionne_vers"] = cible
    
    save_data()
    return jsonify({
        "ok": True,
        "msg": f"Fusion réussie : {rapport['pions_org']} pions et {rapport['transactions']} opérations transférés de {source} vers {cible}. L'ancien code {source} a été désactivé.",
        "rapport": rapport
    })



@app.route("/ventes-tickets/<code>")
def ventes_tickets_org(code):
    """Page dediee : toutes les ventes de tickets d'un organisateur a ses joueuses."""
    global DB
    DB = load_data()
    code = code.upper().strip()
    
    nom = code
    if code in DB.get("codes", {}):
        nom = DB["codes"][code].get("nom", code)
    
    ventes = []
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and c.get("code_org") == code:
            ventes.append({
                "date": c.get("date", "?"),
                "joueur": c.get("code_joueur", "?"),
                "jeu": c.get("jeu", "?"),
                "nb": c.get("nb_tickets", 0),
                "total": c.get("total_pions", 0),
                "statut": c.get("statut", "?")
            })
    
    ventes.sort(key=lambda x: str(x["date"]), reverse=True)
    
    total_tickets = sum(v["nb"] for v in ventes)
    total_pions = sum(v["total"] for v in ventes)
    
    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Ventes de tickets</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:20px}"
    html += ".totaux{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:20px 0;display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;text-align:center}"
    html += ".m{font-size:18px;font-weight:bold;color:#3fb950}"
    html += "table{width:100%;border-collapse:collapse;margin-top:20px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}tr:hover{background:#21262d}"
    html += ".ok{color:#3fb950}.att{color:#f59e0b}</style></head><body>"
    html += "<h1>Ventes de tickets</h1>"
    html += "<div class='sub'>" + str(nom) + " (" + code + ") &rarr; ses joueuses</div>"
    html += "<div class='totaux'>"
    html += "<div><strong>Ventes</strong><br><span class='m'>" + str(len(ventes)) + "</span></div>"
    html += "<div><strong>Tickets vendus</strong><br><span class='m'>" + format(total_tickets, ",") + "</span></div>"
    html += "<div><strong>Total en pions</strong><br><span class='m'>" + format(total_pions, ",") + " XPF</span></div>"
    html += "</div>"
    
    if ventes:
        html += "<table><tr><th>Date</th><th>Joueuse</th><th>Jeu</th><th>Nb tickets</th><th>Total pions</th><th>Statut</th></tr>"
        for v in ventes:
            cls = "ok" if v["statut"] == "validee" else "att"
            lbl = "Valide" if v["statut"] == "validee" else "En attente"
            html += "<tr><td>" + str(v["date"])[:16] + "</td>"
            html += "<td>" + str(v["joueur"]) + "</td>"
            html += "<td>" + str(v["jeu"]) + "</td>"
            html += "<td>" + str(v["nb"]) + "</td>"
            html += "<td>" + format(v["total"], ",") + " XPF</td>"
            html += "<td class='" + cls + "'>" + lbl + "</td></tr>"
        html += "</table>"
    else:
        html += "<p style='color:#8b949e;margin-top:20px'>Aucune vente de ticket pour le moment.</p>"
    
    html += "</body></html>"
    return html



@app.route("/codes-emis/<code_org>")
def codes_emis_org(code_org):
    """Releve de controle : tous les codes joueurs crees par un organisateur, avec dates.
    Permet de verifier en cas de conflit si un organisateur dit la verite."""
    global DB
    DB = load_data()
    code_org = code_org.upper().strip()
    
    nom_org = code_org
    if code_org in DB.get("codes", {}):
        nom_org = DB["codes"][code_org].get("nom", code_org)
    
    # Regrouper par code joueur (un code peut avoir plusieurs tickets)
    joueurs = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_org") == code_org:
            cj = t.get("code_acheteur", "?")
            if not cj:
                continue
            date = t.get("date", "?")
            if cj not in joueurs:
                joueurs[cj] = {
                    "code": cj,
                    "nom": t.get("acheteur", "Joueuse"),
                    "email": t.get("email", ""),
                    "date_creation": date,
                    "nb_tickets": 0
                }
            joueurs[cj]["nb_tickets"] += 1
            # Garder la date la plus ancienne (creation)
            if str(date) < str(joueurs[cj]["date_creation"]):
                joueurs[cj]["date_creation"] = date
    
    liste = list(joueurs.values())
    liste.sort(key=lambda x: str(x["date_creation"]), reverse=True)
    
    # Solde de pions actuel de chaque joueuse
    for j in liste:
        pj = DB.get("pions_joueurs", {}).get(j["code"], {})
        solde = 0
        for v, nb in pj.items():
            try:
                solde += int(v) * nb
            except (ValueError, TypeError):
                pass
        j["solde"] = solde
    
    html = "<!DOCTYPE html><html><head><meta charset='utf-8'><meta name='viewport' content='width=device-width, initial-scale=1'><title>Codes emis</title><style>"
    html += "body{font-family:monospace;background:#0d1117;color:#e6edf3;padding:20px}h1{color:#58a6ff}"
    html += ".sub{color:#8b949e;margin-bottom:20px}"
    html += ".totaux{background:#161b22;border:1px solid #30363d;border-radius:10px;padding:16px;margin:20px 0;text-align:center}"
    html += ".m{font-size:24px;font-weight:bold;color:#3fb950}"
    html += "table{width:100%;border-collapse:collapse;margin-top:20px;font-size:13px}"
    html += "th{background:#0d1117;border:1px solid #30363d;padding:10px;text-align:left;color:#8b949e}"
    html += "td{border:1px solid #30363d;padding:8px}tr:hover{background:#21262d}"
    html += ".code{color:#818cf8;font-weight:bold}.date{color:#f59e0b}</style></head><body>"
    html += "<h1>Codes joueurs emis</h1>"
    html += "<div class='sub'>Par " + str(nom_org) + " (" + code_org + ") &mdash; controle anti-conflit</div>"
    html += "<div class='totaux'><strong>Codes joueurs crees par cet organisateur</strong><br><span class='m'>" + str(len(liste)) + "</span></div>"
    
    if liste:
        html += "<table><tr><th>Code joueuse</th><th>Nom</th><th>Date de creation</th><th>Tickets</th><th>Solde pions</th></tr>"
        for j in liste:
            html += "<tr><td class='code'>" + str(j["code"]) + "</td>"
            html += "<td>" + str(j["nom"]) + "</td>"
            html += "<td class='date'>" + str(j["date_creation"])[:16].replace("T", " ") + "</td>"
            html += "<td>" + str(j["nb_tickets"]) + "</td>"
            html += "<td>" + format(j["solde"], ",") + " XPF</td></tr>"
        html += "</table>"
        html += "<p style='color:#8b949e;font-size:12px;margin-top:16px'>Ce releve liste UNIQUEMENT les codes reellement crees par cet organisateur dans le systeme, avec leur date exacte. En cas de litige, c'est la preuve de ce qui a ete emis.</p>"
    else:
        html += "<p style='color:#8b949e;margin-top:20px'>Cet organisateur n'a cree aucun code joueur.</p>"
    
    html += "</body></html>"
    return html



