    html += "</div>"
    
    if journal:
        html += "<table><tr><th>Date / Heure</th><th>Code</th><th>Nom</th><th>Type</th><th>Resultat</th></tr>"
        for j in journal[:300]:
            res = j.get("resultat", "?")
            lbl, coul = libelles.get(res, (res, "#8b949e"))
            date = str(j.get("date", "?"))[:19].replace("T", " ")
