@app.route("/api/tournoi-programme/creer", methods=["POST"])
def creer_tournoi_programme():
    """L'organisateur programme un tournoi a l'avance (date + heure)."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False, "msg": "Accès refusé"}), 403
    d = request.json
    nom = str(d.get("nom", "")).strip()
    jeu = str(d.get("jeu", "")).strip()
    date_heure = str(d.get("date_heure", "")).strip()
    if not nom or not date_heure:
        return jsonify({"ok": False, "msg": "Nom et date/heure obligatoires"}), 400
    
    if "tournois_programmes" not in DB:
        DB["tournois_programmes"] = []
    
    tournoi = {
        "id": secrets.token_hex(4).upper(),
        "code_org": s["code"],
        "nom_org": s.get("nom", s["code"]),
        "nom": nom,
        "jeu": jeu,
        "date_heure": date_heure,
        "created": datetime.datetime.now().isoformat()
    }
    DB["tournois_programmes"].insert(0, tournoi)
    save_data()
    return jsonify({"ok": True, "tournoi": tournoi})


@app.route("/api/tournois-programmes")
def get_tournois_programmes():
    """Liste les tournois programmes a venir (cache court)."""
    def _lire():
        d = load_data()
        maintenant = datetime.datetime.now()
        limite = maintenant - datetime.timedelta(hours=6)
        a_venir = []
        for t in d.get("tournois_programmes", []):
            if not isinstance(t, dict):
                continue
            try:
                dt = datetime.datetime.fromisoformat(t.get("date_heure", "").replace("Z", ""))
                if dt > limite:
                    a_venir.append(t)
            except (ValueError, TypeError):
                a_venir.append(t)
        a_venir.sort(key=lambda x: str(x.get("date_heure", "")))
        return a_venir
    return jsonify(_cache_lecture("tournois_programmes", _lire))


@app.route("/api/tournoi-programme/supprimer", methods=["POST"])
def supprimer_tournoi_programme():
    """L'organisateur (ou admin) supprime un tournoi programme."""
    global DB
    DB = load_data()
    token = request.headers.get("X-Token", "")
    s = verif_session(token)
    if not s:
        return jsonify({"ok": False}), 403
    tid = request.json.get("id", "")
    avant = len(DB.get("tournois_programmes", []))
    DB["tournois_programmes"] = [t for t in DB.get("tournois_programmes", [])
                                  if not (t.get("id") == tid and (s.get("admin") or t.get("code_org") == s["code"]))]
    if len(DB["tournois_programmes"]) < avant:
        save_data()
        return jsonify({"ok": True})
    return jsonify({"ok": False, "msg": "Tournoi introuvable"}), 404



@app.route("/diag-envois")
def diag_envois():
    """Diagnostic LECTURE SEULE des envois admin -> organisateur (ventes + PDF).
    Protégé : nécessite ?cle=CODE_ADMIN."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response(
            "Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse (ex: /diag-envois?cle=ADMIN2024).",
            status=403, mimetype="text/plain; charset=utf-8")

    org_filtre = (request.args.get("org", "") or "").strip().upper()
    ventes = DB.get("ventes", [])
    codes = DB.get("codes", {})

    # Codes organisateurs connus (= le code de connexion)
    orgs_connus = ""
    for co, inf in codes.items():
        if inf.get("admin"):
            continue
        orgs_connus += (f'<tr><td style="padding:6px;color:#fff">{inf.get("nom", "")}</td>'
                        f'<td style="padding:6px;color:#a78bfa;font-family:monospace">{co}</td>'
                        f'<td style="padding:6px;color:#94a3b8">{inf.get("role", "")}</td></tr>')

    # Combien de ventes par code
    comptes = {}
    for v in ventes:
        co = (v.get("code_org") or "?")
        comptes[co] = comptes.get(co, 0) + 1
    rep_comptes = " &nbsp;·&nbsp; ".join(f'<b style="color:#fff">{c}</b> : {n}'
                                          for c, n in sorted(comptes.items(), key=lambda x: -x[1])) or "aucune vente"

    vus = ventes if not org_filtre else [v for v in ventes if (v.get("code_org", "") or "").upper() == org_filtre]
    lignes = ""
    for v in vus[:40]:
        co = v.get("code_org", "?") or "?"
        pdf_url = v.get("pdf_url") or ""
        existe = False
        if pdf_url:
            pid = pdf_url.split("/")[-1].replace(".pdf", "")
            existe = os.path.exists(f"/data/pdfs/{pid}.pdf")
        if pdf_url and existe:
            etat = '<span style="color:#6ee7b7;font-weight:700">✅ PDF présent</span>'
        elif pdf_url:
            etat = '<span style="color:#fca5a5;font-weight:700">❌ PDF absent du serveur</span>'
        else:
            etat = '<span style="color:#9ca3af">— aucun PDF</span>'
        date_c = (v.get("date", "") or "")[:16].replace("T", " ")
        lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                   f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{co}</td>'
                   f'<td style="padding:8px;color:#fff">{v.get("jeu", "?")}</td>'
                   f'<td style="padding:8px;color:#c4b5fd;font-weight:700">{v.get("serie", "?")}</td>'
                   f'<td style="padding:8px;color:#94a3b8">{v.get("client", "")}</td>'
                   f'<td style="padding:8px;color:#64748b;font-size:12px">{v.get("paiement_statut", "")}</td>'
                   f'<td style="padding:8px">{etat}</td>'
                   f'<td style="padding:8px;color:#64748b;font-size:11px">{date_c}</td></tr>')
    if not lignes:
        lignes = ('<tr><td colspan="7" style="padding:20px;text-align:center;color:#94a3b8">'
                  'Aucune vente' + (f' pour le code {org_filtre}' if org_filtre else '') + '.</td></tr>')

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Diagnostic envois</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:940px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 16px">🔍 Diagnostic des envois admin → organisateur</h1>
      <div style="background:#1e1b3a;border:1px solid #3730a3;border-radius:12px;padding:14px;margin-bottom:14px">
        <div style="font-size:13px;color:#a78bfa;margin-bottom:8px">📦 Où sont rangés les envois (nombre de ventes par code) :</div>
        <div style="font-size:14px;color:#fff;line-height:1.8">{rep_comptes}</div>
      </div>
      <div style="background:#1e1b3a;border:1px solid #3730a3;border-radius:12px;padding:14px;margin-bottom:14px">
        <div style="font-size:13px;color:#a78bfa;margin-bottom:8px">🔑 Codes des organisateurs (le code de connexion exact) :</div>
        <table style="width:100%;border-collapse:collapse">{orgs_connus or '<tr><td style="color:#94a3b8;padding:6px">Aucun</td></tr>'}</table>
      </div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:640px">
        <tr style="border-bottom:2px solid #3730a3">
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Code destinataire</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Jeu</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Série</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Client</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Statut</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Fichier PDF</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Date</th>
        </tr>
        {lignes}
      </table></div>
      <div style="text-align:center;margin-top:16px;font-size:12px;color:#64748b">
        Filtrer un organisateur : ajoute <code style="color:#a78bfa">&amp;org=PKKPZMU1</code> à l'adresse.
      </div>
    </div></body></html>'''

@app.route("/diag-tickets")
def diag_tickets():
    """Diagnostic LECTURE SEULE des tickets clients et de leur plage de pages.
    Repère les tickets qui affichent TOUT le PDF (plage non définie). ?cle=CODE_ADMIN requis."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response(
            "Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse (ex: /diag-tickets?cle=TONCODE).",
            status=403, mimetype="text/plain; charset=utf-8")

    org_filtre = (request.args.get("org", "") or "").strip().upper()
    tickets = DB.get("tickets", [])
    vus = tickets if not org_filtre else [t for t in tickets if (t.get("code_org", "") or "").upper() == org_filtre]

    nb_tout = 0
    lignes = ""
    for t in sorted(vus, key=lambda x: x.get("date", ""), reverse=True)[:80]:
        pd_ = t.get("page_debut")
        pf_ = t.get("page_fin")
        if pd_ in (None, "") or pf_ in (None, ""):
            plage = '<span style="color:#fca5a5;font-weight:700">⚠️ TOUT le PDF</span>'
            nb_feuilles = "tout"
            nb_tout += 1
        else:
            plage = f'<span style="color:#6ee7b7">pages {pd_} → {pf_}</span>'
            try:
                nb_feuilles = str(int(pf_) - int(pd_) + 1)
            except Exception:
                nb_feuilles = "?"
        date_c = (t.get("date", "") or "")[:16].replace("T", " ")
        lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                   f'<td style="padding:8px;color:#fff">{t.get("acheteur", "?")}</td>'
                   f'<td style="padding:8px;color:#c4b5fd">{t.get("jeu", "?")}</td>'
                   f'<td style="padding:8px;color:#94a3b8">{t.get("serie", "?")}</td>'
                   f'<td style="padding:8px">{plage}</td>'
                   f'<td style="padding:8px;color:#fff;text-align:center;font-weight:700">{nb_feuilles}</td>'
                   f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{t.get("code_org", "?")}</td>'
                   f'<td style="padding:8px;color:#64748b;font-size:11px">{date_c}</td></tr>')
    if not lignes:
        lignes = '<tr><td colspan="7" style="padding:20px;text-align:center;color:#94a3b8">Aucun ticket.</td></tr>'

    alerte = ""
    if nb_tout:
        alerte = (f'<div style="background:#7f1d1d;color:#fecaca;padding:12px 16px;border-radius:10px;'
                  f'margin-bottom:16px;font-size:14px;font-weight:600">⚠️ {nb_tout} ticket(s) sans plage de pages : '
                  f'ces clients voient TOUT le PDF (donc trop de cartes). À corriger.</div>')

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Diagnostic tickets</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:940px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 16px">🎫 Diagnostic des tickets clients (plage de pages)</h1>
      {alerte}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:680px">
        <tr style="border-bottom:2px solid #3730a3">
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Client</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Jeu</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Série</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Pages reçues</th>
          <th style="padding:8px;text-align:center;font-size:12px;color:#a78bfa">Nb feuilles</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Code org</th>
          <th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Date</th>
        </tr>
        {lignes}
      </table></div>
      <div style="text-align:center;margin-top:16px;font-size:12px;color:#64748b">
        Filtrer un organisateur : ajoute <code style="color:#a78bfa">&amp;org=PKKPZMU1</code> à l'adresse.
      </div>
    </div></body></html>'''


@app.route("/recherche-joueur")
def recherche_joueur():
    """Recherche LECTURE SEULE : tickets reçus par une joueuse (par code).
    ?cle=CODE_ADMIN requis ; ?code=CODE_JOUEUR pour chercher."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response(
            "Acces reserve. Ajoute ?cle=TON_CODE_ADMIN a l'adresse "
            "(ex: /recherche-joueur?cle=TONCODE&code=64AUO4).",
            status=403, mimetype="text/plain; charset=utf-8")

    code_j = (request.args.get("code", "") or "").strip().upper()
    resultat = ""
    origine_html = ""
    if code_j:
        # --- ORIGINE DU CODE : QR (inscription pub) ou créé par une organisatrice ? ---
        rj = next((x for x in DB.get("rejoindre_log", [])
                   if (x.get("code", "") or "").upper() == code_j), None)
        tks_all = [t for t in DB.get("tickets", [])
                   if (t.get("code_acheteur", "") or "").upper() == code_j]
        pub = any((t.get("code_org") == "PUB" or t.get("source") == "publicite") for t in tks_all)
        if rj or pub:
            camp = (rj.get("campagne") if rj else "") or "—"
            dt = ((rj.get("date") if rj else "") or "")[:16].replace("T", " ")
            origine_html = ('<div style="background:#0c4a6e;color:#bae6fd;padding:16px 18px;border-radius:12px;margin-bottom:16px;font-size:15px">'
                            '📲 <b>Code généré par le QR</b> (inscription publicité).<br>'
                            f'<span style="color:#7dd3fc;font-size:13px">Campagne : <b>{camp}</b>{(" · le " + dt) if dt else ""}</span></div>')
        elif tks_all:
            org_codes = sorted({t.get("code_org") for t in tks_all if t.get("code_org")})
            org_noms = ", ".join(DB.get("codes", {}).get(o, {}).get("nom", o) for o in org_codes) or "—"
            origine_html = ('<div style="background:#3b1d5e;color:#e9d5ff;padding:16px 18px;border-radius:12px;margin-bottom:16px;font-size:15px">'
                            '✍️ <b>Code créé par une organisatrice</b> (pas le QR).<br>'
                            f'<span style="color:#c4b5fd;font-size:13px">Organisatrice : <b>{org_noms}</b></span></div>')
    if code_j:
        tks = [t for t in DB.get("tickets", []) if (t.get("code_acheteur", "") or "").upper() == code_j]
        if not tks:
            resultat = ('<div style="background:#7f1d1d;color:#fecaca;padding:14px 18px;border-radius:10px;'
                        f'font-size:15px">Aucun ticket trouvé pour le code <b>{code_j}</b>.</div>')
        else:
            cartes = ""
            total = 0
            for t in tks:
                pd_ = t.get("page_debut")
                pf_ = t.get("page_fin")
                try:
                    nb = int(pf_) - int(pd_) + 1
                except Exception:
                    nb = None
                if isinstance(nb, int):
                    total += nb
                    nb_txt = str(nb)
                else:
                    nb_txt = '<span style="color:#fca5a5">tout le PDF (plage non définie)</span>'
                date_c = (t.get("date", "") or "")[:16].replace("T", " ")
                cartes += ('<div style="background:#1a1830;border:1px solid #3730a3;border-radius:12px;'
                           'padding:16px 18px;margin-bottom:12px">'
                           '<div style="font-size:13px;color:#a78bfa;margin-bottom:6px">Jeu</div>'
                           f'<div style="font-size:22px;font-weight:800;color:#c4b5fd;margin-bottom:10px">{t.get("jeu", "?")}</div>'
                           '<div style="display:flex;gap:24px;flex-wrap:wrap;font-size:14px">'
                           f'<div><span style="color:#94a3b8">Tickets reçus :</span> <b style="color:#6ee7b7;font-size:18px">{nb_txt}</b></div>'
                           f'<div><span style="color:#94a3b8">Série :</span> <span style="color:#fff">{t.get("serie", "?")}</span></div>'
                           f'<div><span style="color:#94a3b8">Pages :</span> <span style="color:#fff">{t.get("page_debut", "?")} → {t.get("page_fin", "?")}</span></div>'
                           f'<div><span style="color:#94a3b8">Date :</span> <span style="color:#64748b">{date_c}</span></div>'
                           '</div></div>')
            nom = tks[0].get("acheteur", "?")
            resultat = ('<div style="background:#14532d;color:#bbf7d0;padding:16px 18px;border-radius:12px;'
                        f'margin-bottom:16px;font-size:16px">✅ <b>{nom}</b> (code {code_j}) a reçu '
                        f'<b style="font-size:20px">{total}</b> ticket(s) au total.</div>' + cartes)

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Recherche joueuse</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:720px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 16px">🔍 Tickets reçus par une joueuse</h1>
      <form method="get" style="display:flex;gap:8px;margin-bottom:20px;flex-wrap:wrap">
        <input type="hidden" name="cle" value="{cle}">
        <input name="code" value="{code_j}" placeholder="Code joueuse (ex: 64AUO4)" autofocus
          style="flex:1;min-width:180px;padding:12px 14px;border-radius:10px;border:1px solid #3730a3;background:#1a1830;color:#fff;font-size:16px;text-transform:uppercase">
        <button type="submit" style="padding:12px 22px;border:0;border-radius:10px;background:#6366f1;color:#fff;font-size:15px;font-weight:700;cursor:pointer">Rechercher</button>
      </form>
      {origine_html}
      {resultat}
      <div style="text-align:center;margin-top:20px;font-size:12px;color:#64748b">Page admin · lecture seule</div>
    </div></body></html>'''


@app.route("/trace-pions")
def trace_pions():
    """Trace COMPLETE et LECTURE SEULE de tous les mouvements de pions d'un code,
    transferts inclus. ?cle=CODE_ADMIN requis ; ?code=CODE_JOUEUR."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response(
            "Acces reserve. Ajoute ?cle=TON_CODE_ADMIN (ex: /trace-pions?cle=TONCODE&code=CJNRPW).",
            status=403, mimetype="text/plain; charset=utf-8")

    def _i(x):
        try:
            return int(x or 0)
        except Exception:
            return 0

    code = (request.args.get("code", "") or "").strip().upper()
    corps = ""
    if code:
        mv = []
        for c in DB.get("credits_admin", []):
            if (c.get("code_joueur") or "").upper() == code:
                mv.append((c.get("date", ""), "Crédit admin",
                           f"{c.get('nb_pions')}×{c.get('valeur_pion')} (par {c.get('par','?')})",
                           _i(c.get("valeur_pion")) * _i(c.get("nb_pions"))))
        for cm in DB.get("credits_masse", []):
            if code in (cm.get("codes") or []):
                mv.append((cm.get("date", ""), "Crédit/Dédom.", cm.get("motif", "Dédommagement"),
                           _i(cm.get("nb_pions")) * _i(cm.get("valeur_pion"))))
        for c in DB.get("commandes_pions_joueurs", []):
            if (c.get("code_joueur") or "").upper() == code and c.get("statut") == "validee":
                nbp = c.get("pions_credites") or c.get("nb_pions") or 0
                mv.append((c.get("date", ""), "Achat pions",
                           f"{c.get('nb_pions')}×{c.get('valeur_pion')}",
                           _i(nbp) * _i(c.get("valeur_pion"))))
        for g in DB.get("gains_finaux", []):
            if (g.get("code_gagnant") or "").upper() == code:
                if g.get("annule"):
                    mv.append((g.get("date", ""), "Gain ANNULÉ", f"Gain {g.get('jeu','')} (annulé — ne compte pas)", 0))
                    continue
                credite = _i(g.get("montant_credite", g.get("montant_gain", 0)))
                especes = _i(g.get("montant_gain", 0)) - credite
                det = f"Gain {g.get('jeu','')}"
                if especes > 0:
                    det += f" — dont {format(especes, ',')} en espèces (hors poche)"
                mv.append((g.get("date", ""), "Gain", det, credite))
        for c in DB.get("commandes_tickets_pions", []):
            if (c.get("code_joueur") or "").upper() == code and c.get("statut") == "validee":
                mv.append((c.get("date", ""), "Tickets",
                           f"{c.get('jeu','')} ({c.get('nb_tickets',0)} tickets)", -_i(c.get("total_pions"))))
        for c in DB.get("corrections_pions", []):
            if (c.get("code_joueur") or "").upper() == code:
                mv.append((c.get("date", ""), "Correction", c.get("motif", "Correction admin"),
                           -_i(c.get("montant_retire"))))
        for t in DB.get("transferts_pions", []):
            if t.get("annule_fraude"):
                if (t.get("de") or "").upper() == code or (t.get("vers") or "").upper() == code:
                    mv.append((t.get("date", ""), "Transfert ANNULÉ", "fraude — annulé par l'administration", 0))
                continue
            if (t.get("de") or "").upper() == code:
                mv.append((t.get("date", ""), "Transfert ENVOYÉ", f"→ vers {t.get('vers','?')}", -_i(t.get("montant"))))
            if (t.get("vers") or "").upper() == code:
                mv.append((t.get("date", ""), "Transfert REÇU", f"← de {t.get('de','?')}", _i(t.get("montant"))))
        for rb in DB.get("remboursements_tournoi", []):
            if isinstance(rb, dict):
                for det in (rb.get("detail") or []):
                    if isinstance(det, dict) and (det.get("code_joueur", "") or "").upper() == code:
                        mv.append((rb.get("date", ""), "Remboursement",
                                   f"Jeu annulé : {rb.get('jeu','')}", _i(det.get("montant"))))
        # Cadeau d'inscription : la campagne "semaine" crédite 500 F de bonus
        # directement à l'inscription (non journalisé ailleurs). On le retrace ici.
        for x in DB.get("rejoindre_log", []):
            if (x.get("code", "") or "").upper() == code and (x.get("campagne", "") or "") == "semaine":
                mv.append((x.get("date", ""), "Cadeau inscription",
                           "Bonus 500 F offert à l'inscription (QR semaine)", 500))
                break

        mv.sort(key=lambda x: str(x[0]))
        pj = DB.get("pions_joueurs", {}).get(code, {})
        pb = DB.get("pions_bonus_joueurs", {}).get(code, {})
        solde_pions = pj.get("100", 0) * 100 + pj.get("50", 0) * 50 + pj.get("20", 0) * 20 + pj.get("10", 0) * 10
        solde_bonus = pb.get("100", 0) * 100 + pb.get("50", 0) * 50 + pb.get("20", 0) * 20 + pb.get("10", 0) * 10
        solde_reel = solde_pions + solde_bonus

        run = 0
        total_in = 0
        total_out = 0
        rows = ""
        for date, typ, detail, m in mv:
            run += m
            if m >= 0:
                total_in += m
            else:
                total_out += -m
            coul = "#6ee7b7" if m >= 0 else "#fca5a5"
            mtxt = ("+" if m >= 0 else "") + format(m, ",")
            rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.08)">'
                     f'<td style="padding:8px;color:#64748b;font-size:12px">{str(date or "")[:16].replace("T"," ")}</td>'
                     f'<td style="padding:8px;color:#c4b5fd">{typ}</td>'
                     f'<td style="padding:8px;color:#cbd5e1">{detail}</td>'
                     f'<td style="padding:8px;text-align:right;color:{coul};font-weight:700">{mtxt}</td>'
                     f'<td style="padding:8px;text-align:right;color:#fff">{format(run,",")}</td></tr>')
        if not rows:
            rows = '<tr><td colspan="5" style="padding:20px;text-align:center;color:#94a3b8">Aucun mouvement tracé.</td></tr>'

        solde_theorique = run
        ecart = solde_reel - solde_theorique
        if ecart == 0:
            bloc_ecart = '<div style="background:#14532d;color:#bbf7d0;padding:12px 16px;border-radius:10px;margin-bottom:16px;font-size:15px;font-weight:600">✅ Tout est tracé : le solde réel (pions + bonus) correspond exactement aux mouvements.</div>'
        elif ecart > 0:
            bloc_ecart = f'<div style="background:#0c4a6e;color:#bae6fd;padding:12px 16px;border-radius:10px;margin-bottom:16px;font-size:15px;font-weight:600">ℹ️ Solde supérieur de <b>{format(ecart, ",")} XPF</b> aux mouvements tracés. C\'est généralement un cadeau ou un crédit non journalisé — <b>pas une perte</b>.</div>'
        else:
            bloc_ecart = f'<div style="background:#7f1d1d;color:#fecaca;padding:12px 16px;border-radius:10px;margin-bottom:16px;font-size:15px;font-weight:600">⚠️ Solde réel inférieur de <b>{format(-ecart, ",")} XPF</b> aux mouvements tracés (jeu d\'avant le journal détaillé, généralement).</div>'
        corps = (
            '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:16px">'
            f'<div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Entrées tracées</div><div style="font-size:17px;font-weight:800;color:#3fb950">+{format(total_in, ",")}</div></div>'
            f'<div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Sorties tracées</div><div style="font-size:17px;font-weight:800;color:#f85149">-{format(total_out, ",")}</div></div>'
            f'<div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Solde théorique</div><div style="font-size:17px;font-weight:800;color:#58a6ff">{format(solde_theorique, ",")}</div></div>'
            f'<div style="background:#161b22;border-radius:10px;padding:12px;text-align:center"><div style="font-size:12px;color:#8b949e">Solde réel</div><div style="font-size:17px;font-weight:800;color:#fff">{format(solde_reel, ",")}</div><div style="font-size:10px;color:#8b949e;margin-top:2px">dont {format(solde_bonus, ",")} bonus</div></div>'
            '</div>'
            f'{bloc_ecart}'
            '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:640px">'
            '<tr style="border-bottom:2px solid #3730a3"><th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Date</th><th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Type</th><th style="padding:8px;text-align:left;font-size:12px;color:#a78bfa">Détail</th><th style="padding:8px;text-align:right;font-size:12px;color:#a78bfa">Montant</th><th style="padding:8px;text-align:right;font-size:12px;color:#a78bfa">Solde</th></tr>'
            f'{rows}</table></div>')

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Trace pions</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:880px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 6px">🔎 Trace complète des pions (transferts inclus)</h1>
      <p style="color:#64748b;font-size:13px;margin:0 0 16px">Lecture seule. Montre chaque mouvement, transferts envoyés/reçus compris.</p>
      <form method="get" style="display:flex;gap:8px;margin-bottom:20px;flex-wrap:wrap">
        <input type="hidden" name="cle" value="{cle}">
        <input name="code" value="{code}" placeholder="Code (ex: CJNRPW)" autofocus
          style="flex:1;min-width:180px;padding:12px 14px;border-radius:10px;border:1px solid #3730a3;background:#1a1830;color:#fff;font-size:16px;text-transform:uppercase">
        <button type="submit" style="padding:12px 22px;border:0;border-radius:10px;background:#6366f1;color:#fff;font-size:15px;font-weight:700;cursor:pointer">Tracer</button>
      </form>
      {corps}
      <div style="text-align:center;margin-top:20px;font-size:12px;color:#64748b">Page admin · lecture seule</div>
    </div></body></html>'''


@app.route("/annuler-gain", methods=["GET", "POST"])
def annuler_gain_page():
    """Page admin LECTURE + annulation tracée d'un gain erroné.
    Marque le gain 'annule' (ne compte plus dans le relevé). NE touche PAS la poche.
    ?cle=CODE_ADMIN requis ; ?code=CODE_JOUEUR."""
    global DB
    DB = load_data()
    cle = (request.values.get("cle", "") or "").strip().upper()
    info_cle = DB.get("codes", {}).get(cle)
    if not (info_cle and info_cle.get("admin")):
        return Response(
            "Acces reserve. Ajoute ?cle=TON_CODE_ADMIN (ex: /annuler-gain?cle=TONCODE&code=CJNRPW).",
            status=403, mimetype="text/plain; charset=utf-8")

    code = (request.values.get("code", "") or "").strip().upper()
    message = ""

    if request.method == "POST":
        gid = (request.form.get("gain_id", "") or "").strip()
        if gid:
            trouve = False
            for g in DB.get("gains_finaux", []):
                if g.get("id") == gid and (g.get("code_gagnant") or "").upper() == code:
                    g["annule"] = True
                    g["annule_par"] = cle
                    g["annule_date"] = datetime.datetime.now().isoformat()
                    trouve = True
                    break
            if trouve:
                DB.setdefault("gains_annules", []).insert(0, {
                    "gain_id": gid, "code_joueur": code, "par": cle,
                    "date": datetime.datetime.now().isoformat()
                })
                save_data(immediat=True)
                message = ('<div style="background:#14532d;color:#bbf7d0;padding:14px 18px;border-radius:10px;'
                           'margin-bottom:16px;font-size:15px;font-weight:600">✅ Gain annulé. Il ne compte plus dans le relevé. '
                           'La poche de pions n\'a pas été modifiée.</div>')
            else:
                message = ('<div style="background:#7f1d1d;color:#fecaca;padding:14px 18px;border-radius:10px;'
                           'margin-bottom:16px;font-size:15px">Gain introuvable pour ce code.</div>')

    corps = ""
    if code:
        gains = [g for g in DB.get("gains_finaux", []) if (g.get("code_gagnant") or "").upper() == code]
        if not gains:
            corps = ('<div style="background:#1a1830;border-radius:10px;padding:16px;color:#94a3b8">'
                     f'Aucun gain enregistré pour <b>{code}</b>.</div>')
        else:
            cartes = ""
            for g in gains:
                annule = g.get("annule")
                mg = format(_safe_int_gain(g.get("montant_gain", 0)), ",")
                date_c = (g.get("date", "") or "")[:16].replace("T", " ")
                if annule:
                    badge = '<span style="color:#fca5a5;font-weight:700">ANNULÉ</span>'
                    bouton = ('<div style="color:#64748b;font-size:13px">Annulé le '
                              + (g.get("annule_date", "") or "")[:16].replace("T", " ")
                              + " par " + str(g.get("annule_par", "?")) + "</div>")
                else:
                    badge = '<span style="color:#6ee7b7;font-weight:700">ACTIF</span>'
                    bouton = (f'<form method="post" onsubmit="return confirm(\'Annuler ce gain de {mg} XPF ? '
                              f'(la poche de pions ne sera PAS modifiée)\');" style="margin-top:10px">'
                              f'<input type="hidden" name="cle" value="{cle}">'
                              f'<input type="hidden" name="code" value="{code}">'
                              f'<input type="hidden" name="gain_id" value="{g.get("id","")}">'
                              f'<button type="submit" style="padding:10px 18px;border:0;border-radius:8px;'
                              f'background:#dc2626;color:#fff;font-weight:700;cursor:pointer">Annuler ce gain</button></form>')
                cartes += (f'<div style="background:#161b22;border:1px solid #30363d;border-radius:12px;padding:16px 18px;margin-bottom:12px">'
                           f'<div style="display:flex;justify-content:space-between;align-items:center">'
                           f'<div style="font-size:18px;font-weight:800;color:#c4b5fd">Gain {g.get("jeu","?")} — {mg} XPF</div>{badge}</div>'
                           f'<div style="font-size:13px;color:#64748b;margin-top:4px">Le {date_c} · id {g.get("id","?")}</div>'
                           f'{bouton}</div>')
            corps = cartes

    return f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8">
    <meta name="viewport" content="width=device-width,initial-scale=1"><title>Annuler un gain</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:720px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin:4px 0 6px">🚫 Annuler un gain erroné</h1>
      <p style="color:#64748b;font-size:13px;margin:0 0 16px">L'annulation retire le gain du relevé mais NE modifie PAS la poche de pions.</p>
      <form method="get" style="display:flex;gap:8px;margin-bottom:20px;flex-wrap:wrap">
        <input type="hidden" name="cle" value="{cle}">
        <input name="code" value="{code}" placeholder="Code (ex: CJNRPW)" autofocus
          style="flex:1;min-width:180px;padding:12px 14px;border-radius:10px;border:1px solid #3730a3;background:#1a1830;color:#fff;font-size:16px;text-transform:uppercase">
        <button type="submit" style="padding:12px 22px;border:0;border-radius:10px;background:#6366f1;color:#fff;font-size:15px;font-weight:700;cursor:pointer">Voir les gains</button>
      </form>
      {message}
      {corps}
      <div style="text-align:center;margin-top:20px;font-size:12px;color:#64748b">Page admin · annulation tracée</div>
    </div></body></html>'''


def _safe_int_gain(x):
    try:
        return int(x or 0)
    except Exception:
        return 0


def _hash_pin(code, pin):
    """Hache le PIN avec le code comme sel (jamais stocké en clair)."""
    return hashlib.sha256(("PIN|2026|" + str(code) + "|" + str(pin)).encode("utf-8", "ignore")).hexdigest()

@app.route("/api/joueur/pin/etat")
def joueur_pin_etat():
    """Indique si un code a déjà un PIN (pour savoir s'il faut le demander)."""
    global DB
    DB = load_data()
    code = (request.args.get("code", "") or "").upper().strip()
    return jsonify({"ok": True, "a_pin": bool(DB.get("pins_joueurs", {}).get(code))})

@app.route("/api/joueur/pin/definir", methods=["POST"])
def joueur_pin_definir():
    """Définit ou change le PIN d'un code. Si un PIN existe déjà, l'ancien est exigé."""
    global DB
    DB = load_data()
    d = request.json or {}
    code = (d.get("code", "") or "").upper().strip()
    pin = str(d.get("pin", "") or "").strip()
    ancien = str(d.get("ancien_pin", "") or "").strip()
    if not code or not (pin.isdigit() and len(pin) == 4):
        return jsonify({"ok": False, "msg": "Le PIN doit faire 4 chiffres."}), 400
    pins = DB.setdefault("pins_joueurs", {})
    if code in pins and pins[code].get("hash") != _hash_pin(code, ancien):
        return jsonify({"ok": False, "msg": "Ancien PIN incorrect."}), 403
    pins[code] = {"hash": _hash_pin(code, pin), "date": datetime.datetime.now().isoformat()}
    save_data(immediat=True)
    return jsonify({"ok": True})

@app.route("/api/joueur/pin/verifier", methods=["POST"])
def joueur_pin_verifier():
    """Vérifie le PIN d'un code. Si le code n'a pas de PIN, renvoie ok (accès libre)."""
    global DB
    DB = load_data()
    d = request.json or {}
    code = (d.get("code", "") or "").upper().strip()
    pin = str(d.get("pin", "") or "").strip()
    rec = DB.get("pins_joueurs", {}).get(code)
    if not rec:
        return jsonify({"ok": True, "a_pin": False})
    return jsonify({"ok": rec.get("hash") == _hash_pin(code, pin), "a_pin": True})

@app.route("/api/rejoindre", methods=["POST"])
def api_rejoindre():
    """Inscription automatique depuis la pub (page /rejoindre).
    Crée un code joueur, offre 500 XPF de bonus NON RETIRABLE, 1 seul par numéro."""
    global DB
    DB = load_data()
    d = request.json or {}
    nom = (d.get("nom") or "").strip()
    tel = (d.get("telephone") or "").strip()
    email = (d.get("email") or "").strip()
    campagne = (d.get("campagne") or "").strip()[:20]
    tel_clean = "".join(c for c in tel if c.isdigit() or c == "+")
    chiffres = "".join(c for c in tel if c.isdigit())
    if not nom or len(nom) < 2:
        return jsonify({"ok": False, "msg": "Entre ton prénom."}), 400
    if len(chiffres) < 6:
        return jsonify({"ok": False, "msg": "Entre un numéro valide (avec l'indicatif si tu es à l'étranger)."}), 400
    # EMAIL OBLIGATOIRE (14/07/2026) : identifiant obligatoire pour tout nouveau compte.
    if "@" not in email or "." not in email.split("@")[-1] or len(email) < 6:
        return jsonify({"ok": False, "msg": "Entre une adresse email valide (obligatoire)."}), 400

    ip = _get_client_ip()
    maintenant = datetime.datetime.now()
    index_tel = DB.setdefault("joueurs_par_tel", {})
    # 1 SEUL code/bonus par numéro : si déjà inscrit, on renvoie son code (sans nouveau bonus)
    if tel_clean in index_tel:
        return jsonify({"ok": True, "code": index_tel[tel_clean], "deja": True, "bonus": 0})

    # Anti-abus "pions gratuits" : MAX 2 inscriptions bonus par IP. La 3e est REFUSEE.
    # (le telephone est deja limite a 1 seul code/bonus plus haut)
    DB.setdefault("rejoindre_log", [])
    nb_bonus_ip = 0
    for x in DB["rejoindre_log"]:
        if x.get("ip") == ip and (x.get("campagne", "") or "") == "semaine":
            nb_bonus_ip += 1
    if campagne == "semaine" and nb_bonus_ip >= 2:
        return jsonify({"ok": False, "msg": "Acces refuse : limite de 2 inscriptions atteinte pour cet appareil/reseau. Le bonus d'inscription n'est disponible que 2 fois."}), 429

    # Anti-robot : max 3 nouveaux codes/heure/appareil (toutes campagnes)
    recent = 0
    for x in DB["rejoindre_log"]:
        try:
            if x.get("ip") == ip and (maintenant - datetime.datetime.fromisoformat(x["date"])).total_seconds() < 3600:
                recent += 1
        except Exception:
            pass
    if recent >= 3:
        return jsonify({"ok": False, "msg": "Trop d'inscriptions depuis cet appareil. Réessaie plus tard."}), 429

    code = gen_code(6)
    while code in DB.get("tickets_acheteurs", {}) or code in DB.get("pions_joueurs", {}) or code in DB.get("pions_bonus_joueurs", {}):
        code = gen_code(6)

    ticket = {
        "id": hashlib.md5(f"{nom}{tel_clean}{maintenant}".encode()).hexdigest()[:8],
        "acheteur": nom, "jeu": "", "serie": "", "prix": 0,
        "photo_url": None, "pdf_url": None, "page_debut": None, "page_fin": None,
        "code_acheteur": code, "email": email, "telephone": tel_clean,
        "code_org": "PUB", "source": "publicite", "campagne": campagne, "date": maintenant.isoformat()
    }
    DB.setdefault("tickets", []).insert(0, ticket)
    DB.setdefault("tickets_acheteurs", {})[code] = ticket["id"]
    index_tel[tel_clean] = code

    # Bonus immediat selon la campagne. "semaine" (tournois de la semaine) : 500 F de
    # pions offerts DES l'inscription. Les autres campagnes (mini/premier) gagnent leur
    # bonus en achetant 5 tickets, donc 0 a l'inscription.
    bonus_credite = 0
    if campagne == "semaine":
        poche_bonus = DB.setdefault("pions_bonus_joueurs", {}).get(code, {})
        _crediter_pions_montant(poche_bonus, 500)
        DB["pions_bonus_joueurs"][code] = poche_bonus
        bonus_credite = 500
    DB["rejoindre_log"].insert(0, {"ip": ip, "tel": tel_clean, "code": code, "nom": nom, "campagne": campagne, "date": maintenant.isoformat()})
    save_data(immediat=True)
    return jsonify({"ok": True, "code": code, "deja": False, "bonus": bonus_credite})


