@app.route("/perturbateurs")
def page_perturbateurs():
    """ADMIN — Liste des avertissements et blocages. ?cle=ADMIN
    Actions : &debloquer=CODE (débloque + remet les avertissements à zéro)."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    msg_action = ""
    deb = (request.args.get("debloquer", "") or "").upper().strip()
    if deb:
        DB["codes_bloques"] = [c for c in DB.get("codes_bloques", []) if c != deb]
        if deb in DB.get("avertissements_joueurs", {}):
            DB["avertissements_joueurs"].pop(deb, None)
        save_data(immediat=True)
        msg_action = f"✅ {deb} débloquée et avertissements remis à zéro."
    av = DB.get("avertissements_joueurs", {})
    bloques = set(DB.get("codes_bloques", []))
    lignes = []
    for code, rec in av.items():
        nb = int(rec.get("nb", 0))
        est_bloque = code in bloques
        lignes.append((code, nb, est_bloque, rec.get("dernier_motif", ""), rec.get("maj", "")))
    # codes bloqués sans avertissement (bloqués à la main)
    for code in bloques:
        if code not in av:
            lignes.append((code, 0, True, "(bloquée manuellement)", ""))
    lignes.sort(key=lambda x: (0 if x[2] else 1, -x[1]))
    rows = ""
    for code, nb, est_bloque, motif, maj in lignes:
        etat = '<span style="color:#f87171;font-weight:700">🚫 BLOQUÉE</span>' if est_bloque else f'<span style="color:#fbbf24;font-weight:700">⚠️ {nb}/3</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{code}</td>'
                 f'<td style="padding:8px">{etat}</td>'
                 f'<td style="padding:8px;color:#94a3b8;font-size:12px">{motif}</td>'
                 f'<td style="padding:8px;color:#64748b;font-size:11px">{str(maj)[:16].replace("T"," ")}</td>'
                 f'<td style="padding:8px"><a href="/perturbateurs?cle={cle}&debloquer={code}" style="color:#34d399;text-decoration:none;font-weight:700">✅ Débloquer</a></td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:20px;text-align:center;color:#94a3b8">Aucune perturbatrice — tout est calme. 🌿</td></tr>'
    banner = f'<div style="background:rgba(16,185,129,.15);border:1px solid #10b981;border-radius:8px;padding:10px;margin-bottom:12px;color:#34d399;font-weight:700">{msg_action}</div>' if msg_action else ""
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Perturbatrices</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:8px">🚨 Anti-perturbateur</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:12px">Avertissements et blocages. À 3 avertissements, la joueuse est bloquée automatiquement (connexion + pions inaccessibles).</div>
      {banner}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:560px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:8px;color:#a78bfa">Code</th><th style="padding:8px;color:#a78bfa">État</th><th style="padding:8px;color:#a78bfa">Dernier motif</th><th style="padding:8px;color:#a78bfa">Maj</th><th style="padding:8px;color:#a78bfa">Action</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/organisatrices")
def page_organisatrices():
    """ADMIN — Active / désactive les organisatrices. Une organisatrice INACTIVE
    n'apparaît plus sur les écrans des joueuses (ses jeux et PDF sont masqués).
    ?cle=ADMIN  ·  &toggle=CODE pour basculer active/inactive."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    msg_action = ""
    tog = (request.args.get("toggle", "") or "").upper().strip()
    if tog and tog in DB.get("codes", {}):
        c = DB["codes"][tog]
        if isinstance(c, dict) and not c.get("admin"):
            c["actif"] = not bool(c.get("actif"))
            save_data(immediat=True)
            msg_action = f"{c.get('nom', tog)} ({tog}) est maintenant " + ("✅ ACTIVE" if c["actif"] else "⏸️ INACTIVE") + "."
    orgs = []
    for code, c in DB.get("codes", {}).items():
        if not isinstance(c, dict):
            continue
        if c.get("admin") or c.get("role") == "revendeur":
            continue
        orgs.append((code, c.get("nom", code), bool(c.get("actif"))))
    orgs.sort(key=lambda x: (0 if x[2] else 1, str(x[1]).lower()))
    nb_actives = sum(1 for o in orgs if o[2])
    rows = ""
    for code, nom, actif in orgs:
        if actif:
            etat = '<span style="color:#34d399;font-weight:700">✅ Active</span>'
            bouton = f'<a href="/organisatrices?cle={cle}&toggle={code}" style="display:inline-block;padding:7px 14px;background:rgba(245,158,11,.2);color:#fbbf24;border:0.5px solid rgba(245,158,11,.5);border-radius:8px;text-decoration:none;font-weight:700;font-size:13px">⏸️ Désactiver</a>'
        else:
            etat = '<span style="color:#94a3b8;font-weight:700">⏸️ Inactive</span>'
            bouton = f'<a href="/organisatrices?cle={cle}&toggle={code}" style="display:inline-block;padding:7px 14px;background:rgba(16,185,129,.2);color:#34d399;border:0.5px solid rgba(16,185,129,.5);border-radius:8px;text-decoration:none;font-weight:700;font-size:13px">✅ Activer</a>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:10px;font-weight:600">{nom}</td>'
                 f'<td style="padding:10px;font-family:monospace;color:#a78bfa">{code}</td>'
                 f'<td style="padding:10px">{etat}</td>'
                 f'<td style="padding:10px;text-align:right">{bouton}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="4" style="padding:20px;text-align:center;color:#94a3b8">Aucune organisatrice enregistrée.</td></tr>'
    banner = f'<div style="background:rgba(16,185,129,.15);border:1px solid #10b981;border-radius:8px;padding:10px;margin-bottom:12px;color:#34d399;font-weight:700">{msg_action}</div>' if msg_action else ""
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Organisatrices</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff">
    <div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:6px">👑 Organisatrices</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:12px">{len(orgs)} organisatrice(s) · <b style="color:#34d399">{nb_actives} active(s)</b>. Une organisatrice INACTIVE disparaît des écrans des joueuses (ses jeux et PDF sont masqués partout).</div>
      {banner}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px;min-width:520px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:10px;color:#a78bfa">Nom</th><th style="padding:10px;color:#a78bfa">Code</th><th style="padding:10px;color:#a78bfa">État</th><th style="padding:10px;color:#a78bfa;text-align:right">Action</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/rapport-tournoi")
def rapport_tournoi():
    """ADMIN — Rapport FINAL d'un tournoi (toutes les transactions + résumé).
    Sans paramètre : liste des tournois (organisatrice + jour).
    ?cle=ADMIN&org=CODE&date=AAAA-MM-JJ : rapport complet de ce tournoi."""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    codes = DB.get("codes", {})

    def i(x):
        try:
            return int(float(x or 0))
        except Exception:
            return 0

    def onom(o):
        return codes.get(o, {}).get("nom", o) if o else "—"

    def jour(x):
        return str(x or "")[:10]

    f_org = (request.args.get("org", "") or "").strip().upper()
    f_date = (request.args.get("date", "") or "").strip()[:10]

    # ===== MODE LISTE : tous les tournois (org + jour ayant des ventes de tickets) =====
    if not (f_org and f_date):
        tournois = {}
        for c in DB.get("commandes_tickets_pions", []):
            if not isinstance(c, dict):
                continue
            o = (c.get("code_org") or "").upper()
            j = jour(c.get("date"))
            if not o or not j:
                continue
            k = (o, j)
            t = tournois.setdefault(k, {"mises": 0, "tickets": 0, "joueuses": set()})
            if c.get("statut") in ("validee", "en_attente", "rembourse"):
                t["mises"] += i(c.get("total_pions"))
                t["tickets"] += 1
                t["joueuses"].add(c.get("code_joueur"))
        lignes = sorted(tournois.items(), key=lambda kv: kv[0][1], reverse=True)
        rows = ""
        for (o, j), t in lignes:
            rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                     f'<td style="padding:9px;color:#64748b">{j}</td>'
                     f'<td style="padding:9px;color:#fbbf24;font-weight:600">{onom(o)}</td>'
                     f'<td style="padding:9px;text-align:right">{format(t["mises"], ",")} F</td>'
                     f'<td style="padding:9px;text-align:right;color:#94a3b8">{len(t["joueuses"])}</td>'
                     f'<td style="padding:9px;text-align:right"><a href="/rapport-tournoi?cle={cle}&org={o}&date={j}" style="color:#34d399;text-decoration:none;font-weight:700">📊 Rapport →</a></td></tr>')
        if not rows:
            rows = '<tr><td colspan="5" style="padding:20px;text-align:center;color:#94a3b8">Aucun tournoi avec des ventes.</td></tr>'
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Rapports de tournois</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:860px;margin:0 auto">
        <h1 style="font-size:21px;color:#a855f7;margin-bottom:6px">📊 Rapports de tournois</h1>
        <div style="color:#94a3b8;font-size:13px;margin-bottom:14px">Choisis un tournoi pour voir son rapport final (toutes les transactions + résumé financier).</div>
        <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px;min-width:560px">
        <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:9px;color:#a78bfa">Jour</th><th style="padding:9px;color:#a78bfa">Organisatrice</th><th style="padding:9px;color:#a78bfa;text-align:right">Mises</th><th style="padding:9px;color:#a78bfa;text-align:right">Joueuses</th><th style="padding:9px;color:#a78bfa;text-align:right">Rapport</th></tr>
        {rows}</table></div></div></body></html>''', mimetype="text/html; charset=utf-8")

    # ===== MODE RAPPORT : un tournoi précis (org + jour) =====
    def concerne(rec):
        return isinstance(rec, dict) and (rec.get("code_org", "") or "").upper() == f_org and jour(rec.get("date")) == f_date

    mises = tickets_nb = 0
    achats_pions = credits_org = gains = remb = retraits = 0
    ops = []
    for c in DB.get("commandes_tickets_pions", []):
        if concerne(c) and c.get("statut") in ("validee", "en_attente", "rembourse"):
            m = i(c.get("total_pions")); mises += m; tickets_nb += 1
            ops.append((c.get("date", ""), "Achat ticket", "#818cf8", c.get("code_joueur", ""), m, c.get("jeu", "")))
    for c in DB.get("commandes_pions_joueurs", []):
        if concerne(c) and c.get("statut") in ("validee", "valide", "en_attente_validation"):
            m = i(c.get("montant_paye")); achats_pions += m
            ops.append((c.get("date", ""), "Achat pions", "#fbbf24", c.get("code_joueur", ""), m, f'{c.get("nb_pions","?")} pions'))
    for t in DB.get("transactions_joueur_org", []):
        if concerne(t):
            m = i(t.get("montant_total")); credits_org += m
            ops.append((t.get("date", ""), "Crédit org→joueuse", "#34d399", t.get("code_joueur", ""), m, ""))
    for g in DB.get("gains_finaux", []):
        if concerne(g):
            m = i(g.get("montant_credite") or g.get("montant_gain")); gains += m
            ops.append((g.get("date", ""), "Gain payé", "#f472b6", g.get("code_gagnant", ""), m, g.get("jeu", "")))
    for rb in DB.get("remboursements_tournoi", []):
        if concerne(rb):
            m = i(rb.get("total_rembourse")); remb += m
            ops.append((rb.get("date", ""), "Remboursement", "#fca5a5", f'{rb.get("nb_joueuses","?")} joueuses', m, rb.get("jeu", "")))
    for r in DB.get("demandes_retrait", []):
        if concerne(r):
            m = i(r.get("montant_demande")); retraits += m
            ops.append((r.get("date", ""), "Retrait", "#fb923c", r.get("code_joueur", ""), m, r.get("statut", "")))

    cagnotte = round(mises * 0.80)
    part_org = round(mises * 0.20)
    ops.sort(key=lambda o: str(o[0]))
    rows = ""
    for date_op, typ, coul, qui, montant, det in ops:
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:7px;color:#64748b;font-size:11px;white-space:nowrap">{str(date_op)[:16].replace("T"," ")}</td>'
                 f'<td style="padding:7px"><span style="color:{coul};font-weight:600;font-size:12px">{typ}</span></td>'
                 f'<td style="padding:7px;font-family:monospace;font-size:12px;color:#a78bfa">{qui}</td>'
                 f'<td style="padding:7px;text-align:right;font-weight:700;white-space:nowrap">{format(montant, ",")} F</td>'
                 f'<td style="padding:7px;color:#94a3b8;font-size:11px">{det}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:20px;text-align:center;color:#94a3b8">Aucune transaction ce jour-là.</td></tr>'

    def carte(titre, valeur, coul):
        return (f'<div style="flex:1;min-width:135px;background:#161b22;border:1px solid #30363d;border-radius:10px;padding:12px">'
                f'<div style="font-size:11px;color:#94a3b8;margin-bottom:4px">{titre}</div>'
                f'<div style="font-size:18px;font-weight:800;color:{coul}">{format(valeur, ",")} F</div></div>')

    cartes = (carte("Mises sur tickets", mises, "#818cf8")
              + carte("Cagnotte (80%)", cagnotte, "#34d399")
              + carte("Part organisatrice (20%)", part_org, "#fbbf24")
              + carte("Gains payés", gains, "#f472b6")
              + carte("Remboursements", remb, "#fca5a5")
              + carte("Achats de pions", achats_pions, "#fcd34d"))

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Rapport tournoi</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:920px;margin:0 auto">
      <a href="/rapport-tournoi?cle={cle}" style="color:#818cf8;text-decoration:none;font-size:13px">← Tous les tournois</a>
      <h1 style="font-size:22px;color:#a855f7;margin:8px 0 2px">📊 Rapport final — {onom(f_org)}</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:14px">Tournoi du <b style="color:#fff">{f_date}</b> · {tickets_nb} ticket(s) vendu(s)</div>
      <div style="display:flex;flex-wrap:wrap;gap:10px;margin-bottom:18px">{cartes}</div>
      <h2 style="font-size:15px;color:#c7d2fe;margin-bottom:8px">Détail de toutes les transactions</h2>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:600px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Heure</th><th style="padding:7px;color:#a78bfa">Opération</th><th style="padding:7px;color:#a78bfa">Joueuse</th><th style="padding:7px;color:#a78bfa;text-align:right">Montant</th><th style="padding:7px;color:#a78bfa">Détail</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/verif-mises-org")
def verif_mises_org():
    """ADMIN — Vérifie que chaque mise de ticket est bien créditée au compteur de
    l'organisatrice. ?cle=ADMIN[&org=CODE]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    codes = DB.get("codes", {})
    f_org = (request.args.get("org", "") or "").strip().upper()

    def i(x):
        try:
            return int(float(x or 0))
        except Exception:
            return 0

    def onom(o):
        return codes.get(o, {}).get("nom", o) if o else "—"

    # Agréger par organisatrice
    par_org = {}
    anomalies = []
    for c in DB.get("commandes_tickets_pions", []):
        if not isinstance(c, dict):
            continue
        o = (c.get("code_org") or "").upper()
        if not o or (f_org and o != f_org):
            continue
        montant = i(c.get("total_pions"))
        statut = c.get("statut", "")
        creditee = bool(c.get("mise_creditee_org"))
        p = par_org.setdefault(o, {"creditee": 0, "attente": 0, "rembourse": 0, "anomalie": 0})
        if statut == "rembourse":
            p["rembourse"] += montant
        elif statut == "validee":
            if creditee:
                p["creditee"] += montant
            else:
                p["anomalie"] += montant
                anomalies.append((o, c.get("code_joueur", ""), montant, c.get("jeu", ""), c.get("date", "")))
        else:  # en_attente
            p["attente"] += montant

    # Solde réel actuel du compteur de chaque org
    def solde_poche(o):
        poche = DB.get("pions_org", {}).get(o, {})
        return _xpf_total_pions(poche) if isinstance(poche, dict) else 0

    rows = ""
    for o in sorted(par_org.keys(), key=lambda x: onom(x).lower()):
        p = par_org[o]
        alerte = ""
        if p["anomalie"] > 0:
            alerte = f'<span style="color:#f87171;font-weight:700"> ⚠️ {format(p["anomalie"], ",")} F non crédités</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:9px;color:#fbbf24;font-weight:600">{onom(o)}{alerte}</td>'
                 f'<td style="padding:9px;font-family:monospace;color:#a78bfa">{o}</td>'
                 f'<td style="padding:9px;text-align:right;color:#34d399">{format(p["creditee"], ",")} F</td>'
                 f'<td style="padding:9px;text-align:right;color:#fbbf24">{format(p["attente"], ",")} F</td>'
                 f'<td style="padding:9px;text-align:right;color:#fca5a5">{format(p["rembourse"], ",")} F</td>'
                 f'<td style="padding:9px;text-align:right;color:#c7d2fe">{format(solde_poche(o), ",")} F</td></tr>')
    if not rows:
        rows = '<tr><td colspan="6" style="padding:20px;text-align:center;color:#94a3b8">Aucune vente de ticket.</td></tr>'

    anomalies.sort(key=lambda a: str(a[4]), reverse=True)
    anom_html = ""
    if anomalies:
        lignes = ""
        for o, cj, m, jeu, dt in anomalies[:100]:
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                       f'<td style="padding:7px;color:#fbbf24">{onom(o)}</td>'
                       f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{cj}</td>'
                       f'<td style="padding:7px;text-align:right;font-weight:700">{format(m, ",")} F</td>'
                       f'<td style="padding:7px;color:#94a3b8;font-size:11px">{jeu}</td>'
                       f'<td style="padding:7px;color:#64748b;font-size:11px">{str(dt)[:16].replace("T"," ")}</td></tr>')
        anom_html = (f'<h2 style="font-size:15px;color:#fca5a5;margin:20px 0 8px">⚠️ Tickets validés mais mise NON créditée ({len(anomalies)})</h2>'
                     f'<div style="color:#94a3b8;font-size:12px;margin-bottom:8px">Ce sont d\'anciennes validations (avant la correction). Tu peux recréditer manuellement la poche de l\'organisatrice via /organisatrices ou m\'en parler.</div>'
                     f'<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:520px">'
                     f'<tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:7px;color:#fca5a5">Organisatrice</th><th style="padding:7px;color:#fca5a5">Joueuse</th><th style="padding:7px;color:#fca5a5;text-align:right">Montant</th><th style="padding:7px;color:#fca5a5">Jeu</th><th style="padding:7px;color:#fca5a5">Date</th></tr>{lignes}</table></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Vérif mises organisatrices</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:920px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:6px">🔍 Vérification des mises → compteur organisatrice</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:6px">Chaque mise de ticket est créditée au compteur de l'organisatrice <b style="color:#fff">au moment de la validation</b>.</div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:14px">🟢 Créditée = mise bien arrivée · 🟡 En attente = ticket pas encore validé (joueuse débitée, pas encore créditée) · 🔴 Remboursée · 🔵 Solde = compteur réel actuel.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:640px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:9px;color:#a78bfa">Organisatrice</th><th style="padding:9px;color:#a78bfa">Code</th><th style="padding:9px;color:#a78bfa;text-align:right">🟢 Créditée</th><th style="padding:9px;color:#a78bfa;text-align:right">🟡 En attente</th><th style="padding:9px;color:#a78bfa;text-align:right">🔴 Remboursée</th><th style="padding:9px;color:#a78bfa;text-align:right">🔵 Solde compteur</th></tr>
      {rows}</table></div>
      {anom_html}
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/securite-admin")
def page_securite_admin():
    """ADMIN — Contrôle des accès administrateur. Liste les codes admin actifs,
    indique si ADMIN2024 (public) est encore ouvert, et permet de désactiver
    un code admin. ?cle=ADMIN[&desactiver=CODE]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    msg_action = ""
    deb = (request.args.get("desactiver", "") or "").upper().strip()
    if deb:
        if deb == cle:
            msg_action = "⚠️ Impossible de désactiver le code que tu utilises en ce moment."
        elif deb in DB.get("codes", {}):
            DB["codes"][deb]["actif"] = False
            save_data(immediat=True)
            msg_action = f"✅ Le code admin {deb} a été DÉSACTIVÉ."

    env_defini = bool(os.environ.get("ADMIN_CODE_SECRET", "").strip())
    admin2024 = DB.get("codes", {}).get("ADMIN2024", {})
    admin2024_actif = bool(admin2024.get("actif"))

    rows = ""
    nb_actifs = 0
    for code, c in DB.get("codes", {}).items():
        if not isinstance(c, dict) or not c.get("admin"):
            continue
        actif = bool(c.get("actif"))
        if actif:
            nb_actifs += 1
        danger = (code == "ADMIN2024" and actif)
        etat = ('<span style="color:#34d399;font-weight:700">✅ Actif</span>' if actif else '<span style="color:#94a3b8">⏸️ Inactif</span>')
        if danger:
            etat = '<span style="color:#f87171;font-weight:800">🚨 ACTIF & PUBLIC</span>'
        ici = ' <span style="color:#818cf8;font-size:11px">(toi, en ce moment)</span>' if code == cle else ''
        if actif and code != cle:
            action = f'<a href="/securite-admin?cle={cle}&desactiver={code}" style="color:#fca5a5;text-decoration:none;font-weight:700">🔒 Désactiver</a>'
        elif code == cle:
            action = '<span style="color:#64748b">—</span>'
        else:
            action = '<span style="color:#64748b">déjà inactif</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:9px;font-family:monospace;color:#a78bfa">{code}{ici}</td>'
                 f'<td style="padding:9px;color:#94a3b8">{c.get("nom","")}</td>'
                 f'<td style="padding:9px">{etat}</td>'
                 f'<td style="padding:9px;text-align:right">{action}</td></tr>')

    env_html = ('<div style="background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:8px;padding:12px;margin-bottom:10px;color:#34d399;font-size:13px">✅ La variable Railway <b>ADMIN_CODE_SECRET</b> est définie : ton vrai code admin vient de Railway (pas du code public), et ADMIN2024 doit être désactivé.</div>'
                if env_defini else
                '<div style="background:rgba(239,68,68,.12);border:1px solid #f87171;border-radius:8px;padding:12px;margin-bottom:10px;color:#fca5a5;font-size:13px">🚨 La variable Railway <b>ADMIN_CODE_SECRET</b> n\'est PAS définie. Tant qu\'elle est vide, le code public <b>ADMIN2024</b> peut servir d\'admin. Définis-la d\'urgence (voir plus bas).</div>')
    a24_html = ('<div style="background:rgba(239,68,68,.18);border:1px solid #f87171;border-radius:8px;padding:12px;margin-bottom:10px;color:#fca5a5;font-size:13px;font-weight:700">🚨 ADMIN2024 est ENCORE ACTIF et il est public ! Désactive-le dans le tableau ci-dessous.</div>'
                if admin2024_actif else
                '<div style="background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:8px;padding:12px;margin-bottom:10px;color:#34d399;font-size:13px">✅ ADMIN2024 (le code public) est désactivé. Bien.</div>')
    banner = f'<div style="background:rgba(99,102,241,.15);border:1px solid #6366f1;border-radius:8px;padding:10px;margin-bottom:12px;color:#c7d2fe;font-weight:700">{msg_action}</div>' if msg_action else ""

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Sécurité admin</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:10px">🔐 Sécurité des accès administrateur</h1>
      {banner}{env_html}{a24_html}
      <div style="color:#94a3b8;font-size:13px;margin:14px 0 6px"><b style="color:#fff">{nb_actifs}</b> code(s) admin actif(s). Désactive tout ce que tu ne reconnais pas.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px;min-width:520px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:9px;color:#a78bfa">Code admin</th><th style="padding:9px;color:#a78bfa">Nom</th><th style="padding:9px;color:#a78bfa">État</th><th style="padding:9px;color:#a78bfa;text-align:right">Action</th></tr>
      {rows}</table></div>
      <div style="background:#161b22;border:1px solid #30363d;border-radius:10px;padding:14px;margin-top:16px;font-size:13px;color:#cbd5e1;line-height:1.7">
        <b style="color:#fff">Pour sécuriser ton admin (à faire sur Railway) :</b><br>
        1. Va sur Railway → ton projet → onglet <b>Variables</b><br>
        2. Crée une variable <b>ADMIN_CODE_SECRET</b> = un nouveau code secret (ex. une longue suite de lettres/chiffres à toi)<br>
        3. Railway redéploie tout seul → ce nouveau code devient ton admin, et <b>ADMIN2024 se désactive automatiquement</b><br>
        4. Reviens ici avec <b>?cle=TON_NOUVEAU_CODE</b> pour vérifier que tout est ✅
      </div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/codes-similaires")
def codes_similaires():
    """ADMIN — Trouve tous les codes contenant un texte (emoji/caractères bizarres
    inclus) et propose un lien de fusion DÉJÀ encodé, pour ne rien avoir à taper.
    ?cle=ADMIN&contient=TEXTE"""
    global DB
    DB = load_data()
    from urllib.parse import quote
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    contient = (request.args.get("contient", "") or "").strip()

    def solde(code):
        p = DB.get("pions_joueurs", {}).get(code, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    def bonus(code):
        p = DB.get("pions_bonus_joueurs", {}).get(code, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    def nb_gains(code):
        return sum(1 for g in DB.get("gains_finaux", []) if isinstance(g, dict) and g.get("code_gagnant") == code)

    if not contient:
        return Response('<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto"><h1 style="color:#a855f7;font-size:20px">🔎 Codes similaires</h1><p style="color:#94a3b8">Ajoute <code style="color:#fde68a">&contient=DEBUTDUCODE</code> (ex : <code>&contient=OXUZRO</code>).</p></div></body></html>', mimetype="text/html; charset=utf-8")

    # Rassembler tous les codes connus
    tous = set()
    for k in ["pions_joueurs", "pions_bonus_joueurs", "tickets_acheteurs", "codes"]:
        d = DB.get(k, {})
        if isinstance(d, dict):
            tous.update(d.keys())
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code_gagnant"):
            tous.add(g["code_gagnant"])

    cible = contient.upper()
    trouves = sorted([c for c in tous if isinstance(c, str) and cible in c.upper()])

    # Code "propre" = uniquement lettres/chiffres ASCII (candidat destination)
    propres = [c for c in trouves if c.isascii() and c.isalnum()]
    code_propre = propres[0] if len(propres) == 1 else None

    rows = ""
    for c in trouves:
        propre = c.isascii() and c.isalnum()
        acces = c in DB.get("tickets_acheteurs", {})
        etiquette = '<span style="color:#6ee7b7">✅ propre</span>' if propre else '<span style="color:#fca5a5">⚠️ caractère bizarre</span>'
        acc = '<span style="color:#6ee7b7">✅ accès</span>' if acces else '<span style="color:#94a3b8">— pas d\'accès</span>'
        action = "—"
        if code_propre and c != code_propre:
            # lien de fusion DÉJÀ encodé : ce code (de) -> le code propre (vers)
            lien = f"/fusion-codes?cle={quote(cle)}&de={quote(c)}&vers={quote(code_propre)}"
            action = f'<a href="{lien}" style="color:#fde68a;font-weight:700;text-decoration:none">→ Fusionner dans {code_propre}</a>'
        elif code_propre and c == code_propre:
            action = '<span style="color:#6ee7b7">⭐ destination</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:9px;font-family:monospace;color:#a78bfa;font-size:15px">{c}</td>'
                 f'<td style="padding:9px">{etiquette}</td>'
                 f'<td style="padding:9px;text-align:right;color:#34d399">{format(solde(c), ",")} F</td>'
                 f'<td style="padding:9px;text-align:right;color:#fbbf24">{format(bonus(c), ",")} F</td>'
                 f'<td style="padding:9px;text-align:center;color:#c7d2fe">{nb_gains(c)}</td>'
                 f'<td style="padding:9px;text-align:right;color:#94a3b8">{acc}</td>'
                 f'<td style="padding:9px">{action}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="7" style="padding:20px;text-align:center;color:#94a3b8">Aucun code trouvé.</td></tr>'

    note = ""
    if not code_propre:
        note = '<div style="background:rgba(252,165,165,.1);border:1px solid #ef4444;border-radius:8px;padding:10px;margin:10px 0;color:#fca5a5;font-size:13px">⚠️ Je n\'ai pas pu désigner UN seul code « propre » comme destination. Vérifie la liste et dis-moi lequel est le vrai compte.</div>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Codes similaires</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:880px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin-bottom:6px">🔎 Codes contenant « {contient} »</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:10px">⭐ destination = le code propre où la joueuse se connecte. Le bouton « → Fusionner » déplace tout vers lui (aperçu d\'abord, rien n\'est validé sans confirmer).</div>
      {note}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:680px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:9px;color:#a78bfa">Code</th><th style="padding:9px;color:#a78bfa">Type</th><th style="padding:9px;color:#a78bfa;text-align:right">Solde</th><th style="padding:9px;color:#a78bfa;text-align:right">Bonus</th><th style="padding:9px;color:#a78bfa;text-align:center">Gains</th><th style="padding:9px;color:#a78bfa;text-align:right">Accès</th><th style="padding:9px;color:#a78bfa">Action</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/trace-transferts")
def trace_transferts():
    """ADMIN — Enquête : liste TOUS les transferts impliquant un code (envoyés ou
    reçus), en montrant COMMENT chacun a été fait (outil admin 'par X' ou ancienne
    route joueuse 'via IP'). ?cle=ADMIN&code=CODE"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    if not code:
        return Response('<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto"><h1 style="color:#a855f7;font-size:20px">🔎 Trace des transferts</h1><p style="color:#94a3b8">Ajoute <code style="color:#fde68a">&code=LECODE</code> (ex : <code>&code=V2DYIH</code>).</p></div></body></html>', mimetype="text/html; charset=utf-8")

    recs = [t for t in DB.get("transferts_pions", []) if isinstance(t, dict) and (t.get("de") == code or t.get("vers") == code)]
    recs.sort(key=lambda t: str(t.get("date", "")), reverse=True)

    total_recu = sum(int(t.get("montant", 0) or 0) for t in recs if t.get("vers") == code)
    total_envoye = sum(int(t.get("montant", 0) or 0) for t in recs if t.get("de") == code)
    sources = sorted({t.get("de") for t in recs if t.get("vers") == code and t.get("de")})
    nb_admin = sum(1 for t in recs if t.get("admin"))
    nb_joueuse = sum(1 for t in recs if not t.get("admin"))

    rows = ""
    for t in recs:
        sens = ("⬅️ REÇU" if t.get("vers") == code else "➡️ ENVOYÉ")
        coul = "#34d399" if t.get("vers") == code else "#fca5a5"
        autre = t.get("de") if t.get("vers") == code else t.get("vers")
        if t.get("admin"):
            origine = f'<span style="color:#fbbf24;font-weight:700">🔑 OUTIL ADMIN · par {t.get("par","?")}</span>'
        elif t.get("ip"):
            origine = f'<span style="color:#93c5fd">📱 route joueuse · IP {t.get("ip")}</span>'
        else:
            origine = '<span style="color:#94a3b8">— origine non marquée (ancien)</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:8px;color:#64748b;font-size:12px;white-space:nowrap">{str(t.get("date",""))[:16].replace("T"," ")}</td>'
                 f'<td style="padding:8px;color:{coul};font-weight:600">{sens}</td>'
                 f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{autre}</td>'
                 f'<td style="padding:8px;text-align:right;font-weight:700">{format(int(t.get("montant",0) or 0), ",")} F</td>'
                 f'<td style="padding:8px">{origine}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:20px;text-align:center;color:#94a3b8">Aucun transfert pour ce code.</td></tr>'

    alerte = ""
    if nb_admin > 0:
        alerte = (f'<div style="background:rgba(251,191,36,.12);border:1px solid #fbbf24;border-radius:8px;padding:12px;margin-bottom:12px;color:#fde68a;font-size:13px">'
                  f'🔑 <b>{nb_admin}</b> transfert(s) fait(s) avec <b>l\'outil admin</b>. Si ce n\'est pas toi qui les as faits, ton code admin a été utilisé par quelqu\'un d\'autre → change-le d\'urgence (variable Railway ADMIN_CODE_SECRET).</div>')

    src_html = ""
    if sources:
        src_html = f'<div style="color:#94a3b8;font-size:13px;margin:8px 0">Pions reçus depuis <b style="color:#fff">{len(sources)}</b> code(s) : <span style="font-family:monospace;color:#a78bfa">{", ".join(sources)}</span></div>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Trace transferts {code}</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:900px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin-bottom:6px">🔎 Transferts du code <span style="font-family:monospace">{code}</span></h1>
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin:10px 0">
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">⬅️ Total reçu</div><div style="color:#34d399;font-size:18px;font-weight:700">{format(total_recu, ",")} F</div></div>
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">➡️ Total envoyé</div><div style="color:#fca5a5;font-size:18px;font-weight:700">{format(total_envoye, ",")} F</div></div>
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">🔑 via admin / 📱 via joueuse</div><div style="font-size:18px;font-weight:700"><span style="color:#fbbf24">{nb_admin}</span> / <span style="color:#93c5fd">{nb_joueuse}</span></div></div>
      </div>
      {alerte}{src_html}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:660px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:8px;color:#a78bfa">Date</th><th style="padding:8px;color:#a78bfa">Sens</th><th style="padding:8px;color:#a78bfa">Autre code</th><th style="padding:8px;color:#a78bfa;text-align:right">Montant</th><th style="padding:8px;color:#a78bfa">Comment</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/anti-fraude")
def anti_fraude():
    """ADMIN — Réponse anti-fraude : pour une liste de codes suspects, montre
    solde, retraits (argent réel sorti ?), état bloqué, et permet de BLOQUER en
    un clic. ?cle=ADMIN&codes=A,B,C[&bloquer=CODE][&debloquer=CODE]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    msg = ""
    DB.setdefault("codes_bloques", [])
    blq = (request.args.get("bloquer", "") or "").strip().upper()
    if blq:
        if blq not in DB["codes_bloques"]:
            DB["codes_bloques"].append(blq)
            save_data(immediat=True)
        msg = f"🔒 {blq} est maintenant BLOQUÉ (ne peut plus se connecter ni transférer)."
    deb = (request.args.get("debloquer", "") or "").strip().upper()
    if deb:
        DB["codes_bloques"] = [c for c in DB["codes_bloques"] if c != deb]
        save_data(immediat=True)
        msg = f"🔓 {deb} a été débloqué."

    codes_str = (request.args.get("codes", "") or "").strip().upper()
    codes = [c.strip() for c in codes_str.split(",") if c.strip()]

    def solde(code):
        p = DB.get("pions_joueurs", {}).get(code, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    def retraits(code):
        valide = 0; attente = 0
        for r in DB.get("demandes_retrait", []):
            if isinstance(r, dict) and (r.get("code_joueur") or "").upper() == code:
                m = int(r.get("montant_demande", 0) or 0)
                if r.get("statut") == "validee":
                    valide += m
                elif r.get("statut") in (None, "", "en_attente"):
                    attente += m
        return valide, attente

    if not codes:
        return Response('<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto"><h1 style="color:#f87171;font-size:20px">🛡️ Anti-fraude</h1><p style="color:#94a3b8">Ajoute <code style="color:#fde68a">&codes=A,B,C</code> (les codes suspects, séparés par des virgules).</p></div></body></html>', mimetype="text/html; charset=utf-8")

    tot_valide = 0; tot_attente = 0; tot_solde = 0
    rows = ""
    for code in codes:
        s = solde(code); v, a = retraits(code)
        tot_solde += s; tot_valide += v; tot_attente += a
        bloque = code in DB["codes_bloques"]
        etat = ('<span style="color:#f87171;font-weight:700">🔒 BLOQUÉ</span>' if bloque
                else '<span style="color:#34d399">🔓 actif</span>')
        if bloque:
            action = f'<a href="/anti-fraude?cle={cle}&codes={codes_str}&debloquer={code}" style="color:#93c5fd;text-decoration:none">débloquer</a>'
        else:
            action = f'<a href="/anti-fraude?cle={cle}&codes={codes_str}&bloquer={code}" style="color:#fca5a5;font-weight:700;text-decoration:none">🔒 BLOQUER</a>'
        ret_txt = f'<span style="color:#f87171;font-weight:700">{format(v, ",")} F payés</span>' if v else '<span style="color:#94a3b8">0</span>'
        if a:
            ret_txt += f' <span style="color:#fbbf24">· {format(a, ",")} F en attente</span>'
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:9px;font-family:monospace;color:#a78bfa;font-size:15px">{code}</td>'
                 f'<td style="padding:9px;text-align:right;color:#34d399">{format(s, ",")} F</td>'
                 f'<td style="padding:9px">{ret_txt}</td>'
                 f'<td style="padding:9px">{etat}</td>'
                 f'<td style="padding:9px;text-align:right">{action}</td></tr>')

    alerte_argent = ""
    if tot_valide > 0:
        alerte_argent = (f'<div style="background:rgba(239,68,68,.18);border:1px solid #f87171;border-radius:8px;padding:12px;margin-bottom:10px;color:#fca5a5;font-size:14px;font-weight:700">'
                         f'🚨 {format(tot_valide, ",")} XPF de retraits DÉJÀ PAYÉS sur ces comptes — de l\'argent réel est peut-être sorti. Vérifie tes virements/espèces.</div>')
    else:
        alerte_argent = ('<div style="background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:8px;padding:12px;margin-bottom:10px;color:#34d399;font-size:14px">'
                         '✅ Aucun retrait payé sur ces comptes — l\'argent collecté est encore en pions (bloque-les pour le geler).</div>')
    if tot_attente > 0:
        alerte_argent += (f'<div style="background:rgba(251,191,36,.12);border:1px solid #fbbf24;border-radius:8px;padding:12px;margin-bottom:10px;color:#fde68a;font-size:13px">'
                          f'⚠️ {format(tot_attente, ",")} XPF de retraits EN ATTENTE — ne les valide PAS, bloque les comptes d\'abord.</div>')
    msg_html = f'<div style="background:rgba(99,102,241,.15);border:1px solid #6366f1;border-radius:8px;padding:10px;margin-bottom:12px;color:#c7d2fe;font-weight:700">{msg}</div>' if msg else ""

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Anti-fraude</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:860px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:10px">🛡️ Réponse anti-fraude</h1>
      {msg_html}{alerte_argent}
      <div style="color:#94a3b8;font-size:13px;margin-bottom:8px">Solde total gelé sur ces comptes : <b style="color:#fff">{format(tot_solde, ",")} XPF</b>. Bloque un compte = il ne peut plus se connecter, transférer, ni retirer.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:14px;min-width:560px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:9px;color:#fca5a5">Code</th><th style="padding:9px;color:#fca5a5;text-align:right">Solde pions</th><th style="padding:9px;color:#fca5a5">Retraits</th><th style="padding:9px;color:#fca5a5">État</th><th style="padding:9px;color:#fca5a5;text-align:right">Action</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/empreinte")
def empreinte_fraude():
    """ADMIN — Empreinte d'un code : ses IP/appareils/noms de connexion, et TOUS
    les autres codes qui partagent ces IP (réseau du fraudeur). Blocage en 1 clic.
    ?cle=ADMIN&code=CODE[&bloquer=CODE][&debloquer=CODE]"""
