@app.route("/codes-bloques")
def codes_bloques_page():
    """ADMIN — Liste tous les codes BLOQUÉS avec leur solde gelé. Débloquer en 1 clic.
    ?cle=ADMIN[&debloquer=CODE]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    DB.setdefault("codes_bloques", [])
    msg = ""
    deb = (request.args.get("debloquer", "") or "").strip().upper()
    if deb:
        DB["codes_bloques"] = [c for c in DB["codes_bloques"] if c != deb]
        save_data(immediat=True)
        msg = f"🔓 {deb} a été débloqué."

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    def nom_de(c):
        return DB.get("codes", {}).get(c, {}).get("nom", "") or ""

    bloques = sorted(DB.get("codes_bloques", []), key=lambda c: -solde(c))
    total_gele = sum(solde(c) for c in bloques)

    rows = ""
    for c in bloques:
        nm = nom_de(c)
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:8px;color:#94a3b8;font-size:12px">{nm}</td>'
                 f'<td style="padding:8px;text-align:right;color:#34d399">{format(solde(c), ",")} F</td>'
                 f'<td style="padding:8px;text-align:right"><a href="/codes-bloques?cle={cle}&debloquer={c}" style="color:#93c5fd;text-decoration:none">🔓 débloquer</a></td></tr>')
    if not rows:
        rows = '<tr><td colspan="4" style="padding:16px;text-align:center;color:#34d399">Aucun code bloqué.</td></tr>'
    msg_html = f'<div style="background:rgba(99,102,241,.15);border:1px solid #6366f1;border-radius:8px;padding:10px;margin-bottom:12px;color:#c7d2fe;font-weight:700">{msg}</div>' if msg else ""

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Codes bloqués</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:8px">🔒 Codes bloqués</h1>
      {msg_html}
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">Comptes bloqués</div><div style="color:#f87171;font-size:20px;font-weight:700">{len(bloques)}</div></div>
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">Pions gelés</div><div style="color:#34d399;font-size:20px;font-weight:700">{format(total_gele, ",")} F</div></div>
      </div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:8px">Ces comptes ne peuvent ni se connecter, ni transférer, ni retirer. Débloque seulement si tu confirmes qu'un compte est légitime.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:460px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:8px;color:#fca5a5">Code</th><th style="padding:8px;color:#fca5a5">Nom</th><th style="padding:8px;color:#fca5a5;text-align:right">Solde gelé</th><th style="padding:8px;color:#fca5a5;text-align:right">Action</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/audit-credits-admin")
def audit_credits_admin():
    """ADMIN — Retrace TOUS les crédits effectués par l'administrateur (recrédits
    de réconciliation). Montre lesquels sont allés vers des comptes BLOQUÉS
    (fraude) — ceux qu'il ne fallait pas créditer. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    bloques = set(DB.get("codes_bloques", []))

    items = []
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict):
            continue
        code = (c.get("code_joueur") or "").upper()
        montant = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        items.append({
            "code": code, "montant": montant, "par": c.get("par", "?"),
            "date": str(c.get("date", "")), "bloque": code in bloques
        })
    # Crédits de masse aussi
    for c in DB.get("credits_masse", []):
        if not isinstance(c, dict):
            continue
        for code in (c.get("codes") or []):
            code = (code or "").upper()
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            items.append({"code": code, "montant": m, "par": c.get("par", "masse"),
                          "date": str(c.get("date", "")), "bloque": code in bloques})

    items.sort(key=lambda x: x["date"], reverse=True)
    total = sum(i["montant"] for i in items if i["montant"] > 0)
    total_bloq = sum(i["montant"] for i in items if i["bloque"] and i["montant"] > 0)
    total_ok = total - total_bloq
    nb_bloq = len([i for i in items if i["bloque"]])

    rows = ""
    for i in items:
        if i["bloque"]:
            etat = '<span style="color:#f87171;font-weight:700">🔒 FRAUDE</span>'
            bg = 'background:rgba(239,68,68,.06)'
        else:
            etat = '<span style="color:#34d399">✅ légitime</span>'
            bg = ''
        signe = "+" if i["montant"] >= 0 else ""
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06);{bg}">'
                 f'<td style="padding:7px;color:#64748b;font-size:12px;white-space:nowrap">{i["date"][:16].replace("T"," ")}</td>'
                 f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{i["code"]}</td>'
                 f'<td style="padding:7px;text-align:right;font-weight:700;color:{"#f87171" if i["bloque"] else "#34d399"}">{signe}{format(i["montant"], ",")} F</td>'
                 f'<td style="padding:7px;font-family:monospace;color:#94a3b8;font-size:11px">{i["par"]}</td>'
                 f'<td style="padding:7px">{etat}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:16px;text-align:center;color:#94a3b8">Aucun crédit admin enregistré.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Audit crédits admin</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:860px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:10px">🔧 Audit des crédits administrateur</h1>
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">Total crédité</div><div style="color:#fff;font-size:18px;font-weight:700">{format(total, ",")} F</div></div>
        <div style="background:rgba(239,68,68,.12);border:1px solid #f87171;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">🔒 Vers comptes frauduleux</div><div style="color:#f87171;font-size:18px;font-weight:700">{format(total_bloq, ",")} F</div></div>
        <div style="background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">✅ Vers comptes sains</div><div style="color:#34d399;font-size:18px;font-weight:700">{format(total_ok, ",")} F</div></div>
      </div>
      <div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:8px;padding:12px;margin-bottom:14px;color:#fde68a;font-size:13px">⚠️ Les <b>{format(total_bloq, ",")} XPF</b> crédités vers les <b>{nb_bloq}</b> comptes frauduleux (en rouge) n'auraient pas dû l'être. Comme ces comptes sont gelés, ces pions sont neutralisés — mais ça confirme que c'était bien un audit qu'il fallait, pas un recrédit. Tu avais raison.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:560px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Date</th><th style="padding:7px;color:#a78bfa">Code crédité</th><th style="padding:7px;color:#a78bfa;text-align:right">Montant</th><th style="padding:7px;color:#a78bfa">Par</th><th style="padding:7px;color:#a78bfa">Verdict</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/annuler-credits-fraude")
def annuler_credits_fraude():
    """ADMIN — Annule (retire) la valeur injectée par l'ADMIN (recrédits + éventuels
    transferts admin) vers les comptes BLOQUÉS frauduleux. Aperçu d'abord ; rien
    n'est modifié sans &confirme=1. Ne touche QUE les comptes bloqués. ?cle=ADMIN[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    confirme = request.args.get("confirme", "") == "1"
    bloques = set(DB.get("codes_bloques", []))

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    def poser_solde(c, montant):
        montant = max(0, int(montant))
        r = montant
        n100 = r // 100; r -= n100 * 100
        n50 = r // 50; r -= n50 * 50
        n20 = r // 20; r -= n20 * 20
        n10 = r // 10
        DB.setdefault("pions_joueurs", {})[c] = {
            "100": n100,
            "50": n50,
            "20": n20,
            "10": n10,
        }

    # Valeur injectée par l'ADMIN vers chaque code bloqué
    injecte = {}  # code -> {"credits": int, "transferts": int}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            code = (c.get("code_joueur") or "").upper()
            if code in bloques:
                m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
                if m > 0:
                    injecte.setdefault(code, {"credits": 0, "transferts": 0})["credits"] += m
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            for code in (c.get("codes") or []):
                code = (code or "").upper()
                if code in bloques:
                    m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
                    if m > 0:
                        injecte.setdefault(code, {"credits": 0, "transferts": 0})["credits"] += m
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and t.get("admin"):
            code = (t.get("vers") or "").upper()
            if code in bloques:
                injecte.setdefault(code, {"credits": 0, "transferts": 0})["transferts"] += int(t.get("montant", 0) or 0)

    # Calcul de ce qui sera retiré (plafonné au solde actuel, jamais négatif)
    plan = []
    total_inj = total_retire = 0
    for code, d in injecte.items():
        inj = d["credits"] + d["transferts"]
        s = solde(code)
        retire = min(inj, s)
        total_inj += inj; total_retire += retire
        plan.append((code, d["credits"], d["transferts"], s, retire))
    plan.sort(key=lambda x: -x[4])

    if confirme and plan:
        for code, cr, tr, s, retire in plan:
            if retire > 0:
                poser_solde(code, s - retire)
        DB.setdefault("annulations_credits_fraude", []).insert(0, {
            "id": secrets.token_hex(4).upper(),
            "total_retire": total_retire, "nb_codes": len([p for p in plan if p[4] > 0]),
            "par": cle, "date": datetime.datetime.now().isoformat()
        })
        save_data(immediat=True)

    rows = ""
    for code, cr, tr, s, retire in plan:
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:8px;font-family:monospace;color:#a78bfa">{code}</td>'
                 f'<td style="padding:8px;text-align:right;color:#fbbf24">{format(cr, ",")} F</td>'
                 f'<td style="padding:8px;text-align:right;color:#93c5fd">{format(tr, ",")} F</td>'
                 f'<td style="padding:8px;text-align:right;color:#34d399">{format(s, ",")} F</td>'
                 f'<td style="padding:8px;text-align:right;color:#f87171;font-weight:700">−{format(retire, ",")} F</td>'
                 f'<td style="padding:8px;text-align:right;color:#cbd5e1">{format(s - retire, ",")} F</td></tr>')
    if not rows:
        rows = '<tr><td colspan="6" style="padding:16px;text-align:center;color:#34d399">Aucun crédit admin sur un compte bloqué. Rien à annuler. ✅</td></tr>'

    if confirme:
        banniere = (f'<div style="background:rgba(16,185,129,.15);border:2px solid #10b981;border-radius:10px;padding:14px;margin-bottom:14px;color:#34d399;font-weight:800;font-size:15px">'
                    f'✅ FAIT — {format(total_retire, ",")} XPF retirés des comptes frauduleux. Valeur fabriquée neutralisée.</div>')
    else:
        lien_ok = f"/annuler-credits-fraude?cle={cle}&confirme=1"
        banniere = (f'<div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:14px">'
                    f'<div style="color:#fde68a;font-weight:700;margin-bottom:6px">👁️ APERÇU — rien n\'est encore modifié</div>'
                    f'<div style="color:#94a3b8;font-size:13px;margin-bottom:10px">Va retirer <b style="color:#f87171">{format(total_retire, ",")} XPF</b> des comptes <b>bloqués</b> uniquement (plafonné à leur solde, jamais en négatif). Les comptes sains ne sont PAS touchés.</div>'
                    f'<a href="{lien_ok}" style="display:inline-block;background:#ef4444;color:#fff;padding:12px 20px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer l\'annulation</a></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Annuler crédits fraude</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:10px">↩️ Annuler les crédits admin vers les comptes frauduleux</h1>
      {banniere}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:620px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:8px;color:#fca5a5">Code bloqué</th><th style="padding:8px;color:#fca5a5;text-align:right">Recrédits admin</th><th style="padding:8px;color:#fca5a5;text-align:right">Transferts admin</th><th style="padding:8px;color:#fca5a5;text-align:right">Solde actuel</th><th style="padding:8px;color:#fca5a5;text-align:right">À retirer</th><th style="padding:8px;color:#fca5a5;text-align:right">Nouveau solde</th></tr>
      {rows}</table></div>
      <div style="color:#94a3b8;font-size:12px;margin-top:10px">« À retirer » = ce que l'admin a injecté, plafonné au solde actuel (on ne descend jamais sous 0). Le reste du solde (achats réels du fraudeur) reste gelé sur le compte bloqué.</div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/bilan-bloques")
def bilan_bloques():
    """ADMIN — Bilan : liste des comptes BLOQUÉS reliée à l'audit (solde actuel,
    total recrédité par l'admin, pions reçus/envoyés par transfert). ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    bloques = sorted(DB.get("codes_bloques", []))

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    def nom_de(c):
        return DB.get("codes", {}).get(c, {}).get("nom", "") or ""

    # Pré-calcul recrédits admin par code
    cred = {}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            code = (c.get("code_joueur") or "").upper()
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0: cred[code] = cred.get(code, 0) + m
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            for code in (c.get("codes") or []):
                code = (code or "").upper()
                if m > 0: cred[code] = cred.get(code, 0) + m
    recu = {}; envoye = {}
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            v = (t.get("vers") or "").upper(); d = (t.get("de") or "").upper()
            m = int(t.get("montant", 0) or 0)
            if v: recu[v] = recu.get(v, 0) + m
            if d: envoye[d] = envoye.get(d, 0) + m

    rows = ""
    t_solde = t_cred = t_recu = t_env = 0
    for c in sorted(bloques, key=lambda x: -solde(x)):
        s = solde(c); cr = cred.get(c, 0); rc = recu.get(c, 0); en = envoye.get(c, 0)
        t_solde += s; t_cred += cr; t_recu += rc; t_env += en
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:7px;color:#94a3b8;font-size:12px">{nom_de(c)}</td>'
                 f'<td style="padding:7px;text-align:right;color:#34d399;font-weight:600">{format(s, ",")} F</td>'
                 f'<td style="padding:7px;text-align:right;color:#f87171">{format(cr, ",")} F</td>'
                 f'<td style="padding:7px;text-align:right;color:#6ee7b7">{format(rc, ",")} F</td>'
                 f'<td style="padding:7px;text-align:right;color:#fca5a5">{format(en, ",")} F</td></tr>')
    if not rows:
        rows = '<tr><td colspan="6" style="padding:16px;text-align:center;color:#34d399">Aucun code bloqué.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Bilan comptes bloqués</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:900px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:10px">🔒 Bilan des comptes bloqués (relié à l'audit)</h1>
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">Comptes bloqués</div><div style="color:#f87171;font-size:18px;font-weight:700">{len(bloques)}</div></div>
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">💚 Solde gelé restant</div><div style="color:#34d399;font-size:18px;font-weight:700">{format(t_solde, ",")} F</div></div>
        <div style="background:rgba(239,68,68,.12);border:1px solid #f87171;border-radius:8px;padding:10px 14px"><div style="color:#94a3b8;font-size:12px">🔧 Total recrédité (admin)</div><div style="color:#f87171;font-size:18px;font-weight:700">{format(t_cred, ",")} F</div></div>
      </div>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:10px">« Recrédité admin » = ce que l'admin a injecté en tout (même si déjà retiré/circulé). « Reçu/Envoyé » = pions déplacés par transferts. Tout est gelé.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:620px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:7px;color:#fca5a5">Code</th><th style="padding:7px;color:#fca5a5">Nom</th><th style="padding:7px;color:#fca5a5;text-align:right">Solde actuel</th><th style="padding:7px;color:#fca5a5;text-align:right">Recrédité admin</th><th style="padding:7px;color:#fca5a5;text-align:right">Reçu (transf.)</th><th style="padding:7px;color:#fca5a5;text-align:right">Envoyé (transf.)</th></tr>
      {rows}
      <tr style="border-top:2px solid #7f1d1d;font-weight:700"><td style="padding:8px" colspan="2">TOTAUX</td><td style="padding:8px;text-align:right;color:#34d399">{format(t_solde, ",")} F</td><td style="padding:8px;text-align:right;color:#f87171">{format(t_cred, ",")} F</td><td style="padding:8px;text-align:right;color:#6ee7b7">{format(t_recu, ",")} F</td><td style="padding:8px;text-align:right;color:#fca5a5">{format(t_env, ",")} F</td></tr>
      </table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/preuve-code")
def preuve_code():
    """ADMIN — Fiche de PREUVE imprimable pour un code frauduleux : identité,
    connexions (IP/appareils), transferts, crédits admin, achats, retraits, et
    faisceau d'indices. Sans &code : liste tous les bloqués. ?cle=ADMIN[&code=X]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    bloques = set(DB.get("codes_bloques", []))

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    # ---- LISTE (pas de code) ----
    if not code:
        items = ""
        for c in sorted(bloques):
            items += f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)"><td style="padding:8px;font-family:monospace;color:#a78bfa">{c}</td><td style="padding:8px;text-align:right;color:#34d399">{format(solde(c), ",")} F</td><td style="padding:8px"><a href="/preuve-code?cle={cle}&code={c}" style="color:#fde68a;font-weight:700;text-decoration:none">📄 Fiche de preuve →</a></td></tr>'
        if not items:
            items = '<tr><td colspan="3" style="padding:16px;color:#94a3b8">Aucun code bloqué.</td></tr>'
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Fiches de preuve</title></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto">
        <h1 style="font-size:20px;color:#f87171">📄 Fiches de preuve — {len(bloques)} comptes bloqués</h1>
        <div style="color:#94a3b8;font-size:13px;margin-bottom:12px">Clique sur un code pour générer sa fiche de preuve imprimable.</div>
        <table style="width:100%;border-collapse:collapse;font-size:14px"><tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:8px;color:#fca5a5">Code</th><th style="padding:8px;color:#fca5a5;text-align:right">Solde gelé</th><th style="padding:8px;color:#fca5a5">Preuve</th></tr>{items}</table>
        </div></body></html>''', mimetype="text/html; charset=utf-8")

    # ---- FICHE D'UN CODE ----
    jc = [x for x in DB.get("journal_connexions", []) if isinstance(x, dict) and (x.get("code") or "").upper() == code]
    ips = sorted(set(x.get("ip") for x in jc if x.get("ip")))
    devices = sorted(set((x.get("user_agent") or "")[:70] for x in jc if x.get("user_agent")))
    noms = sorted(set(x.get("nom") for x in jc if x.get("nom")))

    transf = [t for t in DB.get("transferts_pions", []) if isinstance(t, dict) and ((t.get("de") or "").upper() == code or (t.get("vers") or "").upper() == code)]
    for t in transf:
        if t.get("ip"): ips.append(t.get("ip"))
    ips = sorted(set(ips))
    transf.sort(key=lambda t: str(t.get("date", "")))

    creds = [c for c in DB.get("credits_admin", []) if isinstance(c, dict) and (c.get("code_joueur") or "").upper() == code]
    achats = [c for c in DB.get("commandes_pions_joueurs", []) if isinstance(c, dict) and (c.get("code_joueur") or "").upper() == code and c.get("statut") == "validee"]
    retraits = [r for r in DB.get("demandes_retrait", []) if isinstance(r, dict) and (r.get("code_joueur") or "").upper() == code]

    # Faisceau d'indices
    indices = []
    # partage IP avec d'autres bloqués
    autres_partage = set()
    for x in DB.get("journal_connexions", []):
        if isinstance(x, dict) and x.get("ip") in ips and (x.get("code") or "").upper() != code and (x.get("code") or "").upper() in bloques:
            autres_partage.add((x.get("code") or "").upper())
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and t.get("ip") in ips:
            for cc in [(t.get("de") or "").upper(), (t.get("vers") or "").upper()]:
                if cc and cc != code and cc in bloques:
                    autres_partage.add(cc)
    if autres_partage:
        indices.append(f"Partage une ou plusieurs adresses IP avec {len(autres_partage)} autre(s) compte(s) frauduleux : {', '.join(sorted(autres_partage))}.")
    env = sum(int(t.get('montant', 0) or 0) for t in transf if (t.get('de') or '').upper() == code)
    rec = sum(int(t.get('montant', 0) or 0) for t in transf if (t.get('vers') or '').upper() == code)
    if env: indices.append(f"A envoyé {format(env, ',')} XPF de pions par transfert vers d'autres comptes (concentration vers collecteurs).")
    if rec: indices.append(f"A reçu {format(rec, ',')} XPF de pions par transfert depuis d'autres comptes.")
    tot_cred = sum(int(c.get('nb_pions', 0) or 0) * int(c.get('valeur_pion', 0) or 0) for c in creds if int(c.get('nb_pions', 0) or 0) * int(c.get('valeur_pion', 0) or 0) > 0)
    if tot_cred: indices.append(f"A bénéficié de {format(tot_cred, ',')} XPF de recrédits administratifs (écarts simulés).")
    tot_achat = sum(int(c.get('nb_pions', 0) or 0) * int(c.get('valeur_pion', 0) or 0) or int(c.get('montant_net', 0) or 0) for c in achats)
    ret_att = sum(int(r.get('montant_demande', 0) or 0) for r in retraits if r.get('statut') in (None, '', 'en_attente'))
    ret_val = sum(int(r.get('montant_demande', 0) or 0) for r in retraits if r.get('statut') == 'validee')
    if ret_att: indices.append(f"A tenté de retirer {format(ret_att, ',')} XPF en argent réel (demande EN ATTENTE, bloquée).")
    if ret_val: indices.append(f"A obtenu {format(ret_val, ',')} XPF de retrait validé.")

    def tr(cells):
        return '<tr>' + ''.join(f'<td style="border:1px solid #ccc;padding:5px">{c}</td>' for c in cells) + '</tr>'
    t_transf = ''.join(tr([str(t.get('date', ''))[:16].replace('T', ' '),
                           '➡️ envoyé' if (t.get('de') or '').upper() == code else '⬅️ reçu',
                           (t.get('vers') if (t.get('de') or '').upper() == code else t.get('de')) or '',
                           format(int(t.get('montant', 0) or 0), ','),
                           t.get('ip', '') or ('admin ' + str(t.get('par', '')) if t.get('admin') else '')]) for t in transf) or '<tr><td colspan="5" style="border:1px solid #ccc;padding:6px">Aucun transfert.</td></tr>'
    t_cred = ''.join(tr([str(c.get('date', ''))[:16].replace('T', ' '), format(int(c.get('nb_pions', 0) or 0) * int(c.get('valeur_pion', 0) or 0), ','), c.get('par', '')]) for c in creds) or '<tr><td colspan="3" style="border:1px solid #ccc;padding:6px">Aucun.</td></tr>'
    t_retr = ''.join(tr([str(r.get('date', ''))[:16].replace('T', ' '), format(int(r.get('montant_demande', 0) or 0), ','), r.get('statut', 'en_attente')]) for r in retraits) or '<tr><td colspan="3" style="border:1px solid #ccc;padding:6px">Aucune.</td></tr>'
    ind_html = ''.join(f'<li style="margin:4px 0">{i}</li>' for i in indices) or '<li>—</li>'
    import datetime as _dt
    maintenant = _dt.datetime.now().strftime("%d/%m/%Y à %H:%M")

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Preuve {code}</title>
    <style>@media print{{.noprint{{display:none}}}} body{{background:#fff;color:#111;font-family:Georgia,serif;line-height:1.5}} h1{{font-size:19px}} h2{{font-size:14px;border-bottom:2px solid #111;padding-bottom:2px;margin-top:20px}} table{{border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:11px;margin:6px 0}} th{{border:1px solid #ccc;padding:5px;background:#f0f0f0;text-align:left}}</style></head>
    <body style="margin:0;padding:22px"><div style="max-width:760px;margin:0 auto">
      <button onclick="window.print()" class="noprint" style="background:#111;color:#fff;border:0;padding:9px 16px;border-radius:6px;font-size:13px;cursor:pointer;margin-bottom:14px">🖨️ Imprimer / PDF</button>
      <a href="/preuve-code?cle={cle}" class="noprint" style="margin-left:8px;color:#555;font-size:13px">← Tous les codes</a>
      <h1>FICHE DE PREUVE — COMPTE FRAUDULEUX</h1>
      <p style="font-size:12px;color:#444">Plateforme Ticket Bingo — EI TUKEA IMPORT (N° Tahiti B90121), Papeete. Document généré le {maintenant}.</p>
      <h2>Identité du compte</h2>
      <p style="font-size:13px">Code : <b>{code}</b> · Nom enregistré : {', '.join(noms) if noms else '— (anonyme)'} · Statut : <b>BLOQUÉ</b> · Solde gelé actuel : <b>{format(solde(code), ',')} XPF</b></p>
      <h2>Faisceau d'indices de fraude</h2>
      <ul style="font-size:13px">{ind_html}</ul>
      <h2>Adresses IP & appareils de connexion</h2>
      <p style="font-size:12px">IP : {', '.join(ips) if ips else '—'}<br>Appareils : {'; '.join(devices) if devices else '—'}</p>
      <h2>Transferts de pions</h2>
      <table><tr><th>Date</th><th>Sens</th><th>Autre compte</th><th>Montant (XPF)</th><th>IP / origine</th></tr>{t_transf}</table>
      <h2>Recrédits administratifs reçus</h2>
      <table><tr><th>Date</th><th>Montant (XPF)</th><th>Par</th></tr>{t_cred}</table>
      <h2>Demandes de retrait (argent réel)</h2>
      <table><tr><th>Date</th><th>Montant demandé (XPF)</th><th>Statut</th></tr>{t_retr}</table>
      <p style="font-size:12px;color:#444;margin-top:16px">Achats réels de pions par ce compte : {format(tot_achat, ',')} XPF. Les journaux techniques horodatés sont conservés et communicables à l'autorité judiciaire sur réquisition.</p>
      <p style="font-size:12px;margin-top:18px">Fait à Papeete, le {maintenant}. Signature : ____________________</p>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/neutraliser-debloquer")
def neutraliser_debloquer():
    """ADMIN — En sécurité : (1) rejette les retraits frauduleux en attente,
    (2) remet à zéro les pions des comptes bloqués, (3) débloque. Aperçu d'abord ;
    rien sans &confirme=1. ?cle=ADMIN[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    confirme = request.args.get("confirme", "") == "1"
    bloques = list(DB.get("codes_bloques", []))

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    def bonus(c):
        p = DB.get("pions_bonus_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    # Ce qui sera fait
    total_pions = sum(solde(c) + bonus(c) for c in bloques)
    retr_att = []
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict) and (r.get("code_joueur") or "").upper() in [b.upper() for b in bloques] and r.get("statut") in (None, "", "en_attente"):
            retr_att.append(r)
    total_retr = sum(int(r.get("montant_demande", 0) or 0) for r in retr_att)

    if confirme:
        # 1. Rejeter les retraits en attente des comptes bloqués
        for r in DB.get("demandes_retrait", []):
            if isinstance(r, dict) and (r.get("code_joueur") or "").upper() in [b.upper() for b in bloques] and r.get("statut") in (None, "", "en_attente"):
                r["statut"] = "rejete_fraude"
        # 2. Remettre à zéro les pions (réels + bonus)
        for c in bloques:
            DB.setdefault("pions_joueurs", {})[c] = {}
            if c in DB.get("pions_bonus_joueurs", {}):
                DB["pions_bonus_joueurs"][c] = {}
        # 3. Débloquer
        DB["codes_bloques"] = []
        DB.setdefault("neutralisations_fraude", []).insert(0, {
            "id": secrets.token_hex(4).upper(), "nb_comptes": len(bloques),
            "pions_remis_zero": total_pions, "retraits_rejetes": total_retr,
            "par": cle, "date": datetime.datetime.now().isoformat()
        })
        save_data(immediat=True)
        return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
        <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:720px;margin:0 auto">
        <div style="background:rgba(16,185,129,.15);border:2px solid #10b981;border-radius:10px;padding:18px;color:#34d399">
        <h1 style="font-size:20px;margin:0 0 10px">✅ Terminé — en sécurité</h1>
        <ul style="font-size:14px;line-height:1.8;color:#e6edf3">
        <li>🚫 <b>{format(total_retr, ",")} XPF</b> de retraits frauduleux <b>rejetés</b></li>
        <li>🧹 <b>{format(total_pions, ",")} XPF</b> de pions fabriqués <b>remis à zéro</b></li>
        <li>🔓 <b>{len(bloques)}</b> comptes <b>débloqués</b> (solde 0 → inoffensifs)</li>
        <li>📄 Ils affichent maintenant « <b>Solde antérieur</b> » comme les bons joueurs</li>
        </ul>
        <div style="color:#94a3b8;font-size:13px;margin-top:8px">Les transferts et IP restent visibles sur leurs relevés (traçage conservé). Action tracée.</div>
        </div></div></body></html>''', mimetype="text/html; charset=utf-8")

    # APERÇU
    rows = ""
    for c in sorted(bloques, key=lambda x: -(solde(x)+bonus(x))):
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:7px;text-align:right;color:#34d399">{format(solde(c)+bonus(c), ",")} F</td></tr>')
    if not rows:
        rows = '<tr><td colspan="2" style="padding:14px;color:#94a3b8">Aucun compte bloqué.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Neutraliser puis débloquer</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:760px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:10px">🛡️ Neutraliser puis débloquer — APERÇU</h1>
      <div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:14px">
        <div style="color:#fde68a;font-weight:700;margin-bottom:6px">👁️ Rien n'est encore modifié. Voici ce qui sera fait :</div>
        <ul style="color:#e6edf3;font-size:14px;line-height:1.8;margin:0">
          <li>🚫 Rejeter <b>{format(total_retr, ",")} XPF</b> de retraits en attente ({len(retr_att)} demandes)</li>
          <li>🧹 Remettre à zéro <b>{format(total_pions, ",")} XPF</b> de pions sur <b>{len(bloques)}</b> comptes</li>
          <li>🔓 Débloquer ces {len(bloques)} comptes (devenus inoffensifs, solde 0)</li>
        </ul>
      </div>
      <a href="/neutraliser-debloquer?cle={cle}&confirme=1" style="display:inline-block;background:#ef4444;color:#fff;padding:13px 22px;border-radius:10px;text-decoration:none;font-weight:800;font-size:15px;margin-bottom:14px">✅ Confirmer (neutraliser + débloquer)</a>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:360px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Compte bloqué</th><th style="padding:7px;color:#a78bfa;text-align:right">Pions à remettre à 0</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/tous-releves")
def tous_releves():
    """ADMIN — Tableau récap de TOUS les joueurs : solde, transferts reçus/émis,
    recrédits admin, + lien vers le relevé détaillé de chacun. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    codes_non_joueurs = set(k for k, v in DB.get("codes", {}).items() if isinstance(v, dict))
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10

    # Noms depuis tickets
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Agrégats transferts / crédits
    t_recu = {}; t_emis = {}
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            v = (t.get("vers") or "").upper(); d = (t.get("de") or "").upper(); m = int(t.get("montant", 0) or 0)
            if v: t_recu[v] = t_recu.get(v, 0) + m
            if d: t_emis[d] = t_emis.get(d, 0) + m
    cred = {}
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            code = (c.get("code_joueur") or "").upper()
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            if m > 0: cred[code] = cred.get(code, 0) + m

    # Tous les codes joueurs
    joueurs = set()
    for k in ["pions_joueurs", "tickets_acheteurs"]:
        d = DB.get(k, {})
        if isinstance(d, dict): joueurs.update(x.upper() for x in d.keys())
    joueurs |= set(t_recu) | set(t_emis) | set(cred)
    joueurs = [c for c in joueurs if c and c not in codes_non_joueurs]

    bloques = set(DB.get("codes_bloques", []))
    joueurs.sort(key=lambda c: -solde(c))

    rows = ""; t_s = t_r = t_e = t_c = 0
    for c in joueurs:
        s = solde(c); rc = t_recu.get(c, 0); em = t_emis.get(c, 0); cr = cred.get(c, 0)
        t_s += s; t_r += rc; t_e += em; t_c += cr
        flag = ' 🔒' if c in bloques else (' ⚠️' if (rc or em) else '')
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{c}{flag}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{noms.get(c, "")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#34d399">{format(s, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#6ee7b7">{format(rc, ",") if rc else "-"}</td>'
                 f'<td style="padding:6px;text-align:right;color:#fca5a5">{format(em, ",") if em else "-"}</td>'
                 f'<td style="padding:6px;text-align:right;color:#fbbf24">{format(cr, ",") if cr else "-"}</td>'
                 f'<td style="padding:6px"><a href="/releve-financier-joueur/{c}?cle={cle}" target="_blank" style="color:#58a6ff;text-decoration:none">relevé →</a></td></tr>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Tous les relevés</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:960px;margin:0 auto">
      <h1 style="font-size:21px;color:#a855f7;margin-bottom:6px">📒 Tous les relevés joueurs ({len(joueurs)})</h1>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">🔒 = compte ex-bloqué · ⚠️ = a fait des transferts · Clique « relevé » pour le détail complet d'un joueur.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px;min-width:680px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:6px;color:#a78bfa">Code</th><th style="padding:6px;color:#a78bfa">Nom</th><th style="padding:6px;color:#a78bfa;text-align:right">Solde</th><th style="padding:6px;color:#a78bfa;text-align:right">Transf. reçus</th><th style="padding:6px;color:#a78bfa;text-align:right">Transf. émis</th><th style="padding:6px;color:#a78bfa;text-align:right">Recréd. admin</th><th style="padding:6px;color:#a78bfa">Détail</th></tr>
      {rows}
      <tr style="border-top:2px solid #3730a3;font-weight:700"><td style="padding:7px" colspan="2">TOTAUX</td><td style="padding:7px;text-align:right;color:#34d399">{format(t_s, ",")}</td><td style="padding:7px;text-align:right;color:#6ee7b7">{format(t_r, ",")}</td><td style="padding:7px;text-align:right;color:#fca5a5">{format(t_e, ",")}</td><td style="padding:7px;text-align:right;color:#fbbf24">{format(t_c, ",")}</td><td></td></tr>
      </table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/codes-relies")
def codes_relies():
    """ADMIN — Liste TOUS les codes reliés à un code donné : par transfert (preuve)
    et par IP partagée (indice). Imprimable pour notes/dossier. ?cle=ADMIN&code=X"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    code = (request.args.get("code", "") or "").strip().upper()
    if not code:
        return Response("Ajoute &code=LE_CODE a verifier.", status=400, mimetype="text/plain; charset=utf-8")

    bloques = set(DB.get("codes_bloques", []))
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # IP du code
    mes_ips = set()
    for x in DB.get("journal_connexions", []):
        if isinstance(x, dict) and (x.get("code") or "").upper() == code and x.get("ip"):
            mes_ips.add(x.get("ip"))
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and t.get("ip") and ((t.get("de") or "").upper() == code or (t.get("vers") or "").upper() == code):
            mes_ips.add(t.get("ip"))

    # Liens par TRANSFERT (preuve solide)
    liens_transf = {}  # autre_code -> montant total échangé
    for t in DB.get("transferts_pions", []):
        if not isinstance(t, dict):
            continue
        de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper(); m = int(t.get("montant", 0) or 0)
        if de == code and vers:
            liens_transf[vers] = liens_transf.get(vers, 0) + m
        elif vers == code and de:
            liens_transf[de] = liens_transf.get(de, 0) + m

    # Liens par IP partagée (indice)
    liens_ip = set()
    for x in DB.get("journal_connexions", []):
        if isinstance(x, dict) and x.get("ip") in mes_ips and (x.get("code") or "").upper() not in ("", code):
            liens_ip.add((x.get("code") or "").upper())
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict) and t.get("ip") in mes_ips:
            for cc in [(t.get("de") or "").upper(), (t.get("vers") or "").upper()]:
                if cc and cc != code:
                    liens_ip.add(cc)

    tous = set(liens_transf) | liens_ip
    def lien_type(c):
        t = c in liens_transf; i = c in liens_ip
        if t and i: return ("💸🌐", "Transfert + IP")
        if t: return ("💸", "Transfert")
        return ("🌐", "IP partagée")
    # tri : transferts d'abord, puis IP
    ordre = sorted(tous, key=lambda c: (0 if c in liens_transf else 1, -liens_transf.get(c, 0), c))

    rows = ""
    for c in ordre:
        ic, lbl = lien_type(c)
        mt = liens_transf.get(c, 0)
        rows += ('<tr>'
                 f'<td style="border:1px solid #ccc;padding:6px;font-family:monospace"><b>{c}</b>{" 🔒" if c in bloques else ""}</td>'
                 f'<td style="border:1px solid #ccc;padding:6px">{noms.get(c, "")}</td>'
                 f'<td style="border:1px solid #ccc;padding:6px">{ic} {lbl}</td>'
                 f'<td style="border:1px solid #ccc;padding:6px;text-align:right">{format(mt, ",") + " F" if mt else "—"}</td>'
                 f'<td style="border:1px solid #ccc;padding:6px;text-align:right">{format(solde(c), ",")} F</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="border:1px solid #ccc;padding:8px">Aucun code relié trouvé.</td></tr>'

    import datetime as _dt
    maintenant = _dt.datetime.now().strftime("%d/%m/%Y à %H:%M")
    nb_t = len(liens_transf); nb_i = len(liens_ip - set(liens_transf))
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Codes reliés à {code}</title>
    <style>@media print{{.noprint{{display:none}}}} body{{background:#fff;color:#111;font-family:Arial,sans-serif}} table{{border-collapse:collapse;width:100%;font-size:12px;margin-top:8px}} th{{border:1px solid #ccc;padding:6px;background:#f0f0f0;text-align:left}}</style></head>
    <body style="margin:0;padding:22px"><div style="max-width:780px;margin:0 auto">
      <button onclick="window.print()" class="noprint" style="background:#111;color:#fff;border:0;padding:9px 16px;border-radius:6px;cursor:pointer;margin-bottom:12px">🖨️ Imprimer / PDF</button>
      <h1 style="font-size:19px">Codes reliés au code <span style="font-family:monospace">{code}</span>{" (TATIE LAHAYNA)" if False else ""}</h1>
      <p style="font-size:12px;color:#444">Plateforme Ticket Bingo — EI TUKEA IMPORT (N° Tahiti B90121). Généré le {maintenant}.<br>
      Code analysé : <b>{code}</b>{(" — " + noms.get(code)) if noms.get(code) else ""} · Solde : {format(solde(code), ",")} F · IP : {", ".join(sorted(mes_ips)) if mes_ips else "—"}</p>
      <p style="font-size:13px"><b>{len(tous)} codes reliés</b> au total : <b>{nb_t}</b> par transfert (preuve), <b>{nb_i}</b> par IP partagée seule (indice).</p>
      <table><tr><th>Code relié</th><th>Nom</th><th>Type de lien</th><th>Pions échangés</th><th>Solde actuel</th></tr>{rows}</table>
      <p style="font-size:11px;color:#666;margin-top:10px">💸 Transfert = pions réellement échangés entre les comptes (lien fort). 🌐 IP partagée = même adresse de connexion (indice ; peut aussi être un wifi commun). 🔒 = compte ex-bloqué.</p>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/clients-bascule")
def clients_bascule():
    """ADMIN — Clients ayant joué chez une 1re organisatrice PUIS basculé vers une autre.
    Par défaut : HEINI -> MAEVA. ?cle=ADMIN[&de=CODE_ORG&vers=CODE_ORG]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    # Organisatrices par défaut : HEINI -> MAEVA (modifiable via &de= et &vers=)
    de = (request.args.get("de", "") or "").strip().upper()
    vers = (request.args.get("vers", "") or "").strip().upper()
    if not de or not vers:
        # retrouver par nom si non fourni
        for c, v in DB.get("codes", {}).items():
            nm = (v.get("nom", "") or "").upper()
            if not de and "HEINI" in nm: de = c
            if not vers and "MAEVA" in nm and not v.get("admin"): vers = c
    nom_de = DB.get("codes", {}).get(de, {}).get("nom", de) or de
    nom_vers = DB.get("codes", {}).get(vers, {}).get("nom", vers) or vers

    # Construire l'historique org par joueur : (date, code_org)
    hist = {}
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("code_org"):
            cj = (t.get("code_acheteur") or "").upper()
            hist.setdefault(cj, []).append((str(t.get("date", "")), (t.get("code_org") or "").upper()))
            if t.get("acheteur"): noms[cj] = t.get("acheteur")
    for tr in DB.get("transactions_joueur_org", []):
        if isinstance(tr, dict) and tr.get("code_joueur") and tr.get("code_org"):
            cj = (tr.get("code_joueur") or "").upper()
            hist.setdefault(cj, []).append((str(tr.get("date", "")), (tr.get("code_org") or "").upper()))

    rows = ""; nb = 0
    for cj, evts in hist.items():
        evts.sort(key=lambda x: x[0])
        orgs_seq = [o for (_d, o) in evts]
        if de in orgs_seq and vers in orgs_seq:
            # 1re date chez 'de' et 1re date chez 'vers'
            d_de = next((d for (d, o) in evts if o == de), "")
            d_vers = next((d for (d, o) in evts if o == vers), "")
            if d_de and d_vers and d_de <= d_vers:
                nb += 1
                rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                         f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{cj}</td>'
                         f'<td style="padding:7px;color:#cbd5e1">{noms.get(cj, "")}</td>'
                         f'<td style="padding:7px;color:#6ee7b7;font-size:12px">{d_de[:10]}</td>'
                         f'<td style="padding:7px;color:#fbbf24;font-size:12px">{d_vers[:10]}</td></tr>')
    if not rows:
        rows = f'<tr><td colspan="4" style="padding:14px;color:#94a3b8">Aucun client trouvé ayant basculé de {nom_de} vers {nom_vers}.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Clients basculés</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:760px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin-bottom:6px">🔄 Clients ayant basculé : {nom_de} → {nom_vers}</h1>
      <div style="color:#94a3b8;font-size:13px;margin-bottom:6px">Joueurs ayant d'abord joué chez <b>{nom_de}</b> ({de}) puis chez <b>{nom_vers}</b> ({vers}). <b>{nb}</b> client(s).</div>
      <div style="color:#6e7681;font-size:11px;margin-bottom:12px">⚠️ Les toutes anciennes parties {nom_de} (sans relevé détaillé) peuvent ne pas toutes figurer ; on se base sur les tickets et transactions enregistrés.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:480px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Code</th><th style="padding:7px;color:#a78bfa">Nom</th><th style="padding:7px;color:#a78bfa">1re activité {nom_de}</th><th style="padding:7px;color:#a78bfa">1re activité {nom_vers}</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/demarrage-org")
def demarrage_org():
    """ADMIN — Date de démarrage et d'activité d'une organisatrice (1re et dernière
    activité dans tickets, transactions, gains de tournois). ?cle=ADMIN[&org=CODE]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    org = (request.args.get("org", "") or "").strip().upper()
    if not org:
        for c, v in DB.get("codes", {}).items():
            if "MAEVA" in (v.get("nom", "") or "").upper() and not v.get("admin"):
                org = c; break
    nom_org = DB.get("codes", {}).get(org, {}).get("nom", org) or org

    sources = {
        "Tickets vendus": [("tickets", "code_org", "date", "code_acheteur")],
        "Transactions joueuses": [("transactions_joueur_org", "code_org", "date", "code_joueur")],
        "Gains de tournois": [("gains_finaux", "code_org", "date", "code")],
        "Achats de pions": [("commandes_pions_joueurs", "code_org", "date", "code_joueur")],
    }
    lignes = ""
    glob_min = None; glob_max = None
    for label, defs in sources.items():
        key, ko, kd, kj = defs[0]
        dates = []; joueurs = set()
        for x in DB.get(key, []):
            if isinstance(x, dict) and (x.get(ko) or "").upper() == org:
                d = str(x.get(kd, "") or "")
                if d: dates.append(d)
                if x.get(kj): joueurs.add((x.get(kj) or "").upper())
        if dates:
            dmin = min(dates); dmax = max(dates)
            glob_min = dmin if glob_min is None or dmin < glob_min else glob_min
            glob_max = dmax if glob_max is None or dmax > glob_max else glob_max
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                       f'<td style="padding:7px;color:#cbd5e1">{label}</td>'
                       f'<td style="padding:7px;text-align:right;color:#6ee7b7">{dmin[:16].replace("T", " ")}</td>'
                       f'<td style="padding:7px;text-align:right;color:#fbbf24">{dmax[:16].replace("T", " ")}</td>'
                       f'<td style="padding:7px;text-align:right;color:#a78bfa">{len(dates)}</td>'
                       f'<td style="padding:7px;text-align:right;color:#93c5fd">{len(joueurs)}</td></tr>')
        else:
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                       f'<td style="padding:7px;color:#6e7681">{label}</td>'
                       f'<td colspan="4" style="padding:7px;color:#6e7681">aucune donnée</td></tr>')

    demarrage = glob_min[:16].replace("T", " ") if glob_min else "—"
    derniere = glob_max[:16].replace("T", " ") if glob_max else "—"
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Démarrage {nom_org}</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:760px;margin:0 auto">
      <h1 style="font-size:20px;color:#a855f7;margin-bottom:10px">📅 Activité de {nom_org} ({org})</h1>
      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:14px">
        <div style="background:rgba(16,185,129,.12);border:1px solid #10b981;border-radius:8px;padding:12px 16px"><div style="color:#94a3b8;font-size:12px">🚀 Tout premier tournoi / activité</div><div style="color:#34d399;font-size:18px;font-weight:700">{demarrage}</div></div>
        <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:12px 16px"><div style="color:#94a3b8;font-size:12px">Dernière activité</div><div style="color:#fbbf24;font-size:18px;font-weight:700">{derniere}</div></div>
      </div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:520px">
      <tr style="border-bottom:2px solid #3730a3;text-align:left"><th style="padding:7px;color:#a78bfa">Source</th><th style="padding:7px;color:#a78bfa;text-align:right">Première</th><th style="padding:7px;color:#a78bfa;text-align:right">Dernière</th><th style="padding:7px;color:#a78bfa;text-align:right">Nb</th><th style="padding:7px;color:#a78bfa;text-align:right">Joueurs</th></tr>
      {lignes}</table></div>
      <div style="color:#6e7681;font-size:11px;margin-top:10px">La date de démarrage = la toute première activité enregistrée de cette organisatrice, toutes sources confondues.</div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/compte-fraude")
def compte_fraude():
    """ADMIN — Compte combien de comptes sont considérés comme fraude (= ayant fait
    des transferts de pions entre comptes), avec la liste. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    codes_staff = set(DB.get("codes", {}).keys())
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Comptes liés par transfert : on compte les LIENS distincts par compte
    liens_par_code = {}
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper()
            if de and vers:
                if de not in codes_staff:
                    liens_par_code.setdefault(de, set()).add(vers)
                if vers not in codes_staff:
                    liens_par_code.setdefault(vers, set()).add(de)
    # Fraude = lié à 2+ AUTRES comptes (réseau de 3 codes ou +). 2 codes (HEINI+MAEVA) = normal.
    fraude = set(c for c, liens in liens_par_code.items() if len(liens) >= 2)
    bloques = set(DB.get("codes_bloques", []))

    rows = ""
    for c in sorted(fraude, key=lambda x: -solde(x)):
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{c}{" 🔒" if c in bloques else ""}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{noms.get(c, "")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#34d399">{format(solde(c), ",")} F</td></tr>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Comptes fraude</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:680px;margin:0 auto">
      <h1 style="font-size:21px;color:#f87171;margin-bottom:8px">🚨 Comptes considérés comme fraude</h1>
      <div style="background:rgba(239,68,68,.12);border:1px solid #f87171;border-radius:10px;padding:16px;margin-bottom:14px;text-align:center">
        <div style="color:#94a3b8;font-size:13px">Total (comptes ayant fait des transferts entre comptes)</div>
        <div style="color:#f87171;font-size:32px;font-weight:800">{len(fraude)}</div>
      </div>
      <div style="color:#6e7681;font-size:12px;margin-bottom:10px">Critère : compte non-staff lié à <b>2 autres comptes ou plus</b> par transfert (réseau de 3 codes ou +). Les comptes avec seulement 2 codes (HEINI + MAEVA) ne sont PAS comptés. 🔒 = encore bloqué.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:380px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:6px;color:#fca5a5">Code</th><th style="padding:6px;color:#fca5a5">Nom</th><th style="padding:6px;color:#fca5a5;text-align:right">Solde</th></tr>
      {rows or '<tr><td colspan=3 style="padding:14px;color:#34d399">Aucun compte avec transfert.</td></tr>'}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/verif-transferts-zero")
def verif_transferts_zero():
    """ADMIN — Vérifie : les comptes ayant REÇU des pions par transfert qui ont
    ENCORE un solde > 0 (transferts pas encore neutralisés). ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    staff = set(DB.get("codes", {}).keys())
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Pour chaque compte : total reçu par transfert + comptes liés (pour distinguer 2 codes vs 3+)
    recu = {}; liens = {}; achat_reel = {}
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper(); m = int(t.get("montant", 0) or 0)
            if vers and vers not in staff:
                recu[vers] = recu.get(vers, 0) + m
                if de: liens.setdefault(vers, set()).add(de)
            if de and de not in staff:
                if vers: liens.setdefault(de, set()).add(vers)
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            achat_reel[cj] = achat_reel.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))

    # Comptes ayant reçu par transfert ET solde > 0
    rows = ""; nb = 0; total_restant = 0
    for c in sorted(recu, key=lambda x: -solde(x)):
        s = solde(c)
        if s > 0:
            nb += 1; total_restant += s
            nbl = len(liens.get(c, set()))
            ar = achat_reel.get(c, 0)
            flag = "🔴 3+ codes" if nbl >= 2 else "🟡 2 codes"
            rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                     f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{c}</td>'
                     f'<td style="padding:7px;color:#cbd5e1;font-size:12px">{noms.get(c, "")}</td>'
                     f'<td style="padding:7px;text-align:right;color:#6ee7b7">{format(recu.get(c,0), ",")}</td>'
                     f'<td style="padding:7px;text-align:right;color:#93c5fd">{format(ar, ",")}</td>'
                     f'<td style="padding:7px;text-align:right;color:#fbbf24;font-weight:700">{format(s, ",")}</td>'
                     f'<td style="padding:7px;font-size:12px">{flag}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="6" style="padding:16px;text-align:center;color:#34d399">✅ Aucun compte ayant reçu des transferts n\'a de solde restant. Tout est à zéro.</td></tr>'

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Vérif transferts</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:840px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🔎 Comptes ayant reçu des transferts avec solde restant</h1>
      <div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:12px">
        <div style="color:#fde68a;font-size:14px"><b>{nb}</b> compte(s) ont reçu des pions par transfert et ont <b>encore un solde</b> (total : <b>{format(total_restant, ",")} XPF</b>).</div>
      </div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">🔴 3+ codes liés = réseau (fraude probable). 🟡 2 codes = peut être un même joueur (HEINI+MAEVA) ou famille — à vérifier avant d'agir. « Acheté réel » = vrai argent payé par ce compte.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:640px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:7px;color:#fca5a5">Code</th><th style="padding:7px;color:#fca5a5">Nom</th><th style="padding:7px;color:#fca5a5;text-align:right">Reçu transf.</th><th style="padding:7px;color:#fca5a5;text-align:right">Acheté réel</th><th style="padding:7px;color:#fca5a5;text-align:right">Solde restant</th><th style="padding:7px;color:#fca5a5">Type</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/verif-codes-sources")
def verif_codes_sources():
    """ADMIN — Contrôle fondamental : pour chaque code ayant ENVOYÉ des pions,
    vérifie qu'il a réellement EU ces pions (achats + reçus + gains + recrédits).
    Si envoyé > total entré => pions créés à partir de rien. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")

    staff = set(DB.get("codes", {}).keys())
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Entrées légitimes par code : achats + gains + recrédits + reçu par transfert
    entre = {}  # toutes les entrées possibles
    recu_tr = {}; envoye_tr = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            entre[cj] = entre.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict):
            cj = (g.get("code") or "").upper()
            entre[cj] = entre.get(cj, 0) + int(g.get("montant_gain", g.get("montant_credite", 0)) or 0)
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            cj = (c.get("code_joueur") or "").upper()
            entre[cj] = entre.get(cj, 0) + int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            for cj in (c.get("codes") or []):
                cj = (cj or "").upper(); entre[cj] = entre.get(cj, 0) + m
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper(); m = int(t.get("montant", 0) or 0)
            if vers: recu_tr[vers] = recu_tr.get(vers, 0) + m
            if de: envoye_tr[de] = envoye_tr.get(de, 0) + m

    # Pour chaque code SOURCE (qui a envoyé), entrées totales = entre + reçu par transfert
    rows = ""; nb_anomalies = 0; total_cree = 0
    for c in sorted(envoye_tr, key=lambda x: -envoye_tr[x]):
        if c in staff:
            continue
        env = envoye_tr.get(c, 0)
        total_entre = entre.get(c, 0) + recu_tr.get(c, 0)
        ecart = env - total_entre  # > 0 => a envoyé plus qu'il n'a eu
        anomalie = ecart > 0
        if anomalie:
            nb_anomalies += 1; total_cree += ecart
        couleur = "#f85149" if anomalie else "#3fb950"
        verdict = (f"🔴 a envoyé {format(ecart, ',')} de trop") if anomalie else "✅ débit cohérent"
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:7px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:7px;color:#cbd5e1;font-size:12px">{noms.get(c, "")}</td>'
                 f'<td style="padding:7px;text-align:right;color:#fca5a5">{format(env, ",")}</td>'
                 f'<td style="padding:7px;text-align:right;color:#6ee7b7">{format(total_entre, ",")}</td>'
                 f'<td style="padding:7px;text-align:right;color:{couleur};font-weight:700">{verdict}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:14px;color:#94a3b8">Aucun code n\'a envoyé de transfert.</td></tr>'

    if nb_anomalies:
        _banniere_msg = "🔴 " + str(nb_anomalies) + " code(s) ont envoyé plus de pions qu'ils n'en ont jamais eu — soit " + format(total_cree, ",") + " XPF créés à partir de rien."
        _bg = "rgba(248,81,73,.12)"; _bd = "#f85149"; _col = "#f85149"
    else:
        _banniere_msg = "✅ Tous les codes sources ont été correctement débités. Aucune création de pions détectée."
        _bg = "rgba(63,185,80,.12)"; _bd = "#3fb950"; _col = "#3fb950"

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Vérif codes sources</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:880px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🔍 Contrôle des codes sources (débit des transferts)</h1>
      <div style="background:{_bg};border:1px solid {_bd};border-radius:10px;padding:14px;margin-bottom:12px">
        <div style="color:{_col};font-size:15px;font-weight:700">{_banniere_msg}</div>
      </div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">« Envoyé » = total transféré vers d'autres comptes. « A réellement eu » = achats + gains + recrédits + reçu par transfert. Si Envoyé > A réellement eu → pions fabriqués.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:660px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:7px;color:#fca5a5">Code source</th><th style="padding:7px;color:#fca5a5">Nom</th><th style="padding:7px;color:#fca5a5;text-align:right">A envoyé</th><th style="padding:7px;color:#fca5a5;text-align:right">A réellement eu</th><th style="padding:7px;color:#fca5a5">Verdict</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/solde-legitime")
def solde_legitime():
    """ADMIN — Calcule le solde LÉGITIME de chaque compte = (vrai argent payé +
    gains) − (tickets + retraits). Ne compte ni les transferts ni les recrédits
    (tainted). Montre qui a un vrai solde à rétablir. Ne modifie rien. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    staff = set(DB.get("codes", {}).keys())
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    achats = {}; gains = {}; tickets_dep = {}; retraits = {}; recus = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee":
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            achats[cj] = achats.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict):
            cj = (g.get("code") or "").upper()
            gains[cj] = gains.get(cj, 0) + int(g.get("montant_gain", g.get("montant_credite", 0)) or 0)
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict):
            cj = (c.get("code_joueur") or "").upper()
            tickets_dep[cj] = tickets_dep.get(cj, 0) + int(c.get("total_pions", 0) or 0)
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict) and r.get("statut") == "validee":
            cj = (r.get("code_joueur") or "").upper()
            retraits[cj] = retraits.get(cj, 0) + int(r.get("montant_demande", 0) or 0)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            v = (t.get("vers") or "").upper()
            if v: recus[v] = recus.get(v, 0) + int(t.get("montant", 0) or 0)

    # tous les comptes ayant une activité
    comptes = set(achats) | set(gains) | set(tickets_dep) | set(retraits) | set(recus)
    comptes = [c for c in comptes if c and c not in staff]

    lignes = []
    for c in comptes:
        vrai_in = achats.get(c, 0) + gains.get(c, 0)
        depense = tickets_dep.get(c, 0) + retraits.get(c, 0)
        legitime = max(0, vrai_in - depense)
        lignes.append((c, achats.get(c, 0), gains.get(c, 0), depense, recus.get(c, 0), legitime, solde(c)))
    # ceux qui ont un solde légitime > 0 en premier
    lignes.sort(key=lambda x: -x[5])

    rows = ""; total_legitime = 0; nb_avec = 0
    for c, a, g, d, rc, leg, sld in lignes:
        if leg > 0: nb_avec += 1; total_legitime += leg
        coul = "#3fb950" if leg > 0 else "#6e7681"
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{noms.get(c, "")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#93c5fd">{format(a, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#93c5fd">{format(g, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#fca5a5">{format(d, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:{coul};font-weight:700">{format(leg, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#8b949e">{format(sld, ",")}</td></tr>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Solde légitime</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:920px;margin:0 auto">
      <h1 style="font-size:20px;color:#3fb950;margin-bottom:8px">💰 Solde légitime de chaque compte</h1>
      <div style="background:rgba(63,185,80,.1);border:1px solid #3fb950;border-radius:10px;padding:14px;margin-bottom:12px">
        <div style="color:#3fb950;font-size:14px"><b>{nb_avec}</b> compte(s) ont un solde légitime &gt; 0 à rétablir éventuellement (total : <b>{format(total_legitime, ",")} XPF</b> de vrai argent). Les autres sont légitimement à 0.</div>
      </div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">Solde légitime = (vrai argent payé + gains) − (tickets + retraits). Les <b>transferts</b> et <b>recrédits</b> ne sont PAS comptés (pions sans contrepartie réelle sûre). « Solde actuel » = ce qu'il a aujourd'hui.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:680px">
      <tr style="border-bottom:2px solid #1f6feb;text-align:left"><th style="padding:6px;color:#93c5fd">Code</th><th style="padding:6px;color:#93c5fd">Nom</th><th style="padding:6px;color:#93c5fd;text-align:right">Acheté réel</th><th style="padding:6px;color:#93c5fd;text-align:right">Gains</th><th style="padding:6px;color:#93c5fd;text-align:right">Dépensé</th><th style="padding:6px;color:#93c5fd;text-align:right">Solde légitime</th><th style="padding:6px;color:#93c5fd;text-align:right">Solde actuel</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/aligner-soldes")
def aligner_soldes():
    """ADMIN — Aligne le COMPTEUR interne de chaque joueur sur son vrai solde
    (entrées − sorties), détruisant les pions fantômes. Aperçu d'abord ;
    rien sans &confirme=1. ?cle=ADMIN[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    confirme = request.args.get("confirme", "") == "1"
    staff = set(DB.get("codes", {}).keys())

    def solde_stocke(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100", 0)*100 + p.get("50", 0)*50 + p.get("20", 0)*20 + p.get("10", 0)*10
    def poser_solde(c, montant):
        montant = max(0, int(montant))
        r = montant
        n100 = r // 100; r -= n100 * 100
        n50 = r // 50; r -= n50 * 50
        n20 = r // 20; r -= n20 * 20
        n10 = r // 10
        DB.setdefault("pions_joueurs", {})[c] = {
            "100": n100, "50": n50, "20": n20, "10": n10}
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Vrai solde = entrées − sorties (mêmes sources que le relevé)
    ent = {}; sor = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("code_joueur") and c.get("statut") == "validee":
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            ent[cj] = ent.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))
    for t in DB.get("transactions_joueur_org", []):
        if isinstance(t, dict) and t.get("code_joueur"):
            cj = (t.get("code_joueur") or "").upper()
            ent[cj] = ent.get(cj, 0) + int(t.get("montant", t.get("nb_pions", 0)) or 0)
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code"):
            cj = (g.get("code") or "").upper()
            ent[cj] = ent.get(cj, 0) + int(g.get("montant_gain", g.get("montant_credite", 0)) or 0)
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            ent[cj] = ent.get(cj, 0) + int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            for cj in (c.get("codes") or []):
                cj = (cj or "").upper(); ent[cj] = ent.get(cj, 0) + m
    for x in DB.get("rejoindre_log", []):
        if isinstance(x, dict) and (x.get("campagne", "") == "semaine") and x.get("code"):
            cj = (x.get("code") or "").upper(); ent[cj] = ent.get(cj, 0) + 500
    for c in DB.get("commandes_tickets_pions", []):
        if isinstance(c, dict) and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            sor[cj] = sor.get(cj, 0) + int(c.get("total_pions", 0) or 0)
    for r in DB.get("demandes_retrait", []):
        if isinstance(r, dict) and r.get("statut") == "validee" and r.get("code_joueur"):
            cj = (r.get("code_joueur") or "").upper()
            sor[cj] = sor.get(cj, 0) + int(r.get("montant_demande", 0) or 0)
    for c in DB.get("corrections_pions", []):
        if isinstance(c, dict) and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            sor[cj] = sor.get(cj, 0) + int(c.get("montant_retire", 0) or 0)
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper(); m = int(t.get("montant", 0) or 0)
            if de: sor[de] = sor.get(de, 0) + m
            if vers: ent[vers] = ent.get(vers, 0) + m

    # Comparer compteur stocké vs vrai solde
    codes = set(DB.get("pions_joueurs", {}).keys()) | set(ent) | set(sor)
    plan = []
    total_detruit = total_ajoute = 0
    for c in codes:
        c = c.upper()
        if c in staff:
            continue
        vrai = max(0, ent.get(c, 0) - sor.get(c, 0))
        stocke = solde_stocke(c)
        if vrai != stocke:
            ecart = vrai - stocke
            if ecart < 0: total_detruit += -ecart
            else: total_ajoute += ecart
            plan.append((c, noms.get(c, ""), stocke, vrai, ecart))
    plan.sort(key=lambda x: x[4])  # plus gros fantômes (écart négatif) en premier

    if confirme and plan:
        for c, nom, stocke, vrai, ecart in plan:
            poser_solde(c, vrai)
        DB.setdefault("alignements_soldes", []).insert(0, {
            "id": secrets.token_hex(4).upper(), "nb_comptes": len(plan),
            "pions_detruits": total_detruit, "pions_ajoutes": total_ajoute,
            "par": cle, "date": datetime.datetime.now().isoformat()})
        save_data(immediat=True)

    rows = ""
    for c, nom, stocke, vrai, ecart in plan:
        coul = "#f85149" if ecart < 0 else "#3fb950"
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{nom}</td>'
                 f'<td style="padding:6px;text-align:right;color:#8b949e">{format(stocke, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#6ee7b7">{format(vrai, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:{coul};font-weight:700">{("+" if ecart>0 else "")}{format(ecart, ",")}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:16px;text-align:center;color:#34d399">✅ Tous les compteurs collent déjà au vrai solde. Rien à corriger.</td></tr>'

    if confirme:
        banniere = (f'<div style="background:rgba(16,185,129,.15);border:2px solid #10b981;border-radius:10px;padding:14px;margin-bottom:14px;color:#34d399;font-weight:800">'
                    f'✅ FAIT — {format(total_detruit, ",")} XPF de pions fantômes détruits, {format(total_ajoute, ",")} XPF rétablis. {len(plan)} compteur(s) alignés sur le vrai solde.</div>')
    else:
        banniere = (f'<div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:14px">'
                    f'<div style="color:#fde68a;font-weight:700;margin-bottom:6px">👁️ APERÇU — rien n\'est encore modifié</div>'
                    f'<div style="color:#94a3b8;font-size:13px;margin-bottom:10px">{len(plan)} compteur(s) à aligner : <b style="color:#f87171">{format(total_detruit, ",")} XPF fantômes à détruire</b>, {format(total_ajoute, ",")} XPF à rétablir. Chaque compteur sera mis à <b>entrées − sorties</b>.</div>'
                    f'<a href="/aligner-soldes?cle={cle}&confirme=1" style="display:inline-block;background:#ef4444;color:#fff;padding:12px 20px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer l\'alignement</a></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Aligner les soldes</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🧹 Aligner les compteurs sur le vrai solde (entrées − sorties)</h1>
      {banniere}
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">« Compteur » = ce que l'appli affiche au jeu. « Vrai solde » = entrées − sorties (comme le relevé). 🔴 écart négatif = pions fantômes à détruire.</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:520px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:6px;color:#fca5a5">Code</th><th style="padding:6px;color:#fca5a5">Nom</th><th style="padding:6px;color:#fca5a5;text-align:right">Compteur actuel</th><th style="padding:6px;color:#fca5a5;text-align:right">Vrai solde</th><th style="padding:6px;color:#fca5a5;text-align:right">Écart</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/sources-emetteurs")
def sources_emetteurs():
    """ADMIN — Pour chaque code qui a ENVOYÉ des pions : d'où viennent ses pions
    (achats Stripe, gains, bonus, crédits, reçus) vs ce qu'il a envoyé. Montre
    l'écart fabriqué. Lecture seule. ?cle=ADMIN[&code=X pour un seul]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    filtre = (request.args.get("code", "") or "").strip().upper()
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    achats = {}; nb_achats = {}; gains = {}; bonus = {}; credits = {}; recu = {}; envoye = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee" and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            achats[cj] = achats.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))
            nb_achats[cj] = nb_achats.get(cj, 0) + 1
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code"):
            cj = (g.get("code") or "").upper()
            gains[cj] = gains.get(cj, 0) + int(g.get("montant_gain", g.get("montant_credite", 0)) or 0)
    for x in DB.get("rejoindre_log", []):
        if isinstance(x, dict) and x.get("campagne", "") == "semaine" and x.get("code"):
            cj = (x.get("code") or "").upper(); bonus[cj] = bonus.get(cj, 0) + 500
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            credits[cj] = credits.get(cj, 0) + int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            for cj in (c.get("codes") or []):
                cj = (cj or "").upper(); credits[cj] = credits.get(cj, 0) + m
    for t in DB.get("transferts_pions", []):
        if isinstance(t, dict):
            de = (t.get("de") or "").upper(); vers = (t.get("vers") or "").upper(); m = int(t.get("montant", 0) or 0)
            if de: envoye[de] = envoye.get(de, 0) + m
            if vers: recu[vers] = recu.get(vers, 0) + m

    emetteurs = sorted([c for c in envoye if envoye[c] > 0], key=lambda c: -(envoye[c] - (achats.get(c,0)+gains.get(c,0)+bonus.get(c,0)+credits.get(c,0)+recu.get(c,0))))
    if filtre:
        emetteurs = [c for c in emetteurs if c == filtre]

    rows = ""; total_fab = 0; nb_fab = 0
    for c in emetteurs:
        a = achats.get(c,0); g = gains.get(c,0); b = bonus.get(c,0); cr = credits.get(c,0); r = recu.get(c,0)
        eu = a + g + b + cr + r
        env = envoye.get(c,0)
        ecart = env - eu
        if ecart > 0: total_fab += ecart; nb_fab += 1
        coul = "#f85149" if ecart > 0 else "#3fb950"
        verdict = (f"🔴 a fabriqué {format(ecart, ',')}" if ecart > 0 else "✅ cohérent")
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{c}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{noms.get(c,"")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#6ee7b7">{format(a, ",")}<br><span style="font-size:10px;color:#6b7280">{nb_achats.get(c,0)} paiement(s)</span></td>'
                 f'<td style="padding:6px;text-align:right;color:#93c5fd">{format(g, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#93c5fd">{format(b+cr, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#fbbf24">{format(r, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#e6edf3;font-weight:700">{format(eu, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#fca5a5;font-weight:700">{format(env, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:{coul};font-weight:800;font-size:12px">{verdict}</td></tr>')

    titre = f"Émetteur {filtre}" if filtre else "Tous les émetteurs"
    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Sources des émetteurs</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:1000px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🔍 D'où viennent les pions des émetteurs — {titre}</h1>
      <div style="background:rgba(248,81,73,.1);border:1px solid #f85149;border-radius:10px;padding:14px;margin-bottom:12px">
        <div style="color:#fca5a5;font-size:14px"><b>{nb_fab}</b> émetteur(s) ont fabriqué des pions (envoyé plus que tout ce qu'ils ont eu). Total fabriqué : <b>{format(total_fab, ",")} XPF</b>.</div>
      </div>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:10px">« A réellement eu » = Achats Stripe + Gains + Bonus/Crédits + Reçus par transfert. Si « Envoyé » &gt; « A eu » → 🔴 pions fabriqués (sortis de nulle part, pas d'un achat).</div>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:820px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:6px;color:#fca5a5">Code</th><th style="padding:6px;color:#fca5a5">Nom</th><th style="padding:6px;color:#fca5a5;text-align:right">Achats réels</th><th style="padding:6px;color:#fca5a5;text-align:right">Gains</th><th style="padding:6px;color:#fca5a5;text-align:right">Bonus/Crédits</th><th style="padding:6px;color:#fca5a5;text-align:right">Reçus</th><th style="padding:6px;color:#fca5a5;text-align:right">A eu (total)</th><th style="padding:6px;color:#fca5a5;text-align:right">Envoyé</th><th style="padding:6px;color:#fca5a5;text-align:right">Verdict</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/chaine-fabrique")
def chaine_fabrique():
    """ADMIN — Trace la chaîne : pour chaque FABRICANT (a envoyé plus qu'il n'a eu),
    liste vers QUI sont partis ses pions, avec montants et dates. Montre où
    atterrissent les pions fabriqués. Lecture seule. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    achats = {}; gains = {}; bc = {}; recu = {}; envoye = {}
    for c in DB.get("commandes_pions_joueurs", []):
        if isinstance(c, dict) and c.get("statut") == "validee" and c.get("code_joueur"):
            cj = (c.get("code_joueur") or "").upper()
            nbp = int(c.get("nb_pions", c.get("pions_credites", 0)) or 0); vp = int(c.get("valeur_pion", 0) or 0)
            achats[cj] = achats.get(cj, 0) + ((nbp * vp) or int(c.get("montant_net", 0) or 0))
    for g in DB.get("gains_finaux", []):
        if isinstance(g, dict) and g.get("code"):
            cj = (g.get("code") or "").upper(); gains[cj] = gains.get(cj, 0) + int(g.get("montant_gain", g.get("montant_credite", 0)) or 0)
    for x in DB.get("rejoindre_log", []):
        if isinstance(x, dict) and x.get("campagne","")=="semaine" and x.get("code"):
            cj=(x.get("code") or "").upper(); bc[cj]=bc.get(cj,0)+500
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict) and c.get("code_joueur"):
            cj=(c.get("code_joueur") or "").upper(); bc[cj]=bc.get(cj,0)+int(c.get("nb_pions",0) or 0)*int(c.get("valeur_pion",0) or 0)
    for c in DB.get("credits_masse", []):
        if isinstance(c, dict):
            m=int(c.get("nb_pions",0) or 0)*int(c.get("valeur_pion",0) or 0)
            for cj in (c.get("codes") or []):
                cj=(cj or "").upper(); bc[cj]=bc.get(cj,0)+m
    transferts = [t for t in DB.get("transferts_pions", []) if isinstance(t, dict)]
    for t in transferts:
        de=(t.get("de") or "").upper(); vers=(t.get("vers") or "").upper(); m=int(t.get("montant",0) or 0)
        if de: envoye[de]=envoye.get(de,0)+m
        if vers: recu[vers]=recu.get(vers,0)+m

    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100",0)*100+p.get("50",0)*50+p.get("20",0)*20+p.get("10",0)*10

    # Les fabricants = envoyé > (achats+gains+bc+recu)
    fab = []
    for c in envoye:
        eu = achats.get(c,0)+gains.get(c,0)+bc.get(c,0)+recu.get(c,0)
        ec = envoye[c]-eu
        if ec > 0: fab.append((c, ec))
    fab.sort(key=lambda x:-x[1])

    blocs = ""
    for c, ec in fab:
        dests = [t for t in transferts if (t.get("de") or "").upper()==c]
        lignes_d = ""
        for t in sorted(dests, key=lambda x:str(x.get("date","")), reverse=True):
            v=(t.get("vers") or "").upper(); m=int(t.get("montant",0) or 0); d=str(t.get("date",""))[:16]
            lignes_d += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
                         f'<td style="padding:4px 8px;color:#8b949e;font-size:11px">{d}</td>'
                         f'<td style="padding:4px 8px;font-family:monospace;color:#fca5a5">→ {v}</td>'
                         f'<td style="padding:4px 8px;color:#94a3b8;font-size:12px">{noms.get(v,"")}</td>'
                         f'<td style="padding:4px 8px;text-align:right;color:#f87171;font-weight:700">{format(m, ",")}</td>'
                         f'<td style="padding:4px 8px;text-align:right;color:#6ee7b7;font-size:11px">solde {v}: {format(solde(v), ",")}</td></tr>')
        blocs += (f'<div style="background:#161b22;border:1px solid #7f1d1d;border-radius:10px;padding:12px;margin-bottom:12px">'
                  f'<div style="color:#fca5a5;font-weight:700;margin-bottom:6px">🔴 {c} <span style="color:#94a3b8;font-weight:400">{noms.get(c,"")}</span> — a fabriqué <b>{format(ec, ",")} XPF</b> (acheté réel : {format(achats.get(c,0), ",")})</div>'
                  f'<table style="width:100%;border-collapse:collapse">{lignes_d}</table></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Chaîne des pions fabriqués</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:880px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🔗 Chaîne des pions fabriqués — où atterrissent-ils ?</h1>
      <div style="color:#94a3b8;font-size:12px;margin-bottom:14px">Pour chaque fabricant (a envoyé plus qu'il n'a eu), voici vers QUI sont partis ses pions. « solde X » = ce que le destinataire détient aujourd'hui.</div>
      {blocs if blocs else '<div style="color:#34d399">Aucun fabricant trouvé.</div>'}
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/credits-admin-liste")
def credits_admin_liste():
    """ADMIN — Liste TOUS les crédits admin regroupés par lot (date/heure à la
    minute), pour repérer les crédits erronés. Lecture seule. ?cle=ADMIN"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    # Regrouper credits_admin par minute
    lots = {}  # date_minute -> {montant_total, entrees:[(code,montant,par,jeu)]}
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict):
            continue
        cj = (c.get("code_joueur") or "").upper()
        m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        d = str(c.get("date", ""))[:16]  # à la minute
        jeu = c.get("jeu", c.get("motif", "")) or ""
        par = c.get("par", "") or ""
        lots.setdefault(d, {"total": 0, "lignes": [], "source": "credits_admin"})
        lots[d]["total"] += m
        lots[d]["lignes"].append((cj, m, par, jeu))
    # credits_masse (lots de masse)
    for c in DB.get("credits_masse", []):
        if not isinstance(c, dict):
            continue
        m1 = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
        codes = [(x or "").upper() for x in (c.get("codes") or [])]
        d = str(c.get("date", "(sans date)"))[:16]
        jeu = c.get("jeu", c.get("motif", "")) or ""
        par = c.get("par", "") or ""
        key = d + " [masse]"
        lots.setdefault(key, {"total": 0, "lignes": [], "source": "credits_masse"})
        lots[key]["total"] += m1 * len(codes)
        for cj in codes:
            lots[key]["lignes"].append((cj, m1, par, jeu))

    cles_triees = sorted(lots.keys(), reverse=True)
    total_general = sum(l["total"] for l in lots.values())

    blocs = ""
    for d in cles_triees:
        L = lots[d]
        lignes = ""
        for cj, m, par, jeu in sorted(L["lignes"], key=lambda x: -x[1]):
            lignes += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
                       f'<td style="padding:3px 8px;font-family:monospace;color:#a78bfa">{cj}</td>'
                       f'<td style="padding:3px 8px;color:#94a3b8;font-size:12px">{noms.get(cj,"")}</td>'
                       f'<td style="padding:3px 8px;text-align:right;color:#6ee7b7;font-weight:700">+{format(m, ",")}</td>'
                       f'<td style="padding:3px 8px;color:#fbbf24;font-size:11px">{jeu}</td>'
                       f'<td style="padding:3px 8px;color:#6b7280;font-size:11px">{par}</td></tr>')
        blocs += (f'<div style="background:#161b22;border:1px solid #30363d;border-radius:10px;padding:12px;margin-bottom:12px">'
                  f'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">'
                  f'<span style="color:#58a6ff;font-weight:700;font-size:15px">📅 {d}</span>'
                  f'<span style="color:#e6edf3;font-weight:800">{len(L["lignes"])} crédit(s) · {format(L["total"], ",")} XPF</span></div>'
                  f'<table style="width:100%;border-collapse:collapse;font-size:13px">{lignes}</table></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Crédits admin par lot</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:880px;margin:0 auto">
      <h1 style="font-size:20px;color:#58a6ff;margin-bottom:6px">📋 Tous les crédits admin, regroupés par lot (date/heure)</h1>
      <div style="background:rgba(88,166,255,.1);border:1px solid #1f6feb;border-radius:10px;padding:12px;margin-bottom:14px;color:#93c5fd">
        Total général des crédits admin : <b>{format(total_general, ",")} XPF</b> · {len(cles_triees)} lot(s). Repère le lot d'hier soir (sauf Flash Quines) → on l'annulera ensuite.</div>
      {blocs if blocs else '<div style="color:#8b949e">Aucun crédit admin trouvé.</div>'}
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/annuler-credits-periode")
def annuler_credits_periode():
    """ADMIN — Annule les crédits admin erronés d'une fenêtre de temps (du/au).
    Retire les crédits ET déduit le montant du compteur du joueur. Aperçu d'abord ;
    rien sans &confirme=1. ?cle=ADMIN&du=2026-06-27T03:00&au=2026-06-27T05:00[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    du = (request.args.get("du", "2026-06-27T03:00") or "").strip()
    au = (request.args.get("au", "2026-06-27T05:00") or "").strip()
    confirme = request.args.get("confirme", "") == "1"
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")
    def solde(c):
        p = DB.get("pions_joueurs", {}).get(c, {})
        return p.get("100",0)*100+p.get("50",0)*50+p.get("20",0)*20+p.get("10",0)*10
    def poser_solde(c, montant):
        montant = max(0, int(montant))
        r = montant
        n100 = r // 100; r -= n100 * 100
        n50 = r // 50; r -= n50 * 50
        n20 = r // 20; r -= n20 * 20
        n10 = r // 10
        DB.setdefault("pions_joueurs", {})[c] = {"100": n100, "50": n50, "20": n20, "10": n10}

    # Crédits dans la fenêtre
    vises = []
    par_compte = {}
    for c in DB.get("credits_admin", []):
        if not isinstance(c, dict):
            continue
        d = str(c.get("date", ""))
        if d and du <= d <= au + "~":
            cj = (c.get("code_joueur") or "").upper()
            m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
            vises.append((cj, m, d[:16]))
            par_compte[cj] = par_compte.get(cj, 0) + m
    total = sum(m for _, m, _ in vises)

    if confirme and vises:
        DB["credits_admin"] = [c for c in DB.get("credits_admin", [])
                               if not (isinstance(c, dict) and str(c.get("date","")) and du <= str(c.get("date","")) <= au + "~")]
        for cj, m in par_compte.items():
            poser_solde(cj, solde(cj) - m)
        DB.setdefault("annulations_credits", []).insert(0, {
            "id": secrets.token_hex(4).upper(), "du": du, "au": au,
            "nb_credits": len(vises), "total": total, "comptes": len(par_compte),
            "par": cle, "date": datetime.datetime.now().isoformat()})
        save_data(immediat=True)

    # Tableau par compte (avant/après)
    rows = ""
    for cj, m in sorted(par_compte.items(), key=lambda x: -x[1]):
        if confirme:
            apres = solde(cj); avant = apres + m
        else:
            avant = solde(cj); apres = max(0, avant - m)
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.06)">'
                 f'<td style="padding:6px;font-family:monospace;color:#a78bfa">{cj}</td>'
                 f'<td style="padding:6px;color:#94a3b8;font-size:12px">{noms.get(cj,"")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#f87171;font-weight:700">-{format(m, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#8b949e">{format(avant, ",")}</td>'
                 f'<td style="padding:6px;text-align:right;color:#6ee7b7;font-weight:700">{format(apres, ",")}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="5" style="padding:16px;text-align:center;color:#8b949e">Aucun crédit dans cette fenêtre.</td></tr>'

    detail = ""
    for cj, m, d in sorted(vises, key=lambda x: x[2], reverse=True):
        detail += f'<div style="font-size:12px;color:#8b949e;padding:2px 0">{d} · {cj} {noms.get(cj,"")} · <span style="color:#f87171">+{format(m, ",")}</span></div>'

    if confirme:
        banniere = (f'<div style="background:rgba(16,185,129,.15);border:2px solid #10b981;border-radius:10px;padding:14px;margin-bottom:14px;color:#34d399;font-weight:800">'
                    f'✅ FAIT — {len(vises)} crédit(s) erronés annulés ({format(total, ",")} XPF retirés). {len(par_compte)} compte(s) corrigés.</div>')
    else:
        banniere = (f'<div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:14px">'
                    f'<div style="color:#fde68a;font-weight:700;margin-bottom:6px">👁️ APERÇU — rien n\'est encore modifié</div>'
                    f'<div style="color:#94a3b8;font-size:13px;margin-bottom:10px">Fenêtre <b>{du}</b> → <b>{au}</b> : <b style="color:#f87171">{len(vises)} crédit(s) à annuler, {format(total, ",")} XPF</b> sur {len(par_compte)} compte(s).</div>'
                    f'<a href="/annuler-credits-periode?cle={cle}&du={du}&au={au}&confirme=1" style="display:inline-block;background:#ef4444;color:#fff;padding:12px 20px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer l\'annulation de ce lot</a></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Annuler crédits erronés</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:820px;margin:0 auto">
      <h1 style="font-size:20px;color:#f0883e;margin-bottom:8px">🧹 Annuler le lot de crédits erronés</h1>
      {banniere}
      <h2 style="font-size:15px;color:#93c5fd;margin:14px 0 6px">Effet par compte (avant → après)</h2>
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:520px">
      <tr style="border-bottom:2px solid #7f1d1d;text-align:left"><th style="padding:6px;color:#fca5a5">Code</th><th style="padding:6px;color:#fca5a5">Nom</th><th style="padding:6px;color:#fca5a5;text-align:right">Retiré</th><th style="padding:6px;color:#fca5a5;text-align:right">Avant</th><th style="padding:6px;color:#fca5a5;text-align:right">Après</th></tr>
      {rows}</table></div>
      <h2 style="font-size:15px;color:#93c5fd;margin:18px 0 6px">Détail des crédits visés</h2>
      <div style="background:#161b22;border:1px solid #30363d;border-radius:8px;padding:10px;max-height:300px;overflow-y:auto">{detail or '<span style="color:#8b949e">—</span>'}</div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


@app.route("/etiqueter-credits")
def etiqueter_credits():
    """ADMIN — Met un MOTIF sur les crédits admin d'une fenêtre (sans changer les
    montants), pour qu'ils s'affichent correctement sur le relevé. Aperçu d'abord ;
    rien sans &confirme=1. ?cle=ADMIN&du=...&au=...&motif=...[&confirme=1]"""
    global DB
    DB = load_data()
    cle = (request.args.get("cle", "") or "").strip().upper()
    info = DB.get("codes", {}).get(cle)
    if not (info and info.get("admin")):
        return Response("Acces reserve. Ajoute ?cle=TON_CODE_ADMIN.", status=403, mimetype="text/plain; charset=utf-8")
    du = (request.args.get("du", "2026-06-27T05:05") or "").strip()
    au = (request.args.get("au", "2026-06-27T10:30") or "").strip()
    motif = (request.args.get("motif", "Remboursement Flash Quines Allonger") or "").strip()
    confirme = request.args.get("confirme", "") == "1"
    noms = {}
    for t in DB.get("tickets", []):
        if isinstance(t, dict) and t.get("code_acheteur") and t.get("acheteur"):
            noms[(t.get("code_acheteur") or "").upper()] = t.get("acheteur")

    vises = []
    total = 0
    for c in DB.get("credits_admin", []):
        if isinstance(c, dict):
            d = str(c.get("date", ""))
            if d and du <= d <= au + "~":
                cj = (c.get("code_joueur") or "").upper()
                m = int(c.get("nb_pions", 0) or 0) * int(c.get("valeur_pion", 0) or 0)
                vises.append((cj, m, d[:16], c.get("motif", "")))
                total += m
                if confirme:
                    c["motif"] = motif

    if confirme and vises:
        DB.setdefault("etiquetages_credits", []).insert(0, {
            "id": secrets.token_hex(4).upper(), "du": du, "au": au, "motif": motif,
            "nb": len(vises), "total": total, "par": cle, "date": datetime.datetime.now().isoformat()})
        save_data(immediat=True)

    rows = ""
    for cj, m, d, anc in sorted(vises, key=lambda x: x[2], reverse=True):
        rows += (f'<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
                 f'<td style="padding:4px 8px;color:#8b949e;font-size:11px">{d}</td>'
                 f'<td style="padding:4px 8px;font-family:monospace;color:#a78bfa">{cj}</td>'
                 f'<td style="padding:4px 8px;color:#94a3b8;font-size:12px">{noms.get(cj,"")}</td>'
                 f'<td style="padding:4px 8px;text-align:right;color:#6ee7b7">+{format(m, ",")}</td></tr>')
    if not rows:
        rows = '<tr><td colspan="4" style="padding:16px;text-align:center;color:#8b949e">Aucun crédit dans cette fenêtre.</td></tr>'

    if confirme:
        banniere = (f'<div style="background:rgba(16,185,129,.15);border:2px solid #10b981;border-radius:10px;padding:14px;margin-bottom:14px;color:#34d399;font-weight:800">'
                    f'✅ FAIT — {len(vises)} crédit(s) étiquetés « {motif} » ({format(total, ",")} XPF). Les montants n\'ont PAS changé. Le relevé affiche maintenant le bon motif.</div>')
    else:
        banniere = (f'<div style="background:rgba(251,191,36,.1);border:1px solid #f59e0b;border-radius:10px;padding:14px;margin-bottom:14px">'
                    f'<div style="color:#fde68a;font-weight:700;margin-bottom:6px">👁️ APERÇU — rien n\'est encore modifié</div>'
                    f'<div style="color:#94a3b8;font-size:13px;margin-bottom:6px">Fenêtre <b>{du}</b> → <b>{au}</b> : <b>{len(vises)} crédit(s)</b> ({format(total, ",")} XPF) recevront le motif :</div>'
                    f'<div style="color:#6ee7b7;font-weight:700;margin-bottom:10px">« {motif} »</div>'
                    f'<div style="color:#94a3b8;font-size:12px;margin-bottom:10px">⚠️ Les montants ne changent PAS. On ajoute juste l\'étiquette pour l\'affichage du relevé.</div>'
                    f'<a href="/etiqueter-credits?cle={cle}&du={du}&au={au}&motif={motif.replace(" ", "%20")}&confirme=1" style="display:inline-block;background:#10b981;color:#fff;padding:12px 20px;border-radius:10px;text-decoration:none;font-weight:700">✅ Confirmer l\'étiquetage</a></div>')

    return Response(f'''<!DOCTYPE html><html lang="fr"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Étiqueter crédits</title></head>
    <body style="margin:0;background:#0f0e1f;font-family:system-ui,sans-serif;padding:16px;color:#fff"><div style="max-width:760px;margin:0 auto">
      <h1 style="font-size:20px;color:#10b981;margin-bottom:8px">🏷️ Étiqueter les crédits (motif sur le relevé)</h1>
      {banniere}
      <div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:13px;min-width:460px">
      <tr style="border-bottom:2px solid #065f46;text-align:left"><th style="padding:6px;color:#6ee7b7">Date</th><th style="padding:6px;color:#6ee7b7">Code</th><th style="padding:6px;color:#6ee7b7">Nom</th><th style="padding:6px;color:#6ee7b7;text-align:right">Montant</th></tr>
      {rows}</table></div>
    </div></body></html>''', mimetype="text/html; charset=utf-8")


